import type { ProviderRegistry } from '../../../registries/provider-registry.ts'
import { Logger } from '../../../utils/logger.ts'
import type { NovaClawConfig } from '../../apis/index.ts'
import type { LLMProvider } from '../../apis/provider.ts'
import { LLMApiError, OpenAICompatibleProvider } from '../../provider/openai-compatible.ts'
import { LLMSession } from '../session/llm-session.ts'
import { createMockSession } from '../session/mock-session.ts'
import { OptimalModelRouter } from './model-router.ts'
import type {
    LLMSessionInterface,
    IModelManager,
    ModelInfo,
} from '../types.ts'

export class ModelManager implements IModelManager {
    private router: OptimalModelRouter
    private logger: Logger
    private activeModel: ModelInfo | null = null
    private activeProvider: LLMProvider | null = null
    private providerRegistry: ProviderRegistry | null = null

    constructor(
        private config: NovaClawConfig,
        options?: { providerRegistry?: ProviderRegistry | null }
    ) {
        this.router = new OptimalModelRouter(config)
        this.logger = new Logger('ModelManager', config.logging?.level || 'info')
        if (options?.providerRegistry) this.providerRegistry = options.providerRegistry
    }

    setProviderRegistry(registry: ProviderRegistry | null): void {
        this.providerRegistry = registry
    }

    getActiveModel(): ModelInfo | null {
        return this.activeModel
    }

    getActiveProvider(): LLMProvider | null {
        return this.activeProvider
    }

    async initialize(): Promise<ModelInfo> {
        const modelInfo = await this.router.selectOptimalModel()
        this.activeModel = modelInfo
        this.activeProvider = this.createProviderForModel(modelInfo)
        this.logger.info('Model initialized', { provider: modelInfo.provider, model: modelInfo.model })
        return modelInfo
    }

    async reinitialize(): Promise<void> {
        await this.initialize()
    }

    recordSuccess(): void {
        if (this.activeModel) this.router.recordSuccess(this.activeModel)
    }

    recordFailure(): void {
        if (this.activeModel) this.router.recordFailure(this.activeModel)
    }

    async switchToFallback(): Promise<boolean> {
        if (this.activeModel) this.router.recordFailure(this.activeModel)

        const fallback = await this.router.selectFallbackModel(this.activeModel ?? undefined)
        if (!fallback) return false

        this.activeModel = fallback
        this.activeProvider = this.createProviderForModel(fallback)
        this.logger.info('Switched to fallback model', { provider: fallback.provider, model: fallback.model })
        return true
    }

    createSession(): LLMSessionInterface {
        const modelInfo = this.activeModel
        const provider = this.activeProvider

        if (!modelInfo || !provider) {
            return createMockSession(this.activeModel?.model ?? 'mock')
        }

        return this.createRealSession(modelInfo, provider)
    }

    async internalLLMCall(systemPrompt: string, userContent: string, maxTokens = 2048): Promise<string | null> {
        const provider = this.activeProvider
        const model = this.activeModel
        if (!provider || !model) return null

        return provider.chatComplete(model.model, [
            { role: 'system', content: systemPrompt },
            { role: 'user', content: userContent }
        ], { maxTokens })
    }

    // ---------------------------------------------------------------------------
    // Private
    // ---------------------------------------------------------------------------

    private getProviderConfig(provider: string): { apiKey: string; baseUrl: string; logLevel?: string } | null {
        const prov = this.config.models?.providers?.[provider as keyof typeof this.config.models.providers]
        if (!prov || typeof prov !== 'object') return null
        const apiKey = (prov as { apiKey?: string }).apiKey?.trim()
        const baseUrl = ((prov as { baseUrl?: string }).baseUrl ?? '').replace(/\/$/, '')
        if (!apiKey || !baseUrl) return null
        return { apiKey, baseUrl, logLevel: this.config.logging?.level }
    }

    private getModelParams(provider: string): {
        temperature?: number; topP?: number; enableThinking?: boolean
        frequencyPenalty?: number; presencePenalty?: number
    } {
        const prov = this.config.models?.providers?.[provider as keyof typeof this.config.models.providers]
        if (!prov || typeof prov !== 'object') return {}
        const p = prov as Record<string, unknown>
        return {
            temperature: typeof p.temperature === 'number' ? p.temperature : undefined,
            topP: typeof p.topP === 'number' ? p.topP : undefined,
            enableThinking: typeof p.enableThinking === 'boolean' ? p.enableThinking : true,
            frequencyPenalty: typeof p.frequencyPenalty === 'number' ? p.frequencyPenalty : undefined,
            presencePenalty: typeof p.presencePenalty === 'number' ? p.presencePenalty : undefined,
        }
    }

    private createProviderForModel(modelInfo: ModelInfo): LLMProvider | null {
        const providerConfig = this.getProviderConfig(modelInfo.provider)
        if (!providerConfig) {
            this.logger.warn('No API key configured, LLM features limited', { provider: modelInfo.provider })
            return null
        }
        const factory = this.providerRegistry?.getFactory(modelInfo.provider)
        if (factory) {
            return factory.create(providerConfig)
        }
        return new OpenAICompatibleProvider(modelInfo.provider, providerConfig)
    }

    private createRealSession(modelInfo: ModelInfo, provider: LLMProvider): LLMSessionInterface {
        return new LLMSession(modelInfo, provider, this.getModelParams(modelInfo.provider), this.logger)
    }
}

export { createMockSession } from '../session/mock-session.ts'
export { LLMApiError }

