/**
 * InboundPipeline — stage-based processor for incoming channel messages.
 *
 * Pipeline stages (each is independently testable):
 *
 *   1. Sanitize     → truncate / normalise raw message
 *   2. SecurityGate → allowFrom + DM-policy check
 *   3. MentionGate  → group @mention filter
 *   4. RouteResolve → binding match → agentId + sessionKey
 *   5. ContextBuild → assemble InboundMessageContext + session hints
 *
 * Returns `null` when a stage drops the message (security rejection,
 * missing mention, etc.), signalling the hub to stop processing.
 */

import type { NovaClawConfig } from '../../../apis/config.ts'
import type { Logger } from '../../../../utils/logger.ts'
import type { ChannelPlugin } from '../../types/plugin.ts'
import type { ChannelRegistry } from '../../registry.ts'
import type { InboundMessageContext } from './normalize.ts'
import { SecurityGate, type SecurityVerdict } from './security-gate.ts'
import { MentionGate } from './mention-gate.ts'
import { resolveAgentRoute, type ChannelBinding, type RoutePeer } from '../routing/index.ts'

// ── Pipeline result ─────────────────────────────────────────────────────

export interface InboundPipelineResult {
    context: InboundMessageContext
    sessionHints: {
        sessionKey?: string
        userId: string
        channel: string
        metadata: Record<string, unknown>
    }
    message: Record<string, unknown>
}

// ── Pairing event (emitted when security rejects an unknown sender) ─────

export interface PairingRequest {
    channelId: string
    senderId: string
    senderName?: string
    reply: string
    metadata?: Record<string, unknown>
}

// ── Pipeline options ────────────────────────────────────────────────────

export interface InboundPipelineOptions {
    registry: ChannelRegistry
    config: NovaClawConfig
    bindings: ChannelBinding[]
    logger: Logger
}

// ── Constants ───────────────────────────────────────────────────────────

const MAX_MESSAGE_LENGTH = 10_000

// ── InboundPipeline ─────────────────────────────────────────────────────

export class InboundPipeline {
    private registry: ChannelRegistry
    private config: NovaClawConfig
    private bindings: ChannelBinding[]
    private logger: Logger
    private securityGate = new SecurityGate()
    private mentionGate = new MentionGate()

    constructor(options: InboundPipelineOptions) {
        this.registry = options.registry
        this.config = options.config
        this.bindings = options.bindings
        this.logger = options.logger
    }

    /**
     * Run the full inbound pipeline.
     *
     * @returns The pipeline result, or `null` if the message was dropped.
     *          When a pairing request is needed, it is returned via
     *          the `onPairing` callback so the hub can emit the event.
     */
    process(
        channelId: string,
        message: unknown,
        onPairing?: (req: PairingRequest) => void,
    ): InboundPipelineResult | null {
        // ── Stage 1: Sanitize ───────────────────────────────────────
        const sanitized = this.sanitize(message)
        const msgObj = (typeof sanitized === 'object' && sanitized !== null)
            ? sanitized as Record<string, unknown>
            : {}

        const plugin = this.registry.get(channelId)

        // ── Stage 2: Security gate ──────────────────────────────────
        const verdict = this.securityGate.check(plugin, channelId, msgObj, this.config)
        if (!verdict.allowed) {
            this.handleSecurityRejection(plugin, channelId, verdict, onPairing)
            return null
        }

        // ── Stage 3: Mention gate ───────────────────────────────────
        const chatType = this.extractChatType(msgObj)
        if (!this.mentionGate.check(plugin, channelId, msgObj, chatType, this.config)) {
            this.logger.debug(`Group message from ${channelId} ignored (no mention)`)
            return null
        }

        // ── Stage 4: Route resolution ───────────────────────────────
        const body = ((msgObj.body as string) ?? (msgObj.text as string) ?? '').trim()
        const peer: RoutePeer = {
            kind: chatType as RoutePeer['kind'],
            id: (msgObj.to as string) ?? (msgObj.peerId as string) ?? (msgObj.roomId as string) ?? 'unknown',
        }
        const parentPeer = (msgObj.threadId as string)
            ? { kind: 'thread' as const, id: msgObj.threadId as string }
            : undefined

        const route = resolveAgentRoute(
            {
                cfg: this.config,
                channel: channelId,
                accountId: (msgObj.accountId as string) ?? 'default',
                peer,
                parentPeer,
                guildId: msgObj.guildId as string | undefined,
                teamId: msgObj.teamId as string | undefined,
                memberRoleIds: msgObj.memberRoleIds as string[] | undefined,
            },
            this.bindings,
        )

        // ── Stage 5: Build context ──────────────────────────────────
        const from = (msgObj.from as string) ?? (msgObj.senderId as string) ?? (msgObj.userId as string) ?? 'anonymous'

        const context: InboundMessageContext = {
            channelId,
            accountId: (msgObj.accountId as string) ?? 'default',
            sessionKey: route.sessionKey,
            agentId: route.agentId,
            from,
            fromName: msgObj.fromName as string | undefined,
            to: peer.id,
            body,
            chatType: chatType as InboundMessageContext['chatType'],
            surface: msgObj.surface as string | undefined,
            provider: msgObj.provider as string | undefined,
            mediaType: msgObj.mediaType as string | undefined,
            mediaUrl: msgObj.mediaUrl as string | undefined,
            timestamp: (msgObj.timestamp as number) ?? Date.now(),
            messageId: msgObj.messageId as string | undefined,
            replyToId: msgObj.replyToId as string | undefined,
            threadId: msgObj.threadId as string | undefined,
            metadata: (msgObj.metadata as Record<string, unknown>) ?? {},
        }

        const sessionHints = {
            sessionKey: context.sessionKey,
            userId: context.from,
            channel: context.channelId,
            metadata: context.metadata ?? {},
        }

        const payload: Record<string, unknown> = {
            ...(sanitized as Record<string, unknown>),
            text: (sanitized as Record<string, unknown>)?.text ?? (sanitized as Record<string, unknown>)?.body ?? context.body,
            body: context.body,
        }

        return { context, sessionHints, message: payload }
    }

    // ── Private helpers ─────────────────────────────────────────────────

    private sanitize(message: unknown): unknown {
        if (typeof message !== 'object' || message === null) return message
        const m = message as Record<string, unknown>
        const text = m.text ?? m.body
        if (typeof text !== 'string') return message
        if (text.length <= MAX_MESSAGE_LENGTH) return message
        return {
            ...m,
            text: text.slice(0, MAX_MESSAGE_LENGTH),
            body: text.slice(0, MAX_MESSAGE_LENGTH),
        }
    }

    private extractChatType(msg: Record<string, unknown>): string {
        if (msg.chatType === 'group' || msg.chatType === 'channel' || msg.chatType === 'thread' || msg.chatType === 'direct') {
            return msg.chatType as string
        }
        if (msg.isThread) return 'thread'
        if (msg.isChannel) return 'channel'
        if (msg.isGroup) return 'group'
        return 'direct'
    }

    private handleSecurityRejection(
        plugin: ChannelPlugin | undefined,
        channelId: string,
        verdict: SecurityVerdict & { allowed: false },
        onPairing?: (req: PairingRequest) => void,
    ): void {
        if (verdict.emitPairing && plugin?.pairing?.buildPairingReply && onPairing) {
            const reply = plugin.pairing.buildPairingReply({
                cfg: this.config,
                senderId: verdict.senderId,
                senderName: verdict.senderName,
                channelId,
            })
            onPairing({
                channelId,
                senderId: verdict.senderId,
                senderName: verdict.senderName,
                reply: reply.text,
                metadata: reply.metadata,
            })
        }
    }
}
