/**
 * Centralized timeout constants.
 * All values in milliseconds unless noted. Import from here instead of hard-coding.
 */

// ── Tool / Process ──────────────────────────────────────────────────────

/** Default per-tool execution timeout. */
export const TOOL_TIMEOUT_MS = 1200_000

/** Long-running process tool timeout (e.g. builds, large scripts). */
export const PROCESS_TOOL_TIMEOUT_MS = 1200_000

// ── LLM ─────────────────────────────────────────────────────────────────

/** Max wait for LLM HTTP response headers before aborting. */
export const LLM_HTTP_TIMEOUT_MS = 90_000

/** Max silence on an LLM SSE stream before treating it as stalled. */
export const LLM_STREAM_STALL_MS = 120_000

/** Non-streaming chatComplete timeout. */
export const LLM_COMPLETE_TIMEOUT_MS = 60_000

/** Overall chat message processing timeout (skills + memory + LLM). */
export const MESSAGE_TIMEOUT_MS = 1200_000

// ── Gateway / WebSocket ─────────────────────────────────────────────────

/** Frontend chunk watchdog — no chunks received for this long triggers timeout UI. */
export const CLIENT_CHUNK_WATCHDOG_MS = 300_000

/** WebSocket reconnect base delay. */
export const WS_RECONNECT_BASE_MS = 1_000

/** Session inactivity timeout before auto-purge. */
export const SESSION_TIMEOUT_MS = 120_000

/** Health check polling interval. */
export const HEALTH_CHECK_INTERVAL_MS = 30_000

// ── Lifecycle / CLI ─────────────────────────────────────────────────────

/** Delay between stop and start during a restart cycle. */
export const RESTART_DELAY_MS = 1_000

/** Max time to wait for a process to exit after SIGTERM before escalating to SIGKILL. */
export const STOP_TIMEOUT_MS = 10_000

/** Polling interval while waiting for a process to exit during stop. */
export const STOP_POLL_INTERVAL_MS = 300

/** Timeout for provider connectivity tests (CLI `providers test`). */
export const PROVIDER_TEST_TIMEOUT_MS = 10_000

/** Default RSS memory threshold (MB) for high-memory warnings. */
export const DEFAULT_RSS_LIMIT_MB = 512

/** Minimum system memory (MB) for the doctor check. */
export const MIN_SYSTEM_MEMORY_MB = 512

/** Minimum required Node.js major version. */
export const MIN_NODE_MAJOR_VERSION = 22
