/**
 * Native Anthropic Messages API provider.
 * Extends BaseStreamProvider — inherits HTTP timeout, stall detection,
 * retry, SSE reading, and tool-call accumulation.
 * Implements only Anthropic-specific: URL, headers, body format, SSE event parsing.
 */

import crypto from 'node:crypto'
import type { ChatStreamOptions, LLMProvider, LLMProviderConfig, ProviderMessage, StreamingChunk } from '../apis/provider.ts'
import { extractSystemPrompt } from './message-utils.ts'
import { BaseStreamProvider, type ParsedSSEResult } from './base-stream-provider.ts'

interface AnthropicMessage {
    role: 'user' | 'assistant'
    content: string | AnthropicContentBlock[]
}

interface AnthropicContentBlock {
    type: 'text' | 'tool_use' | 'tool_result' | 'image'
    text?: string
    id?: string
    name?: string
    input?: Record<string, unknown>
    tool_use_id?: string
    content?: string | AnthropicContentBlock[]
    source?: { type: string; media_type: string; data: string }
}

const DEFAULT_API_VERSION = '2023-06-01'
const DEFAULT_BETA = 'prompt-caching-2024-07-31'

export class AnthropicProvider extends BaseStreamProvider {
    readonly name = 'anthropic'

    private get baseApiUrl(): string {
        return this.config.baseUrl.replace(/\/$/, '')
    }

    protected buildStreamUrl(_model: string): string {
        return `${this.baseApiUrl}/v1/messages`
    }

    protected buildCompleteUrl(_model: string): string {
        return `${this.baseApiUrl}/v1/messages`
    }

    protected buildHeaders(): Record<string, string> {
        const extra = this.config as LLMProviderConfig & { anthropicVersion?: string; anthropicBeta?: string }
        return {
            'Content-Type': 'application/json',
            'x-api-key': this.config.apiKey,
            'anthropic-version': extra.anthropicVersion ?? DEFAULT_API_VERSION,
            'anthropic-beta': extra.anthropicBeta ?? DEFAULT_BETA,
        }
    }

    protected buildStreamBody(
        model: string,
        messages: ProviderMessage[],
        options?: ChatStreamOptions,
    ): Record<string, unknown> {
        const { system, messages: anthropicMsgs } = this.convertMessages(messages)
        const tools = this.convertTools(options?.tools)

        const body: Record<string, unknown> = {
            model,
            messages: anthropicMsgs,
            max_tokens: options?.maxTokens ?? 4096,
            stream: true,
        }
        if (system) body.system = system
        if (tools?.length) body.tools = tools
        return body
    }

    protected buildCompleteBody(
        model: string,
        messages: ProviderMessage[],
        maxTokens: number,
    ): Record<string, unknown> {
        const { system, messages: anthropicMsgs } = this.convertMessages(messages)
        return {
            model,
            system: system || undefined,
            messages: anthropicMsgs,
            max_tokens: maxTokens,
            stream: false,
        }
    }

    protected extractCompleteContent(json: unknown): string | null {
        const data = json as { content?: Array<{ type: string; text?: string }> }
        const textBlock = data.content?.find(b => b.type === 'text')
        return textBlock?.text?.trim() || null
    }

    protected parseSSEPayload(json: Record<string, unknown>): ParsedSSEResult {
        const type = json.type as string
        const chunks: StreamingChunk[] = []
        const toolCalls: ParsedSSEResult['toolCalls'] = []
        let usage: ParsedSSEResult['usage']
        let finished = false

        if (type === 'content_block_start') {
            const block = json.content_block as Record<string, unknown> | undefined
            if (block?.type === 'tool_use') {
                const id = (block.id as string) ?? crypto.randomUUID()
                toolCalls.push({
                    index: id,
                    id,
                    name: (block.name as string) ?? 'exec',
                })
            }
        }

        if (type === 'content_block_delta') {
            const delta = json.delta as Record<string, unknown> | undefined
            if (delta?.type === 'text_delta' && typeof delta.text === 'string') {
                chunks.push({ type: 'content', content: delta.text })
            }
            if (delta?.type === 'input_json_delta' && typeof delta.partial_json === 'string') {
                toolCalls.push({
                    index: this.lastToolCallId ?? '0',
                    argsFragment: delta.partial_json as string,
                })
            }
            if (delta?.type === 'thinking_delta' && typeof delta.thinking === 'string') {
                chunks.push({ type: 'reasoning', content: delta.thinking })
            }
        }

        if (type === 'message_delta') {
            const u = json.usage as Record<string, unknown> | undefined
            if (u) {
                const input = (u.input_tokens as number) ?? 0
                const output = (u.output_tokens as number) ?? 0
                if (input || output) usage = { input, output }
            }
            finished = true
        }

        if (type === 'message_start') {
            const message = json.message as Record<string, unknown> | undefined
            const u = message?.usage as Record<string, unknown> | undefined
            if (u) {
                const input = (u.input_tokens as number) ?? 0
                const output = (u.output_tokens as number) ?? 0
                if (input || output) usage = { input, output }
            }
        }

        if (type === 'message_stop') {
            finished = true
        }

        if (toolCalls.length > 0) {
            const latestWithId = toolCalls.find(tc => tc.id)
            if (latestWithId?.id) this.lastToolCallId = latestWithId.id
        }

        return {
            chunks,
            toolCalls: toolCalls.length > 0 ? toolCalls : undefined,
            usage,
            finished,
        }
    }

    private lastToolCallId: string | null = null

    private convertMessages(messages: ProviderMessage[]): {
        system: string
        messages: AnthropicMessage[]
    } {
        const { systemPrompt: system, nonSystemMessages } = extractSystemPrompt(messages)
        const anthropicMessages: AnthropicMessage[] = []

        for (const msg of nonSystemMessages) {
            if (msg.role === 'tool') {
                anthropicMessages.push({
                    role: 'user',
                    content: [{
                        type: 'tool_result',
                        tool_use_id: msg.tool_call_id,
                        content: msg.content,
                    }],
                })
                continue
            }

            if (msg.role === 'assistant') {
                if (msg.tool_calls?.length) {
                    const blocks: AnthropicContentBlock[] = []
                    if (msg.content) blocks.push({ type: 'text', text: msg.content })
                    for (const tc of msg.tool_calls) {
                        let input: Record<string, unknown> = {}
                        try { input = JSON.parse(tc.function.arguments) } catch { /* keep empty */ }
                        blocks.push({ type: 'tool_use', id: tc.id, name: tc.function.name, input })
                    }
                    anthropicMessages.push({ role: 'assistant', content: blocks })
                } else {
                    anthropicMessages.push({
                        role: 'assistant',
                        content: typeof msg.content === 'string' ? msg.content : '',
                    })
                }
                continue
            }

            anthropicMessages.push({
                role: 'user',
                content: typeof msg.content === 'string' ? msg.content : JSON.stringify(msg.content),
            })
        }

        return { system, messages: anthropicMessages }
    }

    private convertTools(tools?: ChatStreamOptions['tools']): Array<{
        name: string; description: string; input_schema: object
    }> | undefined {
        if (!tools?.length) return undefined
        return tools.map(t => ({
            name: t.function.name,
            description: t.function.description ?? '',
            input_schema: t.function.parameters ?? { type: 'object', properties: {} },
        }))
    }
}

export class AnthropicProviderFactory {
    create(config: LLMProviderConfig): LLMProvider {
        return new AnthropicProvider('anthropic', config)
    }
}
