/**
 * Lightweight OpenClaw migration — reads ~/.openclaw/openclaw.json, discovers
 * extensions, auto-enables channels, and copies skill files so NovaClaw's
 * main config/skills flow can load them natively.
 */

import { existsSync, readFileSync, readdirSync, mkdirSync, cpSync } from 'node:fs'
import { join } from 'node:path'
import { homedir } from 'node:os'
import { NOVACLAW_SKILLS_DIR } from '../constants/paths.ts'
import type { NovaClawConfig, ChannelsConfig, ChannelDetailConfig } from '../framework/core/apis/config.ts'
import type { ILogger } from '../framework/utils/logger.ts'
import { discoverExtensions, type DiscoveredExtension } from '../framework/core/channel/extensions/index.ts'

// ── Constants ────────────────────────────────────────────────────────────

const OPENCLAW_HOME = join(homedir(), '.openclaw')
const OPENCLAW_CONFIG_PATH = join(OPENCLAW_HOME, 'openclaw.json')
const OPENCLAW_EXTENSIONS_DIR = join(OPENCLAW_HOME, 'extensions')
const SKILL_DIR_NAME = 'skills'
const SKILL_FILES = ['SKILL.md', 'skill.md']

// ── OpenClaw config types (minimal subset) ───────────────────────────────

interface OpenClawUserConfig {
    channels?: Record<string, OpenClawChannelEntry>
    mcp?: { servers?: Record<string, OpenClawMCPServer> }
    plugins?: {
        entries?: Record<string, { enabled: boolean }>
    }
    [key: string]: unknown
}

interface OpenClawChannelEntry {
    accounts?: Record<string, Record<string, unknown>>
    [key: string]: unknown
}

interface OpenClawMCPServer {
    transport?: 'stdio' | 'http' | 'sse'
    command?: string
    args?: string[]
    url?: string
    enabled?: boolean
}

// ── Public API ───────────────────────────────────────────────────────────

/**
 * Migrate OpenClaw configuration into a NovaClaw config object:
 *   1. Discover installed extensions and auto-enable their channels
 *   2. Merge channel credentials from ~/.openclaw/openclaw.json
 *   3. Merge MCP server entries from ~/.openclaw/openclaw.json
 *   4. Copy skill files from extensions into NovaClaw's skills directory
 *
 * Returns the merged config. NovaClaw values always take precedence.
 */
export function migrateOpenClawConfig(
    cfg: NovaClawConfig,
    options?: { logger?: ILogger },
): NovaClawConfig {
    const logger = options?.logger
    const ocCfg = readOpenClawConfig()

    const extensions = discoverExtensions()
    if (extensions.length > 0) {
        logger?.info(`OpenClawMigrate: discovered ${extensions.length} extension(s)`)
    }

    let merged = cfg
    if (ocCfg) {
        merged = mergeConfig(merged, ocCfg, extensions, logger)
    }

    copySkillFiles(cfg.workspaceDir, logger)
    return merged
}

// ── Config merge ─────────────────────────────────────────────────────────

function mergeConfig(
    cfg: NovaClawConfig,
    ocCfg: OpenClawUserConfig,
    extensions: DiscoveredExtension[],
    logger?: ILogger,
): NovaClawConfig {
    const mergedChannels = mergeChannelCredentials(cfg, ocCfg, logger)
    autoEnableExtensionChannels(mergedChannels, extensions, ocCfg, logger)
    const mergedMcp = mergeMcpServers(cfg, ocCfg, logger)

    return { ...cfg, channels: mergedChannels, mcp: mergedMcp }
}

function mergeChannelCredentials(
    cfg: NovaClawConfig,
    ocCfg: OpenClawUserConfig,
    logger?: ILogger,
): ChannelsConfig {
    const mergedChannels: ChannelsConfig = { ...cfg.channels }

    if (!ocCfg.channels) return mergedChannels

    const mergedIds: string[] = []
    for (const [channelId, ocEntry] of Object.entries(ocCfg.channels)) {
        const flattened = flattenChannelEntry(ocEntry)
        const existing = mergedChannels[channelId]

        if (existing && typeof existing === 'object' && !Array.isArray(existing)) {
            mergedChannels[channelId] = { ...flattened, ...existing } as ChannelDetailConfig
        } else if (!existing) {
            mergedChannels[channelId] = flattened as ChannelDetailConfig
        }
        mergedIds.push(channelId)
    }

    if (mergedIds.length > 0) {
        logger?.debug(`OpenClawMigrate: merged credentials for [${mergedIds.join(', ')}]`)
    }

    return mergedChannels
}

function autoEnableExtensionChannels(
    channels: ChannelsConfig,
    extensions: DiscoveredExtension[],
    ocCfg: OpenClawUserConfig,
    logger?: ILogger,
): void {
    const enabled = new Set(channels.enabled ?? [])
    const newlyEnabled: string[] = []

    for (const ext of extensions) {
        if (!ext.entryPath || enabled.has(ext.id)) continue
        if (!isExtensionEnabled(ext.id, ocCfg)) continue

        enabled.add(ext.id)
        newlyEnabled.push(ext.id)
    }

    if (newlyEnabled.length > 0) {
        channels.enabled = [...enabled]
        logger?.info(`OpenClawMigrate: auto-enabled extension channels [${newlyEnabled.join(', ')}]`)
    }
}

function mergeMcpServers(
    cfg: NovaClawConfig,
    ocCfg: OpenClawUserConfig,
    logger?: ILogger,
): NovaClawConfig['mcp'] {
    if (!ocCfg.mcp?.servers) return cfg.mcp

    const existingEndpoints = new Set((cfg.mcp ?? []).map(m => m.endpoint))
    const newEntries = Object.entries(ocCfg.mcp.servers)
        .filter(([, srv]) => srv.enabled !== false)
        .filter(([, srv]) => {
            const endpoint = srv.url ?? srv.command ?? ''
            return endpoint && !existingEndpoints.has(endpoint)
        })
        .map(([id, srv]) => ({
            endpoint: srv.url ?? srv.command ?? id,
            transport: srv.transport ?? (srv.command ? 'stdio' as const : 'http' as const),
            command: srv.command,
            args: srv.args,
        }))

    if (newEntries.length === 0) return cfg.mcp

    logger?.info(`OpenClawMigrate: merged ${newEntries.length} MCP server(s)`)
    return [...(cfg.mcp ?? []), ...newEntries]
}

// ── Skill file copy ──────────────────────────────────────────────────────
//
// Skills are now managed in ~/.novaclaw/skills/ (not workspace).
// The SkillMigrator in file-skill-provider.ts handles the full migration
// pipeline. This function is kept for backward compatibility but targets
// the canonical user skills directory.

function copySkillFiles(_workspaceDir: string, logger?: ILogger): void {
    if (!existsSync(OPENCLAW_EXTENSIONS_DIR)) return

    mkdirSync(NOVACLAW_SKILLS_DIR, { recursive: true })

    let entries: string[]
    try {
        entries = readdirSync(OPENCLAW_EXTENSIONS_DIR)
    } catch {
        return
    }

    let copied = 0
    for (const extName of entries) {
        const extDir = join(OPENCLAW_EXTENSIONS_DIR, extName)
        const skillRoot = join(extDir, SKILL_DIR_NAME)
        if (!existsSync(skillRoot)) continue

        const skillDirs = discoverSkillDirs(skillRoot)
        for (const srcDir of skillDirs) {
            const skillFileName = SKILL_FILES.find(f => existsSync(join(srcDir, f)))
            if (!skillFileName) continue

            const dirBaseName = srcDir === skillRoot ? extName : `${extName}-${srcDir.split('/').pop()}`
            const destDir = join(NOVACLAW_SKILLS_DIR, dirBaseName)

            if (existsSync(destDir)) continue

            try {
                mkdirSync(destDir, { recursive: true })
                cpSync(srcDir, destDir, { recursive: true })
                copied++
            } catch (err) {
                logger?.debug(`OpenClawMigrate: failed to copy skill from ${srcDir}: ${err}`)
            }
        }
    }

    if (copied > 0) {
        logger?.info(`OpenClawMigrate: copied ${copied} skill(s) to ${NOVACLAW_SKILLS_DIR}`)
    }
}

// ── Helpers ──────────────────────────────────────────────────────────────

function readOpenClawConfig(): OpenClawUserConfig | null {
    if (!existsSync(OPENCLAW_CONFIG_PATH)) return null
    try {
        const raw = JSON.parse(readFileSync(OPENCLAW_CONFIG_PATH, 'utf-8'))
        if (typeof raw !== 'object' || raw === null) return null
        return raw as OpenClawUserConfig
    } catch {
        return null
    }
}

function isExtensionEnabled(id: string, cfg: OpenClawUserConfig): boolean {
    if (cfg.plugins?.entries?.[id]?.enabled === true) return true
    const channelEntry = cfg.channels?.[id]
    if (!channelEntry?.accounts) return false
    return Object.values(channelEntry.accounts).some(
        (acc) => (acc as Record<string, unknown>).enabled !== false,
    )
}

function flattenChannelEntry(entry: OpenClawChannelEntry): Record<string, unknown> {
    const { accounts, ...rest } = entry
    const defaultAccount = accounts?.default
    if (!defaultAccount) return { ...rest, accounts }

    const { enabled: _enabled, currentUser: _user, ...credentials } = defaultAccount
    return { ...credentials, ...rest, accounts }
}

function discoverSkillDirs(skillRoot: string): string[] {
    const dirs: string[] = []
    try {
        for (const entry of readdirSync(skillRoot)) {
            const candidate = join(skillRoot, entry)
            if (SKILL_FILES.some(f => existsSync(join(candidate, f)))) {
                dirs.push(candidate)
            }
        }
    } catch { /* ignore */ }

    if (SKILL_FILES.some(f => existsSync(join(skillRoot, f)))) {
        dirs.push(skillRoot)
    }

    return dirs
}
