/**
 * Shared message-text extraction for inbound channel messages.
 * Used by both the gateway and pipeline to normalize message payloads.
 */

export function extractMessageText(message: unknown): string | null {
    if (typeof message === 'string') return message || null
    if (typeof message !== 'object' || message === null) return null
    const m = message as Record<string, unknown>
    for (const key of ['text', 'body', 'message', 'content']) {
        if (typeof m[key] === 'string' && (m[key] as string).length > 0) {
            return m[key] as string
        }
    }
    return null
}

/**
 * Resolve the user-facing body from an OpenClaw-style inbound context object.
 * Tries RawBody → CommandBody → Body.body/text/content → body → text.
 */
export function resolveInboundBody(ctx: Record<string, unknown>): string {
    if (typeof ctx.RawBody === 'string' && (ctx.RawBody as string).trim()) return (ctx.RawBody as string).trim()
    if (typeof ctx.CommandBody === 'string' && (ctx.CommandBody as string).trim()) return (ctx.CommandBody as string).trim()

    if (ctx.Body && typeof ctx.Body === 'object') {
        const e = ctx.Body as Record<string, unknown>
        if (typeof e.body === 'string' && e.body.trim()) return e.body.trim()
        if (typeof e.text === 'string' && e.text.trim()) return e.text.trim()
        if (typeof e.content === 'string' && e.content.trim()) return e.content.trim()
    }

    if (typeof ctx.body === 'string' && (ctx.body as string).trim()) return (ctx.body as string).trim()
    if (typeof ctx.text === 'string' && (ctx.text as string).trim()) return (ctx.text as string).trim()
    return ''
}

/** Well-known bot role names to filter out of inbound processing. */
export const BOT_ROLES = new Set(['assistant', 'bot', 'system', 'ai'])
