/**
 * Memory provider registry — register RAG backends (local, vector DB, etc.).
 * NovaClaw creates the active memory from this registry using config.memory.provider.
 */

import type {IMemoryProvider, MemoryProviderFactory, MemoryProviderOptions} from '../core/apis/memory.ts'
import {BaseRegistry} from './base-registry.ts'

export interface MemoryProviderRegistryEntry {
    factory: MemoryProviderFactory
    version?: string
}

export class MemoryProviderRegistry extends BaseRegistry<MemoryProviderRegistryEntry> {
    constructor() {
        super('MemoryProviderRegistry')
    }

    register(id: string, factory: MemoryProviderFactory, options?: { version?: string }): void
    register(id: string, entry: MemoryProviderRegistryEntry): void
    register(id: string, factoryOrEntry: MemoryProviderFactory | MemoryProviderRegistryEntry, options?: { version?: string }): void {
        if ('factory' in factoryOrEntry && typeof (factoryOrEntry as MemoryProviderRegistryEntry).factory === 'function') {
            super.register(id, factoryOrEntry as MemoryProviderRegistryEntry)
        } else {
            super.register(id, {factory: factoryOrEntry as MemoryProviderFactory, version: options?.version})
        }
    }

    /**
     * Create a memory provider instance. Uses "local" if id is missing or not registered.
     */
    create(
        id: string,
        config: Record<string, unknown>,
        options?: MemoryProviderOptions
    ): IMemoryProvider | null {
        const entry = this.entries.get(id)
        if (!entry) return null
        return entry.factory(config, options)
    }
}
