/**
 * Input rule: basic prompt injection detection.
 * Checks user messages for known prompt injection patterns.
 */

import type { IRule, RuleContext, RuleVerdict } from '../../apis/rule.ts'

const INJECTION_PATTERNS = [
    /ignore\s+(all\s+)?previous\s+instructions/i,
    /disregard\s+(all\s+)?prior\s+(instructions|prompts)/i,
    /you\s+are\s+now\s+(?:a\s+)?(?:DAN|jailbroken|unfiltered)/i,
    /system\s*:\s*you\s+(?:are|must)/i,
    /\[SYSTEM\]\s*override/i,
    /pretend\s+(?:you\s+(?:are|have)|to\s+be)\s+.*(?:no\s+restrictions|unrestricted)/i,
]

export function createContentSafetyRule(): IRule {
    return {
        id: 'content-safety',
        name: 'Input content safety',
        description: 'Detect potential prompt injection in user messages',
        phase: 'input',
        priority: 100,

        evaluate(ctx: RuleContext): RuleVerdict | undefined {
            if (ctx.type !== 'message' || !ctx.message) return undefined

            for (const pattern of INJECTION_PATTERNS) {
                if (pattern.test(ctx.message)) {
                    return {
                        action: 'reject',
                        reason: 'Message blocked: potential prompt injection detected',
                    }
                }
            }
            return undefined
        },
    }
}
