/**
 * Session key builder — constructs deterministic session identifiers
 * that associate AI conversation context with channel+peer combinations.
 */

export type SessionScope = 'main' | 'per-peer' | 'per-channel-peer' | 'per-account-channel-peer'

export interface SessionKeyParams {
    agentId: string
    channel: string
    accountId: string
    peerKind: string
    peerId: string
    scope?: SessionScope
}

export function buildSessionKey(params: SessionKeyParams): string {
    const { agentId, channel, accountId, peerKind, peerId, scope = 'main' } = params

    switch (scope) {
        case 'main':
            return `agent:${agentId}:main:${channel}:${accountId}:${peerKind}:${peerId}`
        case 'per-peer':
            return `agent:${agentId}:peer:${peerKind}:${peerId}`
        case 'per-channel-peer':
            return `agent:${agentId}:ch:${channel}:${peerKind}:${peerId}`
        case 'per-account-channel-peer':
            return `agent:${agentId}:acct:${accountId}:ch:${channel}:${peerKind}:${peerId}`
        default:
            scope satisfies never
            return `agent:${agentId}:main:${channel}:${accountId}:${peerKind}:${peerId}`
    }
}

export function buildMainSessionKey(params: Omit<SessionKeyParams, 'scope'>): string {
    return buildSessionKey({ ...params, scope: 'main' })
}

export function parseSessionKey(key: string): Partial<SessionKeyParams> | null {
    const parts = key.split(':')
    if (parts[0] !== 'agent' || parts.length < 3) return null

    const agentId = parts[1]!
    const scope = parts[2] as string

    if (scope === 'main' && parts.length >= 7) {
        return {
            agentId,
            scope: 'main',
            channel: parts[3],
            accountId: parts[4],
            peerKind: parts[5],
            peerId: parts.slice(6).join(':'),
        }
    }

    if (scope === 'peer' && parts.length >= 5) {
        return {
            agentId,
            scope: 'per-peer',
            peerKind: parts[3],
            peerId: parts.slice(4).join(':'),
        }
    }

    return { agentId }
}
