/**
 * Provider registry — register LLM provider factories by key.
 * ModelManager uses this to create provider instances by provider name.
 */

import type {LLMProviderConfig, LLMProviderFactory} from '../core/apis/provider.ts'
import {BaseRegistry} from './base-registry.ts'

export interface ProviderRegistryEntry {
    factory: LLMProviderFactory
    /** Optional contract version for multi-version support */
    version?: string
}

export class ProviderRegistry extends BaseRegistry<ProviderRegistryEntry> {
    constructor() {
        super('ProviderRegistry')
    }

    register(id: string, factory: LLMProviderFactory, options?: { version?: string }): void
    register(id: string, entry: ProviderRegistryEntry): void
    register(id: string, factoryOrEntry: LLMProviderFactory | ProviderRegistryEntry, options?: { version?: string }): void {
        if (this.isRegistryEntry(factoryOrEntry)) {
            super.register(id, factoryOrEntry)
        } else {
            super.register(id, {
                factory: factoryOrEntry,
                version: options?.version
            })
        }
    }

    private isRegistryEntry(value: LLMProviderFactory | ProviderRegistryEntry): value is ProviderRegistryEntry {
        return (
            'factory' in value &&
            value.factory != null &&
            typeof value.factory === 'object' &&
            'create' in value.factory &&
            typeof value.factory.create === 'function'
        )
    }

    getFactory(id: string): LLMProviderFactory | undefined {
        return this.entries.get(id)?.factory
    }

    create(id: string, config: LLMProviderConfig): ReturnType<LLMProviderFactory['create']> | null {
        const entry = this.entries.get(id)
        if (!entry) return null
        return entry.factory.create(config)
    }
}
