/**
 * Stopwatch — minimal performance measurement utility.
 *
 * Usage:
 *   const sw = Stopwatch.start()
 *   // ... work ...
 *   const lap1 = sw.lap('fetch')       // "fetch: 123.4ms"
 *   // ... more work ...
 *   const total = sw.stop('total')      // "total: 456.7ms"
 *   logger.debug(sw.summary())          // "fetch=123.4ms total=456.7ms"
 */

import { performance } from 'node:perf_hooks'

export class Stopwatch {
    private readonly t0: number
    private laps: Array<{ label: string; ms: number }> = []

    private constructor() {
        this.t0 = performance.now()
    }

    static start(): Stopwatch {
        return new Stopwatch()
    }

    /** Record a lap from the start time. Returns formatted string. */
    lap(label: string): string {
        const ms = performance.now() - this.t0
        this.laps.push({ label, ms })
        return `${label}: ${ms.toFixed(1)}ms`
    }

    /** Elapsed milliseconds since creation. */
    elapsed(): number {
        return performance.now() - this.t0
    }

    /** Format elapsed as string. */
    elapsedStr(): string {
        return `${this.elapsed().toFixed(1)}ms`
    }

    /** Record final lap and return formatted string. */
    stop(label = 'total'): string {
        return this.lap(label)
    }

    /** One-line summary of all laps. */
    summary(): string {
        return this.laps.map(l => `${l.label}=${l.ms.toFixed(1)}ms`).join(' ')
    }
}
