/**
 * Tool provider registry — register tools by name.
 * ToolRegistry can merge tools from this registry with builtins and config-driven extensions.
 */

import type {Tool} from '../core/apis/tool.ts'
import {BaseRegistry} from './base-registry.ts'

export interface ToolProviderRegistryEntry {
    tool: Tool
    /** Optional; e.g. for filtering by profile */
    tags?: string[]
    version?: string
}

export class ToolProviderRegistry extends BaseRegistry<ToolProviderRegistryEntry> {
    constructor() {
        super('ToolProviderRegistry')
    }

    register(name: string, tool: Tool, options?: { tags?: string[]; version?: string }): void
    register(id: string, entry: ToolProviderRegistryEntry): void
    register(
        nameOrId: string,
        toolOrEntry: Tool | ToolProviderRegistryEntry,
        options?: { tags?: string[]; version?: string }
    ): void {
        if ('tool' in toolOrEntry && typeof (toolOrEntry as ToolProviderRegistryEntry).tool === 'object') {
            super.register(nameOrId, toolOrEntry as ToolProviderRegistryEntry)
        } else {
            if (!toolOrEntry) throw new Error('ToolProviderRegistry: tool must not be null/undefined')
            super.register(nameOrId, {
                tool: toolOrEntry as Tool,
                tags: options?.tags,
                version: options?.version
            })
        }
    }

    getTool(name: string): Tool | undefined {
        return this.entries.get(name)?.tool
    }

    getEntry(name: string): ToolProviderRegistryEntry | undefined {
        return this.get(name)
    }

    /** Returns all tools as array. Use getAllEntries() for Map of entries. */
    getAllTools(): Tool[] {
        return Array.from(this.entries.values()).map((e) => e.tool)
    }

    getAllEntries(): Map<string, ToolProviderRegistryEntry> {
        return new Map(this.entries)
    }
}
