/**
 * Shared message conversion utilities for LLM providers.
 */

export interface ToolCallEntry {
    id: string
    function: { name: string; arguments: string }
}

export type ProviderMessage =
    | { role: 'system'; content: string }
    | { role: 'user'; content: string | object }
    | { role: 'assistant'; content?: string; tool_calls?: ToolCallEntry[] }
    | { role: 'tool'; tool_call_id: string; content: string }

/**
 * Extracts system messages from the message array and returns the concatenated
 * system prompt plus the remaining non-system messages.
 * All providers filter system messages into a separate string; this helper
 * centralizes that pattern.
 */
export function extractSystemPrompt(messages: ProviderMessage[]): {
    systemPrompt: string
    nonSystemMessages: ProviderMessage[]
} {
    let systemPrompt = ''
    const nonSystemMessages: ProviderMessage[] = []

    for (const msg of messages) {
        if (msg.role === 'system') {
            systemPrompt += typeof msg.content === 'string' ? msg.content : JSON.stringify(msg.content)
            continue
        }
        nonSystemMessages.push(msg)
    }

    return { systemPrompt, nonSystemMessages }
}
