/**
 * Inbound debounce policy — merges rapid consecutive messages from the same sender.
 * Prevents flooding and allows media group buffering.
 */

export interface DebouncePolicyOptions {
    defaultMs?: number
    perChannel?: Record<string, number>
}

interface PendingBuffer {
    senderId: string
    channelId: string
    fragments: Array<{ text?: string; mediaUrl?: string; timestamp: number }>
    timer: ReturnType<typeof setTimeout>
    resolvers: Array<(merged: MergedInboundMessage) => void>
}

export interface MergedInboundMessage {
    senderId: string
    channelId: string
    text: string
    mediaUrls: string[]
    fragmentCount: number
    firstTimestamp: number
    lastTimestamp: number
}

const DEFAULT_DEBOUNCE_MS = 300

export class InboundDebouncePolicy {
    private buffers = new Map<string, PendingBuffer>()
    private defaultMs: number
    private perChannel: Record<string, number>

    constructor(options?: DebouncePolicyOptions) {
        this.defaultMs = options?.defaultMs ?? DEFAULT_DEBOUNCE_MS
        this.perChannel = options?.perChannel ?? {}
    }

    getDebounceMs(channelId: string): number {
        return this.perChannel[channelId] ?? this.defaultMs
    }

    debounce(params: {
        key: string
        senderId: string
        channelId: string
        text?: string
        mediaUrl?: string
    }): Promise<MergedInboundMessage> {
        const { key, senderId, channelId, text, mediaUrl } = params
        const debounceMs = this.getDebounceMs(channelId)

        const existing = this.buffers.get(key)
        if (existing) {
            clearTimeout(existing.timer)
            existing.fragments.push({ text, mediaUrl, timestamp: Date.now() })

            return new Promise<MergedInboundMessage>((resolve) => {
                existing.resolvers.push(resolve)
                existing.timer = setTimeout(() => this.flush(key), debounceMs)
            })
        }

        return new Promise<MergedInboundMessage>((resolve) => {
            const buffer: PendingBuffer = {
                senderId,
                channelId,
                fragments: [{ text, mediaUrl, timestamp: Date.now() }],
                timer: setTimeout(() => this.flush(key), debounceMs),
                resolvers: [resolve],
            }
            this.buffers.set(key, buffer)
        })
    }

    private flush(key: string): void {
        const buffer = this.buffers.get(key)
        if (!buffer) return

        this.buffers.delete(key)

        const texts = buffer.fragments
            .map(f => f.text)
            .filter((t): t is string => !!t)
        const mediaUrls = buffer.fragments
            .map(f => f.mediaUrl)
            .filter((u): u is string => !!u)

        const merged: MergedInboundMessage = {
            senderId: buffer.senderId,
            channelId: buffer.channelId,
            text: texts.join('\n'),
            mediaUrls,
            fragmentCount: buffer.fragments.length,
            firstTimestamp: buffer.fragments[0]!.timestamp,
            lastTimestamp: buffer.fragments[buffer.fragments.length - 1]!.timestamp,
        }

        for (const resolve of buffer.resolvers) {
            resolve(merged)
        }
    }

    clear(): void {
        for (const [, buffer] of this.buffers) {
            clearTimeout(buffer.timer)
            this.flushDiscard(buffer)
        }
        this.buffers.clear()
    }

    private flushDiscard(buffer: PendingBuffer): void {
        const merged: MergedInboundMessage = {
            senderId: buffer.senderId,
            channelId: buffer.channelId,
            text: '',
            mediaUrls: [],
            fragmentCount: 0,
            firstTimestamp: Date.now(),
            lastTimestamp: Date.now(),
        }
        for (const resolve of buffer.resolvers) {
            resolve(merged)
        }
    }
}
