/**
 * ToolRegistry — orchestrates tool loading, filtering, and execution.
 * Delegates loading to ToolLoader, filtering to ToolFilter, and execution
 * through the ToolPolicyPipeline.
 *
 * Security decisions are unified through ToolPolicyPipeline:
 * the RuleEngine is registered as a built-in before-hook so that all
 * blocking decisions flow through a single path.
 */

import { toErrorMessage } from '../../../../constants/errors.ts'
import type { ToolProviderRegistry } from '../../../registries/tool-provider-registry.ts'
import { Logger } from '../../../utils/logger.ts'
import type { NovaClawConfig, SessionContext, Tool, ToolFunctionSchema } from '../../apis/index.ts'
import type { ProtocolBridge } from '../../protocol/protocol-bridge.ts'
import { createExecChannelRule } from '../../rules/exec-channel-rule.ts'
import { RuleEngine } from '../../rules/rule-engine.ts'
import type { SkillsEngine } from '../../skills/skills-engine.ts'
import { isCommandBlocked } from '../../tools/index.ts'
import { ToolPolicyPipeline, type AfterToolCallHook, type BeforeToolCallHook, type ToolPolicyConfig } from '../../tools/tool-policy-pipeline.ts'
import { ToolFilter } from './tool-filter.ts'
import { ToolLoader } from './tool-loader.ts'
import { toolToSchema } from './tool-schema.ts'

// ── Public API re-exports ───────────────────────────────────────────────

export { TOOL_PROFILES } from './tool-profiles.ts'
export { buildOpenAIToolsSchema, toolToSchema } from './tool-schema.ts'
export { isCommandBlocked }

// ── Types ───────────────────────────────────────────────────────────────

export interface ToolWithLifecycle extends Tool {
    initialize?(): Promise<void>
    cleanup?(): Promise<void>
}

// ── ToolRegistry ────────────────────────────────────────────────────────

export class ToolRegistry {
    private logger: Logger
    private tools = new Map<string, Tool>()
    private loader: ToolLoader
    private filter: ToolFilter
    private policyPipeline: ToolPolicyPipeline

    constructor(
        private config: NovaClawConfig,
        options?: {
            protocolBridge?: ProtocolBridge | null
            skillsEngine?: SkillsEngine | null
            ruleEngine?: RuleEngine | null
            toolProviderRegistry?: ToolProviderRegistry | null
            policyConfig?: Partial<ToolPolicyConfig>
        },
    ) {
        this.logger = new Logger('ToolRegistry', config.logging?.level || 'info')
        this.loader = new ToolLoader(config, {
            protocolBridge: options?.protocolBridge,
            skillsEngine: options?.skillsEngine,
            toolProviderRegistry: options?.toolProviderRegistry,
        })
        this.filter = new ToolFilter(config)
        this.policyPipeline = new ToolPolicyPipeline(options?.policyConfig)

        const ruleEngine = options?.ruleEngine ?? new RuleEngine({ rules: [createExecChannelRule()] })
        this.registerRuleEngineHook(ruleEngine)
    }

    // ── Hooks & policy ──────────────────────────────────────────────────

    registerBeforeHook(hook: BeforeToolCallHook): void {
        this.policyPipeline.registerBeforeHook(hook)
    }

    registerAfterHook(hook: AfterToolCallHook): void {
        this.policyPipeline.registerAfterHook(hook)
    }

    updateToolPolicy(patch: Partial<ToolPolicyConfig>): void {
        this.policyPipeline.updatePolicy(patch)
    }

    setProtocolBridge(bridge: ProtocolBridge | null): void {
        this.loader.setProtocolBridge(bridge)
    }

    // ── Lifecycle ───────────────────────────────────────────────────────

    async initialize(): Promise<void> {
        this.logger.info('Initializing...')
        this.tools = await this.loader.loadAll()
        this.logger.info(`Loaded ${this.tools.size} tools`)
    }

    async initializeForScope(scope: {
        builtinTools?: string[]
        mcpServer?: string
        skills?: boolean
    }): Promise<void> {
        this.logger.info('Initializing (scoped)', scope)
        this.tools = await this.loader.loadForScope(scope)
        this.logger.info(`Loaded ${this.tools.size} scoped tools`)
    }

    // ── Query ───────────────────────────────────────────────────────────

    getAll(): Tool[] {
        return Array.from(this.tools.values())
    }

    getContextualTools(context: SessionContext): Tool[] {
        return this.filter.getContextualTools(this.getAll(), context)
    }

    getToolSchemas(context?: SessionContext): ToolFunctionSchema[] {
        const tools = context ? this.getContextualTools(context) : this.getAll()
        return tools.map(toolToSchema)
    }

    register(tool: Tool): void {
        this.tools.set(tool.name, tool)
    }

    // ── Execution (unified security path via ToolPolicyPipeline) ────────

    async executeTool(
        name: string,
        args: Record<string, unknown>,
        context?: SessionContext,
        abortSignal?: AbortSignal,
    ): Promise<{ result?: unknown; error?: string; errorCode?: string }> {
        this.logger.debug(`Executing: ${name}`, { args: args ? Object.keys(args) : [] })
        const tool = this.tools.get(name)
        if (!tool) {
            this.logger.warn(`Unknown tool: ${name}`)
            return { error: `Unknown tool: ${name}`, errorCode: 'TOOL_NOT_FOUND' }
        }

        if (tool.validate) {
            const validationError = tool.validate(args)
            if (validationError) return { error: validationError, errorCode: 'TOOL_VALIDATION_FAILED' }
        }

        try {
            const out = await this.policyPipeline.execute(tool, args, context, abortSignal)
            this.logger.debug(`Completed: ${name}`, { success: out.success })
            if (!out.success) {
                return { error: String((out as Record<string, unknown>).error ?? 'Tool returned success: false'), errorCode: 'TOOL_EXECUTION_FAILED' }
            }
            return { result: out }
        } catch (err) {
            const msg = toErrorMessage(err)
            this.logger.warn(`Tool error: ${name}`, { error: msg })
            return { error: msg, errorCode: 'TOOL_EXECUTION_FAILED' }
        }
    }

    // ── Private ─────────────────────────────────────────────────────────

    private registerRuleEngineHook(ruleEngine: RuleEngine): void {
        const config = this.config
        this.policyPipeline.registerBeforeHook(async (ctx) => {
            const ruleCtx: import('../../apis/rule').RuleContext = {
                type: 'tool',
                toolName: ctx.toolName,
                name: ctx.toolName,
                channel: ctx.context?.channel,
                payload: {
                    channel: ctx.context?.channel,
                    toolName: ctx.toolName,
                    allowExecInChannels: config.tools?.allowExecInChannels,
                },
            }
            const verdict = ruleEngine.evaluate(ruleCtx)
            if (verdict.action === 'reject') {
                return { blocked: true, reason: verdict.reason ?? 'Blocked by rule engine' }
            }
        })
    }
}
