/**
 * Config loader — YAML-based configuration with env-var substitution,
 * Zod validation, and layered config merging.
 *
 * Config merge order (later wins):
 *   defaults < novaclaw.yml < ~/.novaclaw/overrides.yml
 *
 * Credential encryption / decryption is delegated to credential-manager.ts.
 */

import { existsSync } from 'node:fs'
import { chmod, mkdir, readFile, writeFile } from 'node:fs/promises'
import { join } from 'node:path'
import { parse as parseYaml, stringify as stringifyYaml } from 'yaml'
import { createError, ErrorCodes, toErrorMessage } from '../constants/errors.ts'
import {
    NOVACLAW_CONFIG_PATH,
    NOVACLAW_HOME,
    NOVACLAW_OVERRIDES_PATH,
    NOVACLAW_WORKSPACE_DIR,
} from '../constants/paths.ts'
import { MESSAGE_TIMEOUT_MS } from '../constants/timeouts.ts'
import type { ChannelDetailConfig, NovaClawConfig, UserConfig } from '../framework/index.ts'
import { NovaClawConfigSchema } from '../framework/index.ts'
import {
    decryptApiKeysInPlace,
    decryptChannelCredentials,
    encryptApiKeysInPlace,
    encryptChannelCredentials,
} from './credential-manager.ts'
import { deepMerge } from './helpers.ts'
import { Logger } from './logger.ts'

export class ConfigLoader {
    private static logger = new Logger('ConfigLoader')

    // ── Public API ───────────────────────────────────────────────────────

    static async load(configPath?: string): Promise<NovaClawConfig> {
        const defaultPaths = [
            './novaclaw.yml',
            './novaclaw.yaml',
            NOVACLAW_CONFIG_PATH,
        ]
        const paths = configPath ? [configPath, ...defaultPaths] : defaultPaths

        let baseConfig: Record<string, unknown> | null = null

        for (const path of paths) {
            try {
                const content = await readFile(path, 'utf-8')
                const raw = parseYaml(content) as Record<string, unknown>
                baseConfig = this.replaceEnvVars(raw)
                break
            } catch (error) {
                if (path === configPath) {
                    throw createError(
                        `Failed to load config from ${path}: ${toErrorMessage(error)}`,
                        ErrorCodes.CONFIG_LOAD_FAILED,
                        { path, cause: error },
                    )
                }
            }
        }

        if (!baseConfig) {
            this.logger.info('No config file found — scaffolding default config')
            await this.scaffoldGlobalConfig()
            this.logger.info(`Default config written to ${NOVACLAW_CONFIG_PATH}`)
            this.logger.info('Run "novaclaw setup" for interactive configuration with API keys')
            baseConfig = this.getDefaultConfig() as Record<string, unknown>
        }

        const overrides = await this.loadOverrides()
        if (Object.keys(overrides).length > 0) {
            baseConfig = deepMerge(baseConfig, overrides)
            this.autoEnableChannels(baseConfig)
        }

        return this.validateAndParse(baseConfig)
    }

    /**
     * Persist a config object to `~/.novaclaw/config.yml`.
     * When called without arguments, writes the built-in defaults.
     */
    static async scaffoldGlobalConfig(config?: NovaClawConfig): Promise<string> {
        const effective = config ?? this.getDefaultConfig()
        const yaml = this.serializeToYaml(effective)

        await mkdir(NOVACLAW_HOME, { recursive: true })
        for (const sub of ['workspace', 'memory']) {
            const dir = join(NOVACLAW_HOME, sub)
            if (!existsSync(dir)) {
                await mkdir(dir, { recursive: true })
            }
        }

        await writeFile(NOVACLAW_CONFIG_PATH, yaml, 'utf-8')
        return NOVACLAW_CONFIG_PATH
    }

    static serializeToYaml(config: NovaClawConfig | Record<string, unknown>): string {
        return stringifyYaml(config as Record<string, unknown>, {
            lineWidth: 0,
            defaultKeyType: 'PLAIN',
            defaultStringType: 'PLAIN',
        })
    }

    // ── Overrides (~/.novaclaw/overrides.yml) ──────────────────────────

    static async loadOverrides(): Promise<Record<string, unknown>> {
        try {
            const content = await readFile(NOVACLAW_OVERRIDES_PATH, 'utf-8')
            const data = parseYaml(content) as Record<string, unknown>
            if (typeof data !== 'object' || data === null) return {}
            await decryptApiKeysInPlace(data)
            if (data.channels && typeof data.channels === 'object') {
                await decryptChannelCredentials(data as UserConfig)
            }
            return data
        } catch {
            return {}
        }
    }

    static async saveOverrides(overrides: Record<string, unknown>): Promise<void> {
        await mkdir(NOVACLAW_HOME, { recursive: true })
        const copy = JSON.parse(JSON.stringify(overrides)) as Record<string, unknown>
        await encryptApiKeysInPlace(copy)
        if (copy.channels && typeof copy.channels === 'object') {
            await encryptChannelCredentials(copy as UserConfig)
        }
        await writeFile(NOVACLAW_OVERRIDES_PATH, this.serializeToYaml(copy), 'utf-8')
        try { await chmod(NOVACLAW_OVERRIDES_PATH, 0o600) } catch { /* chmod not available on all platforms */ }
    }

    // ── Channel config (stored in overrides.yml) ────────────────────────

    static async getChannelConfig(channelId: string): Promise<ChannelDetailConfig | null> {
        const overrides = await this.loadOverrides()
        const channels = overrides.channels as Record<string, unknown> | undefined
        return (channels?.[channelId] as ChannelDetailConfig) ?? null
    }

    static async saveChannelConfig(channelId: string, detail: ChannelDetailConfig): Promise<void> {
        const overrides = await this.loadOverrides()
        if (!overrides.channels || typeof overrides.channels !== 'object') {
            overrides.channels = {}
        }
        ;(overrides.channels as Record<string, unknown>)[channelId] = detail
        await this.saveOverrides(overrides)
    }

    static async removeChannelConfig(channelId: string): Promise<boolean> {
        const overrides = await this.loadOverrides()
        const channels = overrides.channels as Record<string, unknown> | undefined
        if (!channels?.[channelId]) return false
        delete channels[channelId]
        await this.saveOverrides(overrides)
        return true
    }

    // ── Defaults ─────────────────────────────────────────────────────────

    static getDefaultConfig(): NovaClawConfig {
        return {
            port: 3000,
            bind: 'loopback',
            workspaceDir: NOVACLAW_WORKSPACE_DIR,
            models: { primary: '', fallback: '', providers: {} },
            agent: { maxTurns: 10, toolResultContextMax: 16000, messageTimeoutMs: MESSAGE_TIMEOUT_MS },
            skills: {
                dirs: ['./skills/workspace', './skills/managed', './skills/bundled'],
                include: ['**/*.md'],
                exclude: ['**/drafts/**'],
            },
            tools: {
                policy: 'balanced',
                sandbox: { enabled: true, docker: false, timeout: 30000, maxMemory: '256MB', allowedCommands: [] },
                permissions: {
                    fileSystem: { read: true, write: true, execute: false, delete: false },
                    network: { http: true, https: true, websocket: true },
                    system: { shell: false, process: false },
                },
            },
            channels: { enabled: ['webchat', 'cli'] },
            performance: {
                skillsCache: { maxSize: 100, ttl: 300 },
                semanticSearch: { enabled: true, threshold: 0.7, maxResults: 5 },
                streaming: { enabled: true, chunkSize: 256, maxConcurrent: 4 },
                memory: { maxHeapSize: '512MB', gcInterval: 10000, sessionTimeout: 300000 },
            },
            security: {
                auth: { enabled: false, type: 'none' },
                rateLimit: { enabled: false, windowMs: 60000, maxRequests: 100 },
                cors: { enabled: true, origins: ['*'], credentials: false },
            },
            logging: { level: 'info', format: 'text' },
            monitoring: { enabled: true, rssLimitMB: 512, health: { enabled: true, path: '/health', interval: 30000 } },
        }
    }

    // ── Private ──────────────────────────────────────────────────────────

    /**
     * After merging overrides, auto-enable channels that have at least one
     * enabled account — so users don't have to manually add to channels.enabled.
     */
    private static autoEnableChannels(config: Record<string, unknown>): void {
        const channels = config.channels as Record<string, unknown> | undefined
        if (!channels) return

        const enabled = new Set<string>(
            Array.isArray(channels.enabled) ? channels.enabled as string[] : [],
        )

        for (const [key, value] of Object.entries(channels)) {
            if (key === 'enabled' || !value || typeof value !== 'object') continue
            const detail = value as Record<string, unknown>
            const accounts = detail.accounts as Record<string, Record<string, unknown>> | undefined
            if (!accounts) continue
            const hasEnabledAccount = Object.values(accounts).some((a) => a.enabled !== false)
            if (hasEnabledAccount) enabled.add(key)
        }

        channels.enabled = [...enabled]
    }

    private static validateAndParse(raw: unknown): NovaClawConfig {
        const result = NovaClawConfigSchema.safeParse(raw)
        if (result.success) return result.data

        for (const issue of result.error.issues) {
            this.logger.warn(`Config validation: ${issue.path.join('.')} — ${issue.message}`)
        }
        this.logger.warn('Falling back to defaults for invalid fields')
        return this.mergeWithDefaults(raw as Partial<NovaClawConfig>)
    }

    private static mergeWithDefaults(config: Partial<NovaClawConfig>): NovaClawConfig {
        return deepMerge(
            this.getDefaultConfig() as Record<string, unknown>,
            config as Record<string, unknown>,
        ) as NovaClawConfig
    }

    /** Substitute ${ENV_VAR} references with process.env values. */
    private static replaceEnvVars(config: Record<string, unknown>): Record<string, unknown> {
        const json = JSON.stringify(config)
        const safeEnvName = /^[A-Za-z_][A-Za-z0-9_]*$/
        const replaced = json.replace(/\$\{([^}]+)\}/g, (_, varName: string) => {
            const name = varName.trim()
            if (!safeEnvName.test(name)) return ''
            return (process.env[name] ?? '')
                .replace(/\\/g, '\\\\')
                .replace(/"/g, '\\"')
                .replace(/\n/g, '\\n')
                .replace(/\r/g, '\\r')
                .replace(/\t/g, '\\t')
        })
        return JSON.parse(replaced) as Record<string, unknown>
    }
}
