import type {
    ExtractedEntity,
    ExtractedRelation,
    ExtractionResult,
    EntityType,
    RelationType,
} from './types.ts'
import { ENTITY_TYPES, RELATION_TYPES } from './types.ts'

export type LLMCallFn = (
    systemPrompt: string,
    userContent: string,
    maxTokens?: number
) => Promise<string | null>

export class EntityExtractor {
    constructor(
        private llmCall: LLMCallFn,
        private config: { maxEntitiesPerChunk?: number } = {}
    ) {}

    async extract(chunkText: string): Promise<ExtractionResult> {
        const systemPrompt = this.buildExtractionPrompt()
        const userContent = chunkText
        const maxTokens = 2048

        const response = await this.llmCall(systemPrompt, userContent, maxTokens)
        if (!response) {
            return { entities: [], relations: [] }
        }

        return this.parseResponse(response)
    }

    async extractBatch(
        chunks: Array<{ id: string; text: string }>
    ): Promise<Map<string, ExtractionResult>> {
        const results = new Map<string, ExtractionResult>()

        for (const chunk of chunks) {
            const result = await this.extract(chunk.text)
            results.set(chunk.id, result)
        }

        return results
    }

    private buildExtractionPrompt(): string {
        const maxEntities = this.config.maxEntitiesPerChunk ?? 20
        const entityTypes = ENTITY_TYPES.join(', ')
        const relationTypes = RELATION_TYPES.join(', ')

        return `You are an entity and relation extractor. Extract entities and their relationships from the given text.

Output a valid JSON object with exactly two keys:
- "entities": array of objects, each with "name" (string), "type" (string), "description" (string)
- "relations": array of objects, each with "source" (string, entity name), "target" (string, entity name), "type" (string), "description" (optional string)

Entity types (use exactly one): ${entityTypes}
Relation types (use exactly one): ${relationTypes}

Rules:
- Extract at most ${maxEntities} entities per chunk
- Entity names must be exact strings from the text
- Relation source/target must match entity names exactly
- Return only valid JSON, no markdown or extra text`
    }

    private parseResponse(response: string): ExtractionResult {
        const jsonStr = this.extractJsonFromResponse(response)
        if (!jsonStr) {
            return { entities: [], relations: [] }
        }

        let parsed: { entities?: unknown[]; relations?: unknown[] }
        try {
            parsed = JSON.parse(jsonStr) as { entities?: unknown[]; relations?: unknown[] }
        } catch {
            return { entities: [], relations: [] }
        }

        const entities = this.parseEntities(parsed.entities ?? [])
        const relations = this.parseRelations(parsed.relations ?? [], entities)

        return { entities, relations }
    }

    private extractJsonFromResponse(response: string): string | null {
        let trimmed = response.trim()

        const codeBlockMatch = trimmed.match(/```(?:json)?\s*([\s\S]*?)```/)
        if (codeBlockMatch) {
            const captured = codeBlockMatch[1]
            trimmed = (captured ?? '').trim()
        }

        const objectMatch = trimmed.match(/\{[\s\S]*\}/)
        if (objectMatch) {
            return objectMatch[0]
        }

        return null
    }

    private parseEntities(raw: unknown[]): ExtractedEntity[] {
        const validEntities: ExtractedEntity[] = []
        const entityTypeSet = new Set<string>(ENTITY_TYPES)

        for (const item of raw) {
            if (
                item &&
                typeof item === 'object' &&
                'name' in item &&
                'type' in item &&
                'description' in item
            ) {
                const name = String((item as { name: unknown }).name).trim()
                const typeStr = String((item as { type: unknown }).type).trim()
                const description = String((item as { description: unknown }).description).trim()

                if (name && entityTypeSet.has(typeStr)) {
                    validEntities.push({
                        name,
                        type: typeStr as EntityType,
                        description,
                    })
                }
            }
        }

        return validEntities
    }

    private parseRelations(
        raw: unknown[],
        entities: ExtractedEntity[]
    ): ExtractedRelation[] {
        const validRelations: ExtractedRelation[] = []
        const relationTypeSet = new Set<string>(RELATION_TYPES)
        const entityNames = new Set(entities.map((e) => e.name))

        for (const item of raw) {
            if (
                item &&
                typeof item === 'object' &&
                'source' in item &&
                'target' in item &&
                'type' in item
            ) {
                const source = String((item as { source: unknown }).source).trim()
                const target = String((item as { target: unknown }).target).trim()
                const typeStr = String((item as { type: unknown }).type).trim()
                const description =
                    'description' in item && (item as { description: unknown }).description != null
                        ? String((item as { description: unknown }).description).trim()
                        : undefined

                if (
                    source &&
                    target &&
                    relationTypeSet.has(typeStr) &&
                    entityNames.has(source) &&
                    entityNames.has(target)
                ) {
                    validRelations.push({
                        source,
                        target,
                        type: typeStr as RelationType,
                        description: description || undefined,
                    })
                }
            }
        }

        return validRelations
    }
}
