/**
 * Tool schema utilities — OpenAI function-calling format conversion
 * and parameter compaction for token optimization.
 */

import type { Tool, ToolFunctionSchema } from '../../apis/index.ts'
import type { ToolSchema } from '../types.ts'

export function toolToSchema(tool: Tool): ToolFunctionSchema {
    return {
        type: 'function',
        function: {
            name: tool.name,
            description: tool.description,
            parameters: tool.parameters,
        },
    }
}

export function buildOpenAIToolsSchema(
    tools: Array<{ name: string; description: string; parameters?: object }> | undefined,
): ToolFunctionSchema[] {
    if (!tools || tools.length === 0) return []
    return tools.map((t) => ({
        type: 'function',
        function: {
            name: t.name,
            description: t.description,
            parameters: t.parameters ?? {},
        },
    }))
}

/**
 * Convert Tool[] to OpenAI ToolSchema[] with compact parameters.
 * Single source of truth — used by AgentRuntime, WorkerRuntime, and DirectorRuntime.
 */
export function toolsToOpenAISchema(tools: Array<{ name: string; description: string; parameters?: unknown }>): ToolSchema[] {
    return tools.map(t => ({
        type: 'function' as const,
        function: {
            name: t.name,
            description: t.description,
            parameters: compactParameters(t.parameters),
        },
    }))
}

/**
 * Strip verbose fields from tool parameter schemas to reduce input tokens.
 * Removes `additionalProperties`, trims long property descriptions.
 */
export function compactParameters(params: unknown): object {
    if (!params || typeof params !== 'object') return params as object ?? {}
    const obj = { ...(params as Record<string, unknown>) }
    delete obj.additionalProperties

    if (obj.properties && typeof obj.properties === 'object') {
        const props = { ...(obj.properties as Record<string, Record<string, unknown>>) }
        for (const key of Object.keys(props)) {
            const prop = { ...props[key] }
            if (typeof prop.description === 'string' && prop.description.length > 80) {
                prop.description = prop.description.slice(0, 80)
            }
            delete prop.additionalProperties
            props[key] = prop
        }
        obj.properties = props
    }
    return obj
}
