/**
 * Route resolver — determines which agent handles a given inbound message
 * based on channel, account, peer, and binding configuration.
 */

import type { NovaClawConfig } from '../../../apis/config.ts'
import type { RoutePeer, ChannelBinding } from './bindings.ts'
import { findBestBinding } from './bindings.ts'
import { buildSessionKey, buildMainSessionKey } from './session-key.ts'

export interface ResolveAgentRouteInput {
    cfg: NovaClawConfig
    channel: string
    accountId?: string
    peer?: RoutePeer
    parentPeer?: RoutePeer
    guildId?: string
    teamId?: string
    memberRoleIds?: string[]
}

export interface ResolvedAgentRoute {
    agentId: string
    channel: string
    accountId: string
    sessionKey: string
    mainSessionKey: string
    matchedBy: string
}

export function resolveAgentRoute(
    input: ResolveAgentRouteInput,
    bindings: ChannelBinding[],
    defaultAgentId = 'default',
): ResolvedAgentRoute {
    const { channel, accountId = 'default', peer, parentPeer, guildId, teamId, memberRoleIds } = input

    const matchResult = findBestBinding(bindings, {
        channel,
        accountId,
        peer,
        parentPeer,
        guildId,
        teamId,
        memberRoleIds,
    })

    const agentId = matchResult?.binding.agentId ?? defaultAgentId
    const matchedBy = matchResult?.matchedBy ?? 'default'

    const peerKind = peer?.kind ?? 'direct'
    const peerId = peer?.id ?? 'unknown'

    const sessionKey = buildSessionKey({
        agentId,
        channel,
        accountId,
        peerKind,
        peerId,
    })

    const mainSessionKey = buildMainSessionKey({
        agentId,
        channel,
        accountId,
        peerKind: 'direct',
        peerId,
    })

    return {
        agentId,
        channel,
        accountId,
        sessionKey,
        mainSessionKey,
        matchedBy,
    }
}
