/**
 * Channel runtime routes — list, status, start/stop/restart channel accounts.
 * Delegates to ChannelHub for runtime operations and ChannelRegistry
 * for plugin metadata.
 */

import type { FastifyInstance } from 'fastify'
import { sendError, sendInternalError, sendNotFound, sendUnavailable } from './route-helpers.ts'
import type { RouteDeps } from './types.ts'

export function registerChannelRoutes(server: FastifyInstance, deps: RouteDeps): void {
    const { config, logger, channelHub } = deps

    /**
     * Try to ensure a channel plugin is loaded in the registry.
     * If not registered, checks if the channel is enabled (e.g. an OpenClaw
     * extension that failed during initial load) and attempts to re-load it.
     */
    async function ensurePluginLoaded(
        hub: NonNullable<typeof channelHub>,
        channelId: string,
    ): Promise<'loaded' | 'not_found' | 'load_failed'> {
        const registry = hub.getChannelRegistry()
        if (registry.get(channelId)) return 'loaded'

        const enabledList = hub.getEffectiveConfig().channels?.enabled ?? []
        if (!enabledList.includes(channelId)) return 'not_found'

        try {
            await hub.addChannel(channelId)
        } catch {
            // addChannel may throw — fall through to the registry check below
        }

        return registry.get(channelId) ? 'loaded' : 'load_failed'
    }

    // ── GET /api/channels — all channels with meta + runtime status ─────

    server.get('/api/channels', async (_req, reply) => {
        if (!channelHub) {
            return reply.send({ channels: [] })
        }

        const registry = channelHub.getChannelRegistry()
        const plugins = registry.listPlugins()
        const statuses = channelHub.getAllChannelStatuses()

        // Use the effective config (includes auto-discovered OpenClaw extensions)
        const effectiveConfig = channelHub.getEffectiveConfig()
        const enabledList = effectiveConfig.channels?.enabled ?? []
        const enabledSet = new Set<string>(enabledList)

        const seenIds = new Set<string>()

        // 1. Registered plugins (loaded successfully)
        const channels = plugins.map(plugin => {
            seenIds.add(plugin.id)
            const status = statuses[plugin.id]
            const health = channelHub.getChannelManager().getHealthStatus(plugin.id)

            return {
                id: plugin.id,
                meta: plugin.meta,
                capabilities: plugin.capabilities,
                enabled: enabledSet.has(plugin.id),
                origin: registry.getEntry(plugin.id)?.origin ?? 'unknown',
                status: status
                    ? {
                        connected: status.connected,
                        lastActivity: status.lastActivity,
                        error: status.error,
                        metrics: status.metrics,
                        accounts: status.accounts,
                    }
                    : null,
                health: health
                    ? { status: health.status, consecutiveFailures: health.consecutiveFailures }
                    : null,
            }
        })

        // 2. Enabled channels not yet in the registry (e.g. auto-discovered
        //    OpenClaw extensions that failed to load or are still loading).
        //    Surface them so the frontend shows they exist.
        for (const channelId of enabledList) {
            if (seenIds.has(channelId)) continue
            channels.push({
                id: channelId,
                meta: { id: channelId, label: channelId, selectionLabel: channelId, docsPath: '', blurb: '' },
                capabilities: { chatTypes: ['direct'], media: false },
                enabled: true,
                origin: 'openclaw',
                status: statuses[channelId]
                    ? {
                        connected: statuses[channelId].connected,
                        lastActivity: statuses[channelId].lastActivity,
                        error: statuses[channelId].error,
                        metrics: statuses[channelId].metrics,
                        accounts: statuses[channelId].accounts,
                    }
                    : null,
                health: null,
            })
        }

        const connectedCount = channels.filter(c => c.status?.connected).length

        reply.send({
            channels,
            summary: {
                total: channels.length,
                enabled: enabledSet.size,
                connected: connectedCount,
            },
        })
    })

    // ── GET /api/channels/:channelId — single channel detail ────────────

    server.get<{ Params: { channelId: string } }>(
        '/api/channels/:channelId',
        async (request, reply) => {
            if (!channelHub) {
                return sendUnavailable(reply, 'Channel hub not available')
            }

            const { channelId } = request.params
            const registry = channelHub.getChannelRegistry()
            const resolvedId = registry.normalizeChannelId(channelId)
            const plugin = registry.get(resolvedId)

            if (!plugin) {
                return sendNotFound(reply, `Channel '${channelId}' not found`)
            }

            const status = channelHub.getChannelStatus(resolvedId)
            const health = channelHub.getChannelManager().getHealthStatus(resolvedId)
            const effectiveCfg = channelHub.getEffectiveConfig()
            const enabledSet = new Set<string>(effectiveCfg.channels?.enabled ?? [])

            reply.send({
                id: plugin.id,
                meta: plugin.meta,
                capabilities: plugin.capabilities,
                enabled: enabledSet.has(plugin.id),
                origin: registry.getEntry(plugin.id)?.origin ?? 'unknown',
                status: status
                    ? {
                        connected: status.connected,
                        lastActivity: status.lastActivity,
                        error: status.error,
                        metrics: status.metrics,
                        accounts: status.accounts,
                    }
                    : null,
                health: health
                    ? { status: health.status, consecutiveFailures: health.consecutiveFailures }
                    : null,
                hasGateway: !!plugin.gateway,
                hasOutbound: !!plugin.outbound,
                hasSecurity: !!plugin.security,
                hasPairing: !!plugin.pairing,
            })
        },
    )

    // ── POST /api/channels/:channelId/start — start channel ─────────────

    server.post<{ Params: { channelId: string }; Body: { accountId?: string } }>(
        '/api/channels/:channelId/start',
        async (request, reply) => {
            if (!channelHub) {
                return sendUnavailable(reply, 'Channel hub not available')
            }

            const { channelId } = request.params
            const body = (request.body ?? {}) as Record<string, unknown>
            const accountId = body.accountId as string | undefined

            const pluginStatus = await ensurePluginLoaded(channelHub, channelId)
            if (pluginStatus === 'not_found') {
                return sendNotFound(reply, `Channel plugin not found: ${channelId}`)
            }
            if (pluginStatus === 'load_failed') {
                return sendError(reply, 500, `Channel '${channelId}' is enabled but the plugin could not be loaded`)
            }

            try {
                const manager = channelHub.getChannelManager()
                await manager.startChannel(channelId, accountId)

                logger.info(`Channel ${channelId} started via API`, { accountId })
                reply.send({ success: true, channelId, accountId })
            } catch (err) {
                logger.error(`Failed to start channel ${channelId}`, err)
                sendInternalError(reply, err)
            }
        },
    )

    // ── POST /api/channels/:channelId/stop — stop channel ───────────────

    server.post<{ Params: { channelId: string }; Body: { accountId?: string } }>(
        '/api/channels/:channelId/stop',
        async (request, reply) => {
            if (!channelHub) {
                return sendUnavailable(reply, 'Channel hub not available')
            }

            const { channelId } = request.params
            const body = (request.body ?? {}) as Record<string, unknown>
            const accountId = body.accountId as string | undefined

            const registry = channelHub.getChannelRegistry()
            if (!registry.get(channelId)) {
                const enabledList = channelHub.getEffectiveConfig().channels?.enabled ?? []
                return sendNotFound(reply, enabledList.includes(channelId)
                    ? `Channel '${channelId}' is enabled but the plugin is not loaded — nothing to stop`
                    : `Channel plugin not found: ${channelId}`)
            }

            try {
                const manager = channelHub.getChannelManager()
                await manager.stopChannel(channelId, accountId)

                logger.info(`Channel ${channelId} stopped via API`, { accountId })
                reply.send({ success: true, channelId, accountId })
            } catch (err) {
                logger.error(`Failed to stop channel ${channelId}`, err)
                sendInternalError(reply, err)
            }
        },
    )

    // ── POST /api/channels/:channelId/restart — stop + start ────────────

    server.post<{ Params: { channelId: string }; Body: { accountId?: string } }>(
        '/api/channels/:channelId/restart',
        async (request, reply) => {
            if (!channelHub) {
                return sendUnavailable(reply, 'Channel hub not available')
            }

            const { channelId } = request.params
            const body = (request.body ?? {}) as Record<string, unknown>
            const accountId = body.accountId as string | undefined

            const pluginStatus = await ensurePluginLoaded(channelHub, channelId)
            if (pluginStatus === 'not_found') {
                return sendNotFound(reply, `Channel plugin not found: ${channelId}`)
            }
            if (pluginStatus === 'load_failed') {
                return sendError(reply, 500, `Channel '${channelId}' is enabled but the plugin could not be loaded`)
            }

            try {
                const manager = channelHub.getChannelManager()
                await manager.stopChannel(channelId, accountId)
                manager.resetRestartAttempts(channelId, accountId ?? 'default')
                await manager.startChannel(channelId, accountId)

                logger.info(`Channel ${channelId} restarted via API`, { accountId })
                reply.send({ success: true, channelId, accountId })
            } catch (err) {
                logger.error(`Failed to restart channel ${channelId}`, err)
                sendInternalError(reply, err)
            }
        },
    )

    // ── POST /api/channels/:channelId/enable — add to enabled list ──────

    server.post<{ Params: { channelId: string } }>(
        '/api/channels/:channelId/enable',
        async (request, reply) => {
            const { channelId } = request.params

            try {
                if (!config.channels) {
                    (config as Record<string, unknown>).channels = { enabled: [] }
                }
                const channelsRef = config.channels as Record<string, unknown>
                const enabled = new Set<string>(
                    Array.isArray(channelsRef.enabled) ? channelsRef.enabled as string[] : [],
                )
                enabled.add(channelId)
                channelsRef.enabled = [...enabled]

                if (channelHub) {
                    try {
                        await channelHub.addChannel(channelId)
                    } catch {
                        // already registered — just start it
                        await channelHub.getChannelManager().startChannel(channelId)
                    }
                }

                logger.info(`Channel ${channelId} enabled via API`)
                reply.send({ success: true, channelId, enabled: true })
            } catch (err) {
                logger.error(`Failed to enable channel ${channelId}`, err)
                sendInternalError(reply, err)
            }
        },
    )

    // ── POST /api/channels/:channelId/disable — remove from enabled list ─

    server.post<{ Params: { channelId: string } }>(
        '/api/channels/:channelId/disable',
        async (request, reply) => {
            const { channelId } = request.params

            try {
                if (config.channels) {
                    const channelsRef = config.channels as Record<string, unknown>
                    const enabled = Array.isArray(channelsRef.enabled)
                        ? (channelsRef.enabled as string[]).filter(id => id !== channelId)
                        : []
                    channelsRef.enabled = enabled
                }

                if (channelHub) {
                    try {
                        await channelHub.removeChannel(channelId)
                    } catch {
                        await channelHub.getChannelManager().stopChannel(channelId).catch(() => {})
                    }
                }

                logger.info(`Channel ${channelId} disabled via API`)
                reply.send({ success: true, channelId, enabled: false })
            } catch (err) {
                logger.error(`Failed to disable channel ${channelId}`, err)
                sendInternalError(reply, err)
            }
        },
    )

    // ── GET /api/channels/registry — raw registry info ──────────────────

    server.get('/api/channels/registry', async (_req, reply) => {
        if (!channelHub) {
            return reply.send({ entries: [] })
        }

        const registry = channelHub.getChannelRegistry()
        const plugins = registry.listPlugins()

        const entries = plugins.map(p => ({
            id: p.id,
            meta: p.meta,
            capabilities: p.capabilities,
            origin: registry.getEntry(p.id)?.origin ?? 'unknown',
            version: registry.getEntry(p.id)?.version,
            isBuiltin: registry.isBuiltin(p.id),
        }))

        reply.send({ entries })
    })
}
