/**
 * Path validation and command blocking for default tools. Framework-only.
 */

import path from 'node:path'
import {resolveWorkspaceDir} from '../../../utils/helpers.ts'

export function resolvePathInWorkspace(rawPath: string, workspaceDir: string): string | null {
    const base = resolveWorkspaceDir(workspaceDir)
    const joined = path.isAbsolute(rawPath)
        ? path.normalize(rawPath)
        : path.join(base, path.normalize(rawPath))
    const resolved = path.resolve(joined)
    const rel = path.relative(base, resolved)
    if (rel.startsWith('..') || path.isAbsolute(rel)) return null
    return resolved
}

const SHELL_BUILTINS = new Set([
    'cd', 'echo', 'export', 'source', 'set', 'unset', 'pwd', 'pushd', 'popd',
    'alias', 'unalias', 'type', 'hash', 'read', 'eval', 'exec', 'trap',
    'return', 'exit', 'shift', 'wait', 'bg', 'fg', 'jobs', 'kill',
    'true', 'false', 'test', '[', 'printf', 'local', 'declare', 'typeset',
    'readonly', 'let', 'builtin', 'command', 'enable', 'help', 'logout',
    'mapfile', 'readarray', 'dirs', 'shopt', 'ulimit', 'umask',
])

const BLOCKED_COMMAND_PATTERNS = [
    /rm\s+(-[a-zA-Z]*f[a-zA-Z]*\s+)?\/\s*$/,
    /rm\s+(-[a-zA-Z]*f[a-zA-Z]*\s+)?(\/\*|\/bin|\/usr|\/etc|\/var|\/home)\b/,
    /mkfs\b/,
    /dd\s+if=.*of=\/dev\//,
    /:\(\)\s*\{\s*:\|:\s*&\s*\}\s*;?\s*:/,
    />\s*\/dev\/sd[a-z]/,
    /chmod\s+(-[a-zA-Z]*\s+)*777\s+\//,
    /curl\s.*\|\s*(ba)?sh/,
    /wget\s.*\|\s*(ba)?sh/,
]

function extractBinary(segment: string): string {
    const stripped = segment.replace(/^\s*(?:\w+=\S*\s+)*/, '')
    return stripped.split(/\s/)[0]?.replace(/^.*\//, '') ?? ''
}

export function isCommandBlocked(
    command: string,
    allowedCommands: string[]
): { blocked: boolean; reason?: string } {
    const trimmed = command.trim()
    if (!trimmed) return {blocked: true, reason: 'Empty command'}

    if (allowedCommands.length > 0) {
        const segments = trimmed.split(/\s*(?:&&|\|\||[;|])\s*/)
        for (const seg of segments) {
            const binary = extractBinary(seg)
            if (!binary) continue
            if (SHELL_BUILTINS.has(binary)) continue
            if (!allowedCommands.includes(binary)) {
                return {blocked: true, reason: `Command '${binary}' not in allowedCommands whitelist`}
            }
        }
    }

    for (const pattern of BLOCKED_COMMAND_PATTERNS) {
        if (pattern.test(trimmed)) {
            return {blocked: true, reason: `Command matches blocked pattern: ${pattern.source}`}
        }
    }

    return {blocked: false}
}
