/**
 * Format raw tool/skill/MCP result into human-readable display text.
 * Used across agent, gateway, and UI layers.
 */

const MAX_DISPLAY_LEN = 32_000

export function formatToolResultForDisplay(_toolName: string, result: unknown): string {
    if (result === undefined || result === null) return '(no output)'

    if (typeof result === 'string') {
        const s = result.trim()
        return s.length <= MAX_DISPLAY_LEN ? s : truncate(s)
    }

    if (typeof result !== 'object') return String(result)

    const obj = result as Record<string, unknown>

    // MCP format: { content: Array<{ type, text } | { type: 'image' }>, isError? }
    if (Array.isArray(obj.content)) return formatMcpContent(obj.content)

    // Error result: { success: false, error: string }
    if (obj.success === false && typeof obj.error === 'string') return obj.error

    // Exec result: { success: true, stdout?, stderr? }
    if (obj.success === true) {
        const stdout = typeof obj.stdout === 'string' ? obj.stdout.trim() : ''
        const stderr = typeof obj.stderr === 'string' ? obj.stderr.trim() : ''
        if (stdout && stderr) return truncate(`stdout:\n${stdout}\n\nstderr:\n${stderr}`)
        if (stdout) return truncate(stdout)
        if (stderr) return truncate(stderr)
    }

    // Read / web_fetch: { success: true, content: string }
    if (obj.success === true && typeof obj.content === 'string') {
        return truncate(obj.content.trim())
    }

    // Write / edit: { success: true, path }
    if (obj.success === true && typeof obj.path === 'string') {
        return `Written: ${obj.path}`
    }

    // web_fetch HTTP response
    if (obj.success === true && typeof obj.status === 'number' && ('content' in obj || 'headers' in obj)) {
        const status = obj.status as number
        const label = obj.ok === true ? 'OK' : 'non-2xx'
        const content = typeof obj.content === 'string'
            ? obj.content.trim()
            : typeof obj.content === 'object' && obj.content !== null
                ? JSON.stringify(obj.content, null, 2)
                : ''
        if (!content) return `HTTP ${status} (${label})`
        return `HTTP ${status} (${label})\n\n${truncate(content)}`
    }

    // Fallback: formatted JSON
    try {
        return truncate(JSON.stringify(obj, null, 2))
    } catch {
        return String(result)
    }
}

function formatMcpContent(content: unknown[]): string {
    const parts: string[] = []
    let imageCount = 0

    for (const item of content) {
        if (!item || typeof item !== 'object') continue
        const typed = item as { type?: string; text?: string }
        if (typed.type === 'text' && typeof typed.text === 'string' && typed.text.trim()) {
            parts.push(typed.text.trim())
        } else if (typed.type === 'image') {
            imageCount++
        }
    }

    let out = parts.join('\n\n').trim()
    if (imageCount > 0) out += `${out ? '\n\n' : ''}[${imageCount} image(s)]`
    if (!out) return '(MCP: no text content)'
    return out.length > MAX_DISPLAY_LEN ? truncate(out) : out
}

function truncate(text: string): string {
    if (text.length <= MAX_DISPLAY_LEN) return text
    return `${text.slice(0, MAX_DISPLAY_LEN)}\n\n... (truncated, ${text.length} chars total)`
}
