/**
 * ChannelHub — thin orchestrator façade for the channel subsystem.
 *
 * Composes the pipeline, lifecycle, and registry layers into a single
 * entry point consumed by the gateway and NovaClaw core.
 *
 * ┌────────────────────────────────────────────────────────┐
 * │                      ChannelHub                        │
 * │  ┌──────────┐  ┌──────────────┐  ┌────────────────┐   │
 * │  │ Registry │  │   Pipeline   │  │   Lifecycle     │   │
 * │  │          │  │ inbound  out │  │ manager  health │   │
 * │  └──────────┘  └──────────────┘  └────────────────┘   │
 * └────────────────────────────────────────────────────────┘
 */

import { EventEmitter } from 'node:events'
import { Logger } from '../../utils/logger.ts'
import type { NovaClawConfig } from '../apis/config.ts'
import type { IChannelHub, ChannelStatus, OutboundContent } from '../apis/channel.ts'
import type { ChannelPlugin } from './types/plugin.ts'
import type { ChannelRuntimeSnapshot } from './types/snapshot.ts'
import type { ChannelPluginRegistry } from '../../registries/channel-plugin-registry.ts'
import type { MessageProcessor } from '../agent/message-processor.ts'

import { ChannelRegistry } from './registry.ts'
import { ChannelManager } from './lifecycle/channel-manager.ts'
import { ChannelActivityTracker } from './lifecycle/activity-tracker.ts'
import { ChannelPluginLoader } from './plugin-loader.ts'
import { BUILTIN_CHANNEL_IDS, createBuiltinPlugin, type ChannelBridge } from './default-adapters.ts'
import { InboundPipeline } from './pipeline/inbound/inbound-pipeline.ts'
import { InboundDebouncePolicy } from './pipeline/inbound/debounce-policy.ts'
import { deliverOutboundMessage } from './pipeline/outbound/delivery.ts'
import { resolveInboundBody, BOT_ROLES } from './pipeline/inbound/extract-text.ts'
import type { ChannelBinding } from './pipeline/routing/index.ts'
import { buildChannelRuntime } from './runtime.ts'
import { ChannelExtensionLoader } from './extensions/loader.ts'

// ── Options ─────────────────────────────────────────────────────────────

export interface ChannelHubOptions {
    channelRegistry?: ChannelRegistry
    channelPluginRegistry?: ChannelPluginRegistry
    bindings?: ChannelBinding[]
    skipConfigMerge?: boolean
    messageProcessor?: MessageProcessor
}

// ── ChannelHub ──────────────────────────────────────────────────────────

export class ChannelHub extends EventEmitter implements IChannelHub {
    private registry: ChannelRegistry
    private manager: ChannelManager
    private inboundPipeline: InboundPipeline
    private debouncePolicy: InboundDebouncePolicy
    private activityTracker: ChannelActivityTracker
    private pluginLoader: ChannelPluginLoader
    private extensionLoader: ChannelExtensionLoader
    private messageHandlers = new Map<string, (message: unknown) => Promise<void>>()
    private config: NovaClawConfig
    private logger: Logger
    private pluginRegistry?: ChannelPluginRegistry
    private messageProcessor?: MessageProcessor
    private bindings: ChannelBinding[]

    constructor(config: NovaClawConfig, options?: ChannelHubOptions) {
        super()

        this.config = config
        this.logger = new Logger('ChannelHub', config.logging?.level || 'info')
        this.bindings = options?.bindings ?? []
        this.messageProcessor = options?.messageProcessor
        this.pluginRegistry = options?.channelPluginRegistry

        // Registry & lifecycle
        this.registry = options?.channelRegistry ?? new ChannelRegistry()
        this.manager = new ChannelManager({
            registry: this.registry,
            config: this.config,
            logger: this.logger,
            channelRuntimeFactory: (channelId, accountId) =>
                this.createChannelRuntime(channelId, accountId),
        })

        // Pipeline
        this.inboundPipeline = new InboundPipeline({
            registry: this.registry,
            config: this.config,
            bindings: this.bindings,
            logger: this.logger,
        })
        this.debouncePolicy = new InboundDebouncePolicy()
        this.activityTracker = new ChannelActivityTracker()

        // Plugin discovery
        this.pluginLoader = new ChannelPluginLoader(this.logger)
        this.extensionLoader = new ChannelExtensionLoader({ logger: this.logger })
        this.extensionLoader.discover()
    }

    // ── Initialization ──────────────────────────────────────────────────

    async initialize(): Promise<void> {
        const startTime = performance.now()
        this.logger.info('Initializing Channel Hub...')

        try {
            const enabledChannels = this.config.channels?.enabled || []
            this.logger.debug(`Loading ${enabledChannels.length} enabled channels`)

            const bridge: ChannelBridge = {
                emit: (event, payload) => this.emit(event, payload),
                setMessageHandler: (id, handler) => this.messageHandlers.set(id, handler),
            }

            let successCount = 0
            let failureCount = 0

            for (const channelId of enabledChannels) {
                try {
                    await this.loadChannel(channelId, bridge)
                    successCount++
                } catch (error) {
                    this.logger.warn(`Failed to load channel ${channelId}`, error)
                    failureCount++
                }
            }

            await this.manager.startChannels()

            this.logger.info(`Channel Hub initialized in ${(performance.now() - startTime).toFixed(2)}ms`, {
                successfulChannels: successCount,
                failedChannels: failureCount,
                totalEnabled: enabledChannels.length,
            })
        } catch (error) {
            this.logger.error('Failed to initialize Channel Hub', error)
            throw error
        }
    }

    // ── Inbound ─────────────────────────────────────────────────────────

    async dispatchMessage(channelId: string, message: unknown): Promise<void> {
        const handler = this.messageHandlers.get(channelId)
        if (!handler) {
            throw new Error(`No message handler registered for channel: ${channelId}`)
        }
        await handler(message)
    }

    async routeIncomingMessage(channelId: string, message: unknown): Promise<void> {
        try {
            const result = this.inboundPipeline.process(
                channelId,
                message,
                (pairing) => this.emit('pairing:requested', pairing),
            )

            if (!result) {
                this.activityTracker.recordError(channelId)
                return
            }

            this.activityTracker.recordReceived(channelId)
            this.emit('channel:message:routed', {
                channelId,
                context: result.context,
                sessionHints: result.sessionHints,
                message: result.message,
            })
        } catch (error) {
            this.logger.error(`Error routing message from ${channelId}`, error)
            this.activityTracker.recordError(channelId)
            throw error
        }
    }

    // ── Outbound ────────────────────────────────────────────────────────

    async sendMessage(channelId: string, target: string, content: OutboundContent): Promise<void> {
        const result = await deliverOutboundMessage(
            {
                channel: channelId,
                to: target,
                text: content.text ?? content.markdown ?? '',
                mediaUrl: content.mediaUrl,
                metadata: content.metadata,
            },
            this.config,
            this.registry,
        )

        if (!result.success && result.errors.length > 0) {
            this.activityTracker.recordError(channelId)
            throw result.errors[0]
        }

        this.activityTracker.recordSent(channelId)
        this.emit('message:sent', { channelId, target, content })
    }

    // ── Plugin access ───────────────────────────────────────────────────

    getChannelPlugin(channelId: string): ChannelPlugin | undefined {
        return this.registry.get(channelId)
    }

    getEffectiveConfig(): NovaClawConfig {
        return this.config
    }

    getChannelRegistry(): ChannelRegistry {
        return this.registry
    }

    getChannelManager(): ChannelManager {
        return this.manager
    }

    hasHandler(channelId: string): boolean {
        return this.messageHandlers.has(channelId)
    }

    setMessageProcessor(mp: MessageProcessor): void {
        this.messageProcessor = mp
    }

    registerExternalPlugin(channelId: string, plugin: ChannelPlugin): void {
        if (this.registry.has(channelId)) return
        this.registry.registerPlugin(plugin, 'global')
    }

    // ── Status ──────────────────────────────────────────────────────────

    getRuntimeSnapshot(): ChannelRuntimeSnapshot {
        return this.manager.getRuntimeSnapshot()
    }

    getChannelStatus(channelId: string): ChannelStatus | null {
        const runtimeSnapshot = this.manager.getRuntimeSnapshot()
        const channelState = runtimeSnapshot.channels[channelId]
        if (!channelState) return null
        return this.buildChannelStatus(channelId, channelState)
    }

    getAllChannelStatuses(): Record<string, ChannelStatus> {
        const statuses: Record<string, ChannelStatus> = {}
        const runtimeSnapshot = this.manager.getRuntimeSnapshot()
        for (const [channelId, channelState] of Object.entries(runtimeSnapshot.channels)) {
            statuses[channelId] = this.buildChannelStatus(channelId, channelState)
        }
        return statuses
    }

    // ── Dynamic channel management ──────────────────────────────────────

    async addChannel(channelId: string): Promise<void> {
        if (this.registry.has(channelId)) {
            throw new Error(`Channel ${channelId} already exists`)
        }

        const bridge: ChannelBridge = {
            emit: (event, payload) => this.emit(event, payload),
            setMessageHandler: (id, handler) => this.messageHandlers.set(id, handler),
        }

        await this.loadChannel(channelId, bridge)

        if (!this.registry.has(channelId)) {
            throw new Error(
                `Channel '${channelId}' could not be loaded — not found as novaclaw-channel-${channelId} or openclaw extension`,
            )
        }

        await this.manager.startChannel(channelId)

        this.logger.info(`Channel ${channelId} added`)
        this.emit('channel:added', channelId)
    }

    async removeChannel(channelId: string): Promise<void> {
        if (!this.registry.has(channelId)) {
            throw new Error(`Channel ${channelId} not found`)
        }

        await this.manager.stopChannel(channelId)
        this.registry.unregister(channelId)
        this.messageHandlers.delete(channelId)

        this.logger.info(`Channel ${channelId} removed`)
        this.emit('channel:removed', channelId)
    }

    // ── Lifecycle ───────────────────────────────────────────────────────

    async cleanup(): Promise<void> {
        this.logger.info('Cleaning up Channel Hub...')
        this.debouncePolicy.clear()
        await this.manager.stopAll()
        this.messageHandlers.clear()
        this.removeAllListeners()
        this.logger.info('Channel Hub cleaned up')
    }

    getStats(): Record<string, unknown> {
        const snapshot = this.manager.getRuntimeSnapshot()
        const channelCount = Object.keys(snapshot.channels).length
        const accountCount = Object.values(snapshot.channels)
            .reduce((sum, ch) => sum + Object.keys(ch.accounts).length, 0)
        return {
            channels: channelCount,
            accounts: accountCount,
            handlers: this.messageHandlers.size,
            registryVersion: this.registry.getVersion(),
        }
    }

    // ── Private: channel loading ────────────────────────────────────────

    private async loadChannel(channelId: string, bridge: ChannelBridge): Promise<void> {
        if (this.pluginRegistry) {
            const entry = this.pluginRegistry.get(channelId)
            if (entry?.plugin) {
                this.registry.registerPlugin(entry.plugin, 'config', entry.version)
                return
            }
            if (entry?.factory) {
                const channelCfg = (this.config.channels as Record<string, unknown>)?.[channelId] ?? {}
                const plugin = await entry.factory(channelCfg as Record<string, unknown>)
                this.registry.registerPlugin(plugin, 'config')
                return
            }
        }

        if ((BUILTIN_CHANNEL_IDS as readonly string[]).includes(channelId)) {
            const plugin = createBuiltinPlugin(channelId, bridge)
            this.registry.registerPlugin(plugin, 'bundled')
            return
        }

        await this.loadExternalPlugin(channelId)
    }

    private async loadExternalPlugin(channelId: string): Promise<void> {
        const packageName = `novaclaw-channel-${channelId}`
        const channelCfg = (this.config.channels as Record<string, unknown>)?.[channelId] ?? {}
        const nativePlugin = await this.pluginLoader.loadFromPackage(packageName, channelCfg as Record<string, unknown>)
        if (nativePlugin) {
            this.registry.registerPlugin(nativePlugin, 'global')
            return
        }

        if (this.registry.has(channelId)) return

        const ext = this.extensionLoader.findExtension(channelId)
        if (ext) {
            const channelRuntime = this.createChannelRuntime(channelId, 'default')
            const plugin = await this.extensionLoader.loadExtension(ext, this.config, channelRuntime)
            if (plugin) {
                this.registry.registerPlugin(plugin, 'global')
                return
            }
        }

        this.logger.warn(`Channel '${channelId}' not found as ${packageName} or local extension`)
    }

    // ── Private: channel runtime for plugins ────────────────────────────

    private createChannelRuntime(channelId: string, accountId: string) {
        const mp = this.messageProcessor
        if (!mp) return undefined

        return buildChannelRuntime({
            cfg: this.config,
            channelId,
            accountId,
            registry: this.registry,
            bindings: this.bindings,
            onReply: async (ctx, _cfg, options) => {
                const body = resolveInboundBody(ctx)
                if (!body) return { dispatched: false }

                const senderName = (ctx.SenderName as string)?.toLowerCase()
                if (senderName && BOT_ROLES.has(senderName)) return { dispatched: false }

                const userId = (ctx.From ?? ctx.SenderId ?? 'anonymous') as string
                const sessionKey = ctx.SessionKey as string | undefined

                const response = await mp.process({
                    message: body,
                    sessionKey,
                    userId,
                    channel: channelId,
                })

                const opts = options as { dispatcherOptions?: { deliver?: (p: { text?: string }) => Promise<void> } }
                if (response.success && response.content?.trim() && typeof opts?.dispatcherOptions?.deliver === 'function') {
                    await opts.dispatcherOptions.deliver({ text: response.content })
                }

                return { dispatched: true }
            },
        })
    }

    // ── Private: status helpers ─────────────────────────────────────────

    private buildChannelStatus(
        channelId: string,
        channelState: ChannelRuntimeSnapshot['channels'][string],
    ): ChannelStatus {
        const activity = this.activityTracker.get(channelId)
        const accounts = Object.entries(channelState.accounts).map(([accountId, snap]) => ({
            accountId,
            connected: snap.connected ?? false,
            error: snap.lastError ?? undefined,
        }))

        const bestConnected = accounts.some(a => a.connected)
        const lastActivity = (activity?.lastMessageAt ??
            Math.max(
                ...Object.values(channelState.accounts).map(s => s.lastMessageAt ?? s.lastStartAt ?? 0).filter(Boolean),
                0,
            )) || undefined
        const errors = Object.values(channelState.accounts).filter(s => s.lastError).length
        const allErrors = Object.values(channelState.accounts)
            .map(s => s.lastError)
            .filter((e): e is string => !!e)

        return {
            connected: bestConnected,
            lastActivity: lastActivity || undefined,
            error: allErrors.length > 0 ? allErrors.join('; ') : undefined,
            metrics: {
                messagesSent: activity?.msgSent ?? 0,
                messagesReceived: activity?.msgReceived ?? 0,
                errors: (activity?.errors ?? 0) + errors,
            },
            accounts,
        }
    }
}
