import { performance } from 'node:perf_hooks'
import { t } from '../../i18n/index.ts'
import type { ProviderRegistry } from '../../registries/provider-registry.ts'
import type { RuleRegistry } from '../../registries/rule-registry.ts'
import type { ToolProviderRegistry } from '../../registries/tool-provider-registry.ts'
import { Logger } from '../../utils/logger.ts'
import { Stopwatch } from '../../utils/stopwatch.ts'
import type { AgentResponse, NovaClawConfig } from '../apis/index.ts'
import type { ProtocolBridge } from '../protocol/protocol-bridge.ts'
import type { SkillsEngine } from '../skills/skills-engine.ts'
import { AgentExecutor } from './agent-executor.ts'
import { AgentMetrics } from './agent-metrics.ts'
import { DefaultExecutionPolicy, type IExecutionPolicy } from './execution-policy.ts'
import { ModelManager } from './model/model-manager.ts'
import { PromptBuilder } from './stream/prompt-builder.ts'
import { toolsToOpenAISchema } from './tool/tool-schema.ts'
import { ToolRegistry } from './tool/tool-registry.ts'
import type { Agent, ExecutorParams } from './types.ts'

// ---------------------------------------------------------------------------
// Options
// ---------------------------------------------------------------------------

export interface AgentRuntimeOptions {
    skillsEngine?: SkillsEngine
    providerRegistry?: ProviderRegistry | null
    ruleRegistry?: RuleRegistry | null
    toolProviderRegistry?: ToolProviderRegistry | null
    executionPolicy?: IExecutionPolicy
}

// ---------------------------------------------------------------------------
// AgentRuntime — the main agent orchestrator
// ---------------------------------------------------------------------------

const MAX_FALLBACK_ATTEMPTS = 2

export class AgentRuntime implements Agent {
    private modelManager: ModelManager
    private toolRegistry: ToolRegistry
    private promptBuilder: PromptBuilder
    private executor: AgentExecutor
    private executionPolicy: IExecutionPolicy
    private logger: Logger
    private skillsEngine?: SkillsEngine

    private metrics = new AgentMetrics()

    constructor(config: NovaClawConfig, options: AgentRuntimeOptions = {}) {
        const logLevel = config.logging?.level || 'info'
        this.modelManager = new ModelManager(config, { providerRegistry: options.providerRegistry ?? undefined })
        this.toolRegistry = new ToolRegistry(config, {
            skillsEngine: options.skillsEngine,
            ruleEngine: options.ruleRegistry?.getEngine(),
            toolProviderRegistry: options.toolProviderRegistry ?? undefined
        })
        this.promptBuilder = new PromptBuilder(config)
        this.executor = new AgentExecutor(this.toolRegistry, logLevel, {
            maxTurns: config.agent?.maxTurns ?? 10,
            toolResultContextMax: config.agent?.toolResultContextMax ?? 16_000,
        })
        this.logger = new Logger('AgentRuntime', logLevel)
        this.executionPolicy = options.executionPolicy ?? new DefaultExecutionPolicy(this.logger)
        this.skillsEngine = options.skillsEngine
    }

    setProtocolBridge(bridge: ProtocolBridge | null): void {
        this.toolRegistry.setProtocolBridge(bridge)
    }

    // ---------------------------------------------------------------------------
    // Lifecycle
    // ---------------------------------------------------------------------------

    async initialize(): Promise<void> {
        const startTime = performance.now()
        this.logger.info('Initializing...')

        try {
            const [modelInfo] = await Promise.all([
                this.modelManager.initialize(),
                this.toolRegistry.initialize(),
                this.promptBuilder.loadInstructionFiles()
            ])

            const initTime = performance.now() - startTime
            this.logger.info(`Initialized (${initTime.toFixed(0)}ms)`, {
                model: modelInfo.model,
                provider: modelInfo.provider,
                tools: this.toolRegistry.getAll().length,
            })
        } catch (error) {
            this.logger.error('Initialization failed', error)
            throw error
        }
    }

    async reinitializeSession(): Promise<void> {
        try {
            await this.modelManager.reinitialize()
            const m = this.modelManager.getActiveModel()
            this.logger.info('Session reinitialized', { provider: m?.provider, model: m?.model })
        } catch (err) {
            this.logger.warn('Reinitialize session failed', err)
        }
    }

    async reinitializeToolRegistry(): Promise<void> {
        try {
            await this.toolRegistry.initialize()
            this.logger.info('Tool registry reinitialized')
        } catch (err) {
            this.logger.warn('Reinitialize tool registry failed', err)
        }
    }

    async cleanup(): Promise<void> {
        this.logger.debug('Cleaned up')
    }

    // ---------------------------------------------------------------------------
    // Core execution
    // ---------------------------------------------------------------------------

    async execute(params: ExecutorParams): Promise<AgentResponse> {
        const startTime = performance.now()

        try {
            const result = await this.executeWithRetry(params)
            this.modelManager.recordSuccess()
            return result
        } catch (error) {
            return this.handleExecutionError(error, params, startTime)
        }
    }

    async internalLLMCall(systemPrompt: string, userContent: string, maxTokens = 2048): Promise<string | null> {
        return this.modelManager.internalLLMCall(systemPrompt, userContent, maxTokens)
    }

    // ---------------------------------------------------------------------------
    // Private — execution with retry
    // ---------------------------------------------------------------------------

    private async executeWithRetry(params: ExecutorParams): Promise<AgentResponse> {
        const sw = Stopwatch.start()

        const session = this.modelManager.createSession()
        sw.lap('createSession')

        const contextualTools = this.toolRegistry.getContextualTools(params.context)
        const allSkills = this.skillsEngine ? await this.skillsEngine.listSkills() : []
        const systemPrompt = this.promptBuilder.build({
            context: params.context,
            skills: params.skills,
            allSkills,
            memoryContext: params.memoryContext,
            tools: contextualTools,
        })
        await session.updateSystemPrompt(systemPrompt)
        sw.lap('prompt')

        const toolSchemas = toolsToOpenAISchema(contextualTools)
        sw.lap('toolSchemas')

        const result = await this.executor.execute({
            session,
            message: params.message,
            tools: toolSchemas,
            executor: params
        })
        const processingTime = sw.elapsed()
        sw.stop('execute')

        this.metrics.recordRequest(true, processingTime)
        this.metrics.addTokens(result.usage.totalTokens || 0)

        this.logger.info('Request completed', {
            contentLen: result.content.length,
            toolCalls: result.toolCalls.length,
            perf: sw.summary(),
        })

        return {
            content: result.content,
            thinking: result.thinking,
            toolCalls: result.toolCalls,
            usage: result.usage,
            model: this.modelManager.getActiveModel()?.model ?? 'unknown',
            skillsApplied: params.skills.map(s => s.id),
            aborted: result.aborted,
        }
    }

    // ---------------------------------------------------------------------------
    // Private — error handling (bounded retry, replaces infinite loop)
    // ---------------------------------------------------------------------------

    private async handleExecutionError(error: unknown, params: ExecutorParams, startTime: number): Promise<AgentResponse> {
        const ctx = {
            getActiveModelName: () => this.modelManager.getActiveModel()?.model ?? 'error',
            createErrorResponse: (userMessage: string) => this.buildErrorResponse(userMessage, startTime),
            onChunk: params.onChunk
        }

        let lastError = error
        for (let attempt = 0; attempt < MAX_FALLBACK_ATTEMPTS; attempt++) {
            const decision = await this.executionPolicy.handle(lastError, params, startTime, ctx)

            if (decision.action === 'respond') {
                return decision.response
            }

            if (decision.action === 'retrySameModel') {
                try {
                    const result = await this.executeWithRetry(params)
                    this.modelManager.recordSuccess()
                    return result
                } catch (retryErr) {
                    lastError = retryErr
                    continue
                }
            }

            // action === 'retryAfterFallback'
            const switched = await this.modelManager.switchToFallback()
            if (switched) {
                try {
                    const m = this.modelManager.getActiveModel()
                    this.logger.info('Fallback model activated', { model: m?.model, provider: m?.provider })
                    const result = await this.executeWithRetry(params)
                    this.modelManager.recordSuccess()
                    return result
                } catch (fallbackErr) {
                    const msg = fallbackErr instanceof Error ? fallbackErr.message : String(fallbackErr)
                    this.logger.error(`Fallback model also failed: ${msg}`, fallbackErr)
                    lastError = fallbackErr
                    continue
                }
            }

            return ctx.createErrorResponse(decision.fallbackMessage)
        }

        return ctx.createErrorResponse(t('agent.all_models_unavailable'))
    }

    private buildErrorResponse(userMessage: string, startTime: number): AgentResponse {
        this.metrics.recordRequest(false, performance.now() - startTime)
        return {
            content: userMessage,
            toolCalls: [],
            usage: { totalTokens: 0 },
            model: this.modelManager.getActiveModel()?.model ?? 'error',
            skillsApplied: []
        }
    }

    getStats(): Record<string, unknown> {
        return this.metrics.getSummary(this.modelManager.getActiveModel()?.model)
    }
}
