const DEFAULT_LATENCIES: Record<string, number> = {
    'claude': 2000,
    'gpt-4o': 1500,
    'gpt-4': 3000,
    'gpt-3.5': 1500,
    'o1': 5000,
    'o3': 4000,
    'o4': 3000,
    'deepseek': 2000,
    'gemini': 1500,
    'qwen': 2000,
    'local': 500,
}

const FALLBACK_MAX_TOKENS = 4096

export function getMaxTokensForModel(model: string, configOverrides?: Record<string, number>): number {
    const merged = configOverrides
        ? { ...DEFAULT_TOKEN_LIMITS, ...configOverrides }
        : DEFAULT_TOKEN_LIMITS

    for (const [pattern, limit] of Object.entries(merged)) {
        if (model.includes(pattern)) return limit
    }
    return FALLBACK_MAX_TOKENS
}

export function getCostForModel(model: string): number {
    for (const [pattern, cost] of Object.entries(DEFAULT_COSTS)) {
        if (model.includes(pattern)) return cost
    }
    return 2.0
}

export function getExpectedLatency(model: string): number {
    for (const [pattern, latency] of Object.entries(DEFAULT_LATENCIES)) {
        if (model.includes(pattern)) return latency
    }
    return 2000
}

export function getModelTokenLimit(model: string): number {
    return getMaxTokensForModel(model)
}
