import { Client } from '@modelcontextprotocol/sdk/client'
import { StdioClientTransport } from '@modelcontextprotocol/sdk/client/stdio.js'
import { StreamableHTTPClientTransport } from '@modelcontextprotocol/sdk/client/streamableHttp.js'
import type { ILogger } from '../../../utils/logger.ts'
import type { MCPServerRequestInit } from '../types.ts'
import type { CreateTransportOptions, TransportResult } from './types.ts'

const CLIENT_NAME = 'novaclaw-mcp-client'
const CLIENT_VERSION = '1.0.0'

type MCPClient = Client & { connect: (t: unknown) => Promise<void> }

function isHttpUrl(s: string): boolean {
    return /^https?:\/\//i.test(s.trim())
}

function parseUrl(endpoint: string): URL {
    const s = endpoint.trim()
    if (!isHttpUrl(s)) throw new Error(`Invalid MCP HTTP endpoint: ${endpoint}`)
    return new URL(s)
}

/** Build Fetch API RequestInit from persisted MCP config (JSON-safe). */
export function buildRequestInit(config?: MCPServerRequestInit): RequestInit | undefined {
    if (!config) return undefined
    const init: RequestInit = {}
    if (config.headers && typeof config.headers === 'object') {
        const headers: Record<string, string> = {}
        for (const [k, v] of Object.entries(config.headers)) {
            if (typeof v === 'string' && v.trim() !== '') headers[k] = v
        }
        if (Object.keys(headers).length > 0) init.headers = headers
    }
    if (config.method) init.method = config.method
    if (config.credentials) init.credentials = config.credentials
    return Object.keys(init).length > 0 ? init : undefined
}

/** True if RequestInit carries an Authorization header (any casing). */
export function hasAuthorizationHeader(init: RequestInit | undefined): boolean {
    const h = init?.headers
    if (h == null) return false
    if (typeof Headers !== 'undefined' && h instanceof Headers) return h.has('Authorization')
    if (typeof h === 'object') {
        return Object.keys(h as Record<string, string>).some(k => k.toLowerCase() === 'authorization')
    }
    return false
}

function newClient(): MCPClient {
    return new Client({ name: CLIENT_NAME, version: CLIENT_VERSION }) as MCPClient
}

function streamableOptions(requestInit: RequestInit | undefined) {
    return requestInit != null && Object.keys(requestInit).length > 0
        ? { requestInit }
        : undefined
}

async function createStdioTransport(
    command: string,
    args: string[],
    logger: ILogger,
): Promise<TransportResult> {
    const client = newClient()
    const transport = new StdioClientTransport({ command, args })
    await client.connect(transport)
    logger.debug(`Transport connected: stdio ${command}`)
    return { client, transport }
}

async function createHttpTransport(
    endpoint: string,
    requestInit: MCPServerRequestInit | undefined,
    logger: ILogger,
): Promise<TransportResult> {
    const url = parseUrl(endpoint)
    const fetchInit = buildRequestInit(requestInit)
    logger.debug(`HTTP transport: auth=${hasAuthorizationHeader(fetchInit)}, endpoint=${url.href}`)

    const client = newClient()
    const transport = new StreamableHTTPClientTransport(url, streamableOptions(fetchInit))
    await client.connect(transport)
    logger.debug(`Transport connected: ${url.href}`)
    return { client, transport }
}

/**
 * Create an MCP transport and connect the SDK client.
 * This is the sole file that imports `@modelcontextprotocol/sdk`.
 */
export async function createTransport(
    options: CreateTransportOptions,
    logger: ILogger,
): Promise<TransportResult> {
    const { endpoint, command, args } = options
    const type = options.transport ?? (isHttpUrl(endpoint) ? 'http' : 'stdio')

    if (type === 'stdio') {
        if (!command) throw new Error('stdio transport requires command')
        return createStdioTransport(command, args ?? [], logger)
    }

    if (type === 'http' || type === 'sse') {
        return createHttpTransport(endpoint, options.requestInit, logger)
    }

    throw new Error(`Unsupported MCP transport: ${type}. Endpoint: ${endpoint}`)
}
