import type { SkillDefinition } from '../../apis/skill.ts'
import type { AgentCatalogEntry } from './types.ts'

export interface DirectorPromptBuildParams {
    agentCatalog: AgentCatalogEntry[]
    skillSummaries?: Array<Pick<SkillDefinition, 'id' | 'description'>>
    communitySummaries?: string[]
    context: {
        sessionKey: string
        workspaceDir: string
        userId: string
        channel: string
    }
}

export class DirectorPromptBuilder {
    constructor(private directResponse = true) {}

    build(params: DirectorPromptBuildParams): string {
        const { agentCatalog, skillSummaries, communitySummaries, context } = params
        const sections: string[] = []

        // 1. Base prompt
        sections.push(
            'You are the NovaClaw Director — an orchestrator that delegates tasks to specialized worker agents.',
        )

        // 2. Key instructions about delegate_task vs direct response
        sections.push(`
## Key Instructions
- Use the \`delegate_task\` tool when the user's request requires specialized capabilities (code, files, web research, MCP, channel operations).
- For complex or multi-step tasks, delegate to the appropriate worker agent rather than attempting to handle everything yourself.
- You can respond directly when the request is a simple greeting, clarification question, or general Q&A that does not require specialized tools.`)

        if (this.directResponse) {
            sections.push(`
- For simple greetings or straightforward questions, you may respond directly without delegation.`)
        } else {
            sections.push(`
- Prefer delegation over direct response when in doubt.`)
        }

        // 3. Agent Catalog section
        sections.push(this.buildAgentCatalogSection(agentCatalog))

        // 4. Skills Overview (if skillSummaries provided)
        if (skillSummaries?.length) {
            sections.push(this.buildSkillsOverviewSection(skillSummaries))
        }

        // 5. Knowledge Graph (if communitySummaries provided)
        if (communitySummaries?.length) {
            sections.push(this.buildKnowledgeGraphSection(communitySummaries))
        }

        // 6. Context section
        sections.push(this.buildContextSection(context))

        // 7. Delegation guidelines
        sections.push(this.buildDelegationGuidelinesSection())

        return sections.join('\n\n').trim()
    }

    private buildAgentCatalogSection(catalog: AgentCatalogEntry[]): string {
        const lines = catalog.map(
            (entry) =>
                `- **${entry.id}** (${entry.role}): ${entry.description}\n  Tools: ${entry.tools.join(', ')}`,
        )
        return `## Agent Catalog

The following worker agents are available. Use \`delegate_task\` with the agent id to assign work.

${lines.join('\n\n')}`
    }

    private buildSkillsOverviewSection(
        skillSummaries: Array<Pick<SkillDefinition, 'id' | 'description'>>,
    ): string {
        const lines = skillSummaries.map((s) => `- **${s.id}**: ${s.description}`)
        return `## Skills Overview

${lines.join('\n')}`
    }

    private buildKnowledgeGraphSection(summaries: string[]): string {
        return `## Knowledge Graph

${summaries.map((s) => `- ${s}`).join('\n')}`
    }

    private buildContextSection(context: DirectorPromptBuildParams['context']): string {
        return `## Context
- Session: ${context.sessionKey}
- Workspace: ${context.workspaceDir}
- User: ${context.userId}
- Channel: ${context.channel}`
    }

    private buildDelegationGuidelinesSection(): string {
        return `## Delegation Guidelines

- **Code / file tasks** (editing, reading, searching, refactoring) → delegate to **coder**
- **Web research** (lookup, fact-checking, summaries) → delegate to **web**
- **MCP integration** (external tools, servers, protocols) → delegate to **mcp**
- **Channel operations** (Slack, Discord, etc.) → delegate to **channel**
- **Simple Q&A** (greetings, clarifications, general questions) → use **chat** or respond directly`
    }
}
