/**
 * Generic message processing pipeline.
 *
 * Encapsulates the full cycle: session management, conversation resolution,
 * skill matching, memory retrieval, agent execution, and history + memory
 * persistence.
 *
 * Any consumer — the HTTP gateway, WebSocket handler, channel plugin,
 * or future integrations — calls `process()` with a message and gets back
 * a `MessageResponse`. Conversation lifecycle is managed transparently
 * by the framework (via ConversationResolver) so callers never need to
 * worry about memory persistence.
 */

import { performance } from 'node:perf_hooks'
import type {
    IMemoryProvider,
    MessageResponse,
    NovaClawConfig,
    SessionContext,
    SkillDefinition,
    StreamChunk,
} from '../apis/index.ts'
import type { HookManager } from '../hooks/hook-manager.ts'
import type { SkillsEngine } from '../skills/skills-engine.ts'
import type { Agent } from './types.ts'
import { SessionManager, type CreateSessionPayload } from './session/session-manager.ts'
import { ConversationResolver } from './session/conversation-resolver.ts'
import { toErrorMessage } from '../../../constants/errors.ts'
import { MESSAGE_TIMEOUT_MS } from '../../../constants/timeouts.ts'
import { t } from '../../i18n/index.ts'
import { AsyncLock } from '../../utils/async-lock.ts'
import { Logger } from '../../utils/logger.ts'
import { resolveWorkspaceDir } from '../../../utils/index.ts'

// ── Public types ─────────────────────────────────────────────────────────

export interface MessageProcessorDeps {
    config: NovaClawConfig
    agent: Agent
    skillsEngine: SkillsEngine
    memoryEngine: IMemoryProvider | null
    sessionManager: SessionManager
    hookManager?: HookManager | null
}

export interface ProcessMessageParams {
    message: string
    sessionKey?: string
    userId?: string
    channel?: string
    metadata?: Record<string, unknown>
    images?: Array<{ url?: string; data?: string; mimeType: string; description?: string }>
    onChunk?: (chunk: StreamChunk) => void
    abortSignal?: AbortSignal
}

// ── MessageProcessor ─────────────────────────────────────────────────────

export class MessageProcessor {
    private readonly config: NovaClawConfig
    private readonly logger: Logger
    private readonly agent: Agent
    private readonly skillsEngine: SkillsEngine
    private readonly memoryEngine: IMemoryProvider | null
    private readonly sessionLock = new AsyncLock()
    private readonly hookManager: HookManager | null
    readonly sessionManager: SessionManager

    /** Exposed for gateway-level conversation pre-binding (e.g. WS auth). */
    readonly conversationResolver: ConversationResolver | null

    constructor(deps: MessageProcessorDeps) {
        this.config = deps.config
        this.logger = new Logger('MessageProcessor', deps.config.logging?.level ?? 'info')
        this.agent = deps.agent
        this.skillsEngine = deps.skillsEngine
        this.memoryEngine = deps.memoryEngine
        this.sessionManager = deps.sessionManager
        this.hookManager = deps.hookManager ?? null

        this.conversationResolver = deps.memoryEngine
            ? new ConversationResolver(deps.memoryEngine, deps.sessionManager, this.logger)
            : null
    }

    /**
     * Process a single message through the full agent pipeline.
     *
     * 1. Resolve or create a session
     * 2. Ensure a conversation is bound (auto-create if needed)
     * 3. Match skills + retrieve memory in parallel
     * 4. Execute the agent
     * 5. Update conversation history + persist to memory
     */
    async process(params: ProcessMessageParams): Promise<MessageResponse> {
        const t0 = performance.now()
        const emit = params.onChunk ?? (() => {})

        const session = await this.resolveSession(params)
        await this.conversationResolver?.ensure(session)

        const release = await this.sessionLock.acquire(session.sessionKey)

        const timeoutCtrl = new AbortController()
        const messageTimeoutMs = this.config.agent?.messageTimeoutMs ?? MESSAGE_TIMEOUT_MS
        const timer = setTimeout(() => {
            const elapsedMs = Math.round(performance.now() - t0)
            this.logger.error('Message processing timeout — aborting', {
                sessionKey: session.sessionKey,
                sessionId: session.sessionId,
                channel: session.channel,
                userId: session.userId,
                timeoutMs: messageTimeoutMs,
                elapsedMs,
                messagePreview: params.message.slice(0, 120),
                historyLength: session.messageHistory?.length ?? 0,
                conversationId: session.conversationId ?? null,
            })
            timeoutCtrl.abort()
        }, messageTimeoutMs)

        const signal = params.abortSignal
            ? AbortSignal.any([params.abortSignal, timeoutCtrl.signal])
            : timeoutCtrl.signal

        try {
            await this.hookManager?.trigger('message:before', {
                message: params.message,
                sessionKey: session.sessionKey,
                channel: session.channel,
            })

            return await this.executeAgentTurn(params, session, t0, emit, signal, timeoutCtrl.signal)
        } catch (error) {
            return {
                success: false,
                error: toErrorMessage(error),
                processingTime: performance.now() - t0,
            }
        } finally {
            clearTimeout(timer)
            release()
        }
    }

    // ── Private — session resolution ────────────────────────────────────

    private async resolveSession(params: ProcessMessageParams): Promise<SessionContext> {
        if (params.sessionKey) {
            const existing = this.sessionManager.get(params.sessionKey)
            if (existing) {
                existing.lastActivity = Date.now()
                if (!existing.messageHistory) existing.messageHistory = []
                if (existing.workspaceDir?.includes('~')) {
                    existing.workspaceDir = resolveWorkspaceDir(existing.workspaceDir)
                }
                return existing
            }
        }

        const payload: CreateSessionPayload = {
            userId: params.userId ?? 'anonymous',
            channel: params.channel ?? 'unknown',
            metadata: params.metadata,
        }
        return this.sessionManager.createSession(payload, params.sessionKey)
    }

    // ── Private — skill matching ────────────────────────────────────────

    private async matchSkills(
        message: string,
        session: SessionContext,
        emit: (chunk: StreamChunk) => void,
    ): Promise<SkillDefinition[]> {
        if (!this.skillsEngine) return []

        emit({ type: 'progress', step: 'skills', status: 'running', content: 'Matching skills...' })
        const skills = await this.skillsEngine.findRelevantSkills(message, session, { maxSkills: 8 })
        emit({
            type: 'progress', step: 'skills', status: 'completed',
            content: skills.length > 0 ? `Matched ${skills.length} skills` : 'No skills matched',
        })
        return skills
    }

    // ── Private — memory retrieval ──────────────────────────────────────

    private async retrieveMemory(
        message: string,
        emit: (chunk: StreamChunk) => void,
    ): Promise<string> {
        if (!this.memoryEngine?.enabled) return ''

        emit({ type: 'progress', step: 'memory', status: 'running', content: 'Retrieving memory...' })
        const memResult = await this.memoryEngine.retrieve(message).catch((e: unknown) => {
            this.logger.warn('Memory retrieval failed (non-critical)', e)
            return null
        })

        if (memResult && memResult.results.length > 0) {
            const memoryContext = memResult.results
                .map((r) =>
                    r.sections
                        .map((s) => `[${r.title} > ${s.nodeTitle}]\n${s.content}`)
                        .join('\n\n'),
                )
                .join('\n\n---\n\n')
            emit({
                type: 'progress', step: 'memory', status: 'completed',
                content: `Retrieved ${memResult.results.length} relevant memories`,
            })
            return memoryContext
        }

        emit({
            type: 'progress', step: 'memory',
            status: memResult === null ? 'error' : 'completed',
            content: memResult === null ? 'Memory retrieval failed' : 'No relevant memories',
        })
        return ''
    }

    // ── Private — history & memory persistence ──────────────────────────

    private updateHistory(session: SessionContext, message: string, content: string): void {
        if (session.messageHistory) {
            session.messageHistory.push(
                { role: 'user', content: message },
                { role: 'assistant', content },
            )
            this.sessionManager.trimHistory(session)
        }
    }

    private persistToMemory(
        session: SessionContext,
        userMessage: string,
        content: string,
        response: MessageResponse,
    ): void {
        if (
            !this.memoryEngine?.enabled ||
            !session.conversationId ||
            !response.success ||
            !(content?.trim())
        ) return

        const toolSummary = response.toolCalls?.map((tc) => ({
            name: tc.name,
            args: condensedArgs(tc.args),
            status: tc.status,
            error: tc.error,
        }))
        this.memoryEngine
            .appendMessages(session.conversationId, [
                { role: 'user', content: userMessage },
                {
                    role: 'assistant',
                    content,
                    thinking: response.thinking || undefined,
                    toolCalls: toolSummary?.length ? toolSummary : undefined,
                },
            ])
            .catch((err) => this.logger.warn('Failed to persist conversation turn', err))
    }

    // ── Private — abort reason classification ───────────────────────────

    private classifyAbort(timeoutSignal: AbortSignal): { stopped: boolean; timedOut: boolean } {
        if (timeoutSignal.aborted) return { stopped: false, timedOut: true }
        return { stopped: true, timedOut: false }
    }

    // ── Private — orchestrate a single agent turn ───────────────────────

    private async executeAgentTurn(
        params: ProcessMessageParams,
        session: SessionContext,
        t0: number,
        emit: (chunk: StreamChunk) => void,
        signal: AbortSignal,
        timeoutSignal: AbortSignal,
    ): Promise<MessageResponse> {
        try {
            const [skills, memoryContext] = await Promise.all([
                this.matchSkills(params.message, session, emit),
                this.retrieveMemory(params.message, emit),
            ])

            emit({ type: 'progress', step: 'llm', status: 'running', content: 'Generating response...' })
            const result = await this.agent.execute({
                message: params.message,
                context: session,
                skills,
                memoryContext,
                onChunk: emit,
                images: params.images,
                abortSignal: signal,
            })

            let content = result?.content ?? ''
            let stopped = false
            let timedOut = false

            if (result?.aborted) {
                ;({ stopped, timedOut } = this.classifyAbort(timeoutSignal))
                const suffix = timedOut ? t('agent.stopped_by_timeout') : t('agent.stopped_by_user')
                content += suffix
                emit({ type: 'text', content: suffix })
                if (timedOut) {
                    const elapsedMs = Math.round(performance.now() - t0)
                    this.logger.error('Agent turn aborted by timeout', {
                        sessionKey: session.sessionKey,
                        channel: session.channel,
                        elapsedMs,
                        contentLength: content.length,
                        toolCallCount: result?.toolCalls?.length ?? 0,
                        messagePreview: params.message.slice(0, 120),
                    })
                    emit({ type: 'progress', step: 'llm', status: 'error', content: `Request timed out after ${(elapsedMs / 1000).toFixed(1)}s` })
                }
            } else {
                emit({ type: 'progress', step: 'llm', status: 'completed', content: 'Generation complete' })
            }

            const response: MessageResponse = {
                success: true,
                content,
                thinking: result?.thinking,
                toolCalls: result?.toolCalls ?? [],
                sessionId: session.sessionId,
                processingTime: performance.now() - t0,
                skillsUsed: result?.skillsApplied ?? [],
                stopped,
                timedOut,
                usage: result?.usage,
            }

            this.updateHistory(session, params.message, content)
            this.persistToMemory(session, params.message, content, response)

            await this.hookManager?.trigger('message:after', {
                message: params.message,
                sessionKey: session.sessionKey,
                response: content,
            })

            emit({ type: 'done' })
            return response
        } catch (agentError) {
            const { stopped, timedOut } = this.classifyAbort(timeoutSignal)
            const elapsedMs = Math.round(performance.now() - t0)
            const errMsg = timedOut
                ? `Request timed out after ${(elapsedMs / 1000).toFixed(1)}s, please try again`
                : toErrorMessage(agentError)
            if (timedOut) {
                emit({ type: 'progress', step: 'llm', status: 'error', content: `Request timed out after ${(elapsedMs / 1000).toFixed(1)}s` })
            }
            emit({ type: 'done' })
            this.logger.error('Agent execution error', {
                timedOut,
                stopped,
                elapsedMs,
                sessionKey: session.sessionKey,
                channel: session.channel,
                userId: session.userId,
                messagePreview: params.message.slice(0, 120),
                error: toErrorMessage(agentError),
                errorName: (agentError as Error)?.name,
                errorStack: (agentError as Error)?.stack?.split('\n').slice(0, 5).join('\n'),
            })
            return {
                success: false,
                error: errMsg,
                sessionId: session.sessionId,
                processingTime: performance.now() - t0,
                stopped,
                timedOut,
            }
        }
    }
}

const ARGS_VALUE_MAX = 200

function condensedArgs(args: Record<string, unknown> | undefined): Record<string, unknown> | undefined {
    if (!args || Object.keys(args).length === 0) return undefined
    const out: Record<string, unknown> = {}
    for (const [k, v] of Object.entries(args)) {
        if (typeof v === 'string' && v.length > ARGS_VALUE_MAX) {
            out[k] = v.slice(0, ARGS_VALUE_MAX) + '…'
        } else {
            out[k] = v
        }
    }
    return out
}
