// ── Convenience starter ─────────────────────────────────────────────────
export async function startNovaClaw(configPath?: string): Promise<NovaClaw> {
    const novaclaw = await NovaClaw.create(configPath)
    await novaclaw.initialize()
    await novaclaw.start()
    return novaclaw
}

async function main() {
    try {
        const configPath = process.argv[2]
        const novaclaw = await startNovaClaw(configPath)
        gracefulShutdown(() => novaclaw.stop())
    } catch (error) {
        console.error('Failed to start NovaClaw:', toErrorMessage(error))
        process.exit(1)
    }
}

let isMain = false
if (typeof process !== 'undefined' && process.argv[1]) {
    try {
        isMain = import.meta.url === pathToFileURL(process.argv[1]).href
    } catch {
        isMain =
            import.meta.url.endsWith('index') ||
            process.argv[1].replace(/\\/g, '/').endsWith('index')
    }
}
if (isMain) {
    main().catch((error) => {
        console.error('Unhandled error in main:', error)
        process.exit(1)
    })
}
