/**
 * Shared helpers for route handlers to reduce repetitive error-response patterns.
 */

import type { FastifyReply } from 'fastify'
import { ErrorCodes, toErrorMessage } from '../../constants/errors.ts'

export function sendError(
    reply: FastifyReply,
    status: number,
    error: string,
    code: string = ErrorCodes.INTERNAL_ERROR,
): FastifyReply {
    return reply.status(status).send({ success: false, error, code })
}

export function sendNotFound(reply: FastifyReply, message: string): FastifyReply {
    return sendError(reply, 404, message, ErrorCodes.NOT_FOUND)
}

export function sendUnavailable(reply: FastifyReply, message: string): FastifyReply {
    return sendError(reply, 503, message, ErrorCodes.SERVICE_UNAVAILABLE)
}

export function sendValidation(reply: FastifyReply, message: string): FastifyReply {
    return sendError(reply, 400, message, ErrorCodes.VALIDATION_ERROR)
}

export function sendInternalError(reply: FastifyReply, err: unknown): FastifyReply {
    return sendError(reply, 500, toErrorMessage(err), ErrorCodes.INTERNAL_ERROR)
}
