/**
 * DirectorRuntime — implements the Agent interface using a Director-Worker model.
 * The Director receives user messages, decides which worker to delegate to,
 * and aggregates the results.
 */

import { Logger } from '../../../utils/logger.ts'
import { Stopwatch } from '../../../utils/stopwatch.ts'
import type { RuleRegistry } from '../../../registries/rule-registry.ts'
import type { AgentResponse, NovaClawConfig } from '../../apis/index.ts'
import type { SkillsEngine } from '../../skills/skills-engine.ts'
import type { AgentExecutor } from '../agent-executor.ts'
import type { ModelManager } from '../model/model-manager.ts'
import { toolsToOpenAISchema } from '../tool/tool-schema.ts'
import type { Agent, ExecutorParams } from '../types.ts'
import type { AgentPool } from './agent-pool.ts'
import { createDirectorTools } from './director-tools.ts'
import { DirectorPromptBuilder, type DirectorPromptBuildParams } from './director-prompt.ts'

export interface DirectorRuntimeOptions {
    modelManager: ModelManager
    executor: AgentExecutor
    agentPool: AgentPool
    ruleRegistry?: RuleRegistry | null
    skillsEngine?: SkillsEngine | null
    fallbackAgent?: Agent | null
    directResponse?: boolean
}

export class DirectorRuntime implements Agent {
    private logger: Logger
    private modelManager: ModelManager
    private executor: AgentExecutor
    private agentPool: AgentPool
    private ruleRegistry?: RuleRegistry | null
    private skillsEngine?: SkillsEngine | null
    private fallbackAgent?: Agent | null
    private promptBuilder: DirectorPromptBuilder

    constructor(
        config: NovaClawConfig,
        options: DirectorRuntimeOptions,
    ) {
        this.logger = new Logger('DirectorRuntime', config.logging?.level || 'info')
        this.modelManager = options.modelManager
        this.executor = options.executor
        this.agentPool = options.agentPool
        this.ruleRegistry = options.ruleRegistry
        this.skillsEngine = options.skillsEngine
        this.fallbackAgent = options.fallbackAgent
        this.promptBuilder = new DirectorPromptBuilder(
            options.directResponse ?? config.agents?.director?.directResponse ?? true,
        )
    }

    async initialize(): Promise<void> {
        this.logger.info('Initializing...')
        await this.modelManager.initialize()
        this.agentPool.startPeriodicCleanup()
        this.logger.info('Initialized')
    }

    async cleanup(): Promise<void> {
        await this.agentPool.cleanup()
        this.logger.debug('Cleaned up')
    }

    async execute(params: ExecutorParams): Promise<AgentResponse> {
        const sw = Stopwatch.start()

        try {
            // 1. Input rules
            if (this.ruleRegistry) {
                const inputVerdict = this.ruleRegistry.evaluatePhase('input', {
                    type: 'message',
                    message: params.message,
                    channel: params.context.channel,
                    userId: params.context.userId,
                    sessionKey: params.context.sessionKey,
                })
                if (inputVerdict.action === 'reject') {
                    return {
                        content: inputVerdict.reason,
                        toolCalls: [],
                        usage: { totalTokens: 0 },
                        model: this.modelManager.getActiveModel()?.model ?? 'unknown',
                        skillsApplied: [],
                    }
                }
            }

            // 2. Build Director prompt
            const catalog = this.agentPool.getCatalog()
            const skillSummaries = this.skillsEngine
                ? (await this.skillsEngine.listSkills()).map(s => ({ id: s.id, description: s.description }))
                : []

            const promptParams: DirectorPromptBuildParams = {
                agentCatalog: catalog,
                skillSummaries,
                context: {
                    sessionKey: params.context.sessionKey,
                    workspaceDir: params.context.workspaceDir,
                    userId: params.context.userId,
                    channel: params.context.channel,
                },
            }

            const systemPrompt = this.promptBuilder.build(promptParams)
            sw.lap('prompt')

            // 3. Create session and tools
            const session = this.modelManager.createSession()
            await session.updateSystemPrompt(systemPrompt)

            const directorTools = createDirectorTools(this.agentPool, (chunk) => {
                params.onChunk(chunk)
            })

            const toolSchemas = toolsToOpenAISchema(directorTools)
            sw.lap('tools')

            // 4. Run the Director's ReAct loop
            const result = await this.executor.execute({
                session,
                message: params.message,
                tools: toolSchemas,
                executor: {
                    ...params,
                    onChunk: params.onChunk,
                },
            })
            sw.lap('execute')

            // 5. Output rules
            let finalContent = result.content
            if (this.ruleRegistry) {
                const outputVerdict = this.ruleRegistry.evaluatePhase('output', {
                    type: 'output',
                    content: finalContent,
                    channel: params.context.channel,
                    toolCalls: result.toolCalls,
                }, { channel: params.context.channel })

                if (outputVerdict.action === 'rewrite') {
                    finalContent = outputVerdict.content
                } else if (outputVerdict.action === 'transform') {
                    finalContent = outputVerdict.transformer(finalContent)
                } else if (outputVerdict.action === 'reject') {
                    finalContent = outputVerdict.reason
                }
            }

            this.logger.info('Request completed', {
                contentLen: finalContent.length,
                toolCalls: result.toolCalls.length,
                perf: sw.summary(),
            })

            return {
                content: finalContent,
                thinking: result.thinking,
                toolCalls: result.toolCalls,
                usage: result.usage,
                model: this.modelManager.getActiveModel()?.model ?? 'unknown',
                skillsApplied: params.skills.map(s => s.id),
                aborted: result.aborted,
            }
        } catch (error) {
            this.logger.error('Execution failed, trying fallback', error)

            if (this.fallbackAgent) {
                try {
                    return await this.fallbackAgent.execute(params)
                } catch (fallbackError) {
                    this.logger.error('Fallback agent also failed', fallbackError)
                }
            }

            const errorMsg = error instanceof Error ? error.message : String(error)
            return {
                content: `I encountered an error processing your request: ${errorMsg}`,
                toolCalls: [],
                usage: { totalTokens: 0 },
                model: this.modelManager.getActiveModel()?.model ?? 'error',
                skillsApplied: [],
            }
        }
    }

    async internalLLMCall(systemPrompt: string, userContent: string, maxTokens?: number): Promise<string | null> {
        return this.modelManager.internalLLMCall(systemPrompt, userContent, maxTokens)
    }

    setProtocolBridge(bridge: import('../../protocol/protocol-bridge').ProtocolBridge | null): void {
        this.fallbackAgent?.setProtocolBridge?.(bridge)
        this.agentPool.setProtocolBridge(bridge)
    }

    async reinitializeToolRegistry(): Promise<void> {
        await this.fallbackAgent?.reinitializeToolRegistry?.()
    }

    async reinitializeSession(): Promise<void> {
        await this.fallbackAgent?.reinitializeSession?.()
    }

    getStats(): Record<string, unknown> {
        return {
            mode: 'multi-agent',
            activeWorkers: this.agentPool.getActiveWorkerIds(),
            catalogSize: this.agentPool.getCatalog().length,
            model: this.modelManager.getActiveModel()?.model ?? 'unknown',
        }
    }
}
