import type { FastifyInstance } from 'fastify'
import { existsSync } from 'node:fs'
import { mkdir, readdir, readFile, rm, stat, writeFile } from 'node:fs/promises'
import { join } from 'node:path'
import { exec } from 'node:child_process'
import { promisify } from 'node:util'
import { ErrorCodes, toErrorMessage } from '../../constants/errors.ts'
import { NOVACLAW_SKILLS_DIR } from '../../constants/paths.ts'
import {
    SKILL_FILES,
    findSkillFile,
    findRunScript,
    parseFrontmatter,
} from '../../framework/core/skills/skill-parse-utils.ts'
import type { RouteDeps } from './types.ts'

const execAsync = promisify(exec)

const INSTALL_SCRIPTS = ['install.sh', 'setup.sh'] as const

function findInstallScript(dir: string): string | null {
    for (const name of INSTALL_SCRIPTS) {
        if (existsSync(join(dir, name))) return name
    }
    return null
}

interface SkillMeta {
    name: string
    skillFile: string | null
    hasRunScript: boolean
    hasInstallScript: boolean
    description?: string
    tags?: string[]
}

async function parseSkillMeta(skillsDir: string, dirName: string): Promise<SkillMeta> {
    const dir = join(skillsDir, dirName)
    const skillFilePath = findSkillFile(dir)
    const runScript = findRunScript(dir)
    const installScript = findInstallScript(dir)

    const meta: SkillMeta = {
        name: dirName,
        skillFile: skillFilePath ? SKILL_FILES.find(f => skillFilePath.endsWith(f)) ?? null : null,
        hasRunScript: runScript !== null,
        hasInstallScript: installScript !== null,
    }

    if (skillFilePath) {
        try {
            const raw = await readFile(skillFilePath, 'utf-8')
            const { frontmatter } = parseFrontmatter(raw)
            if (frontmatter.description) meta.description = frontmatter.description
            if (frontmatter.tags) meta.tags = frontmatter.tags
        } catch { /* ignore parse errors */ }
    }

    return meta
}

export function registerSkillRoutes(server: FastifyInstance, deps: RouteDeps): void {
    const { logger } = deps

    // ── GET /api/skills — list all installed skills with metadata ─────────

    server.get('/api/skills', async (_req, reply) => {
        try {
            await mkdir(NOVACLAW_SKILLS_DIR, { recursive: true })
            const entries = await readdir(NOVACLAW_SKILLS_DIR, { withFileTypes: true })
            const skills: SkillMeta[] = []

            for (const entry of entries) {
                if (entry.name.startsWith('.') || !entry.isDirectory()) continue
                skills.push(await parseSkillMeta(NOVACLAW_SKILLS_DIR, entry.name))
            }

            reply.send({ skills, skillsDir: NOVACLAW_SKILLS_DIR })
        } catch (err) {
            logger.error('List skills failed', err)
            reply.status(500).send({
                success: false,
                error: toErrorMessage(err),
                code: ErrorCodes.INTERNAL_ERROR,
            })
        }
    })

    // ── GET /api/skills/:name — get skill SKILL.md content ───────────────

    server.get('/api/skills/:name', async (request, reply) => {
        const { name } = request.params as { name: string }
        const safeName = name.replace(/[^a-zA-Z0-9_-]/g, '-')
        if (!safeName) {
            return reply.status(400).send({
                success: false,
                error: 'Invalid skill name',
                code: ErrorCodes.VALIDATION_ERROR,
            })
        }

        try {
            const skillDir = join(NOVACLAW_SKILLS_DIR, safeName)
            const skillFilePath = findSkillFile(skillDir)
            if (!skillFilePath) {
                return reply.status(404).send({
                    success: false,
                    error: 'Skill not found',
                    code: ErrorCodes.NOT_FOUND,
                })
            }

            const content = await readFile(skillFilePath, 'utf-8')

            const files: string[] = []
            try {
                const entries = await readdir(skillDir)
                files.push(...entries.filter(e => !e.startsWith('.')))
            } catch { /* ignore */ }

            const skillFileName = SKILL_FILES.find(f => skillFilePath.endsWith(f)) ?? null
            reply.send({ name: safeName, content, files, skillFile: skillFileName })
        } catch (err: unknown) {
            if (isEnoent(err)) {
                return reply.status(404).send({
                    success: false,
                    error: 'Skill not found',
                    code: ErrorCodes.NOT_FOUND,
                })
            }
            logger.error('Get skill failed', err)
            reply.status(500).send({
                success: false,
                error: toErrorMessage(err),
                code: ErrorCodes.INTERNAL_ERROR,
            })
        }
    })

    // ── POST /api/skills/install — install a skill directory ─────────────

    server.post('/api/skills/install', async (request, reply) => {
        const body = request.body as { name?: string; content?: string; runInstall?: boolean } | undefined
        if (!body?.name || typeof body.content !== 'string') {
            return reply.status(400).send({
                success: false,
                error: 'name and content required',
                code: ErrorCodes.VALIDATION_ERROR,
            })
        }

        const rawName = String(body.name)
            .replace(/\\/g, '/')
            .replace(/^\/+/, '')
            .replace(/\.md$/i, '')
        const dirName = rawName.split('/').pop()?.replace(/[^a-zA-Z0-9_-]/g, '-') ?? 'unnamed-skill'
        const skillDir = join(NOVACLAW_SKILLS_DIR, dirName)
        const skillFile = join(skillDir, 'SKILL.md')

        try {
            await mkdir(skillDir, { recursive: true })
            await writeFile(skillFile, body.content, 'utf-8')
            logger.info('Skill installed', { dirName, skillFile })

            let installOutput: string | null = null
            if (body.runInstall !== false) {
                const installScript = findInstallScript(skillDir)
                if (installScript) {
                    try {
                        const { stdout, stderr } = await execAsync(
                            `bash "${join(skillDir, installScript)}"`,
                            { cwd: skillDir, timeout: 60_000 },
                        )
                        installOutput = (stdout + stderr).trim() || null
                        logger.info('Install script completed', { dirName, installScript })
                    } catch (err) {
                        logger.warn('Install script failed', { dirName, error: toErrorMessage(err) })
                        installOutput = `Install script failed: ${toErrorMessage(err)}`
                    }
                }
            }

            if (deps.skillsEngine && typeof deps.skillsEngine.reloadFromDisk === 'function') {
                await deps.skillsEngine.reloadFromDisk()
                logger.info('Skills engine reloaded after install')
            }

            reply.send({
                success: true,
                path: dirName,
                writtenPath: skillFile,
                ...(installOutput ? { installOutput } : {}),
            })
        } catch (err) {
            logger.error('Skill install failed', err)
            reply.status(500).send({
                success: false,
                error: toErrorMessage(err),
                code: ErrorCodes.INTERNAL_ERROR,
            })
        }
    })

    // ── DELETE /api/skills/:name — remove a skill directory ──────────────

    server.delete('/api/skills/:name', async (request, reply) => {
        const { name } = request.params as { name: string }
        const safeName = name.replace(/[^a-zA-Z0-9_-]/g, '-')
        if (!safeName) {
            return reply.status(400).send({
                success: false,
                error: 'Invalid skill name',
                code: ErrorCodes.VALIDATION_ERROR,
            })
        }

        try {
            const skillDir = join(NOVACLAW_SKILLS_DIR, safeName)
            const dirStat = await stat(skillDir)
            if (!dirStat.isDirectory()) {
                return reply.status(404).send({
                    success: false,
                    error: 'Skill not found',
                    code: ErrorCodes.NOT_FOUND,
                })
            }

            await rm(skillDir, { recursive: true })

            if (deps.skillsEngine && typeof deps.skillsEngine.reloadFromDisk === 'function') {
                await deps.skillsEngine.reloadFromDisk()
            }

            reply.send({ success: true })
        } catch (err: unknown) {
            if (isEnoent(err)) {
                return reply.status(404).send({
                    success: false,
                    error: 'Skill not found',
                    code: ErrorCodes.NOT_FOUND,
                })
            }
            logger.error('Delete skill failed', err)
            reply.status(500).send({
                success: false,
                error: toErrorMessage(err),
                code: ErrorCodes.INTERNAL_ERROR,
            })
        }
    })
}

function isEnoent(err: unknown): boolean {
    return (
        err != null &&
        typeof err === 'object' &&
        'code' in err &&
        (err as { code: string }).code === 'ENOENT'
    )
}
