/**
 * SkillRegistry — in-memory store for loaded skill definitions.
 *
 * Owns the lifecycle of loading skills from disk, excluding/filtering,
 * hot-reloading via chokidar watcher, and platform-gating.
 */

import {watch, type FSWatcher} from 'chokidar'
import {existsSync} from 'node:fs'
import {readdir, stat} from 'node:fs/promises'
import {extname, join} from 'node:path'
import {debounce} from '../../../utils/index.ts'
import {Logger} from '../../../utils/index.ts'
import {resolvePath} from '../../utils/path-resolver.ts'
import type {SkillDefinition} from '../apis/index.ts'
import {toErrorMessage} from '../../../constants/errors.ts'
import {NOVACLAW_SKILLS_DIR, SKILLS_SUBDIR} from '../../../constants/paths.ts'
import {SkillLoader} from './skill-loader.ts'
import {SkillMigrator} from './skill-migrator.ts'

// ── Config helpers ───────────────────────────────────────────────────────

/**
 * Collect skill directories to scan at runtime.
 * Relative paths in config (e.g. './skills/workspace') are resolved against
 * process.cwd() — the project root — NOT workspaceDir (which is the agent
 * data directory, typically ~/.novaclaw/workspace).
 */
function readSkillDirs(config: Record<string, unknown>): string[] {
    const dirs: string[] = [NOVACLAW_SKILLS_DIR]

    const cfg = config.skills as Record<string, unknown> | undefined
    if (!cfg) return dirs

    const baseDir = process.cwd()

    for (const key of ['dirs', 'load'] as const) {
        const source = key === 'dirs'
            ? cfg.dirs
            : (cfg.load as Record<string, unknown>)?.extraDirs
        if (!Array.isArray(source)) continue
        for (const d of source as string[]) {
            const resolved = resolvePath(d, baseDir)
            if (!dirs.includes(resolved)) dirs.push(resolved)
        }
    }

    return dirs
}

/**
 * Find the project-level skills/ directory for bundled skill migration.
 * Uses process.cwd() (project root) to locate it.
 */
function readBundledDirs(config: Record<string, unknown>): string[] {
    const bundledDirs = config.bundledDirs as string[] | undefined
    if (bundledDirs === undefined) {
        const projectDir = process.cwd()
        const bundledDir = join(projectDir, 'skills')
        return existsSync(bundledDir) ? [bundledDir] : []
    }
    return bundledDirs
}

function compileExcludePatterns(patterns: string[]): RegExp[] {
    return patterns
        .filter((p) =>  p.trim())
        .map((p) => {
            const re = p
                .replace(/[.+^${}()|[\]\\]/g, '\\$&')
                .replace(/\*\*/g, '\0')
                .replace(/\*/g, '[^/]*')
                .replace(/\0/g, '.*')
            return new RegExp(re)
        })
}

// ── SkillRegistry ────────────────────────────────────────────────────────

export class SkillRegistry {
    private skills = new Map<string, SkillDefinition>()
    private watcher: FSWatcher | null = null
    private logger: Logger
    private loader: SkillLoader
    private dirs: string[]
    private bundledDirs: string[]
    private excludePatterns: RegExp[]

    constructor(config: Record<string, unknown>, loader: SkillLoader) {
        const logLevel = (config.logging as Record<string, unknown>)?.level as string | undefined
        this.logger = new Logger('SkillRegistry', logLevel ?? 'info')
        this.loader = loader
        this.dirs = readSkillDirs(config)
        this.bundledDirs = readBundledDirs(config)
        const cfg = config.skills as Record<string, unknown> | undefined
        this.excludePatterns = compileExcludePatterns(
            Array.isArray(cfg?.exclude) ? cfg.exclude as string[] : [],
        )
    }

    ensureMigrated(): void {
        const migrator = new SkillMigrator(this.logger)
        migrator.migrate(this.bundledDirs)
    }

    async loadAll(): Promise<void> {
        this.skills.clear()
        for (const dir of this.dirs) await this.scanDirectory(dir)
        this.logger.info(`Loaded ${this.skills.size} skills from ${this.dirs.length} directories`)
    }

    getAll(): SkillDefinition[] {
        return Array.from(this.skills.values())
    }

    getById(id: string): SkillDefinition | undefined {
        return this.skills.get(id)
    }

    listIds(): string[] {
        return Array.from(this.skills.keys())
    }

    addSkills(skills: SkillDefinition[]): number {
        let added = 0
        for (const skill of skills) {
            if (!this.skills.has(skill.id) && this.platformCheck(skill)) {
                this.skills.set(skill.id, skill)
                added++
            }
        }
        return added
    }

    startWatcher(onReload: () => Promise<void>): void {
        if (this.watcher || this.dirs.length === 0) return
        this.watcher = watch(this.dirs, {ignored: /(^|[/\\])\../, persistent: true, depth: 4})

        const debouncedReload = debounce(async (...args: unknown[]) => {
            const [path, event] = args as [string, string]
            this.logger.info(`File ${event}: ${path}, reloading`)
            try {
                await this.loadAll()
                await onReload()
            } catch (error) {
                this.logger.error('Failed to reload skills after file change', error)
            }
        }, 1000)

        this.watcher
            .on('add', (p) => debouncedReload(p, 'added'))
            .on('change', (p) => debouncedReload(p, 'changed'))
            .on('unlink', (p) => debouncedReload(p, 'removed'))
    }

    async stopWatcher(): Promise<void> {
        if (this.watcher) {
            await this.watcher.close()
            this.watcher = null
        }
    }

    // ── Private ──────────────────────────────────────────────────────────

    private async scanDirectory(dir: string): Promise<void> {
        try {
            const dirStat = await stat(dir)
            if (!dirStat.isDirectory()) return
        } catch {
            return
        }
        try {
            const entries = await readdir(dir, {withFileTypes: true})
            for (const entry of entries) {
                if (entry.name.startsWith('.')) continue
                const fullPath = join(dir, entry.name)
                if (entry.isDirectory()) {
                    await this.loadSkillDir(fullPath)
                } else if (entry.isFile() && extname(entry.name).toLowerCase() === '.md') {
                    await this.loadLegacyMd(fullPath)
                }
            }
        } catch (err) {
            this.logger.warn('Failed to scan skills directory', {dir, error: toErrorMessage(err)})
        }
    }

    private async loadSkillDir(dir: string): Promise<void> {
        const hasSubSkills = existsSync(join(dir, SKILLS_SUBDIR))
        const loaded = hasSubSkills
            ? await this.loader.loadSkillPack(dir)
            : [await this.loader.loadFromDir(dir)]

        for (const skill of loaded) {
            if (skill && this.accept(skill)) {
                this.skills.set(skill.id, skill)
            }
        }
    }

    private async loadLegacyMd(filePath: string): Promise<void> {
        const skill = await this.loader.loadLegacyFile(filePath)
        if (skill && this.accept(skill) && !this.skills.has(skill.id)) {
            this.skills.set(skill.id, skill)
        }
    }

    private accept(skill: SkillDefinition): boolean {
        return this.platformCheck(skill) && !this.isExcluded(skill)
    }

    private isExcluded(skill: SkillDefinition): boolean {
        if (this.excludePatterns.length === 0) return false
        return this.excludePatterns.some((re) => re.test(skill.id) || re.test(skill.filePath))
    }

    private platformCheck(skill: SkillDefinition): boolean {
        const platforms = skill.when?.platforms
        if (!platforms || platforms.length === 0) return true
        return platforms.includes(process.platform)
    }
}
