/**
 * Built-in channel plugins — webchat, cli, rest-api implemented as ChannelPlugin.
 */

import type { NovaClawConfig } from '../apis/config.ts'
import type { ChannelPlugin } from './types/plugin.ts'
import type { OutboundDeliveryResult } from './types/context.ts'
import { BUILTIN_CHANNEL_IDS, type BuiltinChannelId } from './constants.ts'

export { BUILTIN_CHANNEL_IDS, type BuiltinChannelId }

// ── Bridge interface for transport layers ──────────────────────────────

export interface ChannelBridge {
    emit(event: string, payload: unknown): void
    setMessageHandler(channelId: string, handler: (message: unknown) => Promise<void>): void
}

// ── WebChat Plugin ─────────────────────────────────────────────────────

export function createWebChatPlugin(bridge?: ChannelBridge): ChannelPlugin {
    return {
        id: 'webchat',
        meta: {
            id: 'webchat',
            label: 'WebChat',
            selectionLabel: 'WebChat (Browser)',
            docsPath: '/channels/webchat',
            blurb: 'Browser-based chat widget for web applications',
            systemImage: 'bubble.left.and.bubble.right',
            order: 0,
        },
        capabilities: {
            chatTypes: ['direct'],
            media: true,
            edit: false,
            reply: true,
        },
        config: {
            listAccountIds: () => ['default'],
            resolveAccount: (_cfg: NovaClawConfig, _accountId?: string | null) => ({
                accountId: 'default',
                enabled: true,
            }),
            isEnabled: () => true,
            isConfigured: () => true,
        },
        gateway: {
            startAccount: async (ctx) => {
                ctx.setStatus({ connected: true, running: true })
                if (bridge) {
                    bridge.setMessageHandler('webchat', async () => {
                        ctx.setStatus({ lastMessageAt: Date.now() })
                    })
                }
                await new Promise<void>((resolve) => {
                    ctx.abortSignal.addEventListener('abort', () => resolve(), { once: true })
                })
            },
            stopAccount: async (ctx) => {
                ctx.setStatus({ connected: false, running: false })
            },
        },
        outbound: {
            deliveryMode: 'direct',
            textChunkLimit: 10000,
            sendText: async (ctx): Promise<OutboundDeliveryResult> => {
                if (bridge) {
                    bridge.emit('webchat:send', { target: ctx.to, content: { text: ctx.text } })
                }
                return { channel: 'webchat', to: ctx.to }
            },
        },
    }
}

