// ── Factory ────────────────────────────────────────────────────────────

export function createBuiltinPlugin(
    channelId: string,
    bridge?: ChannelBridge,
): ChannelPlugin {
    switch (channelId) {
        case 'webchat':
            return createWebChatPlugin(bridge)
        case 'cli':
            return createCLIPlugin(bridge)
        case 'rest-api':
            return createRestApiPlugin(bridge)
        default:
            throw new Error(`Unknown builtin channel: ${channelId}`)
    }
}
