/**
 * Grep/Search tool — search file contents using ripgrep (rg) or fallback to grep.
 */

import { execa } from 'execa'
import { toErrorMessage } from '../../../constants/errors.ts'
import type { Tool, ToolExecutionResult } from '../apis/tool.ts'
import { resolvePathInWorkspace } from './security.ts'

export class GrepTool implements Tool {
    readonly name = 'grep'
    readonly description = 'Search file contents by regex pattern. Parameters: pattern (required), path (optional, defaults to workspace), include (optional glob, e.g. "*.ts"), ignore_case (optional boolean).'
    readonly parameters = {
        type: 'object',
        properties: {
            pattern: { type: 'string', description: 'Regex pattern to search for' },
            path: { type: 'string', description: 'Directory or file to search in (relative to workspace)' },
            include: { type: 'string', description: 'Glob filter (e.g. "*.ts", "*.py")' },
            ignore_case: { type: 'boolean', description: 'Case-insensitive search' },
            max_results: { type: 'number', description: 'Max results to return (default 50)' }
        },
        required: ['pattern']
    }

    constructor(private workspaceDir: string) {}

    validate(args: Record<string, unknown>): string | null {
        const pattern = typeof args?.pattern === 'string' ? args.pattern.trim() : ''
        if (!pattern) return 'Missing parameter: pattern'
        return null
    }

    async execute(args: Record<string, unknown>): Promise<ToolExecutionResult> {
        const err = this.validate(args)
        if (err) return { success: false, error: err }

        const pattern = (args.pattern as string).trim()

        const searchPath = typeof args.path === 'string' && args.path.trim()
            ? resolvePathInWorkspace(args.path.trim(), this.workspaceDir) ?? this.workspaceDir
            : this.workspaceDir

        const include = typeof args.include === 'string' ? args.include.trim() : ''
        const ignoreCase = args.ignore_case === true
        const maxResults = typeof args.max_results === 'number' ? args.max_results : 50

        const rgArgs = this.buildRgArgs(pattern, searchPath, include, ignoreCase, maxResults)

        try {
            const result = await execa('rg', rgArgs, {
                cwd: this.workspaceDir,
                timeout: 15_000,
                reject: false
            })

            if (result.exitCode === 0 || result.exitCode === 1) {
                const output = (result.stdout ?? '').trim()
                const lines = output.split('\n').filter(Boolean)
                return {
                    success: true,
                    matches: lines.length,
                    output: output.slice(0, 32_000),
                    truncated: output.length > 32_000
                }
            }

            return await this.fallbackGrep(pattern, searchPath, include, ignoreCase, maxResults)
        } catch {
            return this.fallbackGrep(pattern, searchPath, include, ignoreCase, maxResults)
        }
    }

    private buildRgArgs(pattern: string, path: string, include: string, ignoreCase: boolean, maxResults: number): string[] {
        const args = [
            '--line-number',
            '--no-heading',
            '--color', 'never',
            '--max-count', String(maxResults)
        ]
        if (ignoreCase) args.push('--ignore-case')
        if (include) args.push('--glob', include)
        args.push('--', pattern, path)
        return args
    }

    private async fallbackGrep(pattern: string, path: string, include: string, ignoreCase: boolean, maxResults: number): Promise<ToolExecutionResult> {
        try {
            const grepArgs = ['-r', '-n', '--color=never']
            if (ignoreCase) grepArgs.push('-i')
            if (include) grepArgs.push('--include', include)
            grepArgs.push('-m', String(maxResults))
            grepArgs.push('--', pattern, path)

            const result = await execa('grep', grepArgs, {
                cwd: this.workspaceDir,
                timeout: 15_000,
                reject: false
            })

            const output = (result.stdout ?? '').trim()
            const lines = output.split('\n').filter(Boolean)
            return {
                success: true,
                matches: lines.length,
                output: output.slice(0, 32_000),
                truncated: output.length > 32_000
            }
        } catch (err) {
            return { success: false, error: `Search failed: ${toErrorMessage(err)}` }
        }
    }
}
