import {homedir} from 'node:os'

export interface TreeNode {
    id: string
    title: string
    summary: string
    children: TreeNode[]
    sourceRange: { start: number; end: number }
}

export interface Chunk {
    chunkId: string
    documentId: string
    text: string
    startLine: number
    endLine: number
    tokenCount: number
    heading: string
    sourcePath: string
    index: number
    siblingCount: number
}

export interface LocalDocumentIndex {
    documentId: string
    source: 'conversation' | 'workspace' | 'upload'
    filePath: string
    title: string
    tree: TreeNode
    chunks: Chunk[]
    indexedAt: number
    contentHash: string
}

export interface LocalMemoryConfig {
    enabled: boolean
    storageDir: string
    indexConversations: boolean
    indexWorkspace: boolean
    maxDocumentSizeMB: number
    maxRetrievalNodes: number
    chunkSize: number
    chunkOverlap: number
    llmReranking: boolean
    queryExpansion?: boolean
    mmrLambda?: number
    contextWindowLines?: number
    graphRag?: {
        enabled: boolean
        entityExtraction?: { batchSize?: number; maxEntitiesPerChunk?: number }
    }
    hybridRetrieval?: {
        bm25Weight?: number
        vectorWeight?: number
        graphWeight?: number
    }
}

export interface LocalRetrievalResult {
    documentId: string
    source: LocalDocumentIndex['source']
    filePath: string
    title: string
    sections: Array<{ nodeId: string; nodeTitle: string; content: string; score?: number }>
}

export interface LocalMemorySearchResult {
    query: string
    results: LocalRetrievalResult[]
    retrievalTimeMs: number
}

/** Read memory config from generic config object (e.g. from project). */
export function readMemoryConfig(config: Record<string, unknown>): LocalMemoryConfig {
    const mem = (config.memory as Record<string, unknown>) ?? {}
    const home = typeof (config as { homedir?: string }).homedir === 'string'
        ? (config as { homedir: string }).homedir
        : homedir()
    const storageDir = typeof mem.storageDir === 'string' ? mem.storageDir : `${home}/.novaclaw/memory`
    return {
        enabled: mem.enabled === true,
        storageDir,
        indexConversations: mem.indexConversations !== false,
        indexWorkspace: mem.indexWorkspace !== false,
        maxDocumentSizeMB: typeof mem.maxDocumentSizeMB === 'number' ? mem.maxDocumentSizeMB : 10,
        maxRetrievalNodes: typeof mem.maxRetrievalNodes === 'number' ? mem.maxRetrievalNodes : 5,
        chunkSize: typeof mem.chunkSize === 'number' ? mem.chunkSize : 512,
        chunkOverlap: typeof mem.chunkOverlap === 'number' ? mem.chunkOverlap : 64,
        llmReranking: mem.llmReranking === true,
        queryExpansion: mem.queryExpansion !== false,
        mmrLambda: typeof mem.mmrLambda === 'number' ? mem.mmrLambda : 0.7,
        contextWindowLines: typeof mem.contextWindowLines === 'number' ? mem.contextWindowLines : 3,
        graphRag: readGraphRagConfig(mem),
        hybridRetrieval: readHybridRetrievalConfig(mem),
    }
}

function readGraphRagConfig(mem: Record<string, unknown>): LocalMemoryConfig['graphRag'] {
    const raw = mem.graphRag as Record<string, unknown> | undefined
    if (!raw || raw.enabled !== true) return undefined
    const extraction = raw.entityExtraction as Record<string, unknown> | undefined
    return {
        enabled: true,
        entityExtraction: {
            batchSize: typeof extraction?.batchSize === 'number' ? extraction.batchSize : 5,
            maxEntitiesPerChunk: typeof extraction?.maxEntitiesPerChunk === 'number' ? extraction.maxEntitiesPerChunk : 10,
        },
    }
}

function readHybridRetrievalConfig(mem: Record<string, unknown>): LocalMemoryConfig['hybridRetrieval'] {
    const raw = mem.hybridRetrieval as Record<string, unknown> | undefined
    if (!raw) return undefined
    return {
        bm25Weight: typeof raw.bm25Weight === 'number' ? raw.bm25Weight : 0.35,
        vectorWeight: typeof raw.vectorWeight === 'number' ? raw.vectorWeight : 0.40,
        graphWeight: typeof raw.graphWeight === 'number' ? raw.graphWeight : 0.25,
    }
}
