/**
 * Shared version resolver — reads version from package.json once and caches it.
 * Used by both NovaClaw core and CLI to avoid duplicating resolution logic.
 */

import { readFileSync } from 'node:fs'
import { readFile } from 'node:fs/promises'
import { dirname, resolve } from 'node:path'
import { fileURLToPath } from 'node:url'

let cached: string | null = null

function resolvePackageJsonPath(): string {
    const thisFile = fileURLToPath(import.meta.url)
    return resolve(dirname(thisFile), '../../package.json')
}

export function getVersionSync(): string {
    if (cached) return cached
    try {
        const pkg = JSON.parse(readFileSync(resolvePackageJsonPath(), 'utf-8')) as { version?: string }
        cached = pkg.version ?? '0.0.0'
    } catch {
        cached = '0.0.0'
    }
    return cached
}

export async function getVersion(): Promise<string> {
    if (cached) return cached
    try {
        const pkg = JSON.parse(await readFile(resolvePackageJsonPath(), 'utf-8')) as { version?: string }
        cached = pkg.version ?? '0.0.0'
    } catch {
        cached = '0.0.0'
    }
    return cached
}
