import type { FastifyInstance } from 'fastify'
import { ErrorCodes, toErrorMessage } from '../../constants/errors.ts'
import type { RouteDeps } from './types.ts'

export function registerConversationRoutes(server: FastifyInstance, deps: RouteDeps): void {
    const { memoryEngine, logger } = deps

    server.get('/api/conversations', async (_req, reply) => {
        if (!memoryEngine) {
            return reply.send({ conversations: [] })
        }
        try {
            const list = await memoryEngine.listConversations()
            reply.send({ conversations: list })
        } catch (err) {
            logger.error('List conversations failed', err)
            reply.status(500).send({
                success: false,
                error: toErrorMessage(err),
                code: ErrorCodes.INTERNAL_ERROR,
            })
        }
    })

    server.post('/api/conversations', async (request, reply) => {
        if (!memoryEngine) {
            return reply.status(503).send({
                success: false,
                error: 'Memory engine not available',
                code: ErrorCodes.INTERNAL_ERROR,
            })
        }
        try {
            const body = (request.body ?? {}) as { userId?: string }
            const conv = await memoryEngine.createConversation(body.userId)
            reply.send(conv)
        } catch (err) {
            logger.error('Create conversation failed', err)
            reply.status(500).send({
                success: false,
                error: toErrorMessage(err),
                code: ErrorCodes.INTERNAL_ERROR,
            })
        }
    })

    server.get('/api/conversations/:id', async (request, reply) => {
        if (!memoryEngine) {
            return reply.status(503).send({
                success: false,
                error: 'Memory engine not available',
                code: ErrorCodes.INTERNAL_ERROR,
            })
        }
        const { id } = request.params as { id: string }
        try {
            const conv = await memoryEngine.getConversation(id)
            if (!conv) {
                return reply.status(404).send({
                    success: false,
                    error: 'Not found',
                    code: ErrorCodes.NOT_FOUND,
                })
            }
            reply.send(conv)
        } catch (err) {
            logger.error('Get conversation failed', err)
            reply.status(500).send({
                success: false,
                error: toErrorMessage(err),
                code: ErrorCodes.INTERNAL_ERROR,
            })
        }
    })

    server.delete('/api/conversations/:id', async (request, reply) => {
        if (!memoryEngine) {
            return reply.status(503).send({
                success: false,
                error: 'Memory engine not available',
                code: ErrorCodes.INTERNAL_ERROR,
            })
        }
        const { id } = request.params as { id: string }
        try {
            const ok = await memoryEngine.deleteConversation(id)
            reply.send({ success: ok })
        } catch (err) {
            logger.error('Delete conversation failed', err)
            reply.status(500).send({
                success: false,
                error: toErrorMessage(err),
                code: ErrorCodes.INTERNAL_ERROR,
            })
        }
    })
}
