/**
 * ChannelPluginLoader — discovers and loads external channel plugins from package manifests.
 *
 * External plugins declare channel info in package.json under the "NovaClaw" key:
 * ```json
 * {
 *   "NovaClaw": {
 *     "channel": {
 *       "id": "msteams",
 *       "label": "Microsoft Teams",
 *       ...
 *     }
 *   }
 * }
 * ```
 */

import { readdirSync, readFileSync, existsSync } from 'node:fs'
import { join } from 'node:path'
import { toErrorMessage } from '../../../constants/errors.ts'
import type { Logger } from '../../utils/logger.ts'
import type { ChannelPlugin } from './types/plugin.ts'

export interface PluginManifest {
    channel?: {
        id: string
        label: string
        selectionLabel?: string
        docsPath?: string
        blurb?: string
        order?: number
    }
}

export class ChannelPluginLoader {
    constructor(private logger: Logger) {}

    /**
     * Load a channel plugin from an npm package.
     * Tries default export, plugin export, or createPlugin factory.
     */
    async loadFromPackage(
        packageName: string,
        channelConfig: Record<string, unknown>,
    ): Promise<ChannelPlugin | null> {
        try {
            const mod = await import(packageName) as {
                default?: ChannelPlugin
                plugin?: ChannelPlugin
                createPlugin?: (config: Record<string, unknown>) => ChannelPlugin
            }

            let plugin: ChannelPlugin | undefined
            if (mod.default && 'id' in mod.default && 'meta' in mod.default) {
                plugin = mod.default as ChannelPlugin
            } else if (mod.plugin && 'id' in mod.plugin && 'meta' in mod.plugin) {
                plugin = mod.plugin as ChannelPlugin
            } else if (typeof mod.createPlugin === 'function') {
                plugin = mod.createPlugin(channelConfig)
            }

            if (plugin) {
                this.logger.info(`Loaded channel plugin: ${packageName}`)
                return plugin
            }

            this.logger.warn(`Package '${packageName}' does not export a valid ChannelPlugin`)
            return null
        } catch (err) {
            const msg = toErrorMessage(err)
            const code = (err as NodeJS.ErrnoException).code
            const isNotFound =
                code === 'ERR_MODULE_NOT_FOUND' ||
                msg.includes('Cannot find module') ||
                msg.includes('Cannot find package')
            if (isNotFound) {
                this.logger.debug(`Channel plugin '${packageName}' not installed; skipping.`)
            } else {
                this.logger.warn(`Failed to load channel plugin '${packageName}': ${msg}`)
            }
            return null
        }
    }

    /**
     * Discover workspace plugins by scanning node_modules for novaclaw-channel-* packages
     * and loading those that declare a NovaClaw.channel manifest.
     */
    async discoverWorkspacePlugins(workspaceDir: string): Promise<ChannelPlugin[]> {
        const plugins: ChannelPlugin[] = []
        const nodeModulesPath = join(workspaceDir, 'node_modules')

        if (!existsSync(nodeModulesPath)) {
            this.logger.debug(`No node_modules at ${nodeModulesPath}; skipping workspace discovery`)
            return plugins
        }

        let entries: string[]
        try {
            entries = readdirSync(nodeModulesPath)
        } catch (err) {
            this.logger.warn(`Cannot read node_modules: ${toErrorMessage(err)}`)
            return plugins
        }

        const channelPackages = entries.filter((name) =>
            name.startsWith('novaclaw-channel-') && name.length > 'novaclaw-channel-'.length,
        )

        for (const pkgName of channelPackages) {
            const pkgJsonPath = join(nodeModulesPath, pkgName, 'package.json')
            if (!existsSync(pkgJsonPath)) continue

            let pkgJson: { NovaClaw?: PluginManifest; [key: string]: unknown }
            try {
                const raw = readFileSync(pkgJsonPath, 'utf-8')
                pkgJson = JSON.parse(raw) as { NovaClaw?: PluginManifest; [key: string]: unknown }
            } catch {
                this.logger.debug(`Invalid package.json in ${pkgName}; skipping`)
                continue
            }

            const manifest = pkgJson.NovaClaw
            if (!manifest?.channel?.id) {
                this.logger.debug(`Package ${pkgName} has no NovaClaw.channel manifest; skipping`)
                continue
            }

            const channelCfg =
                ({} as Record<string, unknown>) /* config lookup would go here */
            const plugin = await this.loadFromPackage(pkgName, channelCfg)
            if (plugin) {
                plugins.push(plugin)
            }
        }

        return plugins
    }
}
