/**
 * NovaClaw core orchestrator — lifecycle management, event wiring, and
 * performance monitoring.
 *
 * Component construction is delegated to `component-factory.ts`.
 * Background indexing is delegated to `background-indexer.ts`.
 */

import { performance } from 'node:perf_hooks'
import { BackgroundIndexer } from './background-indexer.ts'
import { createRuntimeComponents, type RuntimeComponents } from './component-factory.ts'
import { createError, ErrorCodes, toErrorMessage } from './constants/errors.ts'
import { DEFAULT_RSS_LIMIT_MB, HEALTH_CHECK_INTERVAL_MS, RESTART_DELAY_MS } from './constants/timeouts.ts'
import type {
    HealthStatus,
    MessageRequest,
    MessageResponse,
    NovaClawConfig,
    SessionContext,
} from './framework/index.ts'
import {
    bootstrapFramework,
    ChannelPluginRegistry,
    registerDefaultChannels as fwRegisterDefaultChannels,
    registerDefaultMemoryProviders as fwRegisterDefaultMemoryProviders,
    registerDefaultProviders as fwRegisterDefaultProviders,
    registerDefaultRules as fwRegisterDefaultRules,
    MemoryProviderRegistry,
    ProviderRegistry,
    RuleRegistry,
} from './framework/index.ts'
import {
    ConfigLoader,
    EventEmitter,
    formatBytes,
    formatDuration,
    Logger,
    MetricsCollector,
} from './utils/index.ts'
import { validateNovaClawConfig } from './utils/config-validator.ts'
import { getVersionSync } from './utils/version.ts'

// ── Event map ────────────────────────────────────────────────────────────

export type CoreEventMap = {
    'system:initialized': []
    'system:started': []
    'system:stopped': []
    'system:indexing_complete': [{ indexed: number; elapsed: number }]
    'gateway:started': []
    'gateway:stopped': []
    'session:created': [SessionContext]
    'session:destroyed': [SessionContext]
    'message:received': [MessageRequest]
    'message:processed': [MessageRequest, MessageResponse?]
    'skill:loaded': [string]
    'skill:error': [string]
    'channel:connected': [{ channelId: string }]
    'channel:disconnected': [{ channelId: string; reason?: string }]
    'channel:message': [{
        channelId: string
        sessionHints: { sessionKey?: string; userId: string; channel: string; metadata: Record<string, unknown> }
        message: unknown
    }]
    'health:changed': [HealthStatus]
    'performance:stats': [{ system: Record<string, unknown>; components: Record<string, unknown> }]
}

// ── Bootstrap helpers ────────────────────────────────────────────────────

export interface BootstrapOptions {
    config: NovaClawConfig
    providerRegistry?: ProviderRegistry
    ruleRegistry?: RuleRegistry
    memoryProviderRegistry?: MemoryProviderRegistry
    channelPluginRegistry?: ChannelPluginRegistry
}

export const registerDefaultProviders = fwRegisterDefaultProviders
export const registerDefaultRules = fwRegisterDefaultRules
export const registerDefaultMemoryProviders = fwRegisterDefaultMemoryProviders
export const registerDefaultChannels = fwRegisterDefaultChannels

export function bootstrapRegistries(options: BootstrapOptions): void {
    bootstrapFramework({
        providerRegistry: options.providerRegistry,
        ruleRegistry: options.ruleRegistry,
        memoryProviderRegistry: options.memoryProviderRegistry,
        channelPluginRegistry: options.channelPluginRegistry,
    })
}

// ── NovaClaw ─────────────────────────────────────────────────────────────

export class NovaClaw extends EventEmitter<CoreEventMap> {
    private config: NovaClawConfig
    private readonly logger: Logger
    private readonly metrics: MetricsCollector

    private components!: RuntimeComponents
    private indexer: BackgroundIndexer | null = null

    private running = false
    private startTime = 0
    private perfInterval: ReturnType<typeof setInterval> | null = null
    private shutdownHandlers: Array<() => Promise<void>> = []

    constructor(config?: NovaClawConfig) {
        super()
        this.config = config || ({} as NovaClawConfig)
        this.logger = new Logger('NovaClaw', this.config.logging?.level || 'info')
        this.metrics = new MetricsCollector()
        this.rebuildComponents()
    }

    static async create(configPath?: string): Promise<NovaClaw> {
        try {
            const config = await ConfigLoader.load(configPath)
            return new NovaClaw(config)
        } catch (error) {
            const logger = new Logger('NovaClaw')
            logger.error('Failed to load configuration', error)
            throw createError(
                `Failed to initialize NovaClaw: ${toErrorMessage(error)}`,
                ErrorCodes.CONFIG_LOAD_FAILED,
                { cause: error },
            )
        }
    }

    // ── Lifecycle ────────────────────────────────────────────────────────

    async initialize(): Promise<void> {
        const t0 = performance.now()

        try {
            this.logger.info('Initializing...')
            this.validateConfig()

            const { skillsEngine, agent, protocolBridge, memoryEngine, channelHub } = this.components

            await Promise.all([
                skillsEngine.initialize(),
                agent.initialize(),
                protocolBridge.initialize(),
                memoryEngine.initialize(),
            ])
            await channelHub.initialize()

            agent.setProtocolBridge?.(protocolBridge)
            await agent.reinitializeToolRegistry?.()

            await this.components.hookManager.loadFromDirectory(this.config.workspaceDir)
            await this.components.hookManager.trigger('boot')

            this.indexer = new BackgroundIndexer(memoryEngine, this.config, this.logger, (result) => {
                this.emit('system:indexing_complete', result)
            })
            this.indexer.start()

            const elapsed = performance.now() - t0
            this.logger.info(`Initialized (${elapsed.toFixed(0)}ms)`, {
                workspace: this.config.workspaceDir,
                port: this.config.port,
                channels: this.config.channels?.enabled?.length || 0,
            })

            this.emit('system:initialized')
        } catch (error) {
            this.logger.error('Initialization failed', error)
            throw error
        }
    }

    async start(): Promise<void> {
        if (this.running) {
            this.logger.warn('Already running')
            return
        }

        try {
            this.logger.info('Starting...')
            this.startTime = Date.now()

            await this.components.gateway.start()
            this.running = true
            this.startPerformanceMonitoring()

            const bootTime = Date.now() - this.startTime
            this.logger.info(`Started (${bootTime}ms)`)

            this.emit('system:started')
        } catch (error) {
            this.logger.error('Start failed', error)
            this.running = false
            throw error
        }
    }

    async stop(): Promise<void> {
        if (!this.running) {
            this.logger.warn('Not running')
            return
        }

        try {
            this.logger.info('Stopping...')
            this.running = false

            if (this.indexer) await this.indexer.cancel()

            if (this.perfInterval) {
                clearInterval(this.perfInterval)
                this.perfInterval = null
            }

            const { gateway, skillsEngine, agent, channelHub, protocolBridge, memoryEngine } = this.components

            await gateway.stop()
            await Promise.all([
                skillsEngine.cleanup(),
                agent.cleanup(),
                channelHub.cleanup(),
                protocolBridge.cleanup(),
                memoryEngine.cleanup(),
            ])

            for (const handler of this.shutdownHandlers) {
                try {
                    await handler()
                } catch (error) {
                    this.logger.error('Shutdown handler error', error)
                }
            }

            await this.components.hookManager.trigger('shutdown')

            const uptime = Date.now() - this.startTime
            this.logger.info('Stopped', {
                uptime: formatDuration(uptime),
                stats: this.getSystemStats(),
            })
            this.emit('system:stopped')
        } catch (error) {
            this.logger.error('Error during shutdown', error)
            throw error
        }
    }

    async restart(): Promise<void> {
        this.logger.info('Restarting...')
        await this.stop()
        await new Promise((resolve) => setTimeout(resolve, RESTART_DELAY_MS))
        await this.start()
    }

    async reloadConfig(configPath: string): Promise<void> {
        this.config = await ConfigLoader.load(configPath)
        await this.reloadComponents()
    }

    // ── Diagnostics ──────────────────────────────────────────────────────

    getSystemStats() {
        const mem = process.memoryUsage()
        const uptime = this.running ? Date.now() - this.startTime : 0
        const { skillsEngine, agent, channelHub, protocolBridge, memoryEngine } = this.components

        return {
            system: {
                running: this.running,
                uptime: formatDuration(uptime),
                version: getVersionSync(),
                nodeVersion: process.version,
                platform: process.platform,
                arch: process.arch,
            },
            performance: {
                memory: {
                    rss: formatBytes(mem.rss),
                    heapUsed: formatBytes(mem.heapUsed),
                    heapTotal: formatBytes(mem.heapTotal),
                    external: formatBytes(mem.external),
                },
                metrics: this.metrics.getMetrics(),
            },
            components: {
                gateway: { status: 'running' },
                skills: skillsEngine.getStats(),
                agent: agent.getStats(),
                channels: channelHub.getAllChannelStatuses(),
                protocol: protocolBridge.getStats(),
                memory: memoryEngine.getStats(),
            },
        }
    }

    getRunningPort(): number {
        return this.config.port || 3000
    }

    // ── Private ──────────────────────────────────────────────────────────

    private rebuildComponents(): void {
        this.components = createRuntimeComponents(this.config, this.logger)
        this.wireEvents()
    }

    private wireEvents(): void {
        const { gateway, channelHub } = this.components

        gateway.on('message:received', (request) => {
            this.emit('message:received', request)
        })
        gateway.on('message:processed', (request, response) => {
            this.emit('message:processed', request, response)
        })

        channelHub.on('channel:message:routed', (data: {
            channelId: string
            sessionHints: { sessionKey?: string; userId: string; channel: string; metadata: Record<string, unknown> }
            message: unknown
        }) => {
            gateway.emit('channel:message', data)
        })

        this.on('message:processed', (_request, response) => {
            const r = response as { success?: boolean; processingTime?: number } | undefined
            if (r?.success) {
                this.metrics.incrementRequests('success', r.processingTime || 0)
            } else {
                this.metrics.incrementRequests('error', 0)
            }
        })
    }

    private async reloadComponents(): Promise<void> {
        const wasRunning = this.running
        const { gateway, skillsEngine, agent, channelHub, protocolBridge, memoryEngine } = this.components

        if (wasRunning) {
            this.logger.info('Stopping for config reload...')
            await gateway.stop()
            await Promise.all([
                skillsEngine.cleanup(),
                agent.cleanup(),
                channelHub.cleanup(),
                protocolBridge.cleanup(),
                memoryEngine.cleanup(),
            ])
        }

        gateway.removeAllListeners()
        channelHub.removeAllListeners()
        protocolBridge.removeAllListeners()

        this.rebuildComponents()

        if (wasRunning) {
            this.logger.info('Reinitializing after reload...')
            const c = this.components
            await Promise.all([
                c.skillsEngine.initialize(),
                c.agent.initialize(),
                c.protocolBridge.initialize(),
                c.memoryEngine.initialize(),
            ])
            await c.channelHub.initialize()
            c.agent.setProtocolBridge?.(c.protocolBridge)
            await c.agent.reinitializeToolRegistry?.()
            await c.gateway.start()
        }
    }

    private validateConfig(): void {
        const result = validateNovaClawConfig(this.config)
        for (const d of result.diagnostics) {
            if (d.level === 'warning') {
                this.logger.warn(d.message)
            }
        }
        if (!result.valid) {
            const errors = result.diagnostics
                .filter((d) => d.level === 'error')
                .map((d) => d.message)
                .join('; ')
            throw createError(errors, ErrorCodes.CONFIG_INVALID)
        }
    }

    private startPerformanceMonitoring(): void {
        if (!this.config.monitoring?.enabled) return

        const interval = this.config.monitoring.health?.interval || HEALTH_CHECK_INTERVAL_MS

        this.perfInterval = setInterval(() => {
            try {
                const stats = this.getSystemStats()
                this.emit('performance:stats', stats)

                const rssMB = process.memoryUsage().rss / (1024 * 1024)
                const rssLimitMB = this.config.monitoring?.rssLimitMB ?? DEFAULT_RSS_LIMIT_MB
                if (rssMB > rssLimitMB) {
                    this.logger.warn('High memory usage', {
                        rss: formatBytes(process.memoryUsage().rss),
                        limitMB: rssLimitMB,
                    })
                }
            } catch (error) {
                this.logger.error('Performance monitoring error', error)
            }
        }, interval)
    }
}
