import type { FastifyInstance, FastifyReply, FastifyRequest } from 'fastify'
import type { MessageRequest, SessionContext, StreamChunk } from '../../framework/index.ts'
import { ApiChatRequestSchema } from '../../framework/index.ts'
import { ErrorCodes, toErrorMessage } from '../../constants/errors.ts'
import type { RouteDeps } from './types.ts'

function wantsSSE(request: FastifyRequest): boolean {
    const q = (request.query as Record<string, string>)?.stream
    if (q === 'true' || q === '1') return true
    return request.headers.accept?.includes('text/event-stream') ?? false
}

export function registerChatRoutes(server: FastifyInstance, deps: RouteDeps): void {
    const { sessionManager, metrics, logger, wsHandler } = deps

    server.post('/api/chat', async (request: FastifyRequest, reply: FastifyReply) => {
        const t0 = performance.now()
        try {
            if (!deps.agent || !wsHandler) {
                return reply.status(503).send({
                    success: false,
                    error: 'Chat service is not ready yet',
                    code: ErrorCodes.SERVICE_UNAVAILABLE,
                })
            }

            const parsed = ApiChatRequestSchema.safeParse(request.body ?? {})
            if (!parsed.success) {
                const first = parsed.error.issues[0]
                const msg = first
                    ? `${first.path.join('.')}: ${first.message}`
                    : 'Invalid request body'
                return reply.status(400).send({
                    success: false,
                    error: msg,
                    code: ErrorCodes.VALIDATION_ERROR,
                })
            }

            const body = parsed.data as MessageRequest
            let ctx: SessionContext | undefined = sessionManager.get(body.sessionKey)
            if (!ctx) {
                ctx = await sessionManager.createSession({
                    userId: (request.headers['x-user-id'] as string) || 'anonymous',
                    channel: 'rest-api',
                }, body.sessionKey || undefined)
            }

            if (wantsSSE(request)) {
                return handleSSE(reply, wsHandler, body, ctx, t0, metrics, logger)
            }

            const response = await wsHandler.processMessage({
                ...body,
                sessionKey: ctx.sessionKey,
            })
            const elapsed = performance.now() - t0
            metrics.incrementRequests(response.success ? 'success' : 'error', elapsed)
            return response
        } catch (error) {
            logger.error('REST chat error', error)
            metrics.incrementRequests('error', 0)
            return reply.status(500).send({
                success: false,
                error: toErrorMessage(error),
                code: ErrorCodes.INTERNAL_ERROR,
            })
        }
    })
}

async function handleSSE(
    reply: FastifyReply,
    wsHandler: RouteDeps['wsHandler'],
    body: MessageRequest,
    ctx: SessionContext,
    t0: number,
    metrics: RouteDeps['metrics'],
    logger: RouteDeps['logger'],
): Promise<void> {
    reply.raw.writeHead(200, {
        'Content-Type': 'text/event-stream',
        'Cache-Control': 'no-cache',
        'Connection': 'keep-alive',
        'X-Accel-Buffering': 'no',
    })

    const write = (data: string) => {
        if (!reply.raw.destroyed) reply.raw.write(`data: ${data}\n\n`)
    }

    const onChunk = (chunk: StreamChunk) => {
        write(JSON.stringify(chunk))
    }

    try {
        const response = await wsHandler.processMessage(
            { ...body, sessionKey: ctx.sessionKey },
            onChunk,
        )
        const elapsed = performance.now() - t0
        metrics.incrementRequests(response.success ? 'success' : 'error', elapsed)
    } catch (error) {
        logger.error('SSE chat error', error)
        write(JSON.stringify({ type: 'error', error: toErrorMessage(error) }))
        write('[DONE]')
        metrics.incrementRequests('error', 0)
    } finally {
        if (!reply.raw.destroyed) reply.raw.end()
    }
}
