import { formatToolResultForDisplay } from '../tools/format-result.ts'
import { t } from '../../i18n/index.ts'
import { Logger } from '../../utils/logger.ts'
import type { TokenUsage, ToolCall } from '../apis/index.ts'
import { stripThinkTags } from './stream/stream-parser.ts'
import { StreamConsumer } from './stream/stream-consumer.ts'
import type { ToolRegistry } from './tool/tool-registry.ts'
import type { AgentTurnResult, ChatMessage, ExecutorParams, LLMSessionInterface, ToolSchema } from './types.ts'

/**
 * ReAct (Reason + Act) agent executor.
 *
 * Agentic loop:
 *   1. Send context to LLM
 *   2. If LLM returns tool calls -> execute tools -> feed results back -> repeat
 *   3. If LLM returns final text -> return to user
 *
 * The executor does NOT classify abort reasons (timeout vs user stop).
 * It reports `aborted: true` and lets the caller decide how to present it.
 */
export interface AgentExecutorOptions {
    maxTurns?: number
    toolResultContextMax?: number
}

interface ReActState {
    content: string
    thinking: string
    allToolCalls: ToolCall[]
    usage: TokenUsage
    aborted: boolean
    lastSuccessfulToolResult: string
    conversationMessages: ChatMessage[]
}

export class AgentExecutor {
    private readonly maxTurns: number
    private readonly toolResultContextMax: number
    private readonly streamConsumer = new StreamConsumer()
    private logger: Logger

    constructor(
        private toolRegistry: ToolRegistry,
        logLevel: string = 'info',
        options: AgentExecutorOptions = {},
    ) {
        this.maxTurns = options.maxTurns ?? 10
        this.toolResultContextMax = options.toolResultContextMax ?? 16_000
        this.logger = new Logger('AgentExecutor', logLevel)
    }

    async execute(params: {
        session: LLMSessionInterface
        message: string
        tools: ToolSchema[]
        executor: ExecutorParams
    }): Promise<AgentTurnResult> {
        const state = await this.runReActLoop(params)
        this.buildFallbackContent(state, params.executor.onChunk)

        return {
            content: state.content,
            thinking: state.thinking || undefined,
            toolCalls: state.allToolCalls,
            usage: state.usage,
            aborted: state.aborted,
        }
    }

    // ── ReAct Loop ──────────────────────────────────────────────────────

    private async runReActLoop(params: {
        session: LLMSessionInterface
        message: string
        tools: ToolSchema[]
        executor: ExecutorParams
    }): Promise<ReActState> {
        const { session, message, tools, executor } = params
        const { onChunk, abortSignal, context } = executor

        const state: ReActState = {
            content: '',
            thinking: '',
            allToolCalls: [],
            usage: { totalTokens: 0 },
            aborted: false,
            lastSuccessfulToolResult: '',
            conversationMessages: [{ role: 'user', content: message }],
        }

        for (let turn = 0; turn < this.maxTurns; turn++) {
            if (abortSignal?.aborted) {
                state.aborted = true
                break
            }

            if (turn > 0) {
                onChunk({ type: 'progress', step: 'llm', status: 'running', content: t('agent.thinking_turn', turn + 1) })
            }


            const stream = session.processMessageStream({
                message: turn === 0 ? message : '',
                images: turn === 0 ? executor.images : undefined,
                tools,
                rawExtraMessages: turn > 0 ? state.conversationMessages : undefined,
                context: {
                    sessionKey: context.sessionKey,
                    workspaceDir: context.workspaceDir,
                    userId: context.userId,
                    channel: context.channel,
                    skillsContext: executor.skills.map(s => s.id),
                    messageHistory: context.messageHistory ?? [],
                },
                abortSignal,
            })

            const turnResult = await this.streamConsumer.consume(stream, {
                onText: (content) => {
                    state.content += content
                    onChunk({ type: 'text', content })
                },
                onThinking: (content) => {
                    state.thinking += content
                    onChunk({ type: 'thinking', content })
                },
                abortSignal,
            })

            state.usage = {
                totalTokens: (state.usage.totalTokens || 0) + (turnResult.turnUsage.totalTokens || 0),
                inputTokens: (state.usage.inputTokens || 0) + (turnResult.turnUsage.inputTokens || 0),
                outputTokens: (state.usage.outputTokens || 0) + (turnResult.turnUsage.outputTokens || 0),
            }
            state.aborted = turnResult.aborted

            if (turnResult.streamError && !turnResult.turnContent && turnResult.turnToolCalls.length === 0) {
                this.logger.warn('Stream error with no content, propagating', { error: turnResult.streamError })
                throw new Error(turnResult.streamError)
            }

            if (state.aborted || turnResult.turnToolCalls.length === 0) {
                break
            }

            state.conversationMessages.push({
                role: 'assistant',
                content: turnResult.turnContent || undefined,
                tool_calls: turnResult.turnToolCalls.map(tc => ({
                    id: tc.id,
                    type: 'function' as const,
                    function: { name: tc.name, arguments: JSON.stringify(tc.args ?? {}) },
                })),
            })

            await this.executeToolBatch(turnResult.turnToolCalls, state, executor)

      }

       return state
    }

    // ── Tool Batch Execution ────────────────────────────────────────────

    private async executeToolBatch(
        toolCalls: ToolCall[],
        state: ReActState,
        executor: ExecutorParams,
    ): Promise<void> {
        const { onChunk, context } = executor

        for (const tc of toolCalls) {
            state.allToolCalls.push(tc)
            onChunk({
                type: 'progress',
                step: 'tool',
                status: 'running',
                content: t('agent.calling_tool', tc.name),
                tool: tc.name,
            })
        }

        const execPromises = toolCalls.map(tc => {
            const execArgs = { ...tc.args }
            if (tc.name === 'exec' && context.workspaceDir) execArgs.cwd = context.workspaceDir
            return this.toolRegistry.executeTool(tc.name, execArgs, context, executor.abortSignal)
        })

        const execResults = await Promise.allSettled(execPromises)
        for (let i = 0; i < toolCalls.length; i++) {
            const tc = toolCalls[i]!
            const settled = execResults[i]!
            const execResult = settled.status === 'fulfilled'
                ? settled.value
                : { error: settled.reason instanceof Error ? settled.reason.message : String(settled.reason) }

            tc.status = execResult.error ? 'error' : 'success'
            tc.result = execResult.result
            tc.error = execResult.error

            onChunk(execResult.error
                ? { type: 'progress', step: 'tool', status: 'error', content: t('agent.tool_error', tc.name), tool: tc.name }
                : { type: 'progress', step: 'tool', status: 'completed', content: t('agent.tool_success', tc.name), tool: tc.name },
            )
            onChunk({
                type: 'tool',
                tool: tc.name,
                args: tc.args,
                status: 'completed',
                result: execResult.result,
                error: execResult.error,
            })

            let resultText: string
            if (execResult.error) {
                resultText = `Error: ${execResult.error}`
            } else {
                const rawDisplay = formatToolResultForDisplay(tc.name, execResult.result)
                resultText = rawDisplay
                state.lastSuccessfulToolResult = rawDisplay
            }

            state.conversationMessages.push({
                role: 'tool',
                tool_call_id: tc.id,
                content: resultText.slice(0, this.toolResultContextMax),
            })
        }
    }

    // ── Fallback Content ────────────────────────────────────────────────

    private buildFallbackContent(state: ReActState, onChunk: ExecutorParams['onChunk']): void {
        if (state.aborted) return

        if (state.allToolCalls.length > 0) {
            const visibleBody = stripThinkTags(state.content)
            if (!visibleBody) {
                let fallback = ''
                if (state.lastSuccessfulToolResult) {
                    fallback = state.lastSuccessfulToolResult
                } else {
                    const lastErr = state.allToolCalls.filter(tc => tc.error).pop()
                    if (lastErr) {
                        fallback = t('agent.tool_exec_error', lastErr.name)
                    }
                }
                if (fallback) {
                    state.content += '\n\n' + fallback
                    onChunk({ type: 'text', content: '\n\n' + fallback })
                }
            }
        }

        if (state.allToolCalls.length === 0) {
            const visibleBody = stripThinkTags(state.content)
            if (!visibleBody.trim()) {
                const emptyMsg = t('agent.empty_response')
                this.logger.warn('Empty response from LLM')
                state.content = emptyMsg
                onChunk({ type: 'text', content: emptyMsg })
                onChunk({ type: 'error', error: emptyMsg })
            }
        }
    }

}
