/**
 * Shared SSE stream reader — extracts lines from an HTTP response body
 * with stall-timeout protection and incremental (indexOf-based) parsing.
 */

import { LLM_STREAM_STALL_MS } from '../../../constants/timeouts.ts'

export interface StreamStats {
    firstReadTime: number | null
    readCount: number
    totalBytes: number
}

export interface ReadResponseLinesOptions {
    /** Time (ms) without yielding a non-empty line before calling onStall. */
    stallTimeoutMs?: number
    onStall?: () => void
    stats?: StreamStats
}

/**
 * Async generator that reads an HTTP response body via its reader and
 * yields every non-empty line. Handles:
 *  - Stall detection — resets only on non-comment lines (`data:`, event types,
 *    plain JSON); SSE comments (`:…`) and empty lines do NOT reset the timer
 *  - Incremental line extraction with indexOf (no array allocation per read)
 *  - Reader cleanup (releaseLock) in `finally`
 *  - Optional stat tracking via a mutable `stats` object
 */
export async function* readResponseLines(
    reader: ReadableStreamDefaultReader<Uint8Array>,
    options: ReadResponseLinesOptions = {},
): AsyncGenerator<string> {
    const { stallTimeoutMs = LLM_STREAM_STALL_MS, onStall, stats } = options
    const decoder = new TextDecoder()
    let buffer = ''

    let stallTimer: ReturnType<typeof setTimeout> | null = null
    const resetStall = () => {
        if (stallTimer) clearTimeout(stallTimer)
        if (onStall) stallTimer = setTimeout(onStall, stallTimeoutMs)
    }

    try {
        resetStall()
        for (;;) {
            const { done, value } = await reader.read()
            if (done) break

            if (stats) {
                stats.readCount++
                if (stats.firstReadTime === null) stats.firstReadTime = performance.now()
                if (value) stats.totalBytes += value.byteLength
            }

            buffer += decoder.decode(value, { stream: true })

            let start = 0
            let nlIdx: number
            while ((nlIdx = buffer.indexOf('\n', start)) !== -1) {
                const line = buffer.substring(start, nlIdx)
                start = nlIdx + 1
                if (line) {
                    // SSE comments (`:ping`, `:heartbeat`) keep the TCP connection alive
                    // but carry no useful payload — don't let them reset the stall timer.
                    if (line.charCodeAt(0) !== 58 /* ':' */) resetStall()
                    yield line
                }
            }
            if (start > 0) buffer = buffer.substring(start)
        }
        if (buffer.trim()) yield buffer
    } finally {
        if (stallTimer) clearTimeout(stallTimer)
        reader.releaseLock()
    }
}

/**
 * Parse an SSE line. Returns the data payload string, or `null` for
 * non-data lines, comments, and the `[DONE]` sentinel.
 */
export function parseSSEData(line: string): string | null {
    if (!line.startsWith('data: ')) return null
    const data = line.substring(6).trim()
    if (!data || data === '[DONE]') return null
    return data
}
