/**
 * Rule registry — register rules for tool/channel policy.
 * Wraps RuleEngine so the same rules can be shared (e.g. with ToolRegistry).
 */

import type { IRule, RuleContext, RulePhase, RuleVerdict } from '../core/apis/rule.ts'
import { RuleEngine } from '../core/rules/rule-engine.ts'

export interface RuleRegistryOptions {
    rules?: IRule[]
}

export class RuleRegistry {
    private engine: RuleEngine

    constructor(options: RuleRegistryOptions = {}) {
        this.engine = new RuleEngine({ rules: options.rules })
    }

    register(rule: IRule): void {
        this.engine.register(rule)
    }

    unregister(ruleId: string): boolean {
        return this.engine.unregister(ruleId)
    }

    get(id: string): IRule | undefined {
        return this.engine.get(id)
    }

    listIds(): string[] {
        return this.engine.listIds()
    }

    getAll(): IRule[] {
        return this.engine.getAll()
    }

    getRulesByPhase(phase: RulePhase): IRule[] {
        return this.engine.getRulesByPhase(phase)
    }

    evaluate(ctx: RuleContext): RuleVerdict {
        return this.engine.evaluate(ctx)
    }

    evaluatePhase(
        phase: RulePhase,
        ctx: RuleContext,
        scope?: { agentId?: string; channel?: string },
    ): RuleVerdict {
        return this.engine.evaluatePhase(phase, ctx, scope)
    }

    getEngine(): RuleEngine {
        return this.engine
    }
}
