/**
 * Mock session factory — creates a fake LLM session for testing
 * and fallback when no provider is configured.
 */

import crypto from 'node:crypto'
import { t } from '../../../i18n/index.ts'
import type { LLMSessionInterface, MessageStreamParams, StreamingChunk } from '../types.ts'

export function createMockSession(modelName: string = 'mock'): LLMSessionInterface {
    const sessionId = crypto.randomUUID()

    return {
        sessionId,
        async updateSystemPrompt() {
        },
        getActiveModel() {
            return modelName
        },
        async close() {
        },
        async* processMessageStream(params: MessageStreamParams): AsyncGenerator<StreamingChunk> {
            const msg = params.message.trim()
            const preview = msg.length > 40 ? msg.slice(0, 40) + '…' : msg
            yield { type: 'content', content: t('mock.processing_prefix') }
            await new Promise(r => setTimeout(r, 80))
            yield { type: 'content', content: preview }
            yield { type: 'content', content: '…\n\n' }
            await new Promise(r => setTimeout(r, 150))

            const reply = msg
                ? t('mock.processing', preview)
                : t('mock.prompt')
            for (const part of reply) {
                yield { type: 'content', content: part }
                await new Promise(r => setTimeout(r, 20))
            }
            yield { type: 'usage', usage: { totalTokens: 100, inputTokens: 20, outputTokens: 80 } }
        }
    }
}
