import type { Chunk } from '../types.ts'
import type { GraphRetriever } from '../graph/graph-retriever.ts'
import type { HybridRetrievalConfig } from '../graph/types.ts'
import { rrfFusion, type RankedItem, type FusionWeights } from './rrf-fusion.ts'

export type BM25SearchFn = (query: string, limit: number) => Chunk[]

export class HybridRetriever {
    constructor(
        private bm25Search: BM25SearchFn,
        private graphRetriever: GraphRetriever | null,
        private config: HybridRetrievalConfig
    ) {}

    retrieve(query: string, limit: number = 10): RankedItem[] {
        const resultSets: Array<{ source: string; items: RankedItem[] }> = []

        const bm25Chunks = this.bm25Search(query, limit * 2)
        const bm25Items: RankedItem[] = bm25Chunks.map((chunk, i) => ({
            id: chunk.chunkId,
            score: 1 / (i + 1),
            source: 'bm25',
            content: chunk.text,
            metadata: {
                documentId: chunk.documentId,
                sourcePath: chunk.sourcePath,
                heading: chunk.heading,
            },
        }))
        if (bm25Items.length > 0) {
            resultSets.push({ source: 'bm25', items: bm25Items })
        }

        if (this.graphRetriever) {
            const graphResults = this.graphRetriever.query(query, limit * 2)
            const graphItems: RankedItem[] = graphResults.map((r) => ({
                id: r.entityId,
                score: r.score,
                source: 'graph',
                content: `${r.entityName}: ${r.relations.map((rel) => `${rel.relationType} ${rel.targetEntityName}`).join(', ')}`,
                metadata: {
                    entityName: r.entityName,
                    entityType: r.entityType,
                    sourceChunkIds: r.sourceChunkIds,
                },
            }))
            if (graphItems.length > 0) {
                resultSets.push({ source: 'graph', items: graphItems })
            }
        }

        const weights = this.normalizeWeights()
        const fused = rrfFusion(resultSets, weights)
        return fused.slice(0, limit)
    }

    private normalizeWeights(): FusionWeights {
        const { bm25Weight, graphWeight } = this.config
        const total = bm25Weight + graphWeight
        if (total <= 0) {
            return { bm25: 0.5, vector: 0, graph: 0.5 }
        }
        return {
            bm25: bm25Weight / total,
            vector: 0,
            graph: graphWeight / total,
        }
    }
}
