import { z } from 'zod'
import { MESSAGE_TIMEOUT_MS } from '../../constants/timeouts.ts'

export const ModelProviderConfigSchema = z.object({
    apiKey: z.string().optional(),
    baseUrl: z.string().optional(),
    model: z.string().optional(),
    timeout: z.number().positive().optional(),
    temperature: z.number().min(0).max(2).optional(),
    topP: z.number().min(0).max(1).optional(),
    enableThinking: z.boolean().optional(),
    frequencyPenalty: z.number().optional(),
    presencePenalty: z.number().optional(),
}).passthrough()

export const ModelsConfigSchema = z.object({
    primary: z.string(),
    fallback: z.string(),
    local: z.string().optional(),
    providers: z.record(ModelProviderConfigSchema).default({})
})

export const SkillsConfigSchema = z.object({
    dirs: z.array(z.string()).default(['./skills/workspace', './skills/managed', './skills/bundled']),
    include: z.array(z.string()).optional(),
    exclude: z.array(z.string()).optional(),
}).passthrough()

export const SandboxConfigSchema = z.object({
    enabled: z.boolean().default(true),
    docker: z.boolean().default(false),
    timeout: z.number().positive().default(30000),
    maxMemory: z.string().default('256MB'),
    allowedCommands: z.array(z.string()).default([])
})

export const PermissionsConfigSchema = z.object({
    fileSystem: z.object({
        read: z.boolean().default(true),
        write: z.boolean().default(true),
        execute: z.boolean().default(false),
        delete: z.boolean().default(false)
    }).default({}),
    network: z.object({
        http: z.boolean().default(true),
        https: z.boolean().default(true),
        websocket: z.boolean().default(true)
    }).default({}),
    system: z.object({
        shell: z.boolean().default(false),
        process: z.boolean().default(false)
    }).default({})
})

export const ToolsConfigSchema = z.object({
    policy: z.enum(['minimal', 'coding', 'messaging', 'full', 'balanced']).default('balanced'),
    sandbox: SandboxConfigSchema.default({}),
    permissions: PermissionsConfigSchema.default({}),
    extensions: z.array(z.object({
        type: z.enum(['mcp', 'http', 'custom']),
        name: z.string().optional(),
        endpoint: z.string().optional(),
        url: z.string().optional(),
        method: z.string().optional()
    }).passthrough()).optional(),
    execUseLoginShell: z.boolean().optional(),
    formatResultWithLLM: z.boolean().optional(),
    autoExecuteParsedCalls: z.boolean().optional(),
    allowExecInChannels: z.array(z.string()).optional()
})

export const SecurityConfigSchema = z.object({
    auth: z.object({
        enabled: z.boolean().default(false),
        type: z.enum(['none', 'basic', 'bearer', 'oauth']).default('none'),
        token: z.string().optional()
    }).default({}),
    rateLimit: z.object({
        enabled: z.boolean().default(false),
        windowMs: z.number().positive().default(60000),
        maxRequests: z.number().positive().default(100)
    }).default({}),
    cors: z.object({
        enabled: z.boolean().default(true),
        origins: z.array(z.string()).default(['*']),
        credentials: z.boolean().default(false)
    }).default({})
})

export const PerformanceConfigSchema = z.object({
    skillsCache: z.object({ maxSize: z.number().default(100), ttl: z.number().default(300) }).default({}),
    semanticSearch: z.object({
        enabled: z.boolean().default(true),
        threshold: z.number().min(0).max(1).default(0.7),
        maxResults: z.number().default(5),
        embedModel: z.string().optional()
    }).default({}),
    streaming: z.object({
        enabled: z.boolean().default(true),
        chunkSize: z.number().default(256),
        maxConcurrent: z.number().default(4)
    }).default({}),
    memory: z.object({
        maxHeapSize: z.string().default('512MB'),
        gcInterval: z.number().default(10000),
        sessionTimeout: z.number().default(300000)
    }).default({})
})

export const GraphRagConfigSchema = z.object({
    enabled: z.boolean().default(false),
    entityExtraction: z.object({
        enabled: z.boolean().default(true),
        model: z.string().optional(),
        batchSize: z.number().positive().default(5),
        maxEntitiesPerChunk: z.number().positive().default(10),
    }).default({}),
    communityDetection: z.object({
        enabled: z.boolean().default(true),
        algorithm: z.enum(['leiden', 'louvain']).default('leiden'),
        resolution: z.number().positive().default(1.0),
        levels: z.number().positive().default(2),
    }).default({}),
    queryStrategy: z.object({
        directorLevel: z.enum(['community', 'entity', 'chunk']).default('community'),
        workerLevel: z.enum(['chunk', 'entity']).default('chunk'),
    }).default({}),
}).default({})

export const HybridRetrievalConfigSchema = z.object({
    bm25Weight: z.number().min(0).max(1).default(0.35),
    vectorWeight: z.number().min(0).max(1).default(0.40),
    graphWeight: z.number().min(0).max(1).default(0.25),
    rerankWithLLM: z.boolean().default(true),
}).default({})

export const MemoryConfigSchema = z.object({
    provider: z.string().default('local'),
    enabled: z.boolean().default(false),
    storageDir: z.string().default('~/.novaclaw/memory'),
    indexConversations: z.boolean().default(true),
    indexWorkspace: z.boolean().default(true),
    maxDocumentSizeMB: z.number().positive().default(10),
    maxRetrievalNodes: z.number().positive().default(5),
    chunkSize: z.number().positive().optional(),
    chunkOverlap: z.number().nonnegative().optional(),
    llmReranking: z.boolean().optional(),
    queryExpansion: z.boolean().optional(),
    mmrLambda: z.number().min(0).max(1).optional(),
    contextWindowLines: z.number().positive().optional(),
    graphRag: GraphRagConfigSchema.optional(),
    hybridRetrieval: HybridRetrievalConfigSchema.optional(),
})

export const ChannelAccountConfigSchema = z.object({
    enabled: z.boolean().optional(),
}).passthrough()

export const ChannelDetailConfigSchema = z.object({
    accounts: z.record(ChannelAccountConfigSchema).optional(),
    dmPolicy: z.enum(['open', 'closed', 'allowlist']).optional(),
    allowFrom: z.array(z.string()).optional(),
}).passthrough()

export const ChannelsConfigSchema = z.object({
    enabled: z.array(z.string()).default([]),
}).passthrough().default({})

export const PluginEntrySchema = z.object({
    enabled: z.boolean(),
})

export const PluginInstallSchema = z.object({
    source: z.string(),
    sourcePath: z.string().optional(),
    installPath: z.string().optional(),
    version: z.string().optional(),
    installedAt: z.string().optional(),
})

export const PluginsConfigSchema = z.object({
    entries: z.record(PluginEntrySchema).optional(),
    installs: z.record(PluginInstallSchema).optional(),
    allow: z.array(z.string()).optional(),
})

export const UserConfigMetaSchema = z.object({
    lastTouchedVersion: z.string().optional(),
    lastTouchedAt: z.string().optional(),
})

export const UserConfigSchema = z.object({
    meta: UserConfigMetaSchema.optional(),
    channels: z.record(ChannelDetailConfigSchema).optional(),
    plugins: PluginsConfigSchema.optional(),
})

export const AgentConfigSchema = z.object({
    maxTurns: z.number().positive().default(10),
    toolResultContextMax: z.number().positive().default(16000),
    messageTimeoutMs: z.number().positive().default(MESSAGE_TIMEOUT_MS),
})

export const WorkerOverrideConfigSchema = z.object({
    enabled: z.boolean().default(true),
    model: z.string().optional(),
    maxTurns: z.number().positive().optional(),
    tools: z.array(z.string()).optional(),
    skillDomains: z.array(z.string()).optional(),
}).passthrough()

export const MultiAgentConfigSchema = z.object({
    mode: z.enum(['single', 'multi']).default('single'),
    director: z.object({
        model: z.string().optional(),
        maxTurns: z.number().positive().default(5),
        directResponse: z.boolean().default(true),
    }).default({}),
    workers: z.record(WorkerOverrideConfigSchema).optional(),
    pool: z.object({
        maxIdleTime: z.number().positive().default(300000),
        maxConcurrent: z.number().positive().default(5),
    }).default({}),
})

export const RulesBuiltinConfigSchema = z.object({
    'exec-channel-allowlist': z.boolean().default(true),
    'content-safety': z.boolean().default(true),
    'input-sanitize': z.boolean().default(true),
    'format-channel-adapt': z.boolean().default(true),
    'citation-enforce': z.boolean().default(false),
    'thinking-strip': z.boolean().default(true),
}).passthrough().default({})

export const RulesConfigSchema = z.object({
    builtin: RulesBuiltinConfigSchema.optional(),
    output: z.object({
        channelFormats: z.record(z.object({
            format: z.string().optional(),
            maxLength: z.number().positive().optional(),
        }).passthrough()).optional(),
        tone: z.string().optional(),
        piiFilter: z.object({
            enabled: z.boolean().default(false),
        }).optional(),
    }).optional(),
    custom: z.array(z.object({
        path: z.string(),
    }).passthrough()).optional(),
})

export const MCPServerRequestInitSchema = z.object({
    headers: z.record(z.string(), z.string()).optional(),
    method: z.enum(['GET', 'HEAD', 'POST', 'PUT', 'DELETE', 'PATCH', 'OPTIONS']).optional(),
    credentials: z.enum(['omit', 'same-origin', 'include']).optional(),
}).passthrough()

export const MCPServerEntrySchema = z.object({
    endpoint: z.string().min(1),
    transport: z.enum(['http', 'sse', 'stdio']).optional(),
    command: z.string().optional(),
    args: z.array(z.string()).optional(),
    requestInit: MCPServerRequestInitSchema.optional(),
}).passthrough()

export const NovaClawConfigSchema = z.object({
    port: z.number().min(1).max(65535).default(3000),
    bind: z.string().default('loopback'),
    workspaceDir: z.string().min(1),
    models: ModelsConfigSchema,
    agent: AgentConfigSchema.default({}),
    agents: MultiAgentConfigSchema.optional(),
    rules: RulesConfigSchema.optional(),
    skills: SkillsConfigSchema.default({}),
    tools: ToolsConfigSchema.default({}),
    mcp: z.array(MCPServerEntrySchema).optional(),
    memory: MemoryConfigSchema.optional(),
    channels: ChannelsConfigSchema,
    performance: PerformanceConfigSchema.default({}),
    security: SecurityConfigSchema.default({}),
    logging: z.object({
        level: z.enum(['debug', 'info', 'warn', 'error']).default('info'),
        format: z.enum(['text', 'json', 'pretty']).default('text'),
        file: z.object({
            enabled: z.boolean(),
            path: z.string(),
            maxSize: z.string(),
            maxFiles: z.number()
        }).optional()
    }).default({}),
    monitoring: z.object({
        enabled: z.boolean().default(true),
        rssLimitMB: z.number().positive().default(512),
        metrics: z.object({ enabled: z.boolean(), port: z.number() }).optional(),
        health: z.object({
            enabled: z.boolean().default(true),
            path: z.string().default('/health'),
            interval: z.number().default(30000)
        }).optional()
    }).default({}),
    cluster: z.object({
        enabled: z.boolean(),
        nodes: z.array(z.string()),
        discovery: z.enum(['static', 'consul', 'etcd'])
    }).optional()
})

export const MessageRequestSchema = z.object({
    sessionKey: z.string(),
    message: z.string().min(1),
    images: z.array(z.object({
        url: z.string().optional(),
        data: z.string().optional(),
        mimeType: z.string(),
        description: z.string().optional()
    })).optional(),
    metadata: z.record(z.unknown()).optional()
})

export const ApiChatRequestSchema = MessageRequestSchema.extend({
    sessionKey: z.string().optional()
})

export const WebSocketAuthPayloadSchema = z.object({
    token: z.string().optional(),
    userId: z.string().optional(),
    channel: z.string().optional(),
    conversationId: z.string().optional(),
    metadata: z.record(z.unknown()).optional()
})

export const WebSocketMessagePayloadSchema = z.object({
    message: z.string().min(1).optional(),
    content: z.string().min(1).optional(),
    images: z.array(z.unknown()).optional(),
    metadata: z.record(z.unknown()).optional()
}).refine(
    data => !!(data.message || data.content),
    { message: 'Either message or content is required', path: ['message'] }
)

export function validateConfig(raw: unknown): z.infer<typeof NovaClawConfigSchema> {
    return NovaClawConfigSchema.parse(raw)
}
