/**
 * Shared config validation — single source of truth for runtime config checks.
 *
 * Returns structured results so callers can decide how to handle errors vs
 * warnings (throw, log, render to CLI, etc.) without duplicating rules.
 */

import type { NovaClawConfig } from '../framework/index.ts'

export interface ConfigDiagnostic {
    level: 'error' | 'warning'
    field: string
    message: string
}

export interface ConfigValidationResult {
    valid: boolean
    diagnostics: ConfigDiagnostic[]
}

export function validateNovaClawConfig(config: NovaClawConfig): ConfigValidationResult {
    const diagnostics: ConfigDiagnostic[] = []

    if (!config.workspaceDir) {
        diagnostics.push({
            level: 'error',
            field: 'workspaceDir',
            message: 'workspaceDir is required',
        })
    }

    if (!config.models?.primary) {
        diagnostics.push({
            level: 'warning',
            field: 'models.primary',
            message: 'No primary model configured; LLM features will be limited',
        })
    }

    const port = config.port ?? 3000
    if (port < 1 || port > 65535) {
        diagnostics.push({
            level: 'error',
            field: 'port',
            message: `Invalid port: ${port} (must be 1–65535)`,
        })
    }

    if (config.channels?.enabled?.length === 0) {
        diagnostics.push({
            level: 'warning',
            field: 'channels.enabled',
            message: 'No channels enabled — only direct API calls accepted',
        })
    }

    const hasErrors = diagnostics.some((d) => d.level === 'error')

    return { valid: !hasErrors, diagnostics }
}
