/**
 * UI module — resolves and serves frontend static assets from the ui/ directory.
 *
 * When installed via npm, ui/ lives inside the package directory (resolved via
 * import.meta.url).  In a dev checkout the package root and cwd are the same,
 * so both paths converge.
 */

import { existsSync } from 'node:fs'
import { readFile } from 'node:fs/promises'
import { dirname, join, resolve } from 'node:path'
import { fileURLToPath } from 'node:url'

const DEFAULT_UI_DIR = 'ui'

export function getUiRoot(customDir?: string): string {
    if (customDir) return resolve(process.cwd(), customDir)

    const scriptDir = dirname(fileURLToPath(import.meta.url))

    // Standalone layout: ui/ next to the script file
    const fromScriptDir = join(scriptDir, DEFAULT_UI_DIR)
    if (existsSync(fromScriptDir)) return fromScriptDir

    // npm layout: script is in dist/, ui/ is at the package root
    const fromPackageRoot = resolve(scriptDir, '..', DEFAULT_UI_DIR)
    if (existsSync(fromPackageRoot)) return fromPackageRoot

    // Dev / fallback: resolve from cwd
    return resolve(process.cwd(), DEFAULT_UI_DIR)
}

/**
 * Resolve a relative path within the UI root, preventing directory traversal.
 */
export function resolveUiPath(uiRoot: string, relativePath: string): string | null {
    const normalized = join(uiRoot, relativePath).replace(/\\/g, '/')
    const root = uiRoot.replace(/\\/g, '/')
    if (!normalized.startsWith(root) || normalized === root) return null
    if (normalized.includes('..')) return null
    return normalized
}

export async function readUiFile(uiRoot: string, relativePath: string): Promise<Buffer> {
    const resolved = resolveUiPath(uiRoot, relativePath)
    if (!resolved) throw new Error('Invalid UI path')
    return readFile(resolved)
}

export function getMimeType(path: string): string {
    const ext = path.split('.').pop()?.toLowerCase() ?? ''
    const MIME_TYPES: Record<string, string> = {
        html: 'text/html',
        css: 'text/css',
        js: 'application/javascript',
        json: 'application/json',
        png: 'image/png',
        jpg: 'image/jpeg',
        jpeg: 'image/jpeg',
        gif: 'image/gif',
        ico: 'image/x-icon',
        svg: 'image/svg+xml',
        woff: 'font/woff',
        woff2: 'font/woff2',
    }
    return MIME_TYPES[ext] ?? 'application/octet-stream'
}
