/**
 * Rule engine — evaluates registered rules in priority order (chain of responsibility).
 * Supports three evaluation phases: input, behavior, output.
 */

import type {
    IRule,
    RuleContext,
    RulePhase,
    RuleVerdict,
} from '../apis/rule.ts'

export interface RuleEngineOptions {
    rules?: IRule[]
}

export class RuleEngine {
    private rules: IRule[] = []

    constructor(options: RuleEngineOptions = {}) {
        if (Array.isArray(options.rules)) {
            this.rules = [...options.rules]
            this.sortRules()
        }
    }

    register(rule: IRule): void {
        const idx = this.rules.findIndex((r) => r.id === rule.id)
        if (idx >= 0) this.rules[idx] = rule
        else this.rules.push(rule)
        this.sortRules()
    }

    unregister(ruleId: string): boolean {
        const idx = this.rules.findIndex((r) => r.id === ruleId)
        if (idx < 0) return false
        this.rules.splice(idx, 1)
        return true
    }

    get(id: string): IRule | undefined {
        return this.rules.find((r) => r.id === id)
    }

    listIds(): string[] {
        return this.rules.map((r) => r.id)
    }

    getAll(): IRule[] {
        return [...this.rules]
    }

    getRulesByPhase(phase: RulePhase): IRule[] {
        return this.rules.filter((r) => r.phase === phase)
    }

    /**
     * Evaluate context against all rules in priority order.
     * First rule returning a reject/rewrite/transform short-circuits.
     */
    evaluate(ctx: RuleContext): RuleVerdict {
        for (const rule of this.rules) {
            const verdict = rule.evaluate(ctx)
            if (verdict === undefined) continue
            if (verdict.action === 'reject' || verdict.action === 'rewrite' || verdict.action === 'transform') {
                return verdict
            }
        }
        return { action: 'allow' }
    }

    /**
     * Evaluate only rules matching a specific phase and optional scope.
     * Rules without a phase are skipped.
     */
    evaluatePhase(
        phase: RulePhase,
        ctx: RuleContext,
        scope?: { agentId?: string; channel?: string },
    ): RuleVerdict {
        const contextWithPhase: RuleContext = { ...ctx, phase }

        for (const rule of this.rules) {
            if (rule.phase !== phase) continue

            if (scope && rule.scope) {
                if (rule.scope.agents?.length && scope.agentId && !rule.scope.agents.includes(scope.agentId)) {
                    continue
                }
                if (rule.scope.channels?.length && scope.channel && !rule.scope.channels.includes(scope.channel)) {
                    continue
                }
            }

            const verdict = rule.evaluate(contextWithPhase)
            if (verdict === undefined) continue
            if (verdict.action === 'reject' || verdict.action === 'rewrite' || verdict.action === 'transform') {
                return verdict
            }
        }

        return { action: 'allow' }
    }

    private sortRules(): void {
        this.rules.sort((a, b) => b.priority - a.priority)
    }
}
