/**
 * SecurityGate — first stage of the inbound pipeline.
 *
 * Enforces the allowFrom whitelist and DM policy to decide whether a
 * sender is permitted to interact with the bot on a given channel.
 */

import type { NovaClawConfig, ChannelDetailConfig } from '../../../apis/config.ts'
import type { ChannelPlugin } from '../../types/plugin.ts'
import { mergeDmAllowFromSources, resolveAllowlistMatch } from '../../allowlist.ts'

// ── Result types ────────────────────────────────────────────────────────

export type SecurityVerdict =
    | { allowed: true }
    | { allowed: false; emitPairing: boolean; senderId: string; senderName?: string }

// ── SecurityGate ────────────────────────────────────────────────────────

export class SecurityGate {
    check(
        plugin: ChannelPlugin | undefined,
        channelId: string,
        msg: Record<string, unknown>,
        config: NovaClawConfig,
    ): SecurityVerdict {
        const senderId = (msg.senderId as string) ?? (msg.userId as string) ?? (msg.from as string) ?? ''
        const senderName = msg.fromName as string | undefined

        const channelCfg = config.channels?.[channelId] as ChannelDetailConfig | undefined
        const configAllowFrom = channelCfg?.allowFrom ?? []
        const dmPolicy = channelCfg?.dmPolicy

        let allowFrom: Array<string | number> = [...configAllowFrom]

        if (plugin?.security?.resolveDmPolicy) {
            const dm = plugin.security.resolveDmPolicy({
                cfg: config,
                accountId: (msg.accountId as string) ?? 'default',
            })
            if (dm?.allowFrom) {
                allowFrom = mergeDmAllowFromSources({
                    allowFrom: [...allowFrom, ...dm.allowFrom],
                    dmPolicy: dm,
                })
            }
        } else if (configAllowFrom.length > 0 && dmPolicy) {
            allowFrom = mergeDmAllowFromSources({
                allowFrom,
                dmPolicy: { policy: dmPolicy, allowFromPath: '', approveHint: '' },
            })
        }

        if (allowFrom.length === 0) return { allowed: true }

        const match = resolveAllowlistMatch({
            allowFrom,
            senderId,
            senderName,
            allowNameMatching: true,
        })

        if (match.allowed) return { allowed: true }

        return {
            allowed: false,
            emitPairing: !!plugin?.pairing,
            senderId,
            senderName,
        }
    }
}
