import type { KGEntity } from './types.ts'

export class EntityResolver {
    private aliasMap = new Map<string, string>() // normalized name -> canonical id

    resolve(entities: KGEntity[]): KGEntity[] {
        const byNormalized = new Map<string, KGEntity[]>()

        for (const entity of entities) {
            const key = this.normalize(entity.name)
            const list = byNormalized.get(key)
            if (list) {
                list.push(entity)
            } else {
                byNormalized.set(key, [entity])
            }
        }

        const result: KGEntity[] = []
        const now = Date.now()

        for (const [, group] of byNormalized) {
            const merged = this.mergeGroup(group, now)
            result.push(merged)
            this.aliasMap.set(this.normalize(merged.name), merged.id)
        }

        return result
    }

    getCanonicalId(name: string): string | undefined {
        return this.aliasMap.get(this.normalize(name))
    }

    normalize(name: string): string {
        return name
            .toLowerCase()
            .trim()
            .replace(/\s+/g, ' ')
            .replace(/[.,;:!?]+$/g, '')
    }

    private mergeGroup(group: KGEntity[], now: number): KGEntity {
        const first = group[0]
        if (group.length === 1 && first) {
            return first
        }

        const sorted = [...group].sort((a, b) => {
            const aScore = this.entityScore(a)
            const bScore = this.entityScore(b)
            return bScore - aScore
        })

        const primary = sorted[0]
        if (!primary) {
            throw new Error('mergeGroup: empty group')
        }

        const sourceChunks = new Set<string>(primary.sourceChunks)
        const sourceDocuments = new Set<string>(primary.sourceDocuments)
        const properties = { ...primary.properties }

        for (let i = 1; i < sorted.length; i++) {
            const e = sorted[i]
            if (e) {
                for (const c of e.sourceChunks) sourceChunks.add(c)
                for (const d of e.sourceDocuments) sourceDocuments.add(d)
                Object.assign(properties, e.properties)
            }
        }

        return {
            id: primary.id,
            name: primary.name,
            type: primary.type,
            description: primary.description,
            properties,
            sourceChunks: [...sourceChunks],
            sourceDocuments: [...sourceDocuments],
            createdAt: primary.createdAt,
            updatedAt: now,
        }
    }

    private entityScore(entity: KGEntity): number {
        const propCount = Object.keys(entity.properties).length
        const descLen = entity.description?.length ?? 0
        return propCount * 10 + descLen
    }
}
