/**
 * Native Google Gemini API provider.
 * Handles Gemini's generateContent / streamGenerateContent protocol.
 */

import crypto from 'node:crypto'
import type { ChatStreamOptions, LLMProvider, LLMProviderConfig, ProviderMessage, StreamingChunk } from '../apis/provider.ts'
import { BaseStreamProvider, type ParsedSSEResult } from './base-stream-provider.ts'
import { extractSystemPrompt } from './message-utils.ts'

interface GeminiContent {
    role: 'user' | 'model'
    parts: GeminiPart[]
}

type GeminiPart =
    | { text: string }
    | { functionCall: { name: string; args: Record<string, unknown> } }
    | { functionResponse: { name: string; response: Record<string, unknown> } }

export class GeminiProvider extends BaseStreamProvider {
    readonly name = 'gemini'

    constructor(providerKey: string, config: LLMProviderConfig) {
        super(providerKey, config)
    }

    // -- Hook implementations -------------------------------------------------

    protected buildStreamUrl(model: string): string {
        const base = this.config.baseUrl.replace(/\/$/, '')
        return `${base}/v1beta/models/${model}:streamGenerateContent?alt=sse`
    }

    protected buildCompleteUrl(model: string): string {
        const base = this.config.baseUrl.replace(/\/$/, '')
        return `${base}/v1beta/models/${model}:generateContent`
    }

    protected buildHeaders(): Record<string, string> {
        return {
            'Content-Type': 'application/json',
            'x-goog-api-key': this.config.apiKey,
        }
    }

    protected buildCompleteBody(
        model: string,
        messages: ProviderMessage[],
        maxTokens: number,
    ): Record<string, unknown> {
        void model
        const { systemInstruction, contents } = this.convertMessages(messages)
        const body: Record<string, unknown> = {
            contents,
            generationConfig: { maxOutputTokens: maxTokens },
        }
        if (systemInstruction) body.systemInstruction = systemInstruction
        return body
    }

    protected extractCompleteContent(json: unknown): string | null {
        const data = json as {
            candidates?: Array<{ content?: { parts?: Array<{ text?: string }> } }>
        }
        const text = data.candidates?.[0]?.content?.parts
            ?.filter((p): p is { text: string } => 'text' in p)
            .map(p => p.text)
            .join('')
        return text?.trim() || null
    }

    protected buildStreamBody(
        model: string,
        messages: ProviderMessage[],
        options?: ChatStreamOptions,
    ): Record<string, unknown> {
        void model
        const { systemInstruction, contents } = this.convertMessages(messages)
        const tools = this.convertTools(options?.tools)

        const body: Record<string, unknown> = {
            contents,
            generationConfig: { maxOutputTokens: options?.maxTokens ?? 4096 },
        }
        if (systemInstruction) body.systemInstruction = systemInstruction
        if (tools) body.tools = tools
        return body
    }

    protected parseSSEPayload(json: Record<string, unknown>): ParsedSSEResult {
        const chunks: StreamingChunk[] = []
        let usage: ParsedSSEResult['usage']
        let finished = false

        const candidates = json.candidates as Array<Record<string, unknown>> | undefined
        const candidate = candidates?.[0]
        const content = candidate?.content as { parts?: Array<Record<string, unknown>> } | undefined
        const parts = content?.parts ?? []

        for (const part of parts) {
            if (typeof part.text === 'string' && part.text) {
                chunks.push({ type: 'content', content: part.text })
            }
            if (part.functionCall) {
                const fc = part.functionCall as { name: string; args?: Record<string, unknown> }
                chunks.push({
                    type: 'tool_call',
                    toolCall: {
                        id: crypto.randomUUID(),
                        name: fc.name,
                        args: fc.args ?? {},
                        status: 'running' as const,
                    },
                })
            }
        }

        const usageMetadata = json.usageMetadata as Record<string, unknown> | undefined
        if (usageMetadata) {
            const input = (usageMetadata.promptTokenCount as number) ?? 0
            const output = (usageMetadata.candidatesTokenCount as number) ?? 0
            if (input || output) usage = { input, output }
        }

        const fr = candidate?.finishReason
        if (typeof fr === 'string') finished = true

        return { chunks, usage, finished }
    }

    // -- Gemini-specific conversion -------------------------------------------

    private convertMessages(messages: ProviderMessage[]): {
        systemInstruction?: { parts: Array<{ text: string }> }
        contents: GeminiContent[]
    } {
        const { systemPrompt: systemText, nonSystemMessages } = extractSystemPrompt(messages)
        const contents: GeminiContent[] = []
        const toolCallIdToName = new Map<string, string>()

        for (const msg of nonSystemMessages) {
            if (msg.role === 'tool') {
                const functionName = toolCallIdToName.get(msg.tool_call_id) ?? msg.tool_call_id
                let responseObj: Record<string, unknown>
                try {
                    responseObj = JSON.parse(msg.content)
                } catch {
                    responseObj = { result: msg.content }
                }
                contents.push({
                    role: 'user',
                    parts: [{ functionResponse: { name: functionName, response: responseObj } }],
                })
                continue
            }

            if (msg.role === 'assistant') {
                const parts: GeminiPart[] = []
                if (msg.content) parts.push({ text: msg.content })
                if (msg.tool_calls) {
                    for (const tc of msg.tool_calls) {
                        toolCallIdToName.set(tc.id, tc.function.name)
                        let args: Record<string, unknown> = {}
                        try { args = JSON.parse(tc.function.arguments) } catch { /* ignore */ }
                        parts.push({ functionCall: { name: tc.function.name, args } })
                    }
                }
                if (parts.length > 0) contents.push({ role: 'model', parts })
                continue
            }

            contents.push({
                role: 'user',
                parts: [{ text: typeof msg.content === 'string' ? msg.content : JSON.stringify(msg.content) }],
            })
        }

        return {
            systemInstruction: systemText ? { parts: [{ text: systemText }] } : undefined,
            contents,
        }
    }

    private convertTools(tools?: ChatStreamOptions['tools']): Array<{
        functionDeclarations: Array<{ name: string; description: string; parameters?: object }>
    }> | undefined {
        if (!tools?.length) return undefined
        return [{
            functionDeclarations: tools.map(t => ({
                name: t.function.name,
                description: t.function.description ?? '',
                parameters: t.function.parameters,
            })),
        }]
    }
}

export class GeminiProviderFactory {
    create(config: LLMProviderConfig): LLMProvider {
        return new GeminiProvider('gemini', config)
    }
}
