/**
 * Framework bootstrap — register default implementations into registries.
 * The framework is the agent: apis + default provider, rules, memory, MCP.
 * Project only wires config and optionally adds custom registrations.
 */

import type { LLMProviderConfig } from './core/apis/provider.ts'
import { LocalMemoryProvider } from './core/memory/local-memory-provider.ts'
import { AnthropicProviderFactory } from './core/provider/anthropic.ts'
import { GeminiProviderFactory } from './core/provider/gemini.ts'
import { OpenAICompatibleProvider } from './core/provider/openai-compatible.ts'
import { createExecChannelRule } from './core/rules/exec-channel-rule.ts'
import { createThinkingStripRule } from './core/rules/output/thinking-strip.ts'
import { createFormatChannelRule } from './core/rules/output/format-channel.ts'
import { createContentFilterRule } from './core/rules/output/content-filter.ts'
import { createContentSafetyRule } from './core/rules/input/content-safety.ts'
import { createWebChatPlugin, createCLIPlugin, createRestApiPlugin } from './core/channel/default-adapters.ts'
import type { ChannelPluginRegistry } from './registries/channel-plugin-registry.ts'
import type { MemoryProviderRegistry } from './registries/memory-provider-registry.ts'
import type { ProviderRegistry } from './registries/provider-registry.ts'
import type { RuleRegistry } from './registries/rule-registry.ts'

export interface FrameworkBootstrapOptions {
    providerRegistry?: ProviderRegistry
    ruleRegistry?: RuleRegistry
    memoryProviderRegistry?: MemoryProviderRegistry
    channelPluginRegistry?: ChannelPluginRegistry
}

/**
 * Register default LLM provider factories (openai-compatible) for keys: openai, anthropic.
 * Caller passes provider key; config (apiKey, baseUrl) is passed when creating the provider.
 */
export function registerDefaultProviders(registry: ProviderRegistry): void {
    registry.register('openai', {
        create(config: LLMProviderConfig) { return new OpenAICompatibleProvider('openai', config) }
    }, { version: '2025-01' })

    registry.register('anthropic', new AnthropicProviderFactory(), { version: '2025-01' })

    registry.register('gemini', new GeminiProviderFactory(), { version: '2025-01' })

    registry.register('google', new GeminiProviderFactory(), { version: '2025-01' })

    for (const key of ['openrouter', 'deepseek', 'mistral', 'moonshot', 'qwen', 'scnet']) {
        registry.register(key, {
            create(config: LLMProviderConfig) { return new OpenAICompatibleProvider(key, config) }
        }, { version: '2025-01' })
    }
}

/**
 * Register default rules across all three phases: input, behavior, and output.
 */
export function registerDefaultRules(
    registry: RuleRegistry,
    config?: {
        builtin?: Record<string, boolean>
        channelFormats?: Record<string, { format?: string; maxLength?: number }>
        piiFilter?: { enabled?: boolean }
    },
): void {
    const enabled = (id: string) => config?.builtin?.[id] !== false

    // Behavior phase
    if (enabled('exec-channel-allowlist')) {
        registry.register(createExecChannelRule())
    }

    // Input phase
    if (enabled('content-safety')) {
        registry.register(createContentSafetyRule())
    }

    // Output phase
    if (enabled('thinking-strip')) {
        registry.register(createThinkingStripRule())
    }
    if (enabled('format-channel-adapt')) {
        registry.register(createFormatChannelRule(
            config?.channelFormats as Record<string, { format: 'html' | 'mrkdwn' | 'plain' | 'markdown'; maxLength?: number }>,
        ))
    }
    if (config?.piiFilter?.enabled) {
        registry.register(createContentFilterRule({ enabled: true }))
    }
}

/**
 * Register default local memory provider (BM25 RAG).
 */
export function registerDefaultMemoryProviders(registry: MemoryProviderRegistry): void {
    registry.register(
        'local',
        (config, options) => new LocalMemoryProvider(config, { llmCall: options?.llmCall }),
        { version: '2025-01' }
    )
}

/**
 * Register built-in channel plugins (webchat, cli, rest-api) into the channel plugin registry.
 */
export function registerDefaultChannels(registry: ChannelPluginRegistry): void {
    registry.register('webchat', createWebChatPlugin())
    registry.register('cli', createCLIPlugin())
    registry.register('rest-api', createRestApiPlugin())
}

/**
 * Bootstrap framework defaults into the given registries.
 * Call this from project bootstrap; then project may add custom registrations.
 */
export function bootstrapFramework(options: FrameworkBootstrapOptions): void {
    if (options.providerRegistry) registerDefaultProviders(options.providerRegistry)
    if (options.ruleRegistry) registerDefaultRules(options.ruleRegistry)
    if (options.memoryProviderRegistry) registerDefaultMemoryProviders(options.memoryProviderRegistry)
    if (options.channelPluginRegistry) registerDefaultChannels(options.channelPluginRegistry)
}
