import type {ChatTurn} from '../../apis/index.ts'

const CHARS_PER_TOKEN_LATIN = 4
const CHARS_PER_TOKEN_CJK = 1.5

const CJK_RE = /[\u4e00-\u9fff\u3400-\u4dbf\u3000-\u303f\uff00-\uffef]/g

function estimateTokens(text: string): number {
    const cjkChars = text.match(CJK_RE)?.length ?? 0
    const latinChars = text.length - cjkChars
    return Math.ceil(latinChars / CHARS_PER_TOKEN_LATIN + cjkChars / CHARS_PER_TOKEN_CJK)
}

/**
 * Hybrid context compression:
 * 1. Preserve the most recent `recentTurnCount` user/assistant turns
 * 2. Among older turns, prefer tool-result messages over plain text
 * 3. If total still exceeds budget, drop oldest and insert a summary marker
 */
export function compressHistory(
    history: Array<{ role: string; content: string }>,
    options: {
        maxTokens: number
        recentTurnCount?: number
    }
): ChatTurn[] {
    const {maxTokens, recentTurnCount = 4} = options

    if (history.length === 0) return []

    const budget = Math.floor(maxTokens * 0.6)

    const recentCutoff = Math.max(0, history.length - recentTurnCount * 2)
    const recentMessages = history.slice(recentCutoff)
    const olderMessages = history.slice(0, recentCutoff)

    let recentTokens = 0
    for (const msg of recentMessages) {
        recentTokens += estimateTokens(msg.content)
    }

    if (recentTokens >= budget) {
        const trimmed: ChatTurn[] = []
        let usedTokens = 0
        for (let i = recentMessages.length - 1; i >= 0; i--) {
            const msg = recentMessages[i]!
            const tokens = estimateTokens(msg.content)
            if (usedTokens + tokens > budget) break
            trimmed.unshift({role: msg.role as 'user' | 'assistant', content: msg.content})
            usedTokens += tokens
        }
        if (trimmed.length > 0 && olderMessages.length > 0) {
            trimmed.unshift({role: 'assistant', content: '[...earlier context omitted...]'})
        }
        return trimmed
    }

    let remainingBudget = budget - recentTokens
    const toolMessages: Array<{ msg: { role: string; content: string }; tokens: number }> = []
    const plainMessages: Array<{ msg: { role: string; content: string }; tokens: number }> = []

    for (const msg of olderMessages) {
        const tokens = estimateTokens(msg.content)
        if (msg.role === 'tool' || msg.content.startsWith('[执行结果]') || msg.content.startsWith('[执行失败]')) {
            toolMessages.push({msg, tokens})
        } else {
            plainMessages.push({msg, tokens})
        }
    }

    const keptOlder: ChatTurn[] = []

    for (const {msg, tokens} of toolMessages) {
        if (tokens <= remainingBudget) {
            keptOlder.push({role: msg.role as 'user' | 'assistant', content: msg.content})
            remainingBudget -= tokens
        }
    }

    for (const {msg, tokens} of plainMessages) {
        if (tokens <= remainingBudget) {
            keptOlder.push({role: msg.role as 'user' | 'assistant', content: msg.content})
            remainingBudget -= tokens
        }
    }

    const dropped = olderMessages.length - keptOlder.length
    const result: ChatTurn[] = []

    if (dropped > 0) {
        result.push({role: 'assistant', content: `[...${dropped} earlier messages omitted...]`})
    }
    result.push(...keptOlder)
    for (const msg of recentMessages) {
        result.push({role: msg.role as 'user' | 'assistant', content: msg.content})
    }

    return result
}
