import { readFile, writeFile, mkdir } from 'node:fs/promises'
import { join } from 'node:path'
import { randomUUID } from 'node:crypto'
import { Logger } from '../../../utils/logger.ts'
import type {
    KGEntity,
    KGRelation,
    KGCommunity,
    KnowledgeGraphSnapshot,
    EntityType,
} from './types.ts'

const GRAPH_FILENAME = 'graph.json'
const SNAPSHOT_VERSION = '1.0'

export class KnowledgeGraph {
    private entities = new Map<string, KGEntity>()
    private relations = new Map<string, KGRelation>()
    private communities: KGCommunity[] = []
    private storageDir: string
    private logger = new Logger('KnowledgeGraph')

    constructor(storageDir: string) {
        this.storageDir = storageDir
    }

    async initialize(): Promise<void> {
        await mkdir(this.storageDir, { recursive: true })
        await this.load()
    }

    // ---------------------------------------------------------------------------
    // Entity CRUD
    // ---------------------------------------------------------------------------

    upsertEntity(entity: Omit<KGEntity, 'id' | 'createdAt' | 'updatedAt'>): KGEntity {
        const existing = Array.from(this.entities.values()).find(
            (e) =>
                e.name.toLowerCase() === entity.name.toLowerCase() &&
                e.type === entity.type
        )

        const now = Date.now()

        if (existing) {
            const merged: KGEntity = {
                ...existing,
                description: entity.description ?? existing.description,
                properties: { ...existing.properties, ...entity.properties },
                sourceChunks: [
                    ...new Set([...existing.sourceChunks, ...(entity.sourceChunks ?? [])]),
                ],
                sourceDocuments: [
                    ...new Set([
                        ...existing.sourceDocuments,
                        ...(entity.sourceDocuments ?? []),
                    ]),
                ],
                updatedAt: now,
            }
            this.entities.set(existing.id, merged)
            return merged
        }

        const newEntity: KGEntity = {
            id: randomUUID(),
            name: entity.name,
            type: entity.type,
            description: entity.description ?? '',
            properties: entity.properties ?? {},
            sourceChunks: entity.sourceChunks ?? [],
            sourceDocuments: entity.sourceDocuments ?? [],
            createdAt: now,
            updatedAt: now,
        }
        this.entities.set(newEntity.id, newEntity)
        return newEntity
    }

    getEntity(id: string): KGEntity | undefined {
        return this.entities.get(id)
    }

    findEntitiesByName(query: string): KGEntity[] {
        const q = query.toLowerCase()
        return Array.from(this.entities.values()).filter(
            (e) =>
                e.name.toLowerCase().includes(q) ||
                (e.description && e.description.toLowerCase().includes(q))
        )
    }

    findEntitiesByType(type: EntityType): KGEntity[] {
        return Array.from(this.entities.values()).filter((e) => e.type === type)
    }

    // ---------------------------------------------------------------------------
    // Relation CRUD
    // ---------------------------------------------------------------------------

    upsertRelation(
        relation: Omit<KGRelation, 'id' | 'createdAt'>
    ): KGRelation {
        const existing = Array.from(this.relations.values()).find(
            (r) =>
                r.sourceEntityId === relation.sourceEntityId &&
                r.targetEntityId === relation.targetEntityId &&
                r.type === relation.type
        )

        const now = Date.now()

        if (existing) {
            const updated: KGRelation = {
                ...existing,
                weight: relation.weight,
                description: relation.description ?? existing.description,
                sourceChunks: [
                    ...new Set([
                        ...existing.sourceChunks,
                        ...(relation.sourceChunks ?? []),
                    ]),
                ],
            }
            this.relations.set(existing.id, updated)
            return updated
        }

        const newRelation: KGRelation = {
            id: randomUUID(),
            sourceEntityId: relation.sourceEntityId,
            targetEntityId: relation.targetEntityId,
            type: relation.type,
            description: relation.description,
            weight: relation.weight,
            sourceChunks: relation.sourceChunks ?? [],
            createdAt: now,
        }
        this.relations.set(newRelation.id, newRelation)
        return newRelation
    }

    getRelationsForEntity(entityId: string): KGRelation[] {
        return Array.from(this.relations.values()).filter(
            (r) =>
                r.sourceEntityId === entityId || r.targetEntityId === entityId
        )
    }

    // ---------------------------------------------------------------------------
    // Graph traversal
    // ---------------------------------------------------------------------------

    expandNeighbors(
        entityIds: string[],
        depth: number = 1
    ): { entities: KGEntity[]; relations: KGRelation[] } {
        const seenEntityIds = new Set<string>(entityIds)
        const seenRelationIds = new Set<string>()
        const collectedRelations: KGRelation[] = []

        let frontier = [...entityIds]

        for (let d = 0; d < depth; d++) {
            const nextFrontier: string[] = []

            for (const eid of frontier) {
                const rels = this.getRelationsForEntity(eid)
                for (const rel of rels) {
                    if (seenRelationIds.has(rel.id)) continue
                    seenRelationIds.add(rel.id)
                    collectedRelations.push(rel)

                    const neighbor =
                        rel.sourceEntityId === eid
                            ? rel.targetEntityId
                            : rel.sourceEntityId
                    if (!seenEntityIds.has(neighbor)) {
                        seenEntityIds.add(neighbor)
                        nextFrontier.push(neighbor)
                    }
                }
            }
            frontier = nextFrontier
        }

        const entities = Array.from(seenEntityIds)
            .map((id) => this.entities.get(id))
            .filter((e): e is KGEntity => e !== undefined)

        return { entities, relations: collectedRelations }
    }

    // ---------------------------------------------------------------------------
    // Community management
    // ---------------------------------------------------------------------------

    setCommunities(communities: KGCommunity[]): void {
        this.communities = [...communities]
    }

    getCommunities(): KGCommunity[] {
        return [...this.communities]
    }

    findRelevantCommunities(query: string): KGCommunity[] {
        const tokens = query
            .toLowerCase()
            .split(/\s+/)
            .filter((t) => t.length > 0)

        if (tokens.length === 0) return this.communities

        return this.communities.filter((c) => {
            const text = `${c.name} ${c.summary}`.toLowerCase()
            return tokens.some((t) => text.includes(t))
        })
    }

    // ---------------------------------------------------------------------------
    // Stats
    // ---------------------------------------------------------------------------

    getStats(): {
        entityCount: number
        relationCount: number
        communityCount: number
    } {
        return {
            entityCount: this.entities.size,
            relationCount: this.relations.size,
            communityCount: this.communities.length,
        }
    }

    // ---------------------------------------------------------------------------
    // Persistence
    // ---------------------------------------------------------------------------

    async save(): Promise<void> {
        const snapshot = this.toSnapshot()
        const filePath = join(this.storageDir, GRAPH_FILENAME)
        await writeFile(filePath, JSON.stringify(snapshot, null, 2), 'utf-8')
    }

    private async load(): Promise<void> {
        const filePath = join(this.storageDir, GRAPH_FILENAME)
        try {
            const data = await readFile(filePath, 'utf-8')
            const snapshot = JSON.parse(data) as KnowledgeGraphSnapshot
            this.fromSnapshot(snapshot)
        } catch (err) {
            const e = err as NodeJS.ErrnoException
            if (e.code !== 'ENOENT') {
                this.logger.warn('Failed to load knowledge graph snapshot, starting fresh', {
                    path: filePath, error: e.message,
                })
            }
        }
    }

    private toSnapshot(): KnowledgeGraphSnapshot {
        const now = Date.now()
        const stats = this.getStats()
        return {
            entities: Array.from(this.entities.values()),
            relations: Array.from(this.relations.values()),
            communities: [...this.communities],
            metadata: {
                version: SNAPSHOT_VERSION,
                createdAt: now,
                updatedAt: now,
                entityCount: stats.entityCount,
                relationCount: stats.relationCount,
                communityCount: stats.communityCount,
            },
        }
    }

    private fromSnapshot(snapshot: KnowledgeGraphSnapshot): void {
        this.entities.clear()
        this.relations.clear()
        this.communities = []

        for (const e of snapshot.entities ?? []) {
            this.entities.set(e.id, e)
        }
        for (const r of snapshot.relations ?? []) {
            this.relations.set(r.id, r)
        }
        this.communities = snapshot.communities ?? []
    }

    // ---------------------------------------------------------------------------
    // Cleanup
    // ---------------------------------------------------------------------------

    clear(): void {
        this.entities.clear()
        this.relations.clear()
        this.communities = []
    }
}
