/**
 * RetrievalStrategy — abstracts BM25-only vs Hybrid (BM25 + GraphRAG) retrieval.
 * Eliminates null-check sprawl in LocalMemoryProvider.
 */

import type { RetrievalResult } from '../apis/memory.ts'
import type { LocalDocumentIndex } from './types.ts'
import type { MemoryRetriever } from './memory-retriever.ts'
import type { KnowledgeGraph } from './graph/knowledge-graph.ts'
import type { IncrementalGraphBuilder } from './graph/incremental-builder.ts'
import type { HybridRetriever } from './hybrid/hybrid-retriever.ts'
import type { Logger } from '../../utils/logger.ts'

export interface RetrievalStrategy {
    retrieve(query: string, indexes: LocalDocumentIndex[], limit: number): Promise<RetrievalResult[]>
    onDocumentIndexed(index: LocalDocumentIndex): void
    getGraphStats(): Record<string, unknown> | null
    initializeGraph(): Promise<void>
    saveGraph(): Promise<void>
    clearGraph(): void
}

// ---------------------------------------------------------------------------
// BM25-only strategy (default, no graph)
// ---------------------------------------------------------------------------

export class BM25Strategy implements RetrievalStrategy {
    constructor(private retriever: MemoryRetriever) {}

    async retrieve(query: string, indexes: LocalDocumentIndex[], limit: number): Promise<RetrievalResult[]> {
        void limit
        return this.retriever.retrieve(query, indexes)
    }

    onDocumentIndexed(_index: LocalDocumentIndex): void {}
    getGraphStats(): null { return null }
    async initializeGraph(): Promise<void> {}
    async saveGraph(): Promise<void> {}
    clearGraph(): void {}
}

// ---------------------------------------------------------------------------
// Hybrid strategy (BM25 + GraphRAG fusion)
// ---------------------------------------------------------------------------

export class HybridStrategy implements RetrievalStrategy {
    constructor(
        private hybridRetriever: HybridRetriever,
        private knowledgeGraph: KnowledgeGraph,
        private graphBuilder: IncrementalGraphBuilder,
        private indexLookup: (docId: string) => LocalDocumentIndex | undefined,
        private logger: Logger,
    ) {}

    async retrieve(query: string, _indexes: LocalDocumentIndex[], limit: number): Promise<RetrievalResult[]> {
        const ranked = this.hybridRetriever.retrieve(query, limit * 2)
        const docGroups = new Map<string, Array<{ nodeId: string; nodeTitle: string; content: string; score: number }>>()

        for (const item of ranked) {
            const docId = (item.metadata as Record<string, unknown>)?.documentId as string | undefined
            if (!docId) continue
            let sections = docGroups.get(docId)
            if (!sections) { sections = []; docGroups.set(docId, sections) }
            sections.push({
                nodeId: item.id,
                nodeTitle: (item.metadata as Record<string, unknown>)?.heading as string ?? item.id,
                content: item.content ?? '',
                score: item.score,
            })
        }

        const results: RetrievalResult[] = []
        for (const [documentId, sections] of docGroups) {
            const index = this.indexLookup(documentId)
            results.push({
                documentId,
                source: index?.source ?? 'workspace',
                filePath: index?.filePath ?? '',
                title: index?.title ?? documentId,
                sections: sections.slice(0, limit),
            })
        }
        return results.slice(0, limit)
    }

    onDocumentIndexed(index: LocalDocumentIndex): void {
        this.graphBuilder.onDocumentIndexed({
            id: index.documentId,
            chunks: index.chunks.map((c) => ({ id: c.chunkId, text: c.text })),
        })
        this.graphBuilder.flush().catch((err) => {
            this.logger.warn('GraphRAG flush failed', { error: String(err) })
        })
    }

    getGraphStats(): Record<string, unknown> {
        return this.knowledgeGraph.getStats()
    }

    async initializeGraph(): Promise<void> {
        await this.knowledgeGraph.initialize()
    }

    async saveGraph(): Promise<void> {
        await this.knowledgeGraph.save().catch(() => {})
    }

    clearGraph(): void {
        this.knowledgeGraph.clear()
    }
}
