/**
 * In-memory session store with automatic expiration.
 *
 * Lives in the agent layer so that MessageProcessor, the gateway,
 * and any other consumer can share a single session pool.
 */

import { mkdir } from 'node:fs/promises'
import type { SessionContext } from '../../apis/index.ts'
import { SESSION_TIMEOUT_MS } from '../../../../constants/timeouts.ts'
import { generateId, resolveWorkspaceDir } from '../../../../utils/index.ts'

export interface CreateSessionPayload {
    userId?: string
    channel?: string
    conversationId?: string
    metadata?: Record<string, unknown>
    token?: string
}

export class SessionManager {
    static readonly MAX_SESSION_HISTORY = 20
    private static readonly DEFAULT_TIMEOUT_MS = SESSION_TIMEOUT_MS

    private sessions = new Map<string, SessionContext>()
    private cleanupInterval: ReturnType<typeof setInterval> | null = null

    constructor(
        private workspaceDir: string,
        timeoutMs?: number,
    ) {
        const timeout = timeoutMs ?? SessionManager.DEFAULT_TIMEOUT_MS
        this.cleanupInterval = setInterval(() => this.purgeExpired(timeout), 60_000)
        this.cleanupInterval.unref()
    }

    async createSession(payload: CreateSessionPayload, sessionKey?: string): Promise<SessionContext> {
        const key = sessionKey ?? generateId()
        const now = Date.now()
        const workDir = resolveWorkspaceDir(this.workspaceDir)
        await mkdir(workDir, { recursive: true })

        const ctx: SessionContext = {
            sessionKey: key,
            sessionId: generateId(),
            userId: payload.userId || 'anonymous',
            channel: payload.channel || 'unknown',
            workspaceDir: workDir,
            startTime: now,
            lastActivity: now,
            metadata: payload.metadata ?? {},
            messageHistory: [],
        }
        this.sessions.set(key, ctx)
        return ctx
    }

    get(sessionKey: string): SessionContext | undefined {
        return this.sessions.get(sessionKey)
    }

    set(sessionKey: string, ctx: SessionContext): void {
        this.sessions.set(sessionKey, ctx)
    }

    delete(sessionKey: string): boolean {
        return this.sessions.delete(sessionKey)
    }

    values(): IterableIterator<SessionContext> {
        return this.sessions.values()
    }

    entries(): IterableIterator<[string, SessionContext]> {
        return this.sessions.entries()
    }

    get size(): number {
        return this.sessions.size
    }

    trimHistory(ctx: SessionContext): void {
        if (ctx.messageHistory && ctx.messageHistory.length > SessionManager.MAX_SESSION_HISTORY) {
            ctx.messageHistory.splice(0, ctx.messageHistory.length - SessionManager.MAX_SESSION_HISTORY)
        }
    }

    dispose(): void {
        if (this.cleanupInterval) {
            clearInterval(this.cleanupInterval)
            this.cleanupInterval = null
        }
    }

    private purgeExpired(timeoutMs: number): void {
        const now = Date.now()
        for (const [key, ctx] of this.sessions) {
            if (now - ctx.lastActivity > timeoutMs) {
                this.sessions.delete(key)
            }
        }
    }
}
