/**
 * AgentMetrics — isolated statistics tracking for agent execution.
 * Separates observability from core execution logic.
 */

export class AgentMetrics {
    private totalRequests = 0
    private successfulRequests = 0
    private failedRequests = 0
    private averageResponseTime = 0
    private totalTokensUsed = 0

    recordRequest(success: boolean, processingTime: number): void {
        this.totalRequests++
        if (success) {
            this.successfulRequests++
        } else {
            this.failedRequests++
        }
        const totalTime = this.averageResponseTime * (this.totalRequests - 1) + processingTime
        this.averageResponseTime = totalTime / this.totalRequests
    }

    addTokens(tokens: number): void {
        this.totalTokensUsed += tokens
    }

    getSummary(activeModel?: string): Record<string, unknown> {
        return {
            totalRequests: this.totalRequests,
            successfulRequests: this.successfulRequests,
            failedRequests: this.failedRequests,
            activeModel: activeModel || 'none',
            successRate: this.totalRequests > 0
                ? (this.successfulRequests / this.totalRequests * 100).toFixed(2) + '%'
                : '0%',
            averageResponseTime: this.averageResponseTime.toFixed(2) + 'ms',
            totalTokensUsed: this.totalTokensUsed,
        }
    }
}
