import {readFile, writeFile} from 'node:fs/promises'
import { toErrorMessage } from '../../../constants/errors.ts'
import type {Tool, ToolExecutionResult} from '../apis/tool.ts'
import {resolvePathInWorkspace} from './security.ts'

export class EditTool implements Tool {
    readonly name = 'edit'
    readonly description = 'Edit a file. For partial edit: provide path, old_string, new_string. For full replace: provide path, content.'
    readonly parameters = {
        type: 'object',
        properties: {
            path: {type: 'string', description: 'File path to edit'},
            old_string: {type: 'string', description: 'Exact text to find and replace'},
            new_string: {type: 'string', description: 'Replacement text'},
            content: {type: 'string', description: 'Full file content (for full replace mode)'}
        },
        required: ['path']
    }

    constructor(
        private workspaceDir: string,
        private canRead: boolean = true,
        private canWrite: boolean = true
    ) {
    }

    validate(args: Record<string, unknown>): string | null {
        if (!this.canRead || !this.canWrite) return 'File system read/write is disabled by permissions'
        const p = typeof args?.path === 'string' ? args.path.trim() : ''
        if (!p) return 'Missing parameter: path'
        const resolved = resolvePathInWorkspace(p, this.workspaceDir)
        if (!resolved) return 'Path is outside workspace or invalid'
        return null
    }

    async execute(args: Record<string, unknown>): Promise<ToolExecutionResult> {
        const validationError = this.validate(args)
        if (validationError) return {success: false, error: validationError}

        const p = (args.path as string).trim()
        const resolved = resolvePathInWorkspace(p, this.workspaceDir)!
        const oldStr = typeof args?.old_string === 'string' ? args.old_string : undefined
        const newStr = typeof args?.new_string === 'string' ? args.new_string : undefined

        try {
            if (oldStr !== undefined && newStr !== undefined) {
                const existing = await readFile(resolved, 'utf-8')
                const idx = existing.indexOf(oldStr)
                if (idx === -1) return {success: false, error: 'old_string not found in file'}
                const lastIdx = existing.lastIndexOf(oldStr)
                if (lastIdx !== idx) {
                    return {
                        success: false,
                        error: 'old_string matches multiple locations; provide more context to make it unique'
                    }
                }
                const updated = existing.slice(0, idx) + newStr + existing.slice(idx + oldStr.length)
                await writeFile(resolved, updated, 'utf-8')
                return {success: true, path: resolved, mode: 'partial'}
            }
            const content = args?.content != null ? String(args.content) : ''
            await writeFile(resolved, content, 'utf-8')
            return {success: true, path: resolved, mode: 'full'}
        } catch (err: unknown) {
            return {success: false, error: toErrorMessage(err)}
        }
    }
}
