/**
 * Gateway-level thin wrapper around MessageProcessor.
 *
 * Bridges the MessageRequest DTO (gateway layer) to the
 * ProcessMessageParams (framework layer). The real pipeline
 * lives in MessageProcessor.
 */

import type { MessageProcessor } from '../framework/core/agent/message-processor.ts'
import type { MessageRequest, MessageResponse, StreamChunk } from '../framework/index.ts'

export interface ChatStreamServiceDeps {
    messageProcessor: MessageProcessor
}

export interface ChatStreamRunOptions {
    onChunk?: (chunk: StreamChunk) => void
    abortSignal?: AbortSignal
}

export class ChatStreamService {
    private readonly processor: MessageProcessor

    constructor(deps: ChatStreamServiceDeps) {
        this.processor = deps.messageProcessor
    }

    async run(request: MessageRequest, options: ChatStreamRunOptions = {}): Promise<MessageResponse> {
        return this.processor.process({
            message: request.message,
            sessionKey: request.sessionKey,
            images: request.images,
            metadata: request.metadata,
            channel: request.channel,
            userId: request.userId,
            onChunk: options.onChunk,
            abortSignal: options.abortSignal,
        })
    }
}
