import type { KnowledgeGraph } from './knowledge-graph.ts'
import type { EntityExtractor } from './entity-extractor.ts'
import type { EntityResolver } from './entity-resolver.ts'
import type { KGEntity } from './types.ts'
import { Logger } from '../../../utils/logger.ts'

export class IncrementalGraphBuilder {
    private pendingChunks: Array<{ id: string; text: string; documentId: string }> = []
    private _logger: Logger

    constructor(
        private graph: KnowledgeGraph,
        private extractor: EntityExtractor,
        private resolver: EntityResolver,
        private batchSize: number = 5,
    ) {
        this._logger = new Logger('IncrementalGraphBuilder')
    }

    onDocumentIndexed(doc: { id: string; chunks: Array<{ id: string; text: string }> }): void {
        // Queue chunks for extraction
        for (const chunk of doc.chunks) {
            this.pendingChunks.push({ id: chunk.id, text: chunk.text, documentId: doc.id })
        }
    }

    async flush(): Promise<{ entitiesAdded: number; relationsAdded: number }> {
        // Process pending chunks in batches
        let entitiesAdded = 0
        let relationsAdded = 0

        while (this.pendingChunks.length > 0) {
            const batch = this.pendingChunks.splice(0, this.batchSize)

            // Extract entities and relations from batch
            const results = await this.extractor.extractBatch(
                batch.map((c) => ({ id: c.id, text: c.text })),
            )

            // For each chunk's results:
            //   - Create KGEntity objects with sourceChunks and sourceDocuments
            //   - Resolve entities (merge duplicates)
            //   - Upsert entities and relations into graph
            for (const [chunkId, extraction] of results) {
                const chunk = batch.find((c) => c.id === chunkId)
                if (!chunk) continue

                const entities: KGEntity[] = extraction.entities.map((e) => ({
                    id: '', // will be generated by graph.upsertEntity
                    name: e.name,
                    type: e.type,
                    description: e.description,
                    properties: {},
                    sourceChunks: [chunkId],
                    sourceDocuments: [chunk.documentId],
                    createdAt: Date.now(),
                    updatedAt: Date.now(),
                }))

                const resolved = this.resolver.resolve(entities)

                for (const entity of resolved) {
                    this.graph.upsertEntity(entity)
                    entitiesAdded++
                }

                // Map entity names to IDs for relations
                for (const rel of extraction.relations) {
                    const sourceEntities = this.graph.findEntitiesByName(rel.source)
                    const targetEntities = this.graph.findEntitiesByName(rel.target)
                    if (sourceEntities.length > 0 && targetEntities.length > 0) {
                        this.graph.upsertRelation({
                            sourceEntityId: sourceEntities[0]!.id,
                            targetEntityId: targetEntities[0]!.id,
                            type: rel.type,
                            description: rel.description,
                            weight: 1.0,
                            sourceChunks: [chunkId],
                        })
                        relationsAdded++
                    }
                }
            }
        }

        await this.graph.save()
        this._logger.info('Flushed graph batch', { entitiesAdded, relationsAdded })
        return { entitiesAdded, relationsAdded }
    }

    get pendingCount(): number {
        return this.pendingChunks.length
    }
}
