/**
 * WorkerPromptBuilder — lightweight prompt builder for worker agents.
 * No full skill catalog, no instruction files — just the essentials.
 */

import type { SkillDefinition, Tool } from '../../apis/index.ts'
import type { WorkerAgentConfig } from './types.ts'

export interface WorkerPromptBuildParams {
    task: string
    context: {
        sessionKey: string
        workspaceDir: string
        userId: string
        channel: string
    }
    tools: Tool[]
    skills?: SkillDefinition[]
    memoryContext?: string
}

export class WorkerPromptBuilder {
    constructor(private workerConfig: WorkerAgentConfig) {}

    build(params: WorkerPromptBuildParams): string {
        const parts: string[] = []

        parts.push(this.workerConfig.systemPromptTemplate)

        if (params.tools.length > 0) {
            const toolsList = params.tools.map(t => `- ${t.name}: ${t.description}`).join('\n')
            parts.push(`\n## Available Tools\n${toolsList}`)
        }

        if (params.skills && params.skills.length > 0) {
            const skillBlocks = params.skills.map(s =>
                `### ${s.id}\n${s.description}\n\n${s.content}`
            )
            parts.push(`\n## Active Skills\n${skillBlocks.join('\n\n---\n\n')}`)
        }

        if (params.memoryContext?.trim()) {
            parts.push(`\n## Memory Context\n${params.memoryContext}`)
        }

        parts.push(`\n## Context\n- Session: ${params.context.sessionKey}\n- User: ${params.context.userId}\n- Channel: ${params.context.channel}\n- Workspace: ${params.context.workspaceDir}`)

        parts.push(`\n## Task\n${params.task}`)

        return parts.join('\n').trim()
    }
}
