import type { KnowledgeGraph } from './knowledge-graph.ts'
import type { GraphRetrievalResult } from './types.ts'

export class GraphRetriever {
    constructor(private graph: KnowledgeGraph) {}

    query(query: string, limit: number = 5): GraphRetrievalResult[] {
        const matchingEntities = this.graph.findEntitiesByName(query)
        const results: GraphRetrievalResult[] = []
        const seenEntityIds = new Set<string>()

        for (const entity of matchingEntities) {
            if (seenEntityIds.has(entity.id)) continue
            seenEntityIds.add(entity.id)

            const { entities: neighbors, relations } = this.graph.expandNeighbors(
                [entity.id],
                1
            )
            const relationsForEntity = relations.filter(
                (r) =>
                    r.sourceEntityId === entity.id || r.targetEntityId === entity.id
            )

            const relationInfos = relationsForEntity.map((r) => {
                const targetId =
                    r.sourceEntityId === entity.id ? r.targetEntityId : r.sourceEntityId
                const targetEntity = neighbors.find((e) => e.id === targetId)
                return {
                    targetEntityId: targetId,
                    targetEntityName: targetEntity?.name ?? targetId,
                    relationType: r.type,
                    description: r.description,
                }
            })

            const queryLower = query.toLowerCase()
            const nameMatch = entity.name.toLowerCase() === queryLower
            const partialMatch =
                entity.name.toLowerCase().includes(queryLower) ||
                (entity.description &&
                    entity.description.toLowerCase().includes(queryLower))

            let score = 0
            if (nameMatch) score = 3
            else if (partialMatch) score = 2
            else score = 1

            const sourceChunkIds = [
                ...new Set([
                    ...entity.sourceChunks,
                    ...relationsForEntity.flatMap((r) => r.sourceChunks),
                ]),
            ]

            results.push({
                entityId: entity.id,
                entityName: entity.name,
                entityType: entity.type,
                relations: relationInfos,
                sourceChunkIds,
                score,
            })
        }

        results.sort((a, b) => b.score - a.score)
        return results.slice(0, limit)
    }
}
