import type {Tool, ToolExecutionResult} from '../apis/tool.ts'

const RESULT_MAX_CHARS = 100_000
const DEFAULT_TIMEOUT_MS = 30_000
const ALLOWED_METHODS = ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'HEAD'] as const
type HttpMethod = (typeof ALLOWED_METHODS)[number]

export class WebFetchTool implements Tool {
    readonly name = 'web_fetch'
    readonly description =
        'Fetch a URL via HTTP(S). Supports all common methods (GET/POST/PUT/PATCH/DELETE/HEAD), ' +
        'custom headers, and request bodies. HTML responses are automatically converted to readable text. ' +
        'JSON responses are returned parsed. Parameters: url (required), method (optional, default GET), ' +
        'headers (optional object), body (optional string or object — objects are JSON-serialized), ' +
        'output_format (optional: "text" | "json" | "html" | "auto", default "auto").'

    readonly parameters = {
        type: 'object',
        properties: {
            url: {type: 'string', description: 'URL to fetch (http or https)'},
            method: {type: 'string', enum: ALLOWED_METHODS, description: 'HTTP method (default GET)'},
            headers: {type: 'object', description: 'Custom request headers as key-value pairs'},
            body: {description: 'Request body — string sent as-is, object JSON-serialized'},
            output_format: {
                type: 'string',
                enum: ['text', 'json', 'html', 'auto'],
                description: 'Force output format. "auto" detects from Content-Type (default)'
            }
        },
        required: ['url']
    }

    constructor(
        private canNetwork: boolean = true,
        private timeoutMs: number = DEFAULT_TIMEOUT_MS
    ) {}

    validate(args: Record<string, unknown>): string | null {
        if (!this.canNetwork) return 'Network access is disabled by permissions'
        const url = typeof args?.url === 'string' ? args.url.trim() : ''
        if (!url) return 'Missing required parameter: url'
        if (!/^https?:\/\//i.test(url)) return 'Only http and https URLs are allowed'

        if (args.method !== undefined) {
            const m = String(args.method).toUpperCase()
            if (!(ALLOWED_METHODS as readonly string[]).includes(m)) {
                return `Invalid method "${args.method}". Allowed: ${ALLOWED_METHODS.join(', ')}`
            }
        }
        if (args.headers !== undefined && (typeof args.headers !== 'object' || Array.isArray(args.headers))) {
            return 'headers must be a plain object of key-value pairs'
        }
        return null
    }

    async execute(args: Record<string, unknown>): Promise<ToolExecutionResult> {
        const err = this.validate(args)
        if (err) return {success: false, error: err}

        const url = (args.url as string).trim()
        const method: HttpMethod = args.method
            ? (String(args.method).toUpperCase() as HttpMethod)
            : 'GET'
        const customHeaders = (args.headers ?? {}) as Record<string, string>
        const outputFormat = typeof args.output_format === 'string' ? args.output_format : 'auto'

        const headers: Record<string, string> = {
            'User-Agent': 'NovaClaw/1.0',
            Accept: 'text/html,application/json,application/xml;q=0.9,*/*;q=0.8',
            ...customHeaders
        }

        let body: string | undefined
        if (args.body !== undefined && method !== 'GET' && method !== 'HEAD') {
            if (typeof args.body === 'string') {
                body = args.body
            } else {
                body = JSON.stringify(args.body)
                if (!headers['Content-Type'] && !headers['content-type']) {
                    headers['Content-Type'] = 'application/json'
                }
            }
        }

        try {
            const controller = new AbortController()
            const timer = setTimeout(() => controller.abort(), this.timeoutMs)
            const res = await fetch(url, {
                method,
                headers,
                body,
                signal: controller.signal,
                redirect: 'follow'
            })
            clearTimeout(timer)

            if (method === 'HEAD') {
                return {
                    success: true,
                    status: res.status,
                    ok: res.ok,
                    headers: extractHeaders(res)
                }
            }

            const contentType = res.headers.get('content-type') ?? ''
            const format = outputFormat === 'auto' ? detectFormat(contentType) : outputFormat
            const raw = await res.text()

            let content: unknown
            if (format === 'json') {
                try {
                    content = JSON.parse(raw)
                } catch {
                    content = raw.slice(0, RESULT_MAX_CHARS)
                }
            } else if (format === 'html' || format === 'text') {
                content = htmlToReadableText(raw).slice(0, RESULT_MAX_CHARS)
            } else {
                content = raw.slice(0, RESULT_MAX_CHARS)
            }

            return {
                success: true,
                status: res.status,
                ok: res.ok,
                url: res.url,
                content_type: contentType,
                content
            }
        } catch (e: unknown) {
            const msg = e instanceof Error ? e.message : String(e)
            if (msg.includes('abort')) {
                return {success: false, error: `Request timed out after ${this.timeoutMs}ms`}
            }
            return {success: false, error: msg}
        }
    }
}

function detectFormat(contentType: string): 'json' | 'html' | 'text' {
    const ct = contentType.toLowerCase()
    if (ct.includes('application/json') || ct.includes('+json')) return 'json'
    if (ct.includes('text/html') || ct.includes('application/xhtml')) return 'html'
    return 'text'
}

function extractHeaders(res: Response): Record<string, string> {
    const h: Record<string, string> = {}
    res.headers.forEach((v, k) => { h[k] = v })
    return h
}

// ---------------------------------------------------------------------------
// Lightweight HTML → readable text converter
// ---------------------------------------------------------------------------

const BLOCK_STRIP_TAGS = /< *(script|style|noscript|svg|iframe)[^>]*>[\s\S]*?<\/ *\1 *>/gi
const TAG_HEADING = /< *(h[1-6])[^>]*>([\s\S]*?)<\/ *\1 *>/gi
const TAG_A = /< *a[^>]+href *= *["']([^"']*)["'][^>]*>([\s\S]*?)<\/ *a *>/gi
const TAG_LI = /< *li[^>]*>([\s\S]*?)<\/ *li *>/gi
const TAG_IMG = /< *img[^>]+alt *= *["']([^"']*)["'][^>]* *\/?>/gi
const TAG_BR = /< *br\s*\/?>/gi
const TAG_BLOCK = /< *\/?(p|div|tr|section|article|main|blockquote|pre|ul|ol|dl|dt|dd|table|thead|tbody|tfoot|figcaption|figure)[^>]*>/gi
const TAG_TD = /< *\/?(td|th)[^>]*>/gi
const TAG_ANY = /<[^>]+>/g
const ENTITY_MAP: Record<string, string> = {
    '&amp;': '&', '&lt;': '<', '&gt;': '>', '&quot;': '"',
    '&#39;': "'", '&apos;': "'", '&nbsp;': ' ', '&#x2F;': '/',
    '&ndash;': '–', '&mdash;': '—', '&hellip;': '…',
    '&laquo;': '«', '&raquo;': '»', '&copy;': '©',
}
const ENTITY_RE = new RegExp(Object.keys(ENTITY_MAP).join('|') + '|&#(\\d+);|&#x([0-9a-fA-F]+);', 'gi')

function decodeEntities(s: string): string {
    return s.replace(ENTITY_RE, (match, dec, hex) => {
        if (dec) return String.fromCharCode(Number(dec))
        if (hex) return String.fromCharCode(parseInt(hex, 16))
        return ENTITY_MAP[match.toLowerCase()] ?? match
    })
}

function htmlToReadableText(html: string): string {
    let t = html
    t = t.replace(BLOCK_STRIP_TAGS, '')
    t = t.replace(TAG_HEADING, (_, level, inner) => {
        const prefix = '#'.repeat(Number(level[1]))
        return `\n\n${prefix} ${inner.replace(TAG_ANY, '').trim()}\n\n`
    })
    t = t.replace(TAG_A, (_, href, inner) => {
        const text = inner.replace(TAG_ANY, '').trim()
        if (!text) return ''
        if (!href || href.startsWith('#') || href.startsWith('javascript:')) return text
        return `[${text}](${href})`
    })
    t = t.replace(TAG_LI, (_, inner) => `\n- ${inner.replace(TAG_ANY, '').trim()}`)
    t = t.replace(TAG_IMG, (_, alt) => alt ? `[image: ${alt}]` : '')
    t = t.replace(TAG_BR, '\n')
    t = t.replace(TAG_BLOCK, '\n\n')
    t = t.replace(TAG_TD, ' | ')
    t = t.replace(TAG_ANY, '')
    t = decodeEntities(t)
    t = t.replace(/[ \t]+/g, ' ')
    t = t.replace(/\n{3,}/g, '\n\n')
    return t.trim()
}
