/**
 * User-configurable hook system.
 * Hooks are scripts or functions triggered on system events.
 * Supports loading from workspace .novaclaw/hooks/ directory.
 */

import { readdir, readFile } from 'node:fs/promises'
import { join, extname } from 'node:path'
import { toErrorMessage } from '../../../constants/errors.ts'
import { Logger } from '../../utils/logger.ts'

export type HookEvent =
    | 'session:start'
    | 'session:end'
    | 'message:before'
    | 'message:after'
    | 'tool:before'
    | 'tool:after'
    | 'boot'
    | 'shutdown'

export interface HookDefinition {
    id: string
    event: HookEvent
    name: string
    description?: string
    enabled: boolean
    handler: (context: HookContext) => Promise<void>
}

export interface HookContext {
    event: HookEvent
    timestamp: number
    data: Record<string, unknown>
}

export interface HookFileConfig {
    id: string
    event: HookEvent
    name: string
    description?: string
    enabled?: boolean
    script: string
}

export class HookManager {
    private hooks = new Map<string, HookDefinition>()
    private eventIndex = new Map<HookEvent, Set<string>>()
    private logger: Logger

    constructor(logLevel?: string) {
        this.logger = new Logger('HookManager', logLevel ?? 'info')
    }

    register(hook: HookDefinition): void {
        this.hooks.set(hook.id, hook)
        if (!this.eventIndex.has(hook.event)) {
            this.eventIndex.set(hook.event, new Set())
        }
        this.eventIndex.get(hook.event)!.add(hook.id)
        this.logger.debug('Hook registered', { id: hook.id, event: hook.event })
    }

    unregister(hookId: string): boolean {
        const hook = this.hooks.get(hookId)
        if (!hook) return false
        this.hooks.delete(hookId)
        this.eventIndex.get(hook.event)?.delete(hookId)
        return true
    }

    async trigger(event: HookEvent, data: Record<string, unknown> = {}): Promise<void> {
        const hookIds = this.eventIndex.get(event)
        if (!hookIds || hookIds.size === 0) return

        const context: HookContext = { event, timestamp: Date.now(), data }

        for (const hookId of hookIds) {
            const hook = this.hooks.get(hookId)
            if (!hook || !hook.enabled) continue

            try {
                await hook.handler(context)
            } catch (err) {
                this.logger.warn('Hook execution failed', {
                    hookId: hook.id,
                    event,
                    error: toErrorMessage(err)
                })
            }
        }
    }

    async loadFromDirectory(dir: string): Promise<number> {
        const hooksDir = join(dir, '.novaclaw', 'hooks')
        let loaded = 0

        try {
            const entries = await readdir(hooksDir, { withFileTypes: true })
            for (const entry of entries) {
                if (!entry.isFile()) continue
                const ext = extname(entry.name)
                if (ext !== '.json' && ext !== '.yaml' && ext !== '.yml') continue

                try {
                    const content = await readFile(join(hooksDir, entry.name), 'utf-8')
                    const configs = this.parseHookFile(content, ext)
                    for (const config of configs) {
                        this.registerFromConfig(config)
                        loaded++
                    }
                } catch (err) {
                    this.logger.warn('Failed to load hook file', {
                        file: entry.name,
                        error: toErrorMessage(err)
                    })
                }
            }
        } catch {
            // hooks directory doesn't exist — that's fine
        }

        if (loaded > 0) {
            this.logger.info(`Loaded ${loaded} hooks from ${hooksDir}`)
        }
        return loaded
    }

    list(): Array<{ id: string; event: HookEvent; name: string; enabled: boolean }> {
        return Array.from(this.hooks.values()).map(h => ({
            id: h.id,
            event: h.event,
            name: h.name,
            enabled: h.enabled
        }))
    }

    setEnabled(hookId: string, enabled: boolean): boolean {
        const hook = this.hooks.get(hookId)
        if (!hook) return false
        hook.enabled = enabled
        return true
    }

    private parseHookFile(content: string, ext: string): HookFileConfig[] {
        if (ext === '.json') {
            const parsed = JSON.parse(content)
            return Array.isArray(parsed) ? parsed : [parsed]
        }
        // YAML support would require the yaml package; for now JSON only
        return []
    }

    private registerFromConfig(config: HookFileConfig): void {
        const validEvents: HookEvent[] = [
            'session:start', 'session:end', 'message:before', 'message:after',
            'tool:before', 'tool:after', 'boot', 'shutdown'
        ]
        if (!validEvents.includes(config.event)) {
            this.logger.warn('Invalid hook event', { id: config.id, event: config.event })
            return
        }

        this.register({
            id: config.id,
            event: config.event,
            name: config.name,
            description: config.description,
            enabled: config.enabled !== false,
            handler: async (ctx) => {
                this.logger.debug('Executing hook script', { id: config.id, event: ctx.event })
                // Script hooks log the context; actual script execution can be extended
                // via exec tool or custom runtime
                this.logger.info(`[Hook:${config.id}] ${config.script}`, { context: ctx.data })
            }
        })
    }
}
