/**
 * BM25F full-text search engine for local RAG. Framework-only; no project imports.
 */

// ——— Stopwords ———

const STOPWORDS_EN = new Set([
    'the', 'a', 'an', 'is', 'are', 'was', 'were', 'be', 'been', 'being',
    'have', 'has', 'had', 'do', 'does', 'did', 'will', 'would', 'could',
    'should', 'may', 'might', 'shall', 'can', 'to', 'of', 'in', 'for',
    'on', 'with', 'at', 'by', 'from', 'as', 'into', 'through', 'and',
    'but', 'or', 'nor', 'not', 'so', 'if', 'then', 'than', 'too', 'very',
    'this', 'that', 'these', 'those', 'it', 'its', 'my', 'your', 'his',
    'her', 'our', 'their', 'what', 'which', 'who', 'whom', 'i', 'me', 'we',
    'he', 'she', 'they', 'them', 'up', 'out', 'about', 'just', 'also',
])

const STOPWORDS_ZH = new Set([
    '的', '了', '在', '是', '我', '有', '和', '就', '不', '人', '都', '一',
    '个', '上', '也', '很', '到', '说', '要', '去', '你', '会', '着',
    '没有', '看', '好', '自己', '这', '他', '她', '它', '们', '那',
])

const STEM_RULES: Array<[RegExp, string]> = [
    [/ies$/, 'i'], [/sses$/, 'ss'], [/(\w)s$/, '$1'], [/eed$/, 'ee'],
    [/ing$/, ''], [/ed$/, ''], [/tion$/, 't'], [/ness$/, ''],
    [/ment$/, ''], [/able$/, ''], [/ible$/, ''], [/ful$/, ''],
    [/ous$/, ''], [/ive$/, ''], [/ly$/, ''], [/er$/, ''], [/est$/, ''], [/al$/, ''],
]

function stem(word: string): string {
    if (word.length <= 3) return word
    for (const [pattern, replacement] of STEM_RULES) {
        if (pattern.test(word)) {
            const result = word.replace(pattern, replacement)
            if (result.length >= 2) return result
        }
    }
    return word
}

export interface BM25Params {
    k1: number
    b: number
    phraseBoost: number
}

export interface FieldWeights {
    title: number
    heading: number
    body: number
    path: number
}

export interface FieldedDocument {
    title: string
    heading: string
    body: string
    path: string
}

interface PostingEntry {
    docId: string
    termFrequency: number
    fieldTF: number
}

export interface BM25Snapshot {
    index: Record<string, PostingEntry[]>
    docLengths: Record<string, number>
    totalLength: number
    docCount: number
    params: BM25Params
    fieldWeights: FieldWeights
    phrases: Record<string, Array<{ docId: string; count: number }>>
}

const DEFAULT_PARAMS: BM25Params = {k1: 1.2, b: 0.75, phraseBoost: 2.0}
const DEFAULT_FIELD_WEIGHTS: FieldWeights = {title: 3.0, heading: 2.0, body: 1.0, path: 1.5}

export class BM25Index {
    private invertedIndex = new Map<string, PostingEntry[]>()
    private phraseIndex = new Map<string, Array<{ docId: string; count: number }>>()
    private docLengths = new Map<string, number>()
    private docTerms = new Map<string, Set<string>>()
    private docPhrases = new Map<string, Set<string>>()
    private totalLength = 0
    private docCount = 0
    private params: BM25Params
    private fieldWeights: FieldWeights

    constructor(params?: Partial<BM25Params>, fieldWeights?: Partial<FieldWeights>) {
        this.params = {...DEFAULT_PARAMS, ...params}
        this.fieldWeights = {...DEFAULT_FIELD_WEIGHTS, ...fieldWeights}
    }

    addDocument(docId: string, text: string): void {
        const firstLine = text.split('\n', 1)[0] ?? ''
        this.addFieldedDocument(docId, {title: '', heading: firstLine, body: text, path: ''})
    }

    addFieldedDocument(docId: string, fields: FieldedDocument): void {
        const w = this.fieldWeights
        const allTokens: string[] = []
        const weightedTF = new Map<string, number>()
        const processField = (text: string, weight: number) => {
            const tokens = tokenize(text)
            for (const t of tokens) {
                weightedTF.set(t, (weightedTF.get(t) || 0) + weight)
                allTokens.push(t)
            }
        }
        processField(fields.title, w.title)
        processField(fields.heading, w.heading)
        processField(fields.body, w.body)
        processField(fields.path, w.path)
        this.docLengths.set(docId, allTokens.length)
        this.totalLength += allTokens.length
        this.docCount++
        const termSet = new Set<string>()
        for (const [term, fieldTF] of weightedTF) {
            let postings = this.invertedIndex.get(term)
            if (!postings) {
                postings = [];
                this.invertedIndex.set(term, postings)
            }
            postings.push({docId, termFrequency: fieldTF, fieldTF})
            termSet.add(term)
        }
        this.docTerms.set(docId, termSet)
        this.indexPhrases(docId, allTokens)
    }

    removeDocument(docId: string): void {
        const dl = this.docLengths.get(docId)
        if (dl !== undefined) {
            this.totalLength -= dl
            this.docLengths.delete(docId)
            this.docCount = Math.max(0, this.docCount - 1)
        }
        const terms = this.docTerms.get(docId)
        if (terms) {
            for (const term of terms) {
                const postings = this.invertedIndex.get(term)
                if (!postings) continue
                const filtered = postings.filter(p => p.docId !== docId)
                if (filtered.length === 0) this.invertedIndex.delete(term)
                else this.invertedIndex.set(term, filtered)
            }
            this.docTerms.delete(docId)
        }
        const phrases = this.docPhrases.get(docId)
        if (phrases) {
            for (const phrase of phrases) {
                const entries = this.phraseIndex.get(phrase)
                if (!entries) continue
                const filtered = entries.filter(e => e.docId !== docId)
                if (filtered.length === 0) this.phraseIndex.delete(phrase)
                else this.phraseIndex.set(phrase, filtered)
            }
            this.docPhrases.delete(docId)
        }
    }

    search(query: string, limit: number): Array<{ docId: string; score: number }> {
        const queryTokens = tokenize(query)
        if (queryTokens.length === 0) return []
        const scores = new Map<string, number>()
        const {k1, b, phraseBoost} = this.params
        const N = this.docCount
        const avgdl = this.docCount > 0 ? this.totalLength / this.docCount : 1
        const termCounts = new Map<string, number>()
        for (const t of queryTokens) termCounts.set(t, (termCounts.get(t) || 0) + 1)
        for (const [term, queryTF] of termCounts) {
            const postings = this.invertedIndex.get(term)
            if (!postings) continue
            const df = postings.length
            const idf = Math.log(1 + (N - df + 0.5) / (df + 0.5))
            for (const {docId, fieldTF} of postings) {
                const dl = this.docLengths.get(docId) || 1
                const tfNorm = (fieldTF * (k1 + 1)) / (fieldTF + k1 * (1 - b + b * (dl / avgdl)))
                scores.set(docId, (scores.get(docId) || 0) + idf * tfNorm * queryTF)
            }
        }
        if (phraseBoost > 1 && queryTokens.length >= 2) {
            for (let i = 0; i < queryTokens.length - 1; i++) {
                const bigram = `${queryTokens[i]}|${queryTokens[i + 1]}`
                const entries = this.phraseIndex.get(bigram)
                if (!entries) continue
                for (const {docId, count} of entries) {
                    const base = scores.get(docId)
                    if (base !== undefined) scores.set(docId, base + base * (phraseBoost - 1) * Math.min(count, 3) / 3)
                }
            }
        }
        return Array.from(scores.entries())
            .map(([docId, score]) => ({docId, score}))
            .sort((a, b) => b.score - a.score)
            .slice(0, limit)
    }

    getDocumentFrequency(term: string): number {
        return this.invertedIndex.get(term)?.length ?? 0
    }

    getTopTerms(docId: string, topN: number): string[] {
        const termScores: Array<[string, number]> = []
        for (const [term, postings] of this.invertedIndex) {
            for (const p of postings) {
                if (p.docId === docId) {
                    const df = postings.length
                    const idf = Math.log(1 + this.docCount / (df + 1))
                    termScores.push([term, p.fieldTF * idf])
                    break
                }
            }
        }
        return termScores.sort((a, b) => b[1] - a[1]).slice(0, topN).map(([t]) => t)
    }

    clear(): void {
        this.invertedIndex.clear()
        this.phraseIndex.clear()
        this.docLengths.clear()
        this.docTerms.clear()
        this.docPhrases.clear()
        this.totalLength = 0
        this.docCount = 0
    }

    get size(): number {
        return this.docCount
    }

    serialize(): BM25Snapshot {
        const index: Record<string, PostingEntry[]> = {}
        for (const [term, postings] of this.invertedIndex) index[term] = postings
        const phrases: Record<string, Array<{ docId: string; count: number }>> = {}
        for (const [phrase, entries] of this.phraseIndex) phrases[phrase] = entries
        return {
            index,
            docLengths: Object.fromEntries(this.docLengths),
            totalLength: this.totalLength,
            docCount: this.docCount,
            params: this.params,
            fieldWeights: this.fieldWeights,
            phrases,
        }
    }

    /** Restore internal state from a serialized snapshot. Used by deserialize. */
    private restoreFromSnapshot(snapshot: BM25Snapshot): void {
        this.docCount = snapshot.docCount
        this.totalLength = snapshot.totalLength ?? 0
        this.docLengths.clear()
        for (const [docId, len] of Object.entries(snapshot.docLengths)) {
            this.docLengths.set(docId, len)
        }
        this.invertedIndex.clear()
        for (const [term, postings] of Object.entries(snapshot.index)) {
            this.invertedIndex.set(term, postings)
        }
        this.phraseIndex.clear()
        if (snapshot.phrases) {
            for (const [phrase, entries] of Object.entries(snapshot.phrases)) {
                this.phraseIndex.set(phrase, entries)
            }
        }
        this.docTerms.clear()
        for (const [term, postings] of this.invertedIndex) {
            for (const p of postings) {
                let set = this.docTerms.get(p.docId)
                if (!set) {
                    set = new Set();
                    this.docTerms.set(p.docId, set)
                }
                set.add(term)
            }
        }
        this.docPhrases.clear()
        for (const [phrase, entries] of this.phraseIndex) {
            for (const {docId} of entries) {
                let set = this.docPhrases.get(docId)
                if (!set) {
                    set = new Set();
                    this.docPhrases.set(docId, set)
                }
                set.add(phrase)
            }
        }
    }

    static deserialize(snapshot: BM25Snapshot): BM25Index {
        const bm25 = new BM25Index(snapshot.params, snapshot.fieldWeights)
        bm25.restoreFromSnapshot(snapshot)
        return bm25
    }

    private indexPhrases(docId: string, tokens: string[]): void {
        if (tokens.length < 2) return
        const counts = new Map<string, number>()
        for (let i = 0; i < tokens.length - 1; i++) {
            const bigram = `${tokens[i]}|${tokens[i + 1]}`
            counts.set(bigram, (counts.get(bigram) || 0) + 1)
        }
        const phraseSet = new Set<string>()
        for (const [phrase, count] of counts) {
            let entries = this.phraseIndex.get(phrase)
            if (!entries) {
                entries = [];
                this.phraseIndex.set(phrase, entries)
            }
            entries.push({docId, count})
            phraseSet.add(phrase)
        }
        this.docPhrases.set(docId, phraseSet)
    }
}

export function tokenize(text: string): string[] {
    const lower = text.toLowerCase()
    const tokens: string[] = []
    const codeExpanded = lower
        .replace(/([a-z])([A-Z])/g, '$1 $2')
        .replace(/([A-Z]+)([A-Z][a-z])/g, '$1 $2')
        .replace(/[_\-./\\]+/g, ' ')
    const caseExpanded = text
        .replace(/([a-z])([A-Z])/g, '$1 $2')
        .replace(/([A-Z]+)([A-Z][a-z])/g, '$1 $2')
        .replace(/[_\-./\\]+/g, ' ')
        .toLowerCase()
    const wordSource = `${codeExpanded} ${caseExpanded}`
    const words = wordSource.split(/[^\p{L}\p{N}]+/u).filter(w => w.length > 1)
    const seen = new Set<string>()
    for (const w of words) {
        if (STOPWORDS_EN.has(w)) continue
        if (!seen.has(w)) {
            tokens.push(w);
            seen.add(w)
        }
        const stemmed = stem(w)
        if (stemmed !== w && !seen.has(stemmed)) {
            tokens.push(stemmed);
            seen.add(stemmed)
        }
    }
    const cjkChars = lower.replace(/[^\u4e00-\u9fff\u3400-\u4dbf]+/g, ' ').trim()
    for (const segment of cjkChars.split(/\s+/)) {
        if (segment.length < 2) continue
        for (let i = 0; i <= segment.length - 2; i++) {
            const bigram = segment.slice(i, i + 2)
            if (!STOPWORDS_ZH.has(bigram)) tokens.push(bigram)
        }
        for (let i = 0; i <= segment.length - 3; i++) tokens.push(segment.slice(i, i + 3))
    }
    return tokens
}