/**
 * File-based skill provider — default ISkillProvider.
 *
 * Thin facade that wires together:
 *  - SkillRegistry  — loading, migration, hot-reload, platform gating
 *  - SkillResolver   — BM25-based relevance matching
 *  - LRU cache       — memoises resolve() results
 */

import { createHash } from 'node:crypto'
import { LRUCache } from '../../../utils/cache.ts'
import { Logger } from '../../../utils/logger.ts'
import type { SessionContext } from '../apis/common.ts'
import type { NovaClawConfig } from '../apis/config.ts'
import type { ISkillProvider, SkillDefinition, SkillSearchResult } from '../apis/skill.ts'
import { SkillLoader } from './skill-loader.ts'
import { SkillRegistry } from './skill-registry.ts'
import { SkillResolver } from './skill-resolver.ts'

export class FileSkillProvider implements ISkillProvider {
    readonly id = 'file'
    readonly version = '2026-03'

    private registry: SkillRegistry
    private resolver: SkillResolver
    private cache: LRUCache<SkillDefinition[]>
    private logger: Logger

    constructor(private config: NovaClawConfig) {
        const logLevel = config.logging?.level ?? 'info'
        this.logger = new Logger('FileSkillProvider', logLevel)

        const loader = new SkillLoader(logLevel)
        this.registry = new SkillRegistry(config as Record<string, unknown>, loader)
        this.resolver = new SkillResolver()

        const cacheOpt = (config as Record<string, unknown> & { performance?: { skillsCache?: { maxSize?: number } } })
            .performance?.skillsCache
        this.cache = new LRUCache<SkillDefinition[]>(cacheOpt?.maxSize ?? 100)
    }

    // ── ISkillProvider ───────────────────────────────────────────────────

    async listSkills(): Promise<SkillDefinition[]> {
        return this.registry.getAll()
    }

    async resolve(
        message: string,
        context: SessionContext,
        options: { maxSkills?: number; mentionedFiles?: string[] } = {},
    ): Promise<SkillSearchResult[]> {
        const maxSkills = options.maxSkills ?? 5
        const cacheKey = this.buildCacheKey(message, context.channel, maxSkills)

        const cached = this.cache.get(cacheKey)
        if (cached) return cached.map(s => ({ skill: s, score: 1, source: 'cache' }))

        const results = this.resolver.resolve(message, context, this.registry.getAll(), {
            maxSkills,
            mentionedFiles: options.mentionedFiles,
        })

        const perf = (this.config as Record<string, unknown> & { performance?: { skillsCache?: { ttl?: number } } })
            .performance?.skillsCache
        if (perf?.ttl) this.cache.set(cacheKey, results.map(r => r.skill), perf.ttl)

        return results
    }

    // ── Lifecycle ────────────────────────────────────────────────────────

    async initialize(): Promise<void> {
        this.registry.ensureMigrated()
        await this.registry.loadAll()
        this.resolver.buildIndex(this.registry.getAll())
        this.registry.startWatcher(() => this.onReload())
        this.logger.info('Initialized', { skills: this.registry.getAll().length })
    }

    async cleanup(): Promise<void> {
        await this.registry.stopWatcher()
        this.cache.clear()
    }

    // ── Accessors ────────────────────────────────────────────────────────

    getSkillById(id: string): SkillDefinition | undefined {
        return this.registry.getById(id)
    }

    listSkillIds(): string[] {
        return this.registry.listIds()
    }

    addExternalSkills(skills: SkillDefinition[]): number {
        const added = this.registry.addSkills(skills)
        if (added > 0) {
            this.rebuildIndex()
            this.logger.info(`Merged ${added} external skill(s)`, { total: this.registry.getAll().length })
        }
        return added
    }

    async reloadFromDisk(): Promise<void> {
        await this.registry.loadAll()
        this.rebuildIndex()
        this.logger.info('Reloaded from disk', { skills: this.registry.getAll().length })
    }

    getStats(): { totalSkills: number } {
        return { totalSkills: this.registry.getAll().length }
    }

    // ── Private ──────────────────────────────────────────────────────────

    private async onReload(): Promise<void> {
        this.rebuildIndex()
    }

    private rebuildIndex(): void {
        this.resolver.buildIndex(this.registry.getAll())
        this.cache.clear()
    }

    private buildCacheKey(message: string, channel: string, maxSkills: number): string {
        const hash = createHash('sha256').update(message).digest('hex').slice(0, 16)
        return `${hash}:${channel}:${maxSkills}`
    }
}
