/**
 * Shared skill parsing utilities for loading SKILL.md files.
 */

import { existsSync } from 'node:fs'
import { join } from 'node:path'
import { parse as parseYaml } from 'yaml'

export const SKILL_FILES = ['SKILL.md', 'skill.md'] as const
export const RUN_SCRIPTS = ['run.py', 'run.sh', 'run.ts', 'run.js'] as const

const FRONTMATTER_RE = /^---\n([\s\S]*?)\n---\n([\s\S]*)$/

export interface RawFrontmatter {
    name?: string
    description?: string
    display_name?: string
    globs?: string[]
    alwaysApply?: boolean
    when?: { channels?: string[]; platforms?: string[] }
    tags?: string[]
    priority?: number
    version?: string
    author?: string
    platforms?: string[]
    category?: string
}

/** Find the first existing SKILL.md (or skill.md) in a directory. */
export function findSkillFile(dir: string): string | null {
    for (const name of SKILL_FILES) {
        const p = join(dir, name)
        if (existsSync(p)) return p
    }
    return null
}

/** Find the first existing run script (run.py, run.sh, etc.) in a directory. */
export function findRunScript(dir: string): string | null {
    for (const name of RUN_SCRIPTS) {
        const p = join(dir, name)
        if (existsSync(p)) return p
    }
    return null
}

/** Parse YAML frontmatter from a SKILL.md file. */
export function parseFrontmatter(raw: string): { frontmatter: RawFrontmatter; body: string } {
    const match = FRONTMATTER_RE.exec(raw)
    if (!match?.[1] || !match[2]) {
        return { frontmatter: {}, body: raw.trim() }
    }
    let frontmatter: RawFrontmatter = {}
    try {
        frontmatter = (parseYaml(match[1]) as RawFrontmatter) ?? {}
    } catch {
        return { frontmatter: {}, body: raw.trim() }
    }
    return { frontmatter, body: match[2].trim() }
}
