/**
 * Output rule: strip <think> tags from LLM output.
 * Some models (e.g. DeepSeek, QwQ) emit reasoning inside <think>...</think>.
 */

import type { IRule, RuleContext, RuleVerdict } from '../../apis/rule.ts'

const THINK_PATTERN = /<think>[\s\S]*?<\/think>/g

export function createThinkingStripRule(): IRule {
    return {
        id: 'thinking-strip',
        name: 'Strip thinking tags',
        description: 'Remove <think>...</think> blocks from agent output',
        phase: 'output',
        priority: 90,

        evaluate(ctx: RuleContext): RuleVerdict | undefined {
            if (ctx.type !== 'output' || !ctx.content) return undefined
            if (!THINK_PATTERN.test(ctx.content)) return undefined

            THINK_PATTERN.lastIndex = 0
            const stripped = ctx.content.replace(THINK_PATTERN, '').trim()
            if (stripped !== ctx.content) {
                return { action: 'rewrite', content: stripped }
            }
            return undefined
        },
    }
}
