/**
 * Abstract base for SSE-streaming LLM providers.
 *
 * Encapsulates HTTP timeout/abort wiring, stall detection, perf logging,
 * tool-call accumulation, and usage aggregation. Subclasses implement only
 * the provider-specific bits: URL, headers, body, and SSE payload parsing.
 */

import crypto from 'node:crypto'
import { performance } from 'node:perf_hooks'
import type { ChatStreamOptions, LLMProvider, LLMProviderConfig, ProviderMessage, StreamingChunk } from '../apis/provider.ts'
import { toErrorMessage, toErrorName } from '../../../constants/errors.ts'
import { LLM_COMPLETE_TIMEOUT_MS, LLM_HTTP_TIMEOUT_MS, LLM_STREAM_STALL_MS } from '../../../constants/timeouts.ts'
import { Logger } from '../../utils/logger.ts'
import { readResponseLines, parseSSEData, type StreamStats } from './sse-reader.ts'
import { LLMApiError } from './errors.ts'

export interface ToolCallAccumulator {
    id: string
    name: string
    argsBuffer: string
}

export interface ParsedSSEResult {
    chunks: StreamingChunk[]
    toolCalls?: Array<{ index: number | string; id?: string; name?: string; argsFragment?: string }>
    usage?: { input: number; output: number }
    finished?: boolean
}

export abstract class BaseStreamProvider implements LLMProvider {
    abstract readonly name: string
    protected logger: Logger

    constructor(
        protected providerKey: string,
        protected config: LLMProviderConfig,
    ) {
        this.logger = new Logger(`LLM:${providerKey}`, config.logLevel ?? 'info')
    }

    // -- Subclass hooks -------------------------------------------------------

    protected abstract buildStreamUrl(model: string): string
    protected abstract buildCompleteUrl(model: string): string
    protected abstract buildHeaders(): Record<string, string>
    protected abstract buildStreamBody(
        model: string,
        messages: ProviderMessage[],
        options?: ChatStreamOptions,
    ): Record<string, unknown>
    protected abstract buildCompleteBody(
        model: string,
        messages: ProviderMessage[],
        maxTokens: number,
    ): Record<string, unknown>
    protected abstract extractCompleteContent(json: unknown): string | null

    /**
     * Parse a single SSE JSON payload into streaming chunks.
     * Return yielded chunks, optional tool-call fragments, usage, and finish flag.
     */
    protected abstract parseSSEPayload(json: Record<string, unknown>): ParsedSSEResult

    // -- chatComplete (shared) ------------------------------------------------

    private static readonly COMPLETE_TIMEOUT_MS = LLM_COMPLETE_TIMEOUT_MS

    async chatComplete(
        model: string,
        messages: ProviderMessage[],
        options?: { maxTokens?: number; abortSignal?: AbortSignal },
    ): Promise<string | null> {
        const url = this.buildCompleteUrl(model)
        const controller = new AbortController()
        const timer = setTimeout(() => controller.abort(), BaseStreamProvider.COMPLETE_TIMEOUT_MS)

        const linkAbort = () => controller.abort()
        options?.abortSignal?.addEventListener('abort', linkAbort, { once: true })

        try {
            const res = await fetch(url, {
                method: 'POST',
                headers: this.buildHeaders(),
                body: JSON.stringify(this.buildCompleteBody(model, messages, options?.maxTokens ?? 2048)),
                signal: controller.signal,
            })

            if (!res.ok) {
                const errText = await res.text().catch(() => '')
                const retryAfterRaw = res.headers.get('retry-after')
                const retryAfterSec = retryAfterRaw ? parseInt(retryAfterRaw, 10) || null : null
                this.logger.warn('chatComplete API error', { status: res.status, body: errText.slice(0, 200) })
                throw new LLMApiError(`chatComplete ${res.status}: ${errText}`, res.status, retryAfterSec, this.providerKey)
            }

            return this.extractCompleteContent(await res.json())
        } catch (err) {
            if (err instanceof LLMApiError) throw err
            const msg = toErrorName(err) === 'AbortError' ? 'timeout' : toErrorMessage(err)
            this.logger.warn('chatComplete failed', { reason: msg })
            return null
        } finally {
            clearTimeout(timer)
            options?.abortSignal?.removeEventListener('abort', linkAbort)
        }
    }

    // -- chatStream (shared) --------------------------------------------------

    async *chatStream(
        model: string,
        messages: ProviderMessage[],
        options?: ChatStreamOptions,
    ): AsyncGenerator<StreamingChunk> {
        const url = this.buildStreamUrl(model)
        const body = this.buildStreamBody(model, messages, options)
        const payloadJson = JSON.stringify(body)

        this.logger.debug('Sending request', {
            model,
            messages: messages.length,
            tools: options?.tools?.length ?? 0,
            payloadKB: (payloadJson.length / 1024).toFixed(1),
        })

        const HTTP_TIMEOUT_MS = this.config.httpTimeoutMs ?? LLM_HTTP_TIMEOUT_MS
        const STREAM_STALL_TIMEOUT_MS = this.config.streamStallMs ?? LLM_STREAM_STALL_MS
        const internalController = new AbortController()
        const linkAbort = () => internalController.abort()
        options?.abortSignal?.addEventListener('abort', linkAbort, { once: true })

        const httpTimer = setTimeout(() => {
            this.logger.warn(`HTTP timeout after ${HTTP_TIMEOUT_MS}ms`)
            internalController.abort()
        }, HTTP_TIMEOUT_MS)

        const tFetch0 = performance.now()
        const MAX_RETRIES = 2
        let res: Response | undefined
        let lastErr: unknown
        for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
            try {
                res = await fetch(url, {
                    method: 'POST',
                    headers: { ...this.buildHeaders(), Connection: 'keep-alive' },
                    body: payloadJson,
                    signal: internalController.signal,
                })
                if (res.ok || res.status < 500 || attempt === MAX_RETRIES) break
                this.logger.warn(`Transient ${res.status}, retry ${attempt + 1}/${MAX_RETRIES}`)
                const backoff = Math.min(1000 * 2 ** attempt, 4000)
                await new Promise(r => setTimeout(r, backoff))
                continue
            } catch (err) {
                lastErr = err
                if (internalController.signal.aborted) break
                if (attempt < MAX_RETRIES) {
                    this.logger.warn(`Fetch error, retry ${attempt + 1}/${MAX_RETRIES}: ${toErrorMessage(err)}`)
                    const backoff = Math.min(1000 * 2 ** attempt, 4000)
                    await new Promise(r => setTimeout(r, backoff))
                    continue
                }
                break
            }
        }
        clearTimeout(httpTimer)
        if (!res) {
            options?.abortSignal?.removeEventListener('abort', linkAbort)
            const elapsed = performance.now() - tFetch0
            if (internalController.signal.aborted && elapsed >= HTTP_TIMEOUT_MS - 500) {
                throw new LLMApiError(
                    `${this.providerKey} HTTP timeout: no response after ${(elapsed / 1000).toFixed(1)}s`,
                    408,
                    null,
                    this.providerKey,
                )
            }
            throw lastErr
        }
        const tFetch1 = performance.now()

        this.logger.debug(`Response received (${(tFetch1 - tFetch0).toFixed(0)}ms)`, { status: res.status })

        if (!res.ok) {
            const errText = await res.text().catch(() => '')
            const retryAfterRaw = res.headers.get('retry-after')
            const retryAfterSec = retryAfterRaw ? parseInt(retryAfterRaw, 10) || null : null
            if (res.status === 422) {
                this.logger.warn('422 Unprocessable Entity', { body: errText.slice(0, 300) })
            } else if (res.status === 429) {
                this.logger.warn('429 Rate Limited', { retryAfter: retryAfterSec })
            } else {
                this.logger.warn(`HTTP ${res.status}`, { body: errText.slice(0, 300) })
            }
            throw new LLMApiError(`API ${res.status}: ${errText}`, res.status, retryAfterSec, this.providerKey)
        }

        const reader = res.body?.getReader()
        if (!reader) {
            yield { type: 'error', error: 'No response body' }
            return
        }

        let totalInput = 0
        let totalOutput = 0
        const toolCallsAccumulator = new Map<number | string, ToolCallAccumulator>()

        const tStreamBody0 = performance.now()
        const stats: StreamStats = { firstReadTime: null, readCount: 0, totalBytes: 0 }
        let finished = false
        let linesAfterFinish = 0
        let lineCount = 0

        try {
            for await (const line of readResponseLines(reader, {
                stallTimeoutMs: STREAM_STALL_TIMEOUT_MS,
                onStall: () => {
                    const elapsed = (performance.now() - tStreamBody0).toFixed(0)
                    this.logger.warn(`Stream stalled for ${STREAM_STALL_TIMEOUT_MS}ms, aborting`, {
                        elapsedMs: elapsed,
                        reads: stats.readCount,
                        bytes: stats.totalBytes,
                    })
                    internalController.abort()
                },
                stats,
            })) {
                lineCount++

                const data = parseSSEData(line)
                if (data) {
                    try {
                        const json = JSON.parse(data) as Record<string, unknown>
                        const result = this.parseSSEPayload(json)

                        for (const chunk of result.chunks) yield chunk

                        if (result.toolCalls) {
                            for (const tc of result.toolCalls) {
                                const key = tc.index
                                let acc = toolCallsAccumulator.get(key)
                                if (!acc) {
                                    acc = {
                                        id: tc.id ?? crypto.randomUUID(),
                                        name: tc.name?.trim() || 'exec',
                                        argsBuffer: '',
                                    }
                                    toolCallsAccumulator.set(key, acc)
                                }
                                if (tc.id) acc.id = tc.id
                                if (tc.name) acc.name = tc.name.trim()
                                if (tc.argsFragment) acc.argsBuffer += tc.argsFragment
                            }
                        }

                        if (result.usage) {
                            totalInput = result.usage.input
                            totalOutput = result.usage.output
                        }

                        if (result.finished) finished = true
                    } catch { /* ignore malformed JSON */ }
                } else if (line.trim() && !line.startsWith(':')) {
                    try {
                        const json = JSON.parse(line) as Record<string, unknown>
                        if (typeof json.content === 'string') yield { type: 'content', content: json.content }
                    } catch { /* skip */ }
                }

                if (finished) {
                    linesAfterFinish++
                }
            }
        } finally {
            options?.abortSignal?.removeEventListener('abort', linkAbort)
        }

        yield* this.emitAccumulatedToolCalls(toolCallsAccumulator)

        const tStreamBodyEnd = performance.now()
        this.logger.debug(`Stream complete (${(tStreamBodyEnd - tFetch0).toFixed(0)}ms)`, {
            httpWaitMs: +(tFetch1 - tFetch0).toFixed(0),
            streamMs: +(tStreamBodyEnd - tStreamBody0).toFixed(0),
            reads: stats.readCount,
            bytes: stats.totalBytes,
            tokens: { in: totalInput, out: totalOutput },
            toolCalls: toolCallsAccumulator.size,
        })

        if (totalInput > 0 || totalOutput > 0) {
            yield {
                type: 'usage',
                usage: { totalTokens: totalInput + totalOutput, inputTokens: totalInput, outputTokens: totalOutput },
            }
        }
    }

    private *emitAccumulatedToolCalls(
        accumulator: Map<number | string, ToolCallAccumulator>,
    ): Generator<StreamingChunk> {
        for (const [, acc] of Array.from(accumulator.entries()).sort(([a], [b]) => {
            if (typeof a === 'number' && typeof b === 'number') return a - b
            return String(a).localeCompare(String(b))
        })) {
            this.logger.debug('Tool call parsed', { name: acc.name })
            let args: Record<string, unknown> = {}
            try {
                if (acc.argsBuffer.trim()) args = JSON.parse(acc.argsBuffer) as Record<string, unknown>
            } catch {
                this.logger.warn('Tool call args parse failed, using raw as command', {
                    argsBuffer: acc.argsBuffer.slice(0, 200),
                })
                args = { command: acc.argsBuffer.trim() || '' }
            }
            yield {
                type: 'tool_call',
                toolCall: { id: acc.id, name: acc.name, args, status: 'running' as const },
            }
        }
    }
}
