// ---------------------------------------------------------------------------
// Entity types
// ---------------------------------------------------------------------------

export type EntityType =
    | 'person'
    | 'organization'
    | 'technology'
    | 'concept'
    | 'file'
    | 'function'
    | 'class'
    | 'module'
    | 'api'
    | 'service'
    | 'config'
    | 'event'
    | 'custom'

export const ENTITY_TYPES: readonly EntityType[] = [
    'person', 'organization', 'technology', 'concept',
    'file', 'function', 'class', 'module',
    'api', 'service', 'config', 'event', 'custom',
] as const

// ---------------------------------------------------------------------------
// Relation types
// ---------------------------------------------------------------------------

export type RelationType =
    | 'depends_on'
    | 'imports'
    | 'calls'
    | 'implements'
    | 'contains'
    | 'extends'
    | 'configures'
    | 'relates_to'
    | 'similar_to'
    | 'contrasts_with'
    | 'part_of'
    | 'created_by'
    | 'used_by'
    | 'custom'

export const RELATION_TYPES: readonly RelationType[] = [
    'depends_on', 'imports', 'calls', 'implements',
    'contains', 'extends', 'configures',
    'relates_to', 'similar_to', 'contrasts_with',
    'part_of', 'created_by', 'used_by', 'custom',
] as const

// ---------------------------------------------------------------------------
// Knowledge Graph Entity
// ---------------------------------------------------------------------------

export interface KGEntity {
    id: string
    name: string
    type: EntityType
    description: string
    properties: Record<string, unknown>
    sourceChunks: string[]
    sourceDocuments: string[]
    createdAt: number
    updatedAt: number
}

// ---------------------------------------------------------------------------
// Knowledge Graph Relation
// ---------------------------------------------------------------------------

export interface KGRelation {
    id: string
    sourceEntityId: string
    targetEntityId: string
    type: RelationType
    description?: string
    weight: number
    sourceChunks: string[]
    createdAt: number
}

// ---------------------------------------------------------------------------
// Community (entity clusters)
// ---------------------------------------------------------------------------

export interface KGCommunity {
    id: string
    name: string
    summary: string
    entityIds: string[]
    level: number
}

// ---------------------------------------------------------------------------
// Graph retrieval result
// ---------------------------------------------------------------------------

export interface GraphRetrievalResult {
    entityId: string
    entityName: string
    entityType: EntityType
    relations: Array<{
        targetEntityId: string
        targetEntityName: string
        relationType: RelationType
        description?: string
    }>
    sourceChunkIds: string[]
    score: number
}

// ---------------------------------------------------------------------------
// Graph snapshot (persistence)
// ---------------------------------------------------------------------------

export interface KnowledgeGraphSnapshot {
    entities: KGEntity[]
    relations: KGRelation[]
    communities: KGCommunity[]
    metadata: {
        version: string
        createdAt: number
        updatedAt: number
        entityCount: number
        relationCount: number
        communityCount: number
    }
}

// ---------------------------------------------------------------------------
// Entity extraction result (from LLM)
// ---------------------------------------------------------------------------

export interface ExtractedEntity {
    name: string
    type: EntityType
    description: string
}

export interface ExtractedRelation {
    source: string
    target: string
    type: RelationType
    description?: string
}

export interface ExtractionResult {
    entities: ExtractedEntity[]
    relations: ExtractedRelation[]
}

// ---------------------------------------------------------------------------
// Image parse result (multimodal)
// ---------------------------------------------------------------------------

export interface ImageParseResult {
    description: string
    detectedText: string[]
    entities: ExtractedEntity[]
    relations: ExtractedRelation[]
    metadata: {
        mimeType: string
        storagePath?: string
    }
}

// ---------------------------------------------------------------------------
// GraphRAG configuration
// ---------------------------------------------------------------------------

export interface GraphRagConfig {
    enabled: boolean
    entityExtraction: {
        enabled: boolean
        model?: string
        batchSize: number
        maxEntitiesPerChunk: number
    }
    communityDetection: {
        enabled: boolean
        algorithm: 'leiden' | 'louvain'
        resolution: number
        levels: number
    }
    queryStrategy: {
        directorLevel: 'community' | 'entity' | 'chunk'
        workerLevel: 'chunk' | 'entity'
    }
}

export interface HybridRetrievalConfig {
    bm25Weight: number
    /** @deprecated Vector retrieval is not yet implemented; this field is ignored. */
    vectorWeight: number
    graphWeight: number
    rerankWithLLM: boolean
}

export const DEFAULT_GRAPH_RAG_CONFIG: GraphRagConfig = {
    enabled: false,
    entityExtraction: {
        enabled: true,
        batchSize: 5,
        maxEntitiesPerChunk: 10,
    },
    communityDetection: {
        enabled: true,
        algorithm: 'leiden',
        resolution: 1.0,
        levels: 2,
    },
    queryStrategy: {
        directorLevel: 'community',
        workerLevel: 'chunk',
    },
}

export const DEFAULT_HYBRID_RETRIEVAL_CONFIG: HybridRetrievalConfig = {
    bm25Weight: 0.55,
    vectorWeight: 0,
    graphWeight: 0.45,
    rerankWithLLM: true,
}
