/**
 * Message chunker — splits long messages to fit channel character limits.
 */

export type ChunkerMode = 'text' | 'markdown'

export interface ChunkerOptions {
    mode?: ChunkerMode
    preserveCodeBlocks?: boolean
}

export function chunkText(text: string, limit: number, options?: ChunkerOptions): string[] {
    if (!text || text.length <= limit) return text ? [text] : []

    const mode = options?.mode ?? 'text'
    if (mode === 'markdown' && options?.preserveCodeBlocks !== false) {
        return chunkMarkdown(text, limit)
    }
    return chunkPlainText(text, limit)
}

function chunkPlainText(text: string, limit: number): string[] {
    const chunks: string[] = []
    const lines = text.split('\n')
    let current = ''

    for (const line of lines) {
        if (line.length > limit) {
            if (current) {
                chunks.push(current)
                current = ''
            }
            let remaining = line
            while (remaining.length > limit) {
                const breakAt = findWordBreak(remaining, limit)
                chunks.push(remaining.slice(0, breakAt))
                remaining = remaining.slice(breakAt).trimStart()
            }
            if (remaining) current = remaining
            continue
        }

        const tentative = current ? `${current}\n${line}` : line
        if (tentative.length > limit) {
            chunks.push(current)
            current = line
        } else {
            current = tentative
        }
    }

    if (current) chunks.push(current)
    return chunks
}

function chunkMarkdown(text: string, limit: number): string[] {
    const chunks: string[] = []
    const lines = text.split('\n')
    let current = ''
    let insideCodeBlock = false
    let codeBlockFence = ''

    for (const line of lines) {
        const fenceMatch = line.match(/^(`{3,}|~{3,})/)
        if (fenceMatch) {
            if (!insideCodeBlock) {
                insideCodeBlock = true
                codeBlockFence = fenceMatch[1]!
            } else if (line.startsWith(codeBlockFence)) {
                insideCodeBlock = false
                codeBlockFence = ''
            }
        }

        const tentative = current ? `${current}\n${line}` : line

        if (tentative.length > limit && !insideCodeBlock) {
            if (current) chunks.push(current)
            current = line.length > limit ? line.slice(0, limit) : line
        } else if (tentative.length > limit && insideCodeBlock) {
            if (current) {
                chunks.push(current + `\n${codeBlockFence}`)
                current = `${codeBlockFence}\n${line}`
            } else {
                current = line.length > limit ? line.slice(0, limit) : line
            }
        } else {
            current = tentative
        }
    }

    if (current) {
        if (insideCodeBlock) {
            current += `\n${codeBlockFence}`
        }
        chunks.push(current)
    }

    return chunks
}

function findWordBreak(text: string, limit: number): number {
    if (limit >= text.length) return text.length
    let breakAt = text.lastIndexOf(' ', limit)
    if (breakAt <= 0) breakAt = limit
    return breakAt
}

export const CHANNEL_TEXT_LIMITS: Record<string, number> = {
    telegram: 4000,
    whatsapp: 4000,
    discord: 2000,
    slack: 4000,
    signal: 4000,
    irc: 350,
    webchat: 10000,
    cli: 50000,
    'rest-api': 100000,
}

export function getTextChunkLimit(channelId: string, pluginLimit?: number): number {
    return pluginLimit ?? CHANNEL_TEXT_LIMITS[channelId] ?? 4000
}
