/**
 * LLMSession — real LLM streaming session implementation.
 * Extracted from ModelManager for single-responsibility.
 */

import crypto from 'node:crypto'
import type { LLMProvider } from '../../apis/provider.ts'
import { Logger } from '../../../utils/logger.ts'
import { compressHistory } from './context-compressor.ts'
import type {
    LLMSessionInterface,
    ChatMessage,
    MessageStreamParams,
    ModelInfo,
    StreamingChunk
} from '../types.ts'

export class LLMSession implements LLMSessionInterface {
    readonly sessionId = crypto.randomUUID()
    private systemPrompt = ''

    constructor(
        private readonly modelInfo: ModelInfo,
        private readonly provider: LLMProvider,
        private readonly modelParams: Record<string, unknown>,
        private readonly logger: Logger,
    ) {}

    async updateSystemPrompt(prompt: string): Promise<void> {
        this.systemPrompt = prompt
    }

    getActiveModel(): string {
        return this.modelInfo.model
    }

    async close(): Promise<void> {}

    async *processMessageStream(params: MessageStreamParams): AsyncGenerator<StreamingChunk> {
        const history = compressHistory(
            params.context.messageHistory ?? [],
            { maxTokens: this.modelInfo.maxTokens },
        )

        const messages: ChatMessage[] = [
            ...(this.systemPrompt ? [{ role: 'system' as const, content: this.systemPrompt }] : []),
            ...history.map(h => ({ role: h.role as 'user' | 'assistant', content: h.content })),
        ]

        if (params.rawExtraMessages && params.rawExtraMessages.length > 0) {
            messages.push(...params.rawExtraMessages)
        } else if (params.message) {
            messages.push({ role: 'user' as const, content: params.message })
        }

        this.logger.debug('processMessageStream', {
            historyIn: (params.context.messageHistory ?? []).length,
            historyOut: history.length,
            totalMessages: messages.length,
        })

        const stream = this.provider.chatStream(
            this.modelInfo.model,
            messages,
            {
                tools: params.tools && params.tools.length > 0 ? params.tools : undefined,
                maxTokens: this.modelInfo.maxTokens,
                abortSignal: params.abortSignal,
                ...this.modelParams,
            },
        )
        for await (const chunk of stream) {
            yield chunk as StreamingChunk
        }
    }
}
