/**
 * Rate-limit middleware — token-bucket per-IP rate limiting.
 */

import type { FastifyInstance } from 'fastify'

export interface RateLimitConfig {
    enabled?: boolean
    windowMs: number
    maxRequests: number
}

export interface RateLimitState {
    cleanup: () => void
}

export function registerRateLimit(
    server: FastifyInstance,
    rateLimitConfig: RateLimitConfig,
    preflight: WeakSet<object>,
): RateLimitState {
    const noop: RateLimitState = { cleanup: () => {} }
    if (!rateLimitConfig.enabled) return noop

    const buckets = new Map<string, { count: number; resetTime: number }>()
    const { windowMs, maxRequests } = rateLimitConfig

    const interval = setInterval(() => {
        const now = Date.now()
        for (const [ip, info] of buckets) {
            if (now > info.resetTime) buckets.delete(ip)
        }
    }, windowMs)

    server.addHook('preHandler', async (request, reply) => {
        if (preflight.has(request)) return

        const ip = request.ip
        const now = Date.now()
        let bucket = buckets.get(ip)

        if (!bucket || now > bucket.resetTime) {
            bucket = { count: 1, resetTime: now + windowMs }
            buckets.set(ip, bucket)
        } else {
            bucket.count++
            if (bucket.count > maxRequests) {
                return reply.status(429).send({
                    error: 'Too Many Requests',
                    retryAfter: Math.ceil((bucket.resetTime - now) / 1000),
                })
            }
        }

        reply.header('X-RateLimit-Limit', maxRequests.toString())
        reply.header('X-RateLimit-Remaining', Math.max(0, maxRequests - bucket.count).toString())
        reply.header('X-RateLimit-Reset', Math.ceil(bucket.resetTime / 1000).toString())
    })

    return { cleanup: () => clearInterval(interval) }
}
