/**
 * Type-safe event emitter — lighter alternative to node:events for internal use.
 */

// eslint-disable-next-line @typescript-eslint/no-explicit-any
type AnyFunction = (...args: any[]) => void

export class EventEmitter<T extends Record<string, unknown[]>> {
    private listeners = new Map<keyof T, Set<AnyFunction>>()

    on<K extends keyof T>(event: K, listener: (...args: T[K]) => void): void {
        if (!this.listeners.has(event)) {
            this.listeners.set(event, new Set())
        }
        this.listeners.get(event)!.add(listener as AnyFunction)
    }

    once<K extends keyof T>(event: K, listener: (...args: T[K]) => void): void {
        const wrapper: AnyFunction = (...args: unknown[]) => {
            this.listeners.get(event)?.delete(wrapper)
            ;(listener as AnyFunction)(...args)
        }
        this.on(event, wrapper as (...args: T[K]) => void)
    }

    off<K extends keyof T>(event: K, listener: (...args: T[K]) => void): void {
        this.listeners.get(event)?.delete(listener as AnyFunction)
    }

    emit<K extends keyof T>(event: K, ...args: T[K]): void {
        const set = this.listeners.get(event)
        if (!set) return
        for (const listener of [...set]) {
            try {
                listener(...args)
            } catch (error) {
                console.error(`Error in event listener for ${String(event)}:`, error)
            }
        }
    }

    listenerCount<K extends keyof T>(event: K): number {
        return this.listeners.get(event)?.size ?? 0
    }

    removeAllListeners(event?: keyof T): void {
        if (event) {
            this.listeners.delete(event)
        } else {
            this.listeners.clear()
        }
    }
}
