/**
 * ChannelHealthMonitor — periodic heartbeat probes for channel accounts.
 *
 * Tracks consecutive failures per account and derives a tri-state health
 * status (healthy / degraded / unhealthy) used by the gateway health endpoint.
 */

import { HEALTH_CHECK_INTERVAL_MS } from '../../../../constants/timeouts.ts'
import type { NovaClawConfig } from '../../apis/config.ts'
import type { ChannelPlugin } from '../types/plugin.ts'
import type { ChannelId } from '../types/core.ts'
import type { ChannelRuntimeSnapshot } from '../types/snapshot.ts'

// ── Health status ───────────────────────────────────────────────────────

export type ChannelHealthStatus = 'healthy' | 'degraded' | 'unhealthy'

export interface ChannelHealthInfo {
    status: ChannelHealthStatus
    consecutiveFailures: number
}

const DEGRADED_THRESHOLD = 1
const UNHEALTHY_THRESHOLD = 3

// ── Dependency contract ─────────────────────────────────────────────────

export interface HealthMonitorDeps {
    getConfig(): NovaClawConfig
    getRuntimeSnapshot(): ChannelRuntimeSnapshot
    getPlugin(channelId: ChannelId): ChannelPlugin | undefined
}

// ── Options ─────────────────────────────────────────────────────────────

export interface ChannelHealthMonitorOptions {
    intervalMs?: number
}

// ── Monitor ─────────────────────────────────────────────────────────────

export class ChannelHealthMonitor {
    private intervalMs: number
    private intervalId: ReturnType<typeof setInterval> | null = null
    private deps: HealthMonitorDeps | null = null
    private healthByKey = new Map<string, { consecutiveFailures: number }>()

    constructor(options: ChannelHealthMonitorOptions = {}) {
        this.intervalMs = options.intervalMs ?? HEALTH_CHECK_INTERVAL_MS
    }

    start(deps: HealthMonitorDeps): void {
        this.deps = deps
        this.healthByKey.clear()

        this.intervalId = setInterval(() => this.runHealthCheck(), this.intervalMs)
        if (this.intervalId.unref) {
            this.intervalId.unref()
        }
    }

    stop(): void {
        if (this.intervalId) {
            clearInterval(this.intervalId)
            this.intervalId = null
        }
        this.deps = null
        this.healthByKey.clear()
    }

    getHealth(channelId: string): ChannelHealthInfo | undefined {
        const snapshot = this.deps?.getRuntimeSnapshot()
        const channel = snapshot?.channels[channelId]
        if (!channel) return undefined

        const accounts = Object.keys(channel.accounts)
        if (accounts.length === 0) return undefined

        let maxFailures = 0
        for (const accountId of accounts) {
            const key = `${channelId}:${accountId}`
            const failures = this.healthByKey.get(key)?.consecutiveFailures ?? 0
            maxFailures = Math.max(maxFailures, failures)
        }

        const status: ChannelHealthStatus =
            maxFailures >= UNHEALTHY_THRESHOLD
                ? 'unhealthy'
                : maxFailures >= DEGRADED_THRESHOLD
                  ? 'degraded'
                  : 'healthy'

        return { status, consecutiveFailures: maxFailures }
    }

    getAllHealth(): Record<string, ChannelHealthInfo> {
        const result: Record<string, ChannelHealthInfo> = {}
        const snapshot = this.deps?.getRuntimeSnapshot()
        if (!snapshot) return result

        for (const channelId of Object.keys(snapshot.channels)) {
            const info = this.getHealth(channelId)
            if (info) result[channelId] = info
        }
        return result
    }

    private runHealthCheck(): void {
        const deps = this.deps
        if (!deps) return

        const config = deps.getConfig()
        const snapshot = deps.getRuntimeSnapshot()

        for (const [channelId, channel] of Object.entries(snapshot.channels)) {
            const plugin = deps.getPlugin(channelId as ChannelId)
            if (!plugin?.heartbeat?.ping) continue

            for (const [accountId, account] of Object.entries(channel.accounts)) {
                if (!account.running) continue

                const key = `${channelId}:${accountId}`
                plugin.heartbeat
                    .ping!({ cfg: config, accountId })
                    .then(ok => {
                        if (ok) {
                            this.healthByKey.set(key, { consecutiveFailures: 0 })
                        } else {
                            const failures = (this.healthByKey.get(key)?.consecutiveFailures ?? 0) + 1
                            this.healthByKey.set(key, { consecutiveFailures: failures })
                        }
                    })
                    .catch(() => {
                        const failures = (this.healthByKey.get(key)?.consecutiveFailures ?? 0) + 1
                        this.healthByKey.set(key, { consecutiveFailures: failures })
                    })
            }
        }
    }
}
