import { Logger } from './logger.ts'

const SHUTDOWN_TIMEOUT_MS = 15_000
const logger = new Logger('Lifecycle')

/**
 * Install SIGINT/SIGTERM handlers that invoke `onShutdown`, then exit.
 * Prevents double-shutdown and forces exit if cleanup takes too long.
 */
export function gracefulShutdown(onShutdown: () => Promise<void>): void {
    let shuttingDown = false

    const handler = (signal: string) => {
        if (shuttingDown) return
        shuttingDown = true
        logger.info(`Received ${signal}, shutting down gracefully...`)

        const forceExit = setTimeout(() => {
            logger.error('Shutdown timed out, forcing exit')
            process.exit(1)
        }, SHUTDOWN_TIMEOUT_MS)
        forceExit.unref()

        onShutdown()
            .then(() => {
                clearTimeout(forceExit)
                process.exit(0)
            })
            .catch((err) => {
                logger.error('Error during shutdown', err)
                clearTimeout(forceExit)
                process.exit(1)
            })
    }

    process.once('SIGINT', () => handler('SIGINT'))
    process.once('SIGTERM', () => handler('SIGTERM'))
}
