/**
 * Channel plugin registry — register ChannelPlugin instances or factories.
 */

import type { ChannelPlugin } from '../core/channel/types/plugin.ts'
import {BaseRegistry} from './base-registry.ts'

export type ChannelPluginFactory = (config: Record<string, unknown>) => ChannelPlugin | Promise<ChannelPlugin>

export interface ChannelPluginRegistryEntry {
    plugin?: ChannelPlugin
    factory?: ChannelPluginFactory
    version?: string
}

export class ChannelPluginRegistry extends BaseRegistry<ChannelPluginRegistryEntry> {
    constructor() {
        super('ChannelPluginRegistry')
    }

    register(id: string, pluginOrFactory: ChannelPlugin | ChannelPluginFactory, options?: { version?: string }): void
    register(id: string, entry: ChannelPluginRegistryEntry): void
    register(
        id: string,
        pluginOrFactoryOrEntry: ChannelPlugin | ChannelPluginFactory | ChannelPluginRegistryEntry,
        options?: { version?: string }
    ): void {
        const isEntry = (x: unknown): x is ChannelPluginRegistryEntry =>
            typeof x === 'object' && x !== null && ('plugin' in x || 'factory' in x)
        if (isEntry(pluginOrFactoryOrEntry)) {
            super.register(id, pluginOrFactoryOrEntry)
            return
        }
        const isFactory = typeof pluginOrFactoryOrEntry === 'function'
        const entry: ChannelPluginRegistryEntry = {
            plugin: isFactory ? undefined : (pluginOrFactoryOrEntry as ChannelPlugin),
            factory: isFactory ? (pluginOrFactoryOrEntry as ChannelPluginFactory) : undefined,
            version: options?.version,
        }
        super.register(id, entry)
    }
}
