/**
 * ToolFilter — responsible for channel-based tool filtering.
 * Applies per-channel include/exclude rules and exec gating.
 */

import type { NovaClawConfig, SessionContext, Tool } from '../../apis/index.ts'
import { CHANNEL } from '../../channel/constants.ts'

const SKILL_TOOL_NAMES = ['list_skills', 'get_skill', 'search_skills']

interface ChannelToolRule {
    channel: string
    include?: string[]
    exclude?: string[]
    execGated?: boolean
}

const DEFAULT_CHANNEL_RULES: ChannelToolRule[] = [
    {
        channel: CHANNEL.CLI,
        include: ['read', 'write', 'edit', 'exec', 'grep', 'process', ...SKILL_TOOL_NAMES],
    },
    {
        channel: CHANNEL.WEBCHAT,
        execGated: true,
    },
]

export class ToolFilter {
    constructor(private config: NovaClawConfig) {}

    getContextualTools(allTools: Tool[], context: SessionContext): Tool[] {
        const rule = DEFAULT_CHANNEL_RULES.find(r => r.channel === context.channel)
        if (!rule) return allTools

        const allowExecChannels = this.config.tools?.allowExecInChannels

        return allTools.filter(tool => {
            const n = tool.name

            if (rule.include) {
                return rule.include.includes(n) || n.startsWith('mcp_') || n.startsWith('http_')
            }

            if (rule.exclude?.includes(n)) return false

            if (rule.execGated && n === 'exec') {
                return Array.isArray(allowExecChannels) ? allowExecChannels.includes(context.channel) : true
            }

            return true
        })
    }
}
