/**
 * Bearer token authentication middleware.
 */

import type { FastifyInstance } from 'fastify'
import type { Logger } from '../../utils/logger.ts'
import { verifyBearerToken } from '../../utils/crypto.ts'

export interface AuthConfig {
    enabled?: boolean
    type?: string
    token?: string
}

const PUBLIC_PATHS = new Set(['/health', '/metrics', '/'])

function isPublicPath(url: string): boolean {
    const path = url.split('?')[0] ?? url
    if (PUBLIC_PATHS.has(path)) return true
    if (path === '/chat' || path.startsWith('/chat/assets/')) return true
    if (path === '/ws') return true
    return false
}

function extractToken(request: { headers: { authorization?: string }; url: string }): string | undefined {
    const header = request.headers.authorization
    if (header?.startsWith('Bearer ')) return header.slice(7)

    const idx = request.url.indexOf('?')
    if (idx !== -1) {
        const params = new URLSearchParams(request.url.slice(idx))
        const qToken = params.get('token')
        if (qToken) return qToken
    }
    return undefined
}

export function registerAuth(
    server: FastifyInstance,
    authConfig: AuthConfig,
    preflight: WeakSet<object>,
    logger: Logger,
): void {
    if (!authConfig.enabled || authConfig.type !== 'bearer') return

    const expectedToken = authConfig.token
    if (!expectedToken) {
        logger.warn('Auth enabled with type=bearer but no token configured')
    }

    server.addHook('preHandler', async (request, reply) => {
        if (preflight.has(request)) return
        if (isPublicPath(request.url)) return

        const token = extractToken(request)
        if (!token) {
            return reply.status(401).send({ error: 'Unauthorized' })
        }
        if (!verifyBearerToken(token, expectedToken ?? '')) {
            return reply.status(403).send({ error: 'Forbidden' })
        }
    })
}
