/**
 * Output rule: adapt markdown content to channel-specific format.
 * Transforms markdown to HTML (Telegram), mrkdwn (Slack), or plain text.
 */

import type { IRule, RuleContext, RuleVerdict } from '../../apis/rule.ts'

export interface ChannelFormatConfig {
    format: 'html' | 'mrkdwn' | 'plain' | 'markdown'
    maxLength?: number
}

const DEFAULT_FORMATS: Record<string, ChannelFormatConfig> = {
    telegram: { format: 'html', maxLength: 4096 },
    slack: { format: 'mrkdwn', maxLength: 4000 },
    discord: { format: 'markdown', maxLength: 2000 },
    cli: { format: 'markdown' },
    api: { format: 'markdown' },
}

export function markdownToHtml(md: string): string {
    return md
        .replace(/```[\w]*\n?([\s\S]*?)```/g, '<pre>$1</pre>')
        .replace(/`([^`]+)`/g, '<code>$1</code>')
        .replace(/\*\*(.+?)\*\*/g, '<b>$1</b>')
        .replace(/\*(.+?)\*/g, '<i>$1</i>')
        .replace(/__(.+?)__/g, '<b>$1</b>')
        .replace(/_(.+?)_/g, '<i>$1</i>')
        .replace(/~~(.+?)~~/g, '<s>$1</s>')
        .replace(/^### (.+)$/gm, '<b>$1</b>')
        .replace(/^## (.+)$/gm, '<b>$1</b>')
        .replace(/^# (.+)$/gm, '<b>$1</b>')
}

export function markdownToMrkdwn(md: string): string {
    return md
        .replace(/\*\*(.+?)\*\*/g, '*$1*')
        .replace(/__(.+?)__/g, '*$1*')
        .replace(/~~(.+?)~~/g, '~$1~')
        .replace(/^### (.+)$/gm, '*$1*')
        .replace(/^## (.+)$/gm, '*$1*')
        .replace(/^# (.+)$/gm, '*$1*')
}

export function markdownToPlain(md: string): string {
    return md
        .replace(/```[\w]*\n?([\s\S]*?)```/g, '$1')
        .replace(/`([^`]+)`/g, '$1')
        .replace(/\*\*(.+?)\*\*/g, '$1')
        .replace(/\*(.+?)\*/g, '$1')
        .replace(/__(.+?)__/g, '$1')
        .replace(/_(.+?)_/g, '$1')
        .replace(/~~(.+?)~~/g, '$1')
        .replace(/^#{1,6}\s+(.+)$/gm, '$1')
}

function truncate(text: string, maxLength: number): string {
    if (text.length <= maxLength) return text
    return text.slice(0, maxLength - 3) + '...'
}

export function createFormatChannelRule(
    channelFormats?: Record<string, Partial<ChannelFormatConfig>>,
): IRule {
    const formats = { ...DEFAULT_FORMATS }
    if (channelFormats) {
        for (const [ch, cfg] of Object.entries(channelFormats)) {
            formats[ch] = { ...formats[ch], ...cfg } as ChannelFormatConfig
        }
    }

    return {
        id: 'format-channel-adapt',
        name: 'Channel format adapter',
        description: 'Transform output markdown to channel-native format',
        phase: 'output',
        priority: 50,

        evaluate(ctx: RuleContext): RuleVerdict | undefined {
            if (ctx.type !== 'output' || !ctx.content || !ctx.channel) return undefined
            const config = formats[ctx.channel]
            if (!config) return undefined

            let transformed = ctx.content
            switch (config.format) {
                case 'html':
                    transformed = markdownToHtml(transformed)
                    break
                case 'mrkdwn':
                    transformed = markdownToMrkdwn(transformed)
                    break
                case 'plain':
                    transformed = markdownToPlain(transformed)
                    break
                case 'markdown':
                default:
                    break
            }

            if (config.maxLength) {
                transformed = truncate(transformed, config.maxLength)
            }

            if (transformed !== ctx.content) {
                return { action: 'rewrite', content: transformed }
            }
            return undefined
        },
    }
}
