/**
 * Backoff policy — exponential backoff with jitter for channel restart scheduling.
 */

export interface BackoffPolicy {
    initialMs: number
    maxMs: number
    factor: number
    jitter: number
}

export const DEFAULT_RESTART_POLICY: BackoffPolicy = {
    initialMs: 5_000,
    maxMs: 5 * 60_000,
    factor: 2,
    jitter: 0.1,
}

export const MAX_RESTART_ATTEMPTS = 10

export function computeBackoff(policy: BackoffPolicy, attempt: number): number {
    const delay = Math.min(
        policy.initialMs * Math.pow(policy.factor, attempt - 1),
        policy.maxMs,
    )
    const jitterRange = delay * policy.jitter
    const jitter = (Math.random() * 2 - 1) * jitterRange
    return Math.max(0, Math.round(delay + jitter))
}

export function sleepWithAbort(ms: number, signal?: AbortSignal): Promise<void> {
    return new Promise((resolve, reject) => {
        if (signal?.aborted) {
            reject(signal.reason)
            return
        }
        const timer = setTimeout(resolve, ms)
        signal?.addEventListener('abort', () => {
            clearTimeout(timer)
            reject(signal.reason)
        }, { once: true })
    })
}
