/**
 * CORS middleware — registers Access-Control headers and handles preflight.
 */

import type { FastifyInstance } from 'fastify'

export interface CorsConfig {
    enabled?: boolean
    origins: string[]
    credentials?: boolean
}

export function registerCors(
    server: FastifyInstance,
    corsConfig: CorsConfig,
    preflight: WeakSet<object>,
): void {
    if (!corsConfig.enabled) return

    server.addHook('onRequest', async (request, reply) => {
        const origin = request.headers.origin
        const allowed = corsConfig.origins

        if (allowed.includes('*') || (origin && allowed.includes(origin))) {
            reply.header('Access-Control-Allow-Origin', origin || '*')
            reply.header('Access-Control-Allow-Methods', 'GET,POST,PUT,DELETE,OPTIONS')
            reply.header('Access-Control-Allow-Headers', 'Content-Type,Authorization,X-Session-Key')

            if (corsConfig.credentials) {
                reply.header('Access-Control-Allow-Credentials', 'true')
            }
        }

        if (request.method === 'OPTIONS') {
            preflight.add(request)
            reply.status(204).send()
        }
    })
}
