import type { FastifyInstance } from 'fastify'
import { z } from 'zod'
import {
    ChannelDetailConfigSchema,
    MCPServerEntrySchema,
    ModelsConfigSchema,
} from '../../framework/index.ts'
import type { ChannelDetailConfig } from '../../framework/index.ts'
import { maskMcpListForResponse, mergeMcpIncomingWithExisting } from '../../framework/core/mcp/mcp-config-mask.ts'
import { ErrorCodes, toErrorMessage } from '../../constants/errors.ts'
import { ConfigLoader, mergeInPlace } from '../../utils/index.ts'
import type { RouteDeps } from './types.ts'

function maskSensitiveFields(obj: Record<string, unknown>): Record<string, unknown> {
    const SENSITIVE = ['sid', 'key', 'secret', 'token', 'password', 'credential', 'api_key', 'apikey']
    const result: Record<string, unknown> = {}
    for (const [k, v] of Object.entries(obj)) {
        if (typeof v === 'string' && v.trim() && SENSITIVE.some((s) => k.toLowerCase().includes(s))) {
            result[k] = '***'
        } else if (v && typeof v === 'object' && !Array.isArray(v)) {
            result[k] = maskSensitiveFields(v as Record<string, unknown>)
        } else {
            result[k] = v
        }
    }
    return result
}

export function registerConfigRoutes(server: FastifyInstance, deps: RouteDeps): void {
    const { config, logger, protocolBridge } = deps

    // ── GET /api/config — project-level config (models, tools, channels, mcp) ──

    server.get('/api/config', async (req, reply) => {
        const showKeys = (req.query as Record<string, string>)?.showKeys === 'true'
        const models = config.models
        const providersRaw = models?.providers ?? {}
        const providers: Record<string, { apiKey: string; baseUrl: string; model?: string; timeout?: number }> = {}

        for (const key of Object.keys(providersRaw)) {
            const p = (providersRaw as Record<string, {
                apiKey?: string
                baseUrl?: string
                model?: string
                timeout?: number
            }>)[key]
            if (!p || typeof p !== 'object') continue

            const hasApiKey = p.apiKey && p.apiKey.trim() !== ''
            const hasBaseUrl = p.baseUrl && p.baseUrl.trim() !== ''
            if (!hasApiKey && !hasBaseUrl) continue

            providers[key] = {
                baseUrl: p.baseUrl ?? '',
                apiKey: hasApiKey ? (showKeys ? p.apiKey! : '***') : '',
                ...(p.model != null ? { model: p.model } : {}),
                ...(p.timeout != null ? { timeout: p.timeout } : {}),
            }
        }

        const rawMcp = config.mcp
        const mcp = maskMcpListForResponse(rawMcp, showKeys)
        const channels = config.channels ?? undefined
        reply.send({
            models: {
                primary: models?.primary ?? '',
                fallback: models?.fallback ?? '',
                providers,
            },
            ...(mcp != null ? { mcp } : {}),
            ...(channels ? { channels } : {}),
        })
    })

    // ── POST /api/config — update project-level config ───────────────────

    server.post('/api/config', async (request, reply) => {
        const body = request.body as Record<string, unknown> | undefined
        if (!body || typeof body !== 'object') {
            return reply.status(400).send({
                success: false,
                error: 'Invalid body',
                code: ErrorCodes.VALIDATION_ERROR,
            })
        }

        try {
            if (body.models != null) {
                const result = ModelsConfigSchema.partial().safeParse(body.models)
                if (!result.success) {
                    return reply.status(400).send({
                        success: false,
                        error: 'Invalid models config',
                        code: ErrorCodes.VALIDATION_ERROR,
                        issues: result.error.issues.map((i) => ({
                            path: i.path.join('.'),
                            message: i.message,
                        })),
                    })
                }
            }

            const existingOverrides = await ConfigLoader.loadOverrides()
            const nextOverrides = { ...existingOverrides } as Record<string, unknown>

            if (body.models != null && typeof body.models === 'object') {
                const modelsPatch = JSON.parse(JSON.stringify(body.models)) as Record<string, unknown>

                if (!config.models) {
                    (config as Record<string, unknown>).models = {
                        primary: '',
                        fallback: '',
                        providers: {},
                    }
                }
                const modelsRef = config.models as Record<string, unknown>
                const existingProviders = (modelsRef.providers ?? {}) as Record<string, Record<string, unknown>>

                if (modelsPatch.providers && typeof modelsPatch.providers === 'object') {
                    const incoming = modelsPatch.providers as Record<string, Record<string, unknown>>
                    const nextProviders: Record<string, Record<string, unknown>> = {}
                    for (const [key, entry] of Object.entries(incoming)) {
                        if (!entry || typeof entry !== 'object') continue
                        if (entry.apiKey === '***' || entry.apiKey === undefined) {
                            entry.apiKey = existingProviders[key]?.apiKey
                        }
                        const apiStr = typeof entry.apiKey === 'string' ? (entry.apiKey as string).trim() : ''
                        const baseStr = typeof entry.baseUrl === 'string' ? (entry.baseUrl as string).trim() : ''
                        if (!apiStr && !baseStr) continue
                        nextProviders[key] = entry
                    }
                    modelsPatch.providers = nextProviders
                }

                if (modelsPatch.primary !== undefined) modelsRef.primary = modelsPatch.primary
                if (modelsPatch.fallback !== undefined) modelsRef.fallback = modelsPatch.fallback
                if (modelsPatch.providers !== undefined) modelsRef.providers = modelsPatch.providers
                nextOverrides.models = config.models

                try {
                    await deps.agent?.reinitializeSession?.()
                } catch (err) {
                    logger.warn('Reinit session after config save', err)
                }
            }

            if (body.mcp !== undefined) {
                const parsed = z.array(MCPServerEntrySchema).safeParse(body.mcp)
                if (!parsed.success) {
                    return reply.status(400).send({
                        success: false,
                        error: 'Invalid mcp config',
                        code: ErrorCodes.VALIDATION_ERROR,
                        issues: parsed.error.issues.map((i) => ({
                            path: i.path.join('.'),
                            message: i.message,
                        })),
                    })
                }
                const existingMcp = config.mcp
                const mergedMcp = mergeMcpIncomingWithExisting(parsed.data, existingMcp)
                ;(config as Record<string, unknown>).mcp = mergedMcp
                nextOverrides.mcp = mergedMcp
                try {
                    await protocolBridge?.reloadMcpConnections(mergedMcp)
                } catch (err) {
                    logger.warn('MCP reconnect after config save failed', err)
                }
                try {
                    await deps.agent?.reinitializeToolRegistry?.()
                } catch (err) {
                    logger.warn('Tool registry reinit after MCP save failed', err)
                }
            }

            if (body.channels != null && typeof body.channels === 'object') {
                if (!config.channels) {
                    (config as Record<string, unknown>).channels = { enabled: [] }
                }
                mergeInPlace(
                    config.channels as Record<string, unknown>,
                    body.channels as Record<string, unknown>,
                )
                nextOverrides.channels = config.channels
            }

            if (Object.keys(nextOverrides).length > 0) {
                await ConfigLoader.saveOverrides(nextOverrides)
            }

            reply.send({ success: true })
        } catch (err) {
            logger.error('Save config failed', err)
            reply.status(500).send({
                success: false,
                error: toErrorMessage(err),
                code: ErrorCodes.INTERNAL_ERROR,
            })
        }
    })

    // ── GET /api/config/user — user-level overrides (channels, plugins) ──

    server.get('/api/config/user', async (_req, reply) => {
        try {
            const overrides = await ConfigLoader.loadOverrides()
            const channels = (overrides.channels ?? {}) as Record<string, ChannelDetailConfig>
            const plugins = (overrides.plugins ?? {}) as Record<string, unknown>
            const safeChannels: Record<string, ChannelDetailConfig> = {}

            for (const [chId, detail] of Object.entries(channels)) {
                if (chId === 'enabled' || !detail || typeof detail !== 'object') continue
                safeChannels[chId] = {
                    ...detail,
                    accounts: detail.accounts
                        ? Object.fromEntries(
                            Object.entries(detail.accounts).map(([accId, acc]) => [
                                accId,
                                maskSensitiveFields(acc as Record<string, unknown>),
                            ]),
                        )
                        : undefined,
                }
            }
            reply.send({ channels: safeChannels, plugins })
        } catch (err) {
            logger.error('Load user config failed', err)
            reply.status(500).send({
                success: false,
                error: toErrorMessage(err),
                code: ErrorCodes.INTERNAL_ERROR,
            })
        }
    })

    // ── GET /api/config/channels — list all channel configs ──────────────

    server.get('/api/config/channels', async (_req, reply) => {
        try {
            const overrides = await ConfigLoader.loadOverrides()
            const channels = (overrides.channels ?? {}) as Record<string, ChannelDetailConfig>
            const result: Record<string, unknown> = {}
            for (const [chId, detail] of Object.entries(channels)) {
                if (chId === 'enabled' || !detail || typeof detail !== 'object') continue
                result[chId] = {
                    ...detail,
                    accounts: detail.accounts
                        ? Object.fromEntries(
                            Object.entries(detail.accounts).map(([accId, acc]) => [
                                accId,
                                maskSensitiveFields(acc as Record<string, unknown>),
                            ]),
                        )
                        : undefined,
                }
            }
            reply.send({ channels: result })
        } catch (err) {
            logger.error('Load channel configs failed', err)
            reply.status(500).send({
                success: false,
                error: toErrorMessage(err),
                code: ErrorCodes.INTERNAL_ERROR,
            })
        }
    })

    // ── GET /api/config/channels/:channelId — single channel config ──────

    server.get<{ Params: { channelId: string } }>(
        '/api/config/channels/:channelId',
        async (request, reply) => {
            try {
                const detail = await ConfigLoader.getChannelConfig(request.params.channelId)
                if (!detail) {
                    return reply.status(404).send({
                        success: false,
                        error: `Channel '${request.params.channelId}' not configured`,
                        code: ErrorCodes.NOT_FOUND,
                    })
                }
                const safe = {
                    ...detail,
                    accounts: detail.accounts
                        ? Object.fromEntries(
                            Object.entries(detail.accounts).map(([accId, acc]) => [
                                accId,
                                maskSensitiveFields(acc as Record<string, unknown>),
                            ]),
                        )
                        : undefined,
                }
                reply.send(safe)
            } catch (err) {
                logger.error(`Load channel config failed: ${request.params.channelId}`, err)
                reply.status(500).send({
                    success: false,
                    error: toErrorMessage(err),
                    code: ErrorCodes.INTERNAL_ERROR,
                })
            }
        },
    )

    // ── POST /api/config/channels/:channelId — create or update channel config ──

    server.post<{ Params: { channelId: string } }>(
        '/api/config/channels/:channelId',
        async (request, reply) => {
            const body = request.body as Record<string, unknown> | undefined
            if (!body || typeof body !== 'object') {
                return reply.status(400).send({
                    success: false,
                    error: 'Invalid body',
                    code: ErrorCodes.VALIDATION_ERROR,
                })
            }

            try {
                const validation = ChannelDetailConfigSchema.safeParse(body)
                if (!validation.success) {
                    return reply.status(400).send({
                        success: false,
                        error: 'Invalid channel config',
                        code: ErrorCodes.VALIDATION_ERROR,
                        issues: validation.error.issues.map((i) => ({
                            path: i.path.join('.'),
                            message: i.message,
                        })),
                    })
                }

                const channelId = request.params.channelId
                const existing = await ConfigLoader.getChannelConfig(channelId)
                const merged = existing
                    ? { ...existing, ...body } as ChannelDetailConfig
                    : body as ChannelDetailConfig

                // Strip masked '***' values to avoid overwriting real credentials
                if (merged.accounts && existing?.accounts) {
                    for (const [accId, acc] of Object.entries(merged.accounts)) {
                        const existingAcc = existing.accounts?.[accId]
                        if (!existingAcc) continue
                        for (const [field, value] of Object.entries(acc)) {
                            if (value === '***' && existingAcc[field]) {
                                acc[field] = existingAcc[field]
                            }
                        }
                    }
                }

                await ConfigLoader.saveChannelConfig(channelId, merged)

                if (!config.channels) {
                    (config as Record<string, unknown>).channels = { enabled: [] }
                }
                const channelsRef = config.channels as Record<string, unknown>
                const enabled = new Set<string>(
                    Array.isArray(channelsRef.enabled) ? channelsRef.enabled as string[] : [],
                )
                const hasEnabledAccount = merged.accounts
                    && Object.values(merged.accounts).some((a) => a.enabled !== false)
                if (hasEnabledAccount) {
                    enabled.add(channelId)
                }
                channelsRef.enabled = [...enabled]
                channelsRef[channelId] = merged

                reply.send({ success: true, channelId })
            } catch (err) {
                logger.error(`Save channel config failed: ${request.params.channelId}`, err)
                reply.status(500).send({
                    success: false,
                    error: toErrorMessage(err),
                    code: ErrorCodes.INTERNAL_ERROR,
                })
            }
        },
    )

    // ── DELETE /api/config/channels/:channelId — remove channel config ───

    server.delete<{ Params: { channelId: string } }>(
        '/api/config/channels/:channelId',
        async (request, reply) => {
            try {
                const channelId = request.params.channelId
                const removed = await ConfigLoader.removeChannelConfig(channelId)
                if (!removed) {
                    return reply.status(404).send({
                        success: false,
                        error: `Channel '${channelId}' not configured`,
                        code: ErrorCodes.NOT_FOUND,
                    })
                }

                if (config.channels) {
                    const channelsRef = config.channels as Record<string, unknown>
                    const enabled = Array.isArray(channelsRef.enabled) ? channelsRef.enabled as string[] : []
                    channelsRef.enabled = enabled.filter((id) => id !== channelId)
                    delete channelsRef[channelId]
                }

                reply.send({ success: true, channelId })
            } catch (err) {
                logger.error(`Delete channel config failed: ${request.params.channelId}`, err)
                reply.status(500).send({
                    success: false,
                    error: toErrorMessage(err),
                    code: ErrorCodes.INTERNAL_ERROR,
                })
            }
        },
    )
}
