/**
 * In-memory metrics collector for requests, sessions, skills, and memory usage.
 */

import type { Metrics } from '../framework/index.ts'

export class MetricsCollector {
    private data: Metrics = {
        requests: { total: 0, success: 0, error: 0, averageResponseTime: 0 },
        sessions: { active: 0, total: 0 },
        skills: { loaded: 0, cacheHits: 0, cacheMisses: 0 },
        memory: { used: 0, heap: 0, external: 0 },
    }

    private responseTimes: number[] = []

    incrementRequests(type: 'success' | 'error', responseTime: number): void {
        this.data.requests.total++
        this.data.requests[type]++

        this.responseTimes.push(responseTime)
        if (this.responseTimes.length > 1000) this.responseTimes.shift()

        this.data.requests.averageResponseTime =
            this.responseTimes.reduce((a, b) => a + b, 0) / this.responseTimes.length
    }

    incrementSessions(type: 'created' | 'destroyed'): void {
        if (type === 'created') {
            this.data.sessions.active++
            this.data.sessions.total++
        } else {
            this.data.sessions.active--
        }
    }

    updateSkillsMetrics(loaded: number, cacheHits: number, cacheMisses: number): void {
        this.data.skills.loaded = loaded
        this.data.skills.cacheHits = cacheHits
        this.data.skills.cacheMisses = cacheMisses
    }

    getMetrics(): Metrics {
        const mem = process.memoryUsage()
        this.data.memory.used = mem.rss
        this.data.memory.heap = mem.heapUsed
        this.data.memory.external = mem.external
        return { ...this.data }
    }

    reset(): void {
        this.data = {
            requests: { total: 0, success: 0, error: 0, averageResponseTime: 0 },
            sessions: { active: 0, total: 0 },
            skills: { loaded: 0, cacheHits: 0, cacheMisses: 0 },
            memory: { used: 0, heap: 0, external: 0 },
        }
        this.responseTimes = []
    }
}
