/**
 * Credential manager — AES-256-GCM encryption / decryption for API keys
 * and channel account secrets.
 *
 * Key material is stored in ~/.novaclaw/.keyfile and auto-created on
 * first use.  All public helpers are async because key resolution may
 * involve filesystem I/O.
 */

import { createCipheriv, createDecipheriv, randomBytes } from 'node:crypto'
import { mkdir, readFile, writeFile, chmod } from 'node:fs/promises'
import type { UserConfig } from '../framework/index.ts'
import {
    NOVACLAW_HOME,
    NOVACLAW_KEYFILE_PATH,
} from '../constants/paths.ts'
import { Logger } from './logger.ts'
const ALGO = 'aes-256-gcm'

const SENSITIVE_FIELD_PATTERNS = [
    'sid', 'key', 'secret', 'token', 'password', 'credential', 'api_key', 'apikey',
]

const logger = new Logger('CredentialManager')

// ── Key management ──────────────────────────────────────────────────────

async function getOrCreateKey(): Promise<Buffer> {
    try {
        const hex = (await readFile(NOVACLAW_KEYFILE_PATH, 'utf-8')).trim()
        return Buffer.from(hex, 'hex')
    } catch {
        const key = randomBytes(32)
        await mkdir(NOVACLAW_HOME, { recursive: true })
        await writeFile(NOVACLAW_KEYFILE_PATH, key.toString('hex'), 'utf-8')
        try { await chmod(NOVACLAW_KEYFILE_PATH, 0o600) } catch { /* chmod not available on all platforms */ }
        return key
    }
}

// ── Primitives ──────────────────────────────────────────────────────────

export async function encryptString(plaintext: string): Promise<string> {
    const key = await getOrCreateKey()
    const iv = randomBytes(12)
    const cipher = createCipheriv(ALGO, key, iv)
    const enc = Buffer.concat([cipher.update(plaintext, 'utf8'), cipher.final()])
    const tag = cipher.getAuthTag()
    return `${iv.toString('hex')}:${tag.toString('hex')}:${enc.toString('hex')}`
}

export async function decryptString(ciphertext: string): Promise<string> {
    const parts = ciphertext.split(':')
    if (parts.length !== 3) throw new Error('Invalid encrypted format')
    const key = await getOrCreateKey()
    const iv = Buffer.from(parts[0]!, 'hex')
    const tag = Buffer.from(parts[1]!, 'hex')
    const enc = Buffer.from(parts[2]!, 'hex')
    const decipher = createDecipheriv(ALGO, key, iv)
    decipher.setAuthTag(tag)
    return Buffer.concat([decipher.update(enc), decipher.final()]).toString('utf8')
}

export function isEncrypted(val: string): boolean {
    return /^[0-9a-f]{24}:[0-9a-f]{32}:[0-9a-f]+$/.test(val)
}

export function isSensitiveField(fieldName: string): boolean {
    const lower = fieldName.toLowerCase()
    return SENSITIVE_FIELD_PATTERNS.some((p) => lower.includes(p))
}

// ── Provider API keys ───────────────────────────────────────────────────

export async function encryptApiKeysInPlace(obj: Record<string, unknown>): Promise<void> {
    const providers = (obj.models as Record<string, unknown>)?.providers as
        | Record<string, Record<string, unknown>>
        | undefined
    if (!providers) return

    for (const key of Object.keys(providers)) {
        const p = providers[key]
        if (p?.apiKey && typeof p.apiKey === 'string' && p.apiKey.trim() && !isEncrypted(p.apiKey)) {
            try {
                p.apiKey = await encryptString(p.apiKey)
            } catch (err) {
                logger.debug(`Failed to encrypt API key for provider '${key}'`, err)
            }
        }
    }
}

export async function decryptApiKeysInPlace(obj: Record<string, unknown>): Promise<void> {
    const providers = (obj.models as Record<string, unknown>)?.providers as
        | Record<string, Record<string, unknown>>
        | undefined
    if (!providers) return

    for (const key of Object.keys(providers)) {
        const p = providers[key]
        if (p?.apiKey && typeof p.apiKey === 'string' && isEncrypted(p.apiKey)) {
            try {
                p.apiKey = await decryptString(p.apiKey)
            } catch (err) {
                logger.debug(`Failed to decrypt API key for provider '${key}'`, err)
            }
        }
    }
}

// ── Channel account credentials ─────────────────────────────────────────

export async function encryptChannelCredentials(config: UserConfig): Promise<void> {
    if (!config.channels) return
    for (const [channelId, detail] of Object.entries(config.channels)) {
        if (!detail.accounts) continue
        for (const account of Object.values(detail.accounts)) {
            for (const [field, value] of Object.entries(account)) {
                if (
                    typeof value === 'string'
                    && value.trim()
                    && isSensitiveField(field)
                    && !isEncrypted(value)
                ) {
                    try {
                        account[field] = await encryptString(value)
                    } catch (err) {
                        logger.debug(`Failed to encrypt channel credential: ${channelId}.${field}`, err)
                    }
                }
            }
        }
    }
}

export async function decryptChannelCredentials(config: UserConfig): Promise<void> {
    if (!config.channels) return
    for (const [channelId, detail] of Object.entries(config.channels)) {
        if (!detail.accounts) continue
        for (const account of Object.values(detail.accounts)) {
            for (const [field, value] of Object.entries(account)) {
                if (typeof value === 'string' && isEncrypted(value)) {
                    try {
                        account[field] = await decryptString(value)
                    } catch (err) {
                        logger.debug(`Failed to decrypt channel credential: ${channelId}.${field}`, err)
                    }
                }
            }
        }
    }
}
