import type { FastifyInstance } from 'fastify'
import type { SessionContext } from '../../framework/index.ts'
import type { RouteDeps } from './types.ts'

export function registerSessionRoutes(server: FastifyInstance, deps: RouteDeps): void {
    const { sessionManager } = deps

    server.get('/api/sessions', async (_req, reply) => {
        const sessions = Array.from(sessionManager.values()).map((s: SessionContext) => ({
            sessionId: s.sessionId,
            userId: s.userId,
            channel: s.channel,
            startTime: s.startTime,
            lastActivity: s.lastActivity,
        }))
        reply.send({ sessions })
    })

    server.delete('/api/sessions/:sessionId', async (request, reply) => {
        const { sessionId } = request.params as { sessionId: string }
        let deleted = false
        for (const [key, ctx] of Array.from(sessionManager.entries())) {
            if (ctx.sessionId === sessionId || key === sessionId) {
                deleted = sessionManager.delete(key)
                break
            }
        }
        reply.send({ success: deleted })
    })
}
