import type { ILogger } from '../../utils/logger.ts'
import { Logger } from '../../utils/logger.ts'
import type { IMCPConnector, MCPCallToolResult, MCPConnectOptions, MCPTool } from '../apis/mcp.ts'
import * as conn from './mcp-connection.ts'
import type { MCPConnection } from './types.ts'

const DEFAULT_ID = 'default-mcp'

export interface DefaultMCPConnectorOptions {
    id?: string
    logger?: ILogger
}

export class DefaultMCPConnector implements IMCPConnector {
    readonly id: string
    private readonly logger: ILogger
    private readonly connections = new Map<string, MCPConnection>()

    constructor(options: DefaultMCPConnectorOptions = {}) {
        this.id = options.id ?? DEFAULT_ID
        this.logger = options.logger ?? new Logger('DefaultMCPConnector')
    }

    get connectionCount(): number {
        return this.connections.size
    }

    async connect(options: MCPConnectOptions): Promise<void> {
        const key = options.endpoint.trim()
        if (!key) throw new Error('MCP connect: endpoint is required')

        const existing = this.connections.get(key)
        if (existing) {
            await conn.closeConnection(existing).catch(e =>
                this.logger.warn(`Close existing failed: ${key}`, e),
            )
        }

        this.logger.debug(`Connecting: ${key}`)
        const connection = await conn.openConnection(options, this.logger)
        this.connections.set(key, connection)
        this.logger.info(`Connected: ${key}`)
    }

    async disconnect(endpoint: string): Promise<void> {
        const key = endpoint.trim()
        const connection = this.connections.get(key)
        if (!connection) return
        this.connections.delete(key)
        await conn.closeConnection(connection).catch(e =>
            this.logger.warn(`Close error: ${key}`, e),
        )
        this.logger.info(`Disconnected: ${key}`)
    }

    async listTools(endpoint: string): Promise<MCPTool[]> {
        return conn.listTools(this.requireConnection(endpoint))
    }

    async callTool(
        endpoint: string,
        toolName: string,
        args: Record<string, unknown> = {},
    ): Promise<MCPCallToolResult> {
        this.logger.debug(`Calling tool: ${toolName}`)
        return conn.callTool(this.requireConnection(endpoint), toolName, args)
    }

    async cleanup(): Promise<void> {
        const entries = Array.from(this.connections.entries())
        this.connections.clear()
        await Promise.allSettled(
            entries.map(([key, c]) =>
                conn.closeConnection(c).catch(e => this.logger.warn(`Close error: ${key}`, e)),
            ),
        )
        this.logger.debug('Cleaned up')
    }

    private requireConnection(endpoint: string): MCPConnection {
        const c = this.connections.get(endpoint.trim())
        if (!c) throw new Error(`MCP endpoint not connected: ${endpoint}`)
        return c
    }
}
