/**
 * Component factory — creates all runtime components from a config.
 *
 * Separates construction logic from lifecycle orchestration so NovaClaw
 * stays focused on init/start/stop/restart and event wiring.
 */

import { createError, ErrorCodes } from './constants/errors.ts'
import type { IMemoryProvider, NovaClawConfig } from './framework/index.ts'
import {
    AgentRuntime,
    AgentExecutor,
    AgentPool,
    bootstrapFramework,
    ChannelHub,
    ChannelPluginRegistry,
    DirectorRuntime,
    HookManager,
    MemoryProviderRegistry,
    MessageProcessor,
    ModelManager,
    ProtocolBridge,
    ProviderRegistry,
    RuleRegistry,
    SessionManager,
    SkillsEngine,
    ToolProviderRegistry,
    ToolRegistry,
} from './framework/index.ts'
import type { Agent } from './framework/index.ts'
import { NovaClawGateway } from './gateway/gateway.ts'
import type { Logger } from './utils/index.ts'
import { migrateOpenClawConfig } from './utils/openclaw-migrate.ts'

// ── Types ────────────────────────────────────────────────────────────────

export interface RuntimeRegistries {
    provider: ProviderRegistry
    rule: RuleRegistry
    toolProvider: ToolProviderRegistry
    memoryProvider: MemoryProviderRegistry
    channelPlugin: ChannelPluginRegistry
}

export interface RuntimeComponents {
    registries: RuntimeRegistries
    gateway: NovaClawGateway
    skillsEngine: SkillsEngine
    agent: Agent
    channelHub: ChannelHub
    protocolBridge: ProtocolBridge
    memoryEngine: IMemoryProvider
    messageProcessor: MessageProcessor
    hookManager: HookManager
}

// ── Factory ──────────────────────────────────────────────────────────────

export function createRuntimeComponents(
    config: NovaClawConfig,
    logger: Logger,
): RuntimeComponents {
    const migrated = migrateOpenClawConfig(config, { logger })

    const registries = createRegistries(migrated)
    const skillsEngine = new SkillsEngine(migrated)
    const agent = createAgent(migrated, registries, skillsEngine, logger)
    const protocolBridge = new ProtocolBridge(migrated)
    const memoryEngine = createMemoryEngine(migrated, registries.memoryProvider, agent)
    const sessionManager = new SessionManager(migrated.workspaceDir)
    const hookManager = new HookManager(migrated.logging?.level)

    const messageProcessor = new MessageProcessor({
        config: migrated,
        agent,
        skillsEngine,
        memoryEngine,
        sessionManager,
        hookManager,
    })

    const channelHub = new ChannelHub(migrated, {
        channelPluginRegistry: registries.channelPlugin,
        messageProcessor,
    })

    const gateway = new NovaClawGateway(migrated, {
        skillsEngine,
        agent,
        channelHub,
        protocolBridge,
        memoryEngine,
        messageProcessor,
    })

    return {
        registries,
        gateway,
        skillsEngine,
        agent,
        channelHub,
        protocolBridge,
        memoryEngine,
        messageProcessor,
        hookManager,
    }
}

// ── Internal helpers ─────────────────────────────────────────────────────

function createRegistries(_config: NovaClawConfig): RuntimeRegistries {
    const provider = new ProviderRegistry()
    const rule = new RuleRegistry()
    const toolProvider = new ToolProviderRegistry()
    const memoryProvider = new MemoryProviderRegistry()
    const channelPlugin = new ChannelPluginRegistry()

    bootstrapFramework({
        providerRegistry: provider,
        ruleRegistry: rule,
        memoryProviderRegistry: memoryProvider,
        channelPluginRegistry: channelPlugin,
    })

    return { provider, rule, toolProvider, memoryProvider, channelPlugin }
}

function createAgent(
    config: NovaClawConfig,
    registries: RuntimeRegistries,
    skillsEngine: SkillsEngine,
    logger: Logger,
): Agent {
    const isMultiAgent = config.agents?.mode === 'multi'

    if (isMultiAgent) {
        return createDirectorAgent(config, registries, skillsEngine, logger)
    }

    return new AgentRuntime(config, {
        skillsEngine,
        providerRegistry: registries.provider,
        ruleRegistry: registries.rule,
        toolProviderRegistry: registries.toolProvider,
    })
}

function createDirectorAgent(
    config: NovaClawConfig,
    registries: RuntimeRegistries,
    skillsEngine: SkillsEngine,
    logger: Logger,
): Agent {
    const agentPool = new AgentPool(
        config,
        {
            providerRegistry: registries.provider,
            ruleRegistry: registries.rule,
            toolProviderRegistry: registries.toolProvider,
            skillsEngine,
        },
        config.agents?.pool,
        config.agents?.workers as Record<string, {
            enabled?: boolean; model?: string; maxTurns?: number
            tools?: string[]; skillDomains?: string[]
        }>,
    )

    const directorModelConfig = config.agents?.director?.model
        ? { ...config, models: { ...config.models, primary: config.agents.director.model } }
        : config

    const directorModelManager = new ModelManager(directorModelConfig, {
        providerRegistry: registries.provider,
    })

    const directorToolRegistry = new ToolRegistry(config, {
        ruleEngine: registries.rule.getEngine(),
    })

    const directorExecutor = new AgentExecutor(
        directorToolRegistry,
        config.logging?.level || 'info',
        {
            maxTurns: config.agents?.director?.maxTurns ?? 5,
            toolResultContextMax: config.agent?.toolResultContextMax ?? 16_000,
        },
    )

    const fallbackAgent = new AgentRuntime(config, {
        skillsEngine,
        providerRegistry: registries.provider,
        ruleRegistry: registries.rule,
        toolProviderRegistry: registries.toolProvider,
    })

    logger.info('Multi-agent mode enabled (Director-Worker)')

    return new DirectorRuntime(config, {
        modelManager: directorModelManager,
        executor: directorExecutor,
        agentPool,
        ruleRegistry: registries.rule,
        skillsEngine,
        fallbackAgent,
        directResponse: config.agents?.director?.directResponse,
    })
}

function createMemoryEngine(
    config: NovaClawConfig,
    registry: MemoryProviderRegistry,
    agent: Agent,
): IMemoryProvider {
    const llmCall = (sys: string, usr: string, max?: number) =>
        agent.internalLLMCall(sys, usr, max)
    const providerId = config.memory?.provider ?? 'local'
    const configAsRecord = config as Record<string, unknown>

    const engine =
        registry.create(providerId, configAsRecord, { llmCall }) ??
        registry.create('local', configAsRecord, { llmCall })

    if (!engine) {
        throw createError(
            `Failed to create memory provider '${providerId}' (fallback 'local' also unavailable).`,
            ErrorCodes.INTERNAL_ERROR,
        )
    }

    return engine
}
