/**
 * Channel Facade — lightweight adapter layer for shared code paths.
 *
 * Facade provides channel metadata without triggering eager loading of heavy
 * channel implementations (e.g. discord.js, puppeteer, baileys).
 * Shared code should import from channel-facade.ts rather than the full plugin.
 */

import type { ChannelCapabilities, ChannelId } from './types/core.ts'
import type {
    ChannelAgentPromptAdapter,
    ChannelCommandAdapter,
    ChannelConfigAdapter,
    ChannelElevatedAdapter,
    ChannelGroupAdapter,
    ChannelMentionAdapter,
    ChannelThreadingAdapter,
} from './types/adapters.ts'
import type { ChannelPlugin } from './types/plugin.ts'
import type { ChannelRegistry } from './registry.ts'

export interface ChannelFacade {
    id: ChannelId
    capabilities: ChannelCapabilities
    commands?: ChannelCommandAdapter
    outbound?: { textChunkLimit?: number }
    streaming?: { blockStreamingCoalesceDefaults?: { minChars?: number; idleMs?: number } }
    elevated?: ChannelElevatedAdapter
    config?: Pick<ChannelConfigAdapter, 'resolveAllowFrom' | 'formatAllowFrom' | 'resolveDefaultTo'>
    groups?: ChannelGroupAdapter
    mentions?: ChannelMentionAdapter
    threading?: ChannelThreadingAdapter
    agentPrompt?: ChannelAgentPromptAdapter
}

export function buildFacadeFromPlugin(plugin: ChannelPlugin): ChannelFacade {
    return {
        id: plugin.id,
        capabilities: plugin.capabilities,
        commands: plugin.commands,
        outbound: plugin.outbound
            ? { textChunkLimit: plugin.outbound.textChunkLimit }
            : undefined,
        streaming: plugin.streaming
            ? { blockStreamingCoalesceDefaults: plugin.streaming.blockStreamingCoalesceDefaults }
            : undefined,
        elevated: plugin.elevated,
        config: plugin.config
            ? {
                resolveAllowFrom: plugin.config.resolveAllowFrom,
                formatAllowFrom: plugin.config.formatAllowFrom,
                resolveDefaultTo: plugin.config.resolveDefaultTo,
            }
            : undefined,
        groups: plugin.groups,
        mentions: plugin.mentions,
        threading: plugin.threading,
        agentPrompt: plugin.agentPrompt,
    }
}

export function getChannelFacade(channelId: ChannelId, registry: ChannelRegistry): ChannelFacade | undefined {
    return registry.getChannelFacade(channelId)
}

export function clearFacadeCache(registry: ChannelRegistry): void {
    registry.clearFacadeCache()
}
