/**
 * ChannelActivityTracker — lightweight per-channel message / error counters.
 */

export interface ChannelActivityMetrics {
    msgSent: number
    msgReceived: number
    errors: number
    lastMessageAt?: number
}

export class ChannelActivityTracker {
    private metrics = new Map<string, ChannelActivityMetrics>()

    recordReceived(channelId: string): void {
        const m = this.getOrCreate(channelId)
        m.msgReceived++
        m.lastMessageAt = Date.now()
    }

    recordSent(channelId: string): void {
        const m = this.getOrCreate(channelId)
        m.msgSent++
        m.lastMessageAt = Date.now()
    }

    recordError(channelId: string): void {
        this.getOrCreate(channelId).errors++
    }

    get(channelId: string): ChannelActivityMetrics | undefined {
        return this.metrics.get(channelId)
    }

    getAll(): Map<string, ChannelActivityMetrics> {
        return new Map(this.metrics)
    }

    private getOrCreate(channelId: string): ChannelActivityMetrics {
        let m = this.metrics.get(channelId)
        if (!m) {
            m = { msgSent: 0, msgReceived: 0, errors: 0 }
            this.metrics.set(channelId, m)
        }
        return m
    }
}
