/**
 * OpenClaw extension adapter — handles loading channel plugins that use
 * OpenClaw's register(api) convention and import `openclaw/plugin-sdk`.
 *
 * This adapter patches imports, generates a minimal SDK shim, and captures
 * the ChannelPlugin produced by the extension's register() call.
 */

import { createHash } from 'node:crypto'
import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'node:fs'
import { join, resolve } from 'node:path'
import { pathToFileURL } from 'node:url'
import { toErrorMessage } from '../../../../../constants/errors.ts'
import { NOVACLAW_CACHE_DIR } from '../../../../../constants/paths.ts'
import type { ChannelPlugin } from '../../types/plugin.ts'
import type { ChannelGatewayContext, PluginChannelRuntime } from '../../types/context.ts'
import type { DiscoveredExtension, ExtensionAdapter, ExtensionLoadContext } from '../types.ts'

const COMPAT_SHIM_FILENAME = 'openclaw-compat.mjs'
const PLUGIN_CACHE_DIR = join(NOVACLAW_CACHE_DIR, 'plugins')
const RESOLVED_CACHE_DIR = resolve(PLUGIN_CACHE_DIR)

/** SHA-256 hashes of patched files, keyed by absolute path. */
const integrityHashes = new Map<string, string>()

function sha256(content: string): string {
    return createHash('sha256').update(content).digest('hex')
}

function assertInsideCacheDir(filePath: string): void {
    const resolved = resolve(filePath)
    if (!resolved.startsWith(RESOLVED_CACHE_DIR)) {
        throw new Error(`Plugin path escapes cache directory: ${filePath}`)
    }
}

const PLUGIN_SDK_SHIM = [
    'export const DEFAULT_ACCOUNT_ID = "default";',
    'export function emptyPluginConfigSchema() {',
    '  return {',
    '    safeParse(v) {',
    '      if (v === undefined) return { success: true, data: undefined };',
    '      if (!v || typeof v !== "object" || Array.isArray(v)) return { success: false, error: { issues: [{ message: "expected object" }] } };',
    '      return { success: true, data: v };',
    '    },',
    '    jsonSchema: { type: "object", additionalProperties: false, properties: {} },',
    '  };',
    '}',
].join('\n')

export class OpenClawAdapter implements ExtensionAdapter {
    readonly id = 'openclaw'

    canHandle(ext: DiscoveredExtension): boolean {
        return ext.source === 'openclaw' || ext.source === 'unknown'
    }

    async load(ext: DiscoveredExtension, ctx: ExtensionLoadContext): Promise<ChannelPlugin | null> {
        if (!ext.entryPath) return null

        try {
            ctx.logger.debug(`OpenClawAdapter: loading '${ext.id}' from ${ext.entryPath}`)
            const patchedPath = patchAndCache(ext.id, ext.entryPath)
            const plugin = await importAndCapture(ext.id, patchedPath, ctx)

            if (plugin) {
                ctx.logger.info(`OpenClawAdapter: loaded channel plugin '${ext.id}'`)
                return bridgeGatewayLifecycle(plugin)
            }
            return plugin
        } catch (err) {
            ctx.logger.warn(`OpenClawAdapter: failed to load '${ext.id}': ${toErrorMessage(err)}`)
            return null
        }
    }
}

// ── Gateway lifecycle bridge ─────────────────────────────────────────────

/**
 * Wrap the captured plugin's gateway to bridge OpenClaw's lifecycle with
 * NovaClaw's ChannelGatewayContext.setStatus() contract.
 *
 * OpenClaw extensions manage connections internally (WebSocket open/close,
 * reconnection) but never call ctx.setStatus() because OpenClaw's gateway
 * context didn't expose it. This bridge ensures the ChannelManager's snapshot
 * accurately reflects the gateway state — matching the convention used by all
 * NovaClaw built-in plugins.
 *
 * Cleanup (connected=false) is handled by the ChannelManager's .finally()
 * block when the startAccount promise settles.
 */
function bridgeGatewayLifecycle(plugin: ChannelPlugin): ChannelPlugin {
    const originalGateway = plugin.gateway
    if (!originalGateway?.startAccount) return plugin

    return {
        ...plugin,
        gateway: {
            ...originalGateway,
            async startAccount(ctx: ChannelGatewayContext) {
                ctx.setStatus({ connected: true, lastConnectedAt: Date.now() })
                return originalGateway.startAccount!(ctx)
            },
        },
    }
}

// ── Import patching ──────────────────────────────────────────────────────

function patchAndCache(extensionId: string, sourcePath: string): string {
    mkdirSync(PLUGIN_CACHE_DIR, { recursive: true })
    const outPath = join(PLUGIN_CACHE_DIR, `${extensionId}.mjs`)
    assertInsideCacheDir(outPath)

    let source = readFileSync(sourcePath, 'utf-8')
    source = source.replace(
        /from\s+["']openclaw\/plugin-sdk["']/g,
        `from "./${COMPAT_SHIM_FILENAME}.ts"`,
    )
    source = source.replace(
        /import \* as (__WEBPACK_EXTERNAL_MODULE_\w+__) from "(events|http|https|net|tls|stream|crypto|zlib|os|fs|path|url|util|assert|buffer|child_process)"/g,
        'import $1 from "$2"',
    )

    writeIfChanged(outPath, source)
    integrityHashes.set(resolve(outPath), sha256(source))

    const shimPath = join(PLUGIN_CACHE_DIR, COMPAT_SHIM_FILENAME)
    assertInsideCacheDir(shimPath)
    writeIfChanged(shimPath, PLUGIN_SDK_SHIM)
    integrityHashes.set(resolve(shimPath), sha256(PLUGIN_SDK_SHIM))

    return outPath
}

// ── Plugin capture ───────────────────────────────────────────────────────

async function importAndCapture(
    extensionId: string,
    modulePath: string,
    ctx: ExtensionLoadContext,
): Promise<ChannelPlugin | null> {
    assertInsideCacheDir(modulePath)

    const resolvedPath = resolve(modulePath)
    const expectedHash = integrityHashes.get(resolvedPath)
    if (expectedHash) {
        const onDisk = readFileSync(resolvedPath, 'utf-8')
        if (sha256(onDisk) !== expectedHash) {
            throw new Error(`Integrity check failed for plugin '${extensionId}': file was modified after patching`)
        }
    }

    const fileUrl = pathToFileURL(modulePath)
    fileUrl.searchParams.set('t', String(Date.now()))
    const mod = await import(fileUrl.href) as Record<string, unknown>
    const defaultExport = mod.default as {
        register?: (api: unknown) => void | Promise<void>
        name?: string
        description?: string
    } | undefined

    if (defaultExport?.register) {
        return captureViaRegister(extensionId, defaultExport, ctx)
    }

    for (const [key, value] of Object.entries(mod)) {
        if (key === 'default') continue
        if (isChannelPluginShaped(value)) return value as ChannelPlugin
    }

    if (defaultExport && isChannelPluginShaped(defaultExport)) {
        return defaultExport as ChannelPlugin
    }

    return null
}

/**
 * Build the runtime object passed to extension.register(api).
 * Wraps the standard PluginChannelRuntime under `runtime.channel` to match
 * the OpenClaw runtime shape extensions expect.
 */
function buildExtensionRuntime(
    config: Record<string, unknown>,
    channelRuntime?: PluginChannelRuntime,
): Record<string, unknown> {
    const noop = () => {}
    const asyncNoop = async () => null

    return {
        version: '0.0.0-novaclaw',
        channel: channelRuntime ?? {},
        config: { loadConfig: async () => config, writeConfigFile: asyncNoop },
        system: { enqueueSystemEvent: noop, requestHeartbeatNow: noop, runCommandWithTimeout: async () => ({ exitCode: 1, stdout: '', stderr: '' }), formatNativeDependencyHint: () => '' },
        media: { loadWebMedia: asyncNoop, detectMime: () => 'application/octet-stream', mediaKindFromMime: () => 'document', isVoiceCompatibleAudio: () => false, getImageMetadata: asyncNoop, resizeToJpeg: async (b: unknown) => b },
        tts: { textToSpeechTelephony: asyncNoop },
        stt: { transcribeAudioFile: asyncNoop },
        tools: { createMemoryGetTool: () => null, createMemorySearchTool: () => null, registerMemoryCli: noop },
        events: { onAgentEvent: () => ({ unsubscribe: noop }), onSessionTranscriptUpdate: () => ({ unsubscribe: noop }) },
        logging: { shouldLogVerbose: () => false, getChildLogger: () => ({ debug: noop, info: noop, warn: noop, error: noop }) },
        state: { resolveStateDir: () => (config.workspaceDir as string) ?? '' },
        subagent: { run: async () => ({ runId: 'noop' }), waitForRun: async () => ({ status: 'error', error: 'not available' }), getSessionMessages: async () => ({ messages: [] }), getSession: async () => ({ messages: [] }), deleteSession: asyncNoop },
    }
}

function captureViaRegister(
    extensionId: string,
    definition: { register?: (api: unknown) => void | Promise<void>; name?: string; description?: string },
    ctx: ExtensionLoadContext,
): Promise<ChannelPlugin | null> {
    let captured: ChannelPlugin | null = null
    const noop = () => {}
    const config = ctx.config as Record<string, unknown>

    const api = {
        id: extensionId,
        name: definition.name ?? extensionId,
        version: '0.0.0',
        description: definition.description,
        source: `extension:${extensionId}`,
        config,
        pluginConfig: {},
        runtime: buildExtensionRuntime(config, ctx.channelRuntime),
        logger: {
            debug: (msg: string) => ctx.logger.debug(`[ext:${extensionId}] ${msg}`),
            info: (msg: string) => ctx.logger.info(`[ext:${extensionId}] ${msg}`),
            warn: (msg: string) => ctx.logger.warn(`[ext:${extensionId}] ${msg}`),
            error: (msg: string) => ctx.logger.error(`[ext:${extensionId}] ${msg}`),
        },
        registerChannel: (reg: Record<string, unknown>) => {
            captured = ('plugin' in reg && reg.plugin)
                ? reg.plugin as ChannelPlugin
                : isChannelPluginShaped(reg)
                    ? reg as unknown as ChannelPlugin
                    : null
        },
        registerTool: noop,
        registerHook: noop,
        registerHttpRoute: noop,
        registerGatewayMethod: noop,
        registerCli: noop,
        registerService: noop,
        registerProvider: noop,
        registerCommand: noop,
        registerContextEngine: noop,
        resolvePath: (input: string) => input,
        on: noop,
    }

    return Promise.resolve(definition.register!(api)).then(() => captured)
}

// ── Utilities ────────────────────────────────────────────────────────────

function isChannelPluginShaped(value: unknown): boolean {
    return typeof value === 'object' && value !== null && 'id' in value && 'meta' in value
}

function writeIfChanged(filePath: string, content: string): void {
    if (existsSync(filePath)) {
        const existing = readFileSync(filePath, 'utf-8')
        if (existing === content) return
    }
    writeFileSync(filePath, content)
}
