/**
 * Extension discovery — scans configurable directories for channel extension
 * plugins. Each subdirectory with a package.json or dist/index.js is treated
 * as a candidate extension.
 */

import { existsSync, readFileSync, readdirSync, statSync } from 'node:fs'
import { join } from 'node:path'
import { homedir } from 'node:os'
import { NOVACLAW_EXTENSIONS_DIR } from '../../../../constants/paths.ts'
import type { DiscoveredExtension, ExtensionManifest, ExtensionSource } from './types.ts'

const DEFAULT_DIRS = [
    NOVACLAW_EXTENSIONS_DIR,
    join(homedir(), '.openclaw', 'extensions'),
]

/**
 * Discover extensions from one or more directories.
 * Falls back to `~/.novaclaw/extensions/` and `~/.openclaw/extensions/`.
 */
export function discoverExtensions(dirs?: string[]): DiscoveredExtension[] {
    const searchDirs = dirs?.length ? dirs : DEFAULT_DIRS
    const results: DiscoveredExtension[] = []
    const seen = new Set<string>()

    for (const dir of searchDirs) {
        if (!existsSync(dir)) continue

        let entries: string[]
        try {
            entries = readdirSync(dir)
        } catch {
            continue
        }

        for (const name of entries) {
            if (seen.has(name)) continue
            const extDir = join(dir, name)
            if (!isExtensionDir(extDir)) continue

            seen.add(name)
            const manifest = readManifest(extDir)
            results.push({
                id: manifest?.novaclaw?.channel?.id ?? name,
                dir: extDir,
                entryPath: resolveEntryPath(extDir, manifest),
                manifest,
                source: classifySource(extDir, manifest),
            })
        }
    }

    return results
}

// ── Helpers ──────────────────────────────────────────────────────────────

function isExtensionDir(dir: string): boolean {
    try {
        if (!statSync(dir).isDirectory()) return false
    } catch {
        return false
    }
    return existsSync(join(dir, 'package.json')) || existsSync(join(dir, 'dist', 'index.js'))
}

function readManifest(extDir: string): ExtensionManifest | null {
    const pkgPath = join(extDir, 'package.json')
    if (!existsSync(pkgPath)) return null
    try {
        const raw = JSON.parse(readFileSync(pkgPath, 'utf-8'))
        if (typeof raw !== 'object' || raw === null) return null
        return raw as ExtensionManifest
    } catch {
        return null
    }
}

function resolveEntryPath(extDir: string, manifest: ExtensionManifest | null): string | null {
    if (manifest?.openclaw?.extensions?.[0]) {
        const p = join(extDir, manifest.openclaw.extensions[0])
        if (existsSync(p)) return p
    }

    if (manifest?.novaclaw?.channel?.id && manifest.main) {
        const p = join(extDir, manifest.main)
        if (existsSync(p)) return p
    }

    if (manifest?.main) {
        const p = join(extDir, manifest.main)
        if (existsSync(p)) return p
    }

    const dist = join(extDir, 'dist', 'index.js')
    if (existsSync(dist)) return dist

    const root = join(extDir, 'index.js')
    if (existsSync(root)) return root

    return null
}

function classifySource(dir: string, manifest: ExtensionManifest | null): ExtensionSource {
    if (manifest?.novaclaw?.channel) return 'novaclaw'

    if (manifest?.openclaw?.extensions) return 'openclaw'

    if (dir.includes('.openclaw')) return 'openclaw'

    return 'unknown'
}
