/**
 * StreamConsumer — consumes an LLM streaming response into a structured turn result.
 *
 * Responsibilities:
 *   - Read streaming chunks (content, reasoning, tool_call, usage, error)
 *   - Parse think tags via ThinkTagStreamParser
 *   - Handle abort signals gracefully
 *   - Track perf timing for the stream
 *
 * Extracted from AgentExecutor for single-responsibility and testability.
 */

import type { TokenUsage, ToolCall } from '../../apis/index.ts'
import { ThinkTagStreamParser, type ThinkChunk } from './stream-parser.ts'
import type { StreamingChunk } from '../types.ts'

export interface StreamConsumeParams {
    onText: (content: string) => void
    onThinking: (content: string) => void
    abortSignal?: AbortSignal
}

export interface StreamConsumeResult {
    turnContent: string
    turnToolCalls: ToolCall[]
    turnUsage: TokenUsage
    aborted: boolean
    streamError: string | null
}

export class StreamConsumer {
    consume(
        stream: AsyncGenerator<StreamingChunk>,
        params: StreamConsumeParams,
    ): Promise<StreamConsumeResult> {
        return this.doConsume(stream, params)
    }

    private async doConsume(
        stream: AsyncGenerator<StreamingChunk>,
        params: StreamConsumeParams,
    ): Promise<StreamConsumeResult> {
        const { onText, onThinking, abortSignal } = params

        let turnContent = ''
        let aborted = false
        let streamError: string | null = null
        const turnUsage: TokenUsage = { totalTokens: 0 }
        const turnToolCalls: ToolCall[] = []
        const thinkParser = new ThinkTagStreamParser()

        const emitParsed = (chunks: ThinkChunk[]) => {
            for (const p of chunks) {
                if (p.kind === 'thinking') {
                    onThinking(p.content)
                } else {
                    turnContent += p.content
                    onText(p.content)
                }
            }
        }

        try {
            for await (const chunk of stream) {
                if (abortSignal?.aborted) {
                    aborted = true
                    break
                }
                switch (chunk.type) {
                    case 'content':
                        if (chunk.content) emitParsed(thinkParser.feed(chunk.content))
                        break
                    case 'reasoning':
                        if (chunk.content) {
                            emitParsed(thinkParser.flush())
                            onThinking(chunk.content)
                        }
                        break
                    case 'tool_call':
                        if (chunk.toolCall) turnToolCalls.push(chunk.toolCall)
                        break
                    case 'usage':
                        if (chunk.usage) {
                            turnUsage.totalTokens = (turnUsage.totalTokens || 0) + (chunk.usage.totalTokens || 0)
                            turnUsage.inputTokens = (turnUsage.inputTokens || 0) + (chunk.usage.inputTokens || 0)
                            turnUsage.outputTokens = (turnUsage.outputTokens || 0) + (chunk.usage.outputTokens || 0)
                        }
                        break
                    case 'error':
                        streamError = chunk.error ?? null
                        break
                }
            }
            emitParsed(thinkParser.flush())
        } catch (err: unknown) {
            emitParsed(thinkParser.flush())
            if (abortSignal?.aborted || (err instanceof Error && err.name === 'AbortError')) {
                aborted = true
            } else {
                throw err
            }
        }

        return { turnContent, turnToolCalls, turnUsage, aborted, streamError }
    }
}
