type MessageKey = keyof typeof messages

let currentLocale: Locale = 'zh'

export function setLocale(locale: Locale): void {
    currentLocale = locale
}

export function getLocale(): Locale {
    return currentLocale
}

/** Reset locale to default (zh). Useful for tests. */
export function resetLocale(): void {
    currentLocale = 'zh'
}

export function t<K extends MessageKey>(key: K, ...args: unknown[]): string {
    const entry = messages[key]
    const value = entry[currentLocale]
    if (typeof value === 'function') {
        return (value as (...a: unknown[]) => string)(...args)
    }
    return value as string
}

export function detectLocale(): Locale {
    const lang = process.env.LANG || process.env.LANGUAGE || process.env.LC_ALL || ''
    if (lang.toLowerCase().startsWith('zh')) return 'zh'
    return 'en'
}
