/**
 * WebSocket frame encoding/decoding — shared between handler and tests.
 */

import type { WebSocket } from 'ws'

export type ClientFrame =
    | { type: 'req'; id?: string; method: string; params?: unknown }
    | { type: 'event'; event: string; payload?: unknown }

const WS_OPEN = 1

export function sendEvent(socket: WebSocket, event: string, payload?: unknown): void {
    if (socket.readyState !== WS_OPEN) return
    // Stream chunks use a flat format for backwards compat with older clients
    const isStreamChunk =
        event === 'stream_chunk' && payload && typeof payload === 'object' && 'chunk' in payload
    const body = isStreamChunk
        ? { type: 'stream_chunk', chunk: (payload as { chunk: unknown }).chunk }
        : { type: 'event', event, payload }
    socket.send(JSON.stringify(body))
}

export function sendRes(
    socket: WebSocket,
    id: string | undefined,
    ok: boolean,
    payload?: unknown,
    error?: string,
): void {
    if (socket.readyState !== WS_OPEN) return
    // Legacy message_complete format when no request id
    const body =
        id === undefined && payload && typeof payload === 'object' && 'success' in payload
            ? { type: 'message_complete', response: payload }
            : { type: 'res', id, ok, payload, error }
    socket.send(JSON.stringify(body))
}

export function sendLegacy(socket: WebSocket, type: string, data?: Record<string, unknown>): void {
    if (socket.readyState !== WS_OPEN) return
    socket.send(JSON.stringify({ type, ...data }))
}

export function parseClientMessage(raw: string): ClientFrame | null {
    let msg: unknown
    try {
        msg = JSON.parse(raw)
    } catch {
        return null
    }
    if (!msg || typeof msg !== 'object') return null

    const m = msg as Record<string, unknown>

    if (m.type === 'req' && typeof m.method === 'string') {
        return { type: 'req', id: m.id as string | undefined, method: m.method, params: m.params }
    }
    if (m.type === 'event' && typeof m.event === 'string') {
        return { type: 'event', event: m.event, payload: m.payload }
    }
    // Fallback: treat `type` as method name for simple clients
    if (typeof m.type === 'string') {
        return { type: 'req', id: m.id as string | undefined, method: m.type, params: m.payload ?? m }
    }
    return null
}
