/**
 * HTTPBridge — HTTP webhook management and outbound request client.
 * Extracted from ProtocolBridge for single-responsibility.
 */

import { Logger } from '../../utils/logger.ts'

export interface HttpSendOptions {
    method?: string
    headers?: Record<string, string>
    body?: unknown
}

export interface HttpSendResult {
    ok: boolean
    status: number
    data?: unknown
    headers?: Record<string, string>
}

export type WebhookHandler = (
    req: unknown,
    res: {
        json: (data: unknown) => unknown;
        status: (code: number) => { json: (data: unknown) => { status: number; data: unknown } }
    }
) => Promise<unknown>

interface WebhookEntry {
    handler: WebhookHandler
    registered: number
    calls: number
}

export class HTTPBridge {
    private logger = new Logger('HTTPBridge')
    private webhooks = new Map<string, WebhookEntry>()

    async initialize(): Promise<void> {
        this.logger.info('Initializing HTTP Bridge...')
        this.logger.info('HTTP Bridge initialized')
    }

    async registerWebhook(path: string, handler: WebhookHandler): Promise<void> {
        this.webhooks.set(path, { handler, registered: Date.now(), calls: 0 })
        this.logger.info(`Webhook registered: ${path}`)
    }

    async handleRequest(path: string, request: unknown): Promise<unknown> {
        const webhook = this.webhooks.get(path)
        if (!webhook) throw new Error(`No webhook registered for path: ${path}`)
        webhook.calls++
        try {
            return await webhook.handler(request, {
                json: (data: unknown) => data,
                status: (code: number) => ({ json: (data: unknown) => ({ status: code, data }) })
            })
        } catch (error) {
            this.logger.error(`Error handling HTTP request for ${path}`, error)
            throw error
        }
    }

    async sendRequest(url: string, options: HttpSendOptions = {}): Promise<HttpSendResult> {
        const { method = 'GET', headers = {}, body } = options
        this.logger.debug(`Sending HTTP ${method} request to: ${url}`)
        const res = await fetch(url, {
            method,
            headers: { 'Content-Type': 'application/json', ...headers },
            body: body != null ? (typeof body === 'string' ? body : JSON.stringify(body)) : undefined
        })
        const headersObj: Record<string, string> = {}
        res.headers.forEach((v, k) => {
            headersObj[k] = v
        })
        const contentType = res.headers.get('content-type') ?? ''
        const data = contentType.includes('application/json')
            ? await res.json().catch(() => null)
            : await res.text()
        return { ok: res.ok, status: res.status, data, headers: headersObj }
    }

    getWebhookStats(): Record<string, { registered: number; calls: number }> {
        const stats: Record<string, { registered: number; calls: number }> = {}
        for (const [path, webhook] of this.webhooks) stats[path] = {
            registered: webhook.registered,
            calls: webhook.calls
        }
        return stats
    }

    async cleanup(): Promise<void> {
        this.webhooks.clear()
        this.logger.info('HTTP Bridge cleaned up')
    }
}
