/**
 * Outbound delivery — resolves channel plugin and delivers messages.
 */

import type { NovaClawConfig } from '../../../apis/config.ts'
import type { ChannelPlugin } from '../../types/plugin.ts'
import type { OutboundDeliveryResult } from '../../types/context.ts'
import type { ChannelRegistry } from '../../registry.ts'
import { chunkText, getTextChunkLimit } from './chunker.ts'

export interface DeliveryRequest {
    channel: string
    accountId?: string
    to: string
    text?: string
    mediaUrl?: string
    mediaType?: string
    replyToId?: string
    threadId?: string
    channelData?: Record<string, unknown>
    metadata?: Record<string, unknown>
}

export interface DeliveryResult {
    success: boolean
    results: OutboundDeliveryResult[]
    errors: Error[]
}

export async function deliverOutboundMessage(
    request: DeliveryRequest,
    cfg: NovaClawConfig,
    registry: ChannelRegistry,
): Promise<DeliveryResult> {
    const plugin = registry.get(request.channel)
    if (!plugin) {
        return {
            success: false,
            results: [],
            errors: [new Error(`Channel plugin not found: ${request.channel}`)],
        }
    }

    const outbound = plugin.outbound
    if (!outbound) {
        return {
            success: false,
            results: [],
            errors: [new Error(`Channel ${request.channel} has no outbound adapter`)],
        }
    }

    if (outbound.resolveTarget) {
        const resolved = outbound.resolveTarget({ to: request.to, cfg, accountId: request.accountId })
        if (!resolved.ok) {
            return { success: false, results: [], errors: [resolved.error] }
        }
        request = { ...request, to: resolved.to }
    }

    const results: OutboundDeliveryResult[] = []
    const errors: Error[] = []

    try {
        if (request.channelData && outbound.sendPayload) {
            const result = await outbound.sendPayload({
                cfg,
                to: request.to,
                text: request.text,
                accountId: request.accountId,
                replyToId: request.replyToId,
                threadId: request.threadId,
                metadata: request.metadata,
                channelData: request.channelData,
            })
            results.push(result)
        } else if (request.mediaUrl && outbound.sendMedia) {
            const result = await outbound.sendMedia({
                cfg,
                to: request.to,
                text: request.text,
                mediaUrl: request.mediaUrl,
                mediaType: request.mediaType,
                accountId: request.accountId,
                replyToId: request.replyToId,
                threadId: request.threadId,
                metadata: request.metadata,
            })
            results.push(result)
        } else if (request.text && outbound.sendText) {
            const chunks = splitTextForChannel(request.text, plugin)
            for (const chunk of chunks) {
                const result = await outbound.sendText({
                    cfg,
                    to: request.to,
                    text: chunk,
                    accountId: request.accountId,
                    replyToId: request.replyToId,
                    threadId: request.threadId,
                    metadata: request.metadata,
                })
                results.push(result)
            }
        }
    } catch (err) {
        errors.push(err instanceof Error ? err : new Error(String(err)))
    }

    return {
        success: errors.length === 0 && results.length > 0,
        results,
        errors,
    }
}

function splitTextForChannel(text: string, plugin: ChannelPlugin): string[] {
    const outbound = plugin.outbound!
    const limit = getTextChunkLimit(plugin.id, outbound.textChunkLimit)

    if (outbound.chunker) {
        return outbound.chunker(text, limit)
    }

    return chunkText(text, limit, {
        mode: outbound.chunkerMode ?? 'text',
    })
}
