/**
 * Channel Registry — extends BaseRegistry<ChannelPlugin> with ordering,
 * alias resolution, and facade caching on top of the framework's standard
 * registry pattern.
 */

import type { ChannelId, ChannelMeta } from './types/core.ts'
import type { ChannelPlugin } from './types/plugin.ts'
import { buildFacadeFromPlugin } from './channel-facade.ts'
import type { ChannelFacade } from './channel-facade.ts'
import { BUILTIN_CHANNEL_IDS, type BuiltinChannelId } from './constants.ts'
import { BaseRegistry } from '../../registries/base-registry.ts'

export type { BuiltinChannelId }

export const BUILTIN_CHANNEL_ORDER: readonly BuiltinChannelId[] = BUILTIN_CHANNEL_IDS

const BUILTIN_CHANNEL_META: Record<BuiltinChannelId, ChannelMeta> = {
    webchat: {
        id: 'webchat',
        label: 'WebChat',
        selectionLabel: 'WebChat (Browser)',
        docsPath: '/channels/webchat',
        blurb: 'Browser-based chat widget for web applications',
        systemImage: 'bubble.left.and.bubble.right',
        order: 0,
    },
    cli: {
        id: 'cli',
        label: 'CLI',
        selectionLabel: 'CLI (Terminal)',
        docsPath: '/channels/cli',
        blurb: 'Command-line interface for terminal interactions',
        systemImage: 'terminal',
        order: 1,
    },
    'rest-api': {
        id: 'rest-api',
        label: 'REST API',
        selectionLabel: 'REST API (HTTP)',
        docsPath: '/channels/rest-api',
        blurb: 'RESTful HTTP API for programmatic access',
        systemImage: 'arrow.left.arrow.right',
        order: 2,
    },
}

export const BUILTIN_CHANNEL_ALIASES: Record<string, BuiltinChannelId> = {
    web: 'webchat',
    chat: 'webchat',
    terminal: 'cli',
    api: 'rest-api',
    rest: 'rest-api',
}

export type PluginOrigin = 'config' | 'workspace' | 'global' | 'bundled'

const ORIGIN_PRIORITY: Record<PluginOrigin, number> = {
    config: 0,
    workspace: 1,
    global: 2,
    bundled: 3,
}

export interface ChannelRegistryEntry {
    plugin: ChannelPlugin
    origin: PluginOrigin
    version?: string
    registeredAt: number
}

interface CachedChannelPlugins {
    registryVersion: number
    sorted: ChannelPlugin[]
    byId: Map<ChannelId, ChannelPlugin>
    allMeta: ChannelMeta[]
}

export class ChannelRegistry extends BaseRegistry<ChannelPlugin> {
    private readonly meta = new Map<ChannelId, Omit<ChannelRegistryEntry, 'plugin'>>()
    private aliases = new Map<string, ChannelId>(Object.entries(BUILTIN_CHANNEL_ALIASES))
    private version = 0
    private pluginCache: CachedChannelPlugins | null = null
    private facadeCache = new Map<ChannelId, { version: number; facade: ChannelFacade }>()

    constructor() {
        super('ChannelRegistry')
    }

    /**
     * Register a channel plugin with origin-based priority.
     * Lower-priority origins cannot overwrite higher-priority ones.
     */
    registerPlugin(plugin: ChannelPlugin, origin: PluginOrigin = 'config', version?: string): void {
        const existing = this.meta.get(plugin.id)
        if (existing) {
            const existingPriority = ORIGIN_PRIORITY[existing.origin]
            const newPriority = ORIGIN_PRIORITY[origin]
            if (newPriority > existingPriority) return
        }

        super.register(plugin.id, plugin)
        this.meta.set(plugin.id, { origin, version, registeredAt: Date.now() })

        if (plugin.meta.aliases) {
            for (const alias of plugin.meta.aliases) {
                this.aliases.set(alias.toLowerCase(), plugin.id)
            }
        }

        this.version++
        this.pluginCache = null
    }

    override unregister(channelId: ChannelId): boolean {
        const plugin = this.get(channelId)
        if (!plugin) return false

        if (plugin.meta.aliases) {
            for (const alias of plugin.meta.aliases) {
                this.aliases.delete(alias.toLowerCase())
            }
        }

        this.meta.delete(channelId)
        super.unregister(channelId)
        this.version++
        this.pluginCache = null
        return true
    }

    getEntry(channelId: ChannelId): ChannelRegistryEntry | undefined {
        const plugin = this.get(channelId)
        const entryMeta = this.meta.get(channelId)
        if (!plugin || !entryMeta) return undefined
        return { plugin, ...entryMeta }
    }

    resolveAlias(idOrAlias: string): ChannelId {
        return this.aliases.get(idOrAlias.toLowerCase()) ?? idOrAlias
    }

    normalizeChannelId(idOrAlias: string): ChannelId {
        return this.resolveAlias(idOrAlias.toLowerCase())
    }

    listPlugins(): ChannelPlugin[] {
        return this.resolve().sorted
    }

    listMeta(): ChannelMeta[] {
        return this.resolve().allMeta
    }

    override listIds(): ChannelId[] {
        return this.resolve().sorted.map(p => p.id)
    }

    getVersion(): number {
        return this.version
    }

    isBuiltin(channelId: string): boolean {
        return (BUILTIN_CHANNEL_IDS as readonly string[]).includes(channelId)
    }

    getBuiltinMeta(channelId: BuiltinChannelId): ChannelMeta {
        return BUILTIN_CHANNEL_META[channelId]
    }

    getChannelFacade(channelId: ChannelId): ChannelFacade | undefined {
        const registryVersion = this.getVersion()
        const cached = this.facadeCache.get(channelId)
        if (cached && cached.version === registryVersion) {
            return cached.facade
        }

        const plugin = this.get(channelId)
        if (!plugin) return undefined

        const facade = buildFacadeFromPlugin(plugin)
        this.facadeCache.set(channelId, { version: registryVersion, facade })
        return facade
    }

    clearFacadeCache(): void {
        this.facadeCache.clear()
    }

    private resolve(): CachedChannelPlugins {
        if (this.pluginCache && this.pluginCache.registryVersion === this.version) {
            return this.pluginCache
        }

        const plugins = Array.from(this.entries.values())
        const deduped = this.dedupeByOriginPriority(plugins)

        const sorted = [...deduped].sort((a: ChannelPlugin, b: ChannelPlugin) => {
            const orderA = a.meta.order ?? 999
            const orderB = b.meta.order ?? 999
            if (orderA !== orderB) return orderA - orderB
            return a.meta.label.localeCompare(b.meta.label)
        })

        const byId = new Map<ChannelId, ChannelPlugin>()
        for (const p of sorted) byId.set(p.id, p)

        this.pluginCache = {
            registryVersion: this.version,
            sorted,
            byId,
            allMeta: sorted.map(p => p.meta),
        }
        return this.pluginCache
    }

    private dedupeByOriginPriority(plugins: ChannelPlugin[]): ChannelPlugin[] {
        const best = new Map<ChannelId, { plugin: ChannelPlugin; priority: number }>()
        for (const plugin of plugins) {
            const entryMeta = this.meta.get(plugin.id)
            const priority = entryMeta ? ORIGIN_PRIORITY[entryMeta.origin] : 999
            const existing = best.get(plugin.id)
            if (!existing || priority < existing.priority) {
                best.set(plugin.id, { plugin, priority })
            }
        }
        return Array.from(best.values()).map(e => e.plugin)
    }
}
