import { toErrorMessage } from '../../../constants/errors.ts'
import { EventEmitter } from '../../../utils/event-emitter.ts'
import { Logger } from '../../utils/logger.ts'
import type { MCPServerEntry } from '../apis/config.ts'
import type { IMCPConnector, MCPCallToolResult, MCPConnectOptions, MCPTool } from '../apis/mcp.ts'
import { DefaultMCPConnector } from '../mcp/mcp-connector.ts'
import { HTTPBridge, type HttpSendOptions, type HttpSendResult, type WebhookHandler } from './http-bridge.ts'

interface ProtocolBridgeEventMap extends Record<string, unknown[]> {
    'mcp:connected': [endpoint: string]
    'mcp:tool_called': [data: { endpoint: string; toolName: string; args: Record<string, unknown>; result: MCPCallToolResult }]
    'http:webhook_registered': [path: string]
    'http:request_sent': [data: { url: string; options: HttpSendOptions; result: HttpSendResult }]
}

export type { HttpSendOptions, HttpSendResult, WebhookHandler }

export interface ProtocolBridgeOptions {
    mcpConnector?: IMCPConnector
    logger?: Logger
}

/** 协议桥接主类：MCP + HTTP，配置为 Record 以保持 framework 无项目依赖。 */
export class ProtocolBridge extends EventEmitter<ProtocolBridgeEventMap> {
    private readonly mcpConnector: IMCPConnector
    private readonly httpBridge: HTTPBridge
    private readonly logger: Logger
    private readonly configRecord: Record<string, unknown>

    constructor(
        config: Record<string, string> | import('../apis/config').NovaClawConfig,
        options?: ProtocolBridgeOptions,
    ) {
        super()
        this.configRecord = config as Record<string, unknown>
        const logLevel = (config as Record<string, unknown> & { logging?: { level?: string } }).logging?.level
        this.logger = options?.logger ?? new Logger('ProtocolBridge', logLevel ?? 'info')
        this.mcpConnector = options?.mcpConnector ?? new DefaultMCPConnector({ logger: this.logger })
        this.httpBridge = new HTTPBridge()
    }

    async initialize(): Promise<void> {
        const startTime = performance.now()
        const workspace = this.configRecord.workspaceDir as string | undefined
        this.logger.info('Initializing', { workspace })

        try {
            await this.httpBridge.initialize()
            const mcpConfig = (this.configRecord as { mcp?: MCPServerEntry[] }).mcp
            if (Array.isArray(mcpConfig)) {
                for (const entry of mcpConfig) {
                    await this.connectEntry(entry)
                }
            }
            this.logger.info(`Initialized (${(performance.now() - startTime).toFixed(0)}ms)`)
        } catch (error) {
            this.logger.error('Initialization failed', error)
            throw error
        }
    }

    async connectMCP(endpoint: string, options: Omit<MCPConnectOptions, 'endpoint'> = {}): Promise<void> {
        await this.mcpConnector.connect({ endpoint, ...options })
        this.emit('mcp:connected', endpoint)
    }

    /** Drop all MCP sessions and reconnect from config (e.g. after saving overrides). */
    async reloadMcpConnections(entries: MCPServerEntry[]): Promise<void> {
        await this.mcpConnector.cleanup()
        for (const entry of entries) {
            await this.connectEntry(entry)
        }
    }

    async getMCPTools(endpoint: string): Promise<MCPTool[]> {
        return this.mcpConnector.listTools(endpoint)
    }

    async callMCPTool(endpoint: string, toolName: string, args: Record<string, unknown> = {}): Promise<MCPCallToolResult> {
        const result = await this.mcpConnector.callTool(endpoint, toolName, args)
        this.emit('mcp:tool_called', { endpoint, toolName, args, result })
        return result
    }

    async registerHTTPWebhook(path: string, handler: WebhookHandler): Promise<void> {
        await this.httpBridge.registerWebhook(path, handler)
        this.emit('http:webhook_registered', path)
    }

    async sendHTTPRequest(url: string, options: HttpSendOptions = {}): Promise<HttpSendResult> {
        const result = await this.httpBridge.sendRequest(url, options)
        this.emit('http:request_sent', { url, options, result })
        return result
    }

    async callExternal(
        protocol: 'mcp' | 'http',
        params: {
            endpoint?: string
            tool?: string
            args?: Record<string, unknown>
            url?: string
            options?: HttpSendOptions
        },
    ): Promise<unknown> {
        switch (protocol) {
            case 'mcp':
                if (params.endpoint == null || params.tool == null) throw new Error('MCP call requires endpoint and tool')
                return this.callMCPTool(params.endpoint, params.tool, params.args ?? {})
            case 'http':
                if (params.url == null) throw new Error('HTTP call requires url')
                return this.sendHTTPRequest(params.url, params.options)
            default:
                throw new Error(`Unsupported protocol: ${protocol}`)
        }
    }

    getStats(): Record<string, unknown> {
        return {
            mcp: { connections: (this.mcpConnector as DefaultMCPConnector).connectionCount ?? 0 },
            http: { webhooks: this.httpBridge.getWebhookStats() },
        }
    }

    async healthCheck(): Promise<{
        status: 'healthy' | 'degraded' | 'unhealthy'
        components: Record<string, { status: string; connections?: number; webhooks?: number }>
    }> {
        const connCount = (this.mcpConnector as DefaultMCPConnector).connectionCount ?? 0
        const components = {
            mcp: { status: 'healthy' as const, connections: connCount },
            http: { status: 'healthy' as const, webhooks: Object.keys(this.httpBridge.getWebhookStats()).length },
        }
        return {
            status: Object.values(components).every(c => c.status === 'healthy') ? 'healthy' : 'degraded',
            components,
        }
    }

    async cleanup(): Promise<void> {
        await Promise.all([this.mcpConnector.cleanup(), this.httpBridge.cleanup()])
        this.removeAllListeners()
        this.logger.debug('Cleaned up')
    }

    private async connectEntry(entry: MCPServerEntry): Promise<void> {
        const endpoint = entry?.endpoint?.trim()
        if (!endpoint) return
        try {
            await this.mcpConnector.connect({
                endpoint,
                transport: entry.transport,
                command: entry.command,
                args: entry.args,
                requestInit: entry.requestInit,
            })
            this.emit('mcp:connected', endpoint)
        } catch (err) {
            this.logMcpConnectFailure(endpoint, err)
        }
    }

    private logMcpConnectFailure(endpoint: string, err: unknown): void {
        const msg = toErrorMessage(err)
        this.logger.warn(`MCP connect failed: ${endpoint}`, err)
        if (/bearer|no bearer|unauthorized|401|403/i.test(msg)) {
            this.logger.info(
                'Hint: add requestInit.headers.Authorization under this MCP entry in novaclaw.yml or the MCP settings UI',
            )
        }
    }
}
