/**
 * ChannelRuntime builder — constructs the PluginChannelRuntime passed to external plugins
 * via ctx.channelRuntime for reply dispatch, routing, chunking, and other runtime services.
 */

import type { PluginChannelRuntime, EnvelopeFormatOptions, FormatEnvelopeParams } from './types/context.ts'
import type { NovaClawConfig } from '../apis/config.ts'
import type { ChannelRegistry } from './registry.ts'
import { chunkText } from './pipeline/outbound/chunker.ts'
import { resolveAgentRoute, type ChannelBinding, type RoutePeer } from './pipeline/routing/index.ts'
import { getChannelFacade } from './channel-facade.ts'

export interface BuildChannelRuntimeParams {
    cfg: NovaClawConfig
    channelId: string
    accountId: string
    registry: ChannelRegistry
    bindings?: ChannelBinding[]
    onReply?: (
        ctx: Record<string, unknown>,
        cfg: NovaClawConfig,
        options: Record<string, unknown>,
    ) => Promise<unknown>
}

export function buildChannelRuntime(params: BuildChannelRuntimeParams): PluginChannelRuntime {
    const { cfg, channelId, accountId, registry, bindings = [], onReply } = params

    return {
        reply: {
            resolveEnvelopeFormatOptions: (overrideCfg?: NovaClawConfig): EnvelopeFormatOptions => {
                const activeCfg = overrideCfg ?? cfg
                const channelsCfg = activeCfg.channels as Record<string, unknown> | undefined
                const channelCfg = channelsCfg?.[channelId] as Record<string, unknown> | undefined
                const envelope = channelCfg?.envelope as Record<string, unknown> | undefined
                return {
                    enabled: envelope?.enabled !== false,
                    showTimestamp: envelope?.showTimestamp !== false,
                    showChannel: envelope?.showChannel !== false,
                    showSender: envelope?.showSender !== false,
                }
            },

            formatAgentEnvelope: (fmtParams: FormatEnvelopeParams): string => {
                const { channel, from, timestamp, envelope, body } = fmtParams
                if (!envelope || envelope.enabled === false) return body

                const parts: string[] = []
                if (envelope.showChannel !== false) parts.push(`[${channel}]`)
                if (envelope.showSender !== false) parts.push(from)
                if (envelope.showTimestamp !== false) {
                    const time = new Date(timestamp).toLocaleTimeString('en-GB', {
                        hour: '2-digit', minute: '2-digit',
                    })
                    parts.push(`(${time})`)
                }

                return parts.length ? `${parts.join(' ')}:\n${body}` : body
            },

            finalizeInboundContext: (ctxParams: Record<string, unknown>): Record<string, unknown> => {
                const ctx: Record<string, unknown> = {}
                for (const [k, v] of Object.entries(ctxParams)) {
                    if (v !== undefined) ctx[k] = v
                }
                return ctx
            },

            dispatchReplyWithBufferedBlockDispatcher: async (dispatchParams) => {
                if (onReply) {
                    return onReply(dispatchParams.ctx, dispatchParams.cfg, {
                        dispatcherOptions: dispatchParams.dispatcherOptions,
                    })
                }
                return undefined
            },
        },
        routing: {
            resolveAgentRoute: (input: Record<string, unknown>) => {
                return resolveAgentRoute(
                    {
                        cfg,
                        channel: (input.channel as string) ?? channelId,
                        accountId: (input.accountId as string) ?? accountId,
                        peer: input.peer as RoutePeer | undefined,
                        parentPeer: input.parentPeer as RoutePeer | undefined,
                        guildId: input.guildId as string | undefined,
                        teamId: input.teamId as string | undefined,
                        memberRoleIds: input.memberRoleIds as string[] | undefined,
                    },
                    bindings,
                    'default',
                )
            },
        },
        text: {
            chunk: (text: string, limit: number) => chunkText(text, limit),
        },
        media: {
            fetchRemote: async (url: string): Promise<Buffer> => {
                const controller = new AbortController()
                const timeout = setTimeout(() => controller.abort(), 30_000)
                try {
                    const res = await fetch(url, { signal: controller.signal })
                    if (!res.ok) {
                        throw new Error(`fetchRemote failed: ${res.status} ${res.statusText}`)
                    }
                    const arrayBuffer = await res.arrayBuffer()
                    return Buffer.from(arrayBuffer)
                } finally {
                    clearTimeout(timeout)
                }
            },
        },
        groups: {
            resolvePolicy: (params: Record<string, unknown>) => {
                const facade = getChannelFacade(channelId, registry)
                if (!facade?.groups) return undefined

                const groupCtx = {
                    cfg,
                    channelId,
                    accountId,
                    peerId: (params.peerId as string) ?? '',
                    peerKind: (params.peerKind as 'group' | 'channel' | 'thread') ?? 'direct',
                    guildId: params.guildId as string | undefined,
                    teamId: params.teamId as string | undefined,
                }

                return facade.groups.resolveToolPolicy?.(groupCtx) ?? facade.groups.resolveRequireMention?.(groupCtx)
            },
        },
        debounce: {
            create: (ms: number) => {
                return (fn: () => void) => {
                    let timeout: ReturnType<typeof setTimeout> | null = null
                    return () => {
                        if (timeout) clearTimeout(timeout)
                        timeout = setTimeout(() => {
                            fn()
                            timeout = null
                        }, ms)
                    }
                }
            },
        },
        mentions: {
            buildRegex: (botName: string) => {
                const escaped = botName.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')
                return new RegExp(`@${escaped}\\b|\\b${escaped}\\b`, 'i')
            },
        },
    }
}
