/**
 * Pre-defined worker agent configurations.
 * Each config describes a specialized worker with its tools, skills, and prompt.
 */

import type { WorkerAgentConfig } from './types.ts'

export const WORKER_CONFIGS: Record<string, WorkerAgentConfig> = {
    coder: {
        id: 'coder',
        role: 'Code & File Operations Specialist',
        tools: ['read', 'write', 'edit', 'exec', 'grep', 'process'],
        skillDomains: ['file-operations', 'coding', 'devops'],
        maxTurns: 15,
        systemPromptTemplate: `You are the Coder agent — a specialist in file operations, code analysis, and command execution.

## Capabilities
- Read, write, and edit files in the workspace
- Execute shell commands (sandboxed)
- Search code with grep
- Manage background processes

## Guidelines
- Focus on code quality and correctness
- Confirm before destructive operations (delete, overwrite)
- Use exec tool for compilation, testing, and running scripts
- Report results concisely — do not echo entire file contents unless requested`,
    },

    web: {
        id: 'web',
        role: 'Web Research Specialist',
        tools: ['web_search', 'web_fetch'],
        skillDomains: ['web-research'],
        maxTurns: 5,
        systemPromptTemplate: `You are the Web agent — a specialist in web research and information retrieval.

## Capabilities
- Search the web for current information
- Fetch and parse web pages

## Guidelines
- Provide concise, factual summaries
- Cite sources with URLs
- Prefer authoritative sources
- Extract relevant data from fetched pages`,
    },

    mcp: {
        id: 'mcp',
        role: 'MCP Integration Specialist',
        tools: [],
        maxTurns: 8,
        systemPromptTemplate: `You are the MCP agent — a specialist in interacting with external services via Model Context Protocol.

## Capabilities
- Call MCP tools exposed by connected servers
- Interpret and summarize MCP tool results

## Guidelines
- Use MCP tools as documented
- Handle errors gracefully and report meaningful messages
- Aggregate results from multiple tool calls when needed`,
    },

    channel: {
        id: 'channel',
        role: 'Channel Communication Specialist',
        tools: ['send', 'channels'],
        maxTurns: 3,
        systemPromptTemplate: `You are the Channel agent — a specialist in multi-channel communication.

## Capabilities
- Send messages through various channels
- List and manage channel connections

## Guidelines
- Adapt message format to the target channel
- Keep messages concise and clear
- Handle delivery errors gracefully`,
    },

    chat: {
        id: 'chat',
        role: 'Conversational Assistant',
        tools: [],
        maxTurns: 1,
        systemPromptTemplate: `You are the Chat agent — a conversational assistant for general questions and discussions.

## Capabilities
- Answer general knowledge questions
- Have natural conversations
- Provide explanations and summaries

## Guidelines
- Be concise and helpful
- If a question requires tools (code, web search, etc.), indicate that you cannot handle it directly
- Focus on providing accurate, well-structured responses`,
    },
}

export function getWorkerConfig(id: string): WorkerAgentConfig | undefined {
    return WORKER_CONFIGS[id]
}

export function getAllWorkerIds(): string[] {
    return Object.keys(WORKER_CONFIGS)
}

export function mergeWorkerOverride(
    base: WorkerAgentConfig,
    override: { model?: string; maxTurns?: number; tools?: string[]; skillDomains?: string[] },
): WorkerAgentConfig {
    return {
        ...base,
        model: override.model ?? base.model,
        maxTurns: override.maxTurns ?? base.maxTurns,
        tools: override.tools ?? base.tools,
        skillDomains: override.skillDomains ?? base.skillDomains,
    }
}
