/**
 * MentionGate — filters group messages that don't @mention the bot.
 *
 * In group / channel / thread contexts, many channels require an explicit
 * @mention before the bot responds.  This stage consults the plugin's
 * groups and mentions adapters to enforce that policy.
 */

import type { ChannelPlugin } from '../../types/plugin.ts'
import type { NovaClawConfig } from '../../../apis/config.ts'

export class MentionGate {
    /**
     * Returns `true` if the message should proceed through the pipeline.
     * Returns `false` to silently drop the message.
     */
    check(
        plugin: ChannelPlugin | undefined,
        channelId: string,
        msg: Record<string, unknown>,
        chatType: string,
        config: NovaClawConfig,
    ): boolean {
        const isGroup = chatType === 'group' || chatType === 'channel' || chatType === 'thread'
        if (!isGroup || !plugin?.mentions) return true

        const requireMention = plugin.groups?.resolveRequireMention?.({
            cfg: config,
            channelId,
            accountId: (msg.accountId as string) ?? 'default',
            peerId: (msg.to as string) ?? (msg.peerId as string) ?? '',
            peerKind: chatType as 'group' | 'channel' | 'thread',
            guildId: msg.guildId as string | undefined,
            teamId: msg.teamId as string | undefined,
        })

        if (!requireMention) return true

        const botName = plugin.meta?.label ?? plugin.id
        const body = (msg.body as string) ?? (msg.text as string) ?? ''

        return !!plugin.mentions.isMentioned?.({
            text: body,
            botName,
            botId: msg.botId as string | undefined,
        })
    }
}
