import {readFile} from 'node:fs/promises'
import type {Tool, ToolExecutionResult} from '../apis/tool.ts'
import {resolvePathInWorkspace} from './security.ts'

export class ReadTool implements Tool {
    readonly name = 'read'
    readonly description = 'Read file contents from workspace. Parameters: path (relative to workspace).'
    readonly parameters = {
        type: 'object',
        properties: {
            path: {type: 'string', description: 'File path relative to workspace'}
        },
        required: ['path']
    }

    constructor(
        private workspaceDir: string,
        private canRead: boolean = true
    ) {
    }

    validate(args: Record<string, unknown>): string | null {
        if (!this.canRead) return 'File system read is disabled by permissions'
        const p = typeof args?.path === 'string' ? args.path.trim() : ''
        if (!p) return 'Missing parameter: path'
        const resolved = resolvePathInWorkspace(p, this.workspaceDir)
        if (!resolved) return 'Path is outside workspace or invalid'
        return null
    }

    async execute(args: Record<string, unknown>): Promise<ToolExecutionResult> {
        const validationError = this.validate(args)
        if (validationError) return {success: false, error: validationError}

        const p = (args.path as string).trim()
        const resolved = resolvePathInWorkspace(p, this.workspaceDir)!

        try {
            const content = await readFile(resolved, 'utf-8')
            return {success: true, content}
        } catch (err: unknown) {
            const e = err as NodeJS.ErrnoException
            if (e.code === 'ENOENT') return {success: false, error: `File not found: ${p}`}
            if (e.code === 'EACCES') return {success: false, error: `Permission denied: ${p}`}
            return {success: false, error: e.message ?? String(err)}
        }
    }
}
