/**
 * Centralized path constants for the ~/.novaclaw/ data directory.
 *
 * Every module that needs a path under the NovaClaw home directory MUST import
 * from here instead of constructing paths with join(homedir(), '.novaclaw', …).
 *
 * Environment variable overrides (used in Docker / CI):
 *   NOVACLAW_HOME       — root data directory   (default: ~/.novaclaw)
 *   NOVACLAW_SKILLS_DIR — user-global skills dir (default: $NOVACLAW_HOME/skills)
 */

import { homedir } from 'node:os'
import { join } from 'node:path'

export const NOVACLAW_HOME = process.env.NOVACLAW_HOME
    ?? join(homedir(), '.novaclaw')

// ── Config files (all .yml) ──────────────────────────────────────────────

export const NOVACLAW_CONFIG_PATH = join(NOVACLAW_HOME, 'config.yml')
export const NOVACLAW_OVERRIDES_PATH = join(NOVACLAW_HOME, 'overrides.yml')

// ── Data directories ────────────────────────────────────────────────────

export const NOVACLAW_SKILLS_DIR = process.env.NOVACLAW_SKILLS_DIR
    ?? join(NOVACLAW_HOME, 'skills')
export const SKILLS_SUBDIR = 'skills'

export const NOVACLAW_WORKSPACE_DIR = join(NOVACLAW_HOME, 'workspace')
export const NOVACLAW_MEMORY_DIR = join(NOVACLAW_HOME, 'memory')
export const NOVACLAW_CACHE_DIR = join(NOVACLAW_HOME, 'cache')
export const NOVACLAW_EXTENSIONS_DIR = join(NOVACLAW_HOME, 'extensions')

// ── Runtime files ───────────────────────────────────────────────────────

export const NOVACLAW_KEYFILE_PATH = join(NOVACLAW_HOME, '.keyfile')
export const NOVACLAW_AUTH_TOKEN_PATH = join(NOVACLAW_HOME, '.auth-token')
export const NOVACLAW_PID_PATH = join(NOVACLAW_HOME, '.pid')
