import type {AgentResponse} from '../apis/index.ts'
import {t} from '../../i18n/index.ts'
import type {ExecutorParams} from './types.ts'

interface ApiErrorLike {
    isAuth?: boolean
    isRateLimit?: boolean
    isModelNotFound?: boolean
    isBadRequest?: boolean
    retryAfterSeconds?: number | null
    provider?: string
}

export type ExecutionDecision =
    | { action: 'respond'; response: AgentResponse }
    | { action: 'retrySameModel' }
    | { action: 'retryAfterFallback'; fallbackMessage: string }

export interface ExecutionPolicyContext {
    getActiveModelName(): string
    createErrorResponse(userMessage: string): AgentResponse
    onChunk: ExecutorParams['onChunk']
}

export interface IExecutionPolicy {
    handle(
        error: unknown,
        params: ExecutorParams,
        startTime: number,
        ctx: ExecutionPolicyContext
    ): Promise<ExecutionDecision>
}

export class DefaultExecutionPolicy implements IExecutionPolicy {
    constructor(private logger: {
        warn: (msg: string, meta?: unknown) => void;
        error: (msg: string, meta?: unknown) => void
    }) {
    }

    async handle(
        error: unknown,
        params: ExecutorParams,
        _startTime: number,
        ctx: ExecutionPolicyContext
    ): Promise<ExecutionDecision> {
        const err = error as Error
        const apiErr: ApiErrorLike | null = error !== null && typeof error === 'object' && 'isAuth' in error ? (error as ApiErrorLike) : null
        const isAbort = params.abortSignal?.aborted || err.name === 'AbortError'

        if (isAbort || apiErr?.isAuth) {
            const userMsg = isAbort ? t('policy.request_cancelled') : t('policy.auth_failed')
            this.logger.error('Non-retriable error', {abort: isAbort, auth: apiErr?.isAuth})
            return {action: 'respond', response: ctx.createErrorResponse(userMsg)}
        }

        if (apiErr?.isRateLimit) {
            const waitSec = apiErr.retryAfterSeconds ?? 15
            this.logger.warn(`Rate limited (429), waiting ${waitSec}s`, {provider: apiErr.provider})
            params.onChunk({type: 'error', error: t('policy.rate_limited', waitSec)})
            await new Promise<void>((resolve) => {
                const timer = setTimeout(resolve, waitSec * 1000)
                params.abortSignal?.addEventListener('abort', () => {
                    clearTimeout(timer)
                    resolve()
                }, { once: true })
            })
            if (params.abortSignal?.aborted) {
                return {action: 'respond', response: ctx.createErrorResponse(t('policy.request_cancelled'))}
            }
            return {action: 'retrySameModel'}
        }

        if (apiErr?.isBadRequest) {
            this.logger.error('422 Bad Request, no fallback', {
                model: ctx.getActiveModelName(),
                error: err.message,
            })
            return {
                action: 'respond',
                response: ctx.createErrorResponse(t('policy.bad_request'))
            }
        }

        if (apiErr?.isModelNotFound) {
            this.logger.warn('Model not found, trying fallback', {model: ctx.getActiveModelName()})
            return {action: 'retryAfterFallback', fallbackMessage: t('policy.no_fallback')}
        }

        this.logger.warn('Stream error, attempting fallback', {error: err.message})
        params.onChunk({type: 'error', error: t('policy.switching_fallback')})
        return {action: 'retryAfterFallback', fallbackMessage: t('agent.all_models_unavailable')}
    }
}
