/**
 * Director meta-tools — delegate_task and parallel_tasks for the Director agent
 * to delegate work to worker agents.
 */

import type { StreamChunk } from '../../apis/common.ts'
import type { SessionContext, Tool, ToolExecutionResult } from '../../apis/tool.ts'
import type { AgentPool } from './agent-pool.ts'
import type { ParallelTaskItem } from './types.ts'
import { Logger } from '../../../utils/logger.ts'

const DEFAULT_SESSION_KEY = 'director-delegate'
const DEFAULT_WORKSPACE = '.'
const DEFAULT_USER_ID = 'director'
const DEFAULT_CHANNEL = 'internal'

function buildWorkerContext(
    sessionContext?: SessionContext | null,
    overrides?: Record<string, unknown> | null,
): { sessionKey: string; workspaceDir: string; userId: string; channel: string; messageHistory?: Array<{ role: 'user' | 'assistant'; content: string }> } {
    const base = (sessionContext ?? {}) as Partial<SessionContext>
    const extra = overrides ?? {}
    return {
        sessionKey: (extra.sessionKey as string) ?? base.sessionKey ?? DEFAULT_SESSION_KEY,
        workspaceDir: (extra.workspaceDir as string) ?? base.workspaceDir ?? DEFAULT_WORKSPACE,
        userId: (extra.userId as string) ?? base.userId ?? DEFAULT_USER_ID,
        channel: (extra.channel as string) ?? base.channel ?? DEFAULT_CHANNEL,
        messageHistory: (extra.messageHistory as Array<{ role: 'user' | 'assistant'; content: string }>) ?? base.messageHistory,
    }
}

/**
 * Creates the Director meta-tools (delegate_task, parallel_tasks) that delegate
 * work to worker agents via the given pool.
 */
export function createDirectorTools(
    pool: AgentPool,
    onChunk: (chunk: StreamChunk) => void,
): Tool[] {
    const logger = new Logger('DirectorTools', 'info')

    const delegateTask: Tool = {
        name: 'delegate_task',
        description: 'Delegate a task to a specialized worker agent',
        parameters: {
            type: 'object',
            properties: {
                agent: { type: 'string', description: 'ID of the worker agent to delegate to' },
                task: { type: 'string', description: 'The task description for the worker' },
                context: {
                    type: 'object',
                    description: 'Optional context (sessionKey, workspaceDir, userId, channel, skillHints, etc.)',
                    properties: {
                        sessionKey: { type: 'string' },
                        workspaceDir: { type: 'string' },
                        userId: { type: 'string' },
                        channel: { type: 'string' },
                        skillHints: { type: 'array', items: { type: 'string' } },
                    },
                },
            },
            required: ['agent', 'task'],
        },
        async execute(
            args: Record<string, unknown>,
            context?: SessionContext,
            abortSignal?: AbortSignal,
        ): Promise<ToolExecutionResult> {
            try {
                const agent = args.agent as string | undefined
                const task = args.task as string | undefined
                const argsContext = args.context as Record<string, unknown> | undefined

                if (!agent || typeof agent !== 'string') {
                    return { success: false, error: 'Missing or invalid required parameter: agent' }
                }
                if (!task || typeof task !== 'string') {
                    return { success: false, error: 'Missing or invalid required parameter: task' }
                }

                const worker = await pool.getOrCreate(agent)
                if (!worker) {
                    return { success: false, error: `Worker agent not found or disabled: ${agent}` }
                }

                const workerContext = buildWorkerContext(context, argsContext)
                const result = await worker.execute({
                    task,
                    context: workerContext,
                    skillHints: argsContext && Array.isArray(argsContext.skillHints)
                        ? (argsContext.skillHints as string[])
                        : undefined,
                    onChunk: (chunk) => onChunk(chunk),
                    abortSignal,
                })

                return {
                    success: true,
                    content: result.content,
                    toolCalls: result.toolCalls,
                    usage: result.usage,
                    error: result.error,
                }
            } catch (err) {
                const msg = err instanceof Error ? err.message : String(err)
                logger.error('delegate_task failed', err)
                return { success: false, error: msg }
            }
        },
    }

    const parallelTasks: Tool = {
        name: 'parallel_tasks',
        description: 'Execute multiple tasks in parallel across different worker agents',
        parameters: {
            type: 'object',
            properties: {
                tasks: {
                    type: 'array',
                    description: 'Array of tasks to execute in parallel',
                    items: {
                        type: 'object',
                        properties: {
                            id: { type: 'string', description: 'Unique identifier for this task result' },
                            agent: { type: 'string', description: 'ID of the worker agent' },
                            task: { type: 'string', description: 'Task description' },
                            context: {
                                type: 'object',
                                description: 'Optional context overrides for this task',
                            },
                        },
                        required: ['id', 'agent', 'task'],
                    },
                },
            },
            required: ['tasks'],
        },
        async execute(
            args: Record<string, unknown>,
            context?: SessionContext,
            abortSignal?: AbortSignal,
        ): Promise<ToolExecutionResult> {
            try {
                const tasks = args.tasks as ParallelTaskItem[] | undefined

                if (!Array.isArray(tasks) || tasks.length === 0) {
                    return { success: false, error: 'Missing or invalid required parameter: tasks (must be non-empty array)' }
                }

                const promises = tasks.map(async (item: ParallelTaskItem) => {
                    const { id, agent, task, context: taskContext } = item
                    const worker = await pool.getOrCreate(agent)

                    if (!worker) {
                        return {
                            id,
                            agentId: agent,
                            content: '',
                            error: `Worker agent not found or disabled: ${agent}`,
                        }
                    }

                    try {
                        const workerContext = buildWorkerContext(context, taskContext)
                        const result = await worker.execute({
                            task,
                            context: workerContext,
                            skillHints: taskContext && typeof taskContext === 'object' && Array.isArray((taskContext as Record<string, unknown>).skillHints)
                                ? ((taskContext as Record<string, unknown>).skillHints as string[])
                                : undefined,
                            onChunk: (chunk) => onChunk(chunk),
                            abortSignal,
                        })
                        return {
                            id,
                            agentId: result.agentId,
                            content: result.content,
                            error: result.error,
                        }
                    } catch (err) {
                        const msg = err instanceof Error ? err.message : String(err)
                        logger.error(`parallel_tasks item ${id} (${agent}) failed`, err)
                        return { id, agentId: agent, content: '', error: msg }
                    }
                })

                const settled = await Promise.allSettled(promises)
                const results = settled.map((p) =>
                    p.status === 'fulfilled' ? p.value : { id: 'unknown', agentId: 'unknown', content: '', error: String(p.reason) },
                )

                return { success: true, results }
            } catch (err) {
                const msg = err instanceof Error ? err.message : String(err)
                logger.error('parallel_tasks failed', err)
                return { success: false, error: msg }
            }
        },
    }

    return [delegateTask, parallelTasks]
}
