/**
 * ChannelExtensionLoader — orchestrates extension discovery and loading.
 *
 * 1. Discovers extensions from configured directories
 * 2. Tries native loading (standard ChannelPlugin export)
 * 3. Falls back to registered ExtensionAdapters for non-standard formats
 *
 * Ships with the OpenClawAdapter registered by default.
 */

import { pathToFileURL } from 'node:url'
import type { ILogger } from '../../../utils/logger.ts'
import type { NovaClawConfig } from '../../apis/config.ts'
import type { ChannelPlugin } from '../types/plugin.ts'
import type { PluginChannelRuntime } from '../types/context.ts'
import type { DiscoveredExtension, ExtensionAdapter, ExtensionLoadContext } from './types.ts'
import { discoverExtensions } from './discovery.ts'
import { OpenClawAdapter } from './adapters/openclaw-adapter.ts'

export interface ChannelExtensionLoaderOptions {
    extensionDirs?: string[]
    adapters?: ExtensionAdapter[]
    logger: ILogger
}

export class ChannelExtensionLoader {
    private extensions: DiscoveredExtension[] = []
    private adapters: ExtensionAdapter[]
    private logger: ILogger
    private extensionDirs?: string[]

    constructor(options: ChannelExtensionLoaderOptions) {
        this.logger = options.logger
        this.extensionDirs = options.extensionDirs
        this.adapters = options.adapters ?? [new OpenClawAdapter()]
    }

    /**
     * Run discovery and cache results. Safe to call multiple times;
     * re-scans the directories each time.
     */
    discover(): DiscoveredExtension[] {
        this.extensions = discoverExtensions(this.extensionDirs)
        if (this.extensions.length > 0) {
            this.logger.info(`ExtensionLoader: discovered ${this.extensions.length} extension(s)`)
        }
        return this.extensions
    }

    getDiscoveredExtensions(): DiscoveredExtension[] {
        return this.extensions
    }

    findExtension(channelId: string): DiscoveredExtension | undefined {
        return this.extensions.find(e => e.id === channelId)
    }

    registerAdapter(adapter: ExtensionAdapter): void {
        if (!this.adapters.some(a => a.id === adapter.id)) {
            this.adapters.push(adapter)
        }
    }

    /**
     * Load a single extension as a ChannelPlugin.
     * Tries native import first, then falls back to registered adapters.
     */
    async loadExtension(
        ext: DiscoveredExtension,
        config: NovaClawConfig,
        channelRuntime?: PluginChannelRuntime,
    ): Promise<ChannelPlugin | null> {
        if (!ext.entryPath) {
            this.logger.debug(`ExtensionLoader: '${ext.id}' has no entry path, skipping`)
            return null
        }

        const nativePlugin = await this.tryNativeLoad(ext)
        if (nativePlugin) return nativePlugin

        const ctx: ExtensionLoadContext = {
            config,
            logger: this.logger,
            channelRuntime,
        }

        for (const adapter of this.adapters) {
            if (!adapter.canHandle(ext)) continue
            const plugin = await adapter.load(ext, ctx)
            if (plugin) return plugin
        }

        this.logger.debug(`ExtensionLoader: no adapter could load '${ext.id}'`)
        return null
    }

    /**
     * Try importing the extension natively — checks for a standard
     * ChannelPlugin export (default, named, or createPlugin factory).
     */
    private async tryNativeLoad(ext: DiscoveredExtension): Promise<ChannelPlugin | null> {
        if (!ext.entryPath) return null

        try {
            const fileUrl = pathToFileURL(ext.entryPath)
            fileUrl.searchParams.set('t', String(Date.now()))
            const mod = await import(fileUrl.href) as Record<string, unknown>

            if (isChannelPlugin(mod.default)) {
                this.logger.info(`ExtensionLoader: native load '${ext.id}' (default export)`)
                return mod.default as ChannelPlugin
            }

            if (typeof mod.createPlugin === 'function') {
                const plugin = (mod.createPlugin as (cfg: unknown) => ChannelPlugin)({})
                if (isChannelPlugin(plugin)) {
                    this.logger.info(`ExtensionLoader: native load '${ext.id}' (createPlugin)`)
                    return plugin
                }
            }

            for (const [key, value] of Object.entries(mod)) {
                if (key === 'default') continue
                if (isChannelPlugin(value)) {
                    this.logger.info(`ExtensionLoader: native load '${ext.id}' (named export '${key}')`)
                    return value as ChannelPlugin
                }
            }
        } catch {
            // Native import failed — fall through to adapters
        }

        return null
    }
}

function isChannelPlugin(value: unknown): value is ChannelPlugin {
    return (
        typeof value === 'object' &&
        value !== null &&
        'id' in value &&
        'meta' in value &&
        'capabilities' in value &&
        'config' in value
    )
}
