/**
 * Document indexer for local RAG. Framework-only.
 */

import {createHash} from 'node:crypto'
import {readdir, readFile, stat} from 'node:fs/promises'
import {join} from 'node:path'
import { toErrorMessage } from '../../../constants/errors.ts'
import type {ConversationRecord} from '../apis/memory.ts'
import {Logger} from '../../utils/logger.ts'
import type {Chunk, LocalDocumentIndex, LocalMemoryConfig, TreeNode} from './types.ts'

const INDEXABLE_EXTENSIONS = new Set([
    '.md', '.txt', '.ts', '', '.py', '.json', '.yaml', '.yml',
    '.tsx', '.jsx', '.css', '.html', '.sh', '.bash', '.go', '.rs',
    '.java', '.c', '.cpp', '.h', '.rb', '.php', '.sql', '.toml'
])
const MB = 1024 * 1024
const HEADING_RE = /^(#{1,4})\s+(.+)/
const FUNC_RE = /^(?:export\s+)?(?:async\s+)?(?:function|class|interface|type|const|def |public |private |protected )\s+(\w+)/
const CONV_RE = /^\[(?:user|assistant)\]:/i

export class DocumentIndexer {
    private logger: Logger
    private chunkSize: number
    private chunkOverlap: number

    constructor(
        config: Record<string, unknown>,
        private memoryConfig: LocalMemoryConfig
    ) {
        const logLevel = (config.logging as Record<string, unknown>)?.level as string | undefined
        this.logger = new Logger('MemoryIndexer', logLevel ?? 'info')
        this.chunkSize = memoryConfig.chunkSize ?? 512
        this.chunkOverlap = memoryConfig.chunkOverlap ?? 64
    }

    async indexConversation(conversation: ConversationRecord): Promise<LocalDocumentIndex | null> {
        if (conversation.messages.length === 0) {
            this.logger.debug('[Indexer:conv] Empty conversation, skipping', {id: conversation.id})
            return null
        }
        const content = conversation.messages.map(m => `[${m.role}]: ${m.content}`).join('\n\n')
        const hash = this.hashContent(content)
        const title = conversation.title
        const docId = `conv-${conversation.id}`
        const chunks = this.chunkDocument(content, docId, title, conversation.id)
        const tree = this.buildStructureTree(content, title)
        return {
            documentId: docId,
            source: 'conversation',
            filePath: conversation.id,
            title,
            tree,
            chunks,
            indexedAt: Date.now(),
            contentHash: hash
        }
    }

    async indexFile(filePath: string, source: 'workspace' | 'upload'): Promise<LocalDocumentIndex | null> {
        try {
            const fileStat = await stat(filePath)
            if (fileStat.size > this.memoryConfig.maxDocumentSizeMB * MB) {
                this.logger.warn('[Indexer:file] File too large, skipping', {
                    filePath,
                    sizeMB: (fileStat.size / MB).toFixed(1)
                })
                return null
            }
            const content = await readFile(filePath, 'utf-8')
            if (!content.trim()) {
                this.logger.debug('[Indexer:file] Empty file, skipping', {filePath})
                return null
            }
            const hash = this.hashContent(content)
            const title = filePath.split('/').pop() ?? filePath
            const docId = `${source}-${hash.slice(0, 12)}`
            const chunks = this.chunkDocument(content, docId, title, filePath)
            const tree = this.buildStructureTree(content, title)
            return {
                documentId: docId,
                source,
                filePath,
                title,
                tree,
                chunks,
                indexedAt: Date.now(),
                contentHash: hash
            }
        } catch (err) {
            this.logger.warn('Failed to index file', {filePath, error: toErrorMessage(err)})
            return null
        }
    }

    async scanWorkspaceFiles(workspaceDir: string): Promise<string[]> {
        const files: string[] = []
        await this.walkDir(workspaceDir, files, 0)
        return files
    }

    chunkDocument(content: string, docId: string, title: string, sourcePath: string): Chunk[] {
        const lines = content.split('\n')
        const headingMap = this.buildHeadingMap(lines)
        const chunks: Chunk[] = []
        let currentLines: string[] = []
        let currentTokenCount = 0
        let chunkStartLine = 0
        let chunkIdx = 0
        for (let lineIdx = 0; lineIdx < lines.length; lineIdx++) {
            const line = lines[lineIdx]!
            const lineTokens = this.estimateTokens(line)
            if (currentTokenCount + lineTokens > this.chunkSize && currentLines.length > 0) {
                chunks.push(this.makeChunk(docId, chunkIdx, currentLines, chunkStartLine, headingMap.get(chunkStartLine) ?? title, sourcePath))
                chunkIdx++
                const {keptLines, keptTokens} = this.computeOverlap(currentLines)
                currentLines = keptLines
                currentTokenCount = keptTokens
                chunkStartLine = lineIdx - keptLines.length
            }
            currentLines.push(line)
            currentTokenCount += lineTokens
        }
        if (currentLines.length > 0) {
            chunks.push(this.makeChunk(docId, chunkIdx, currentLines, chunkStartLine, headingMap.get(chunkStartLine) ?? title, sourcePath))
            chunkIdx++
        }
        for (const chunk of chunks) chunk.siblingCount = chunkIdx
        return chunks
    }

    hashContent(content: string): string {
        return createHash('sha256').update(content).digest('hex')
    }

    private static readonly MAX_WALK_DEPTH = 6
    private static readonly SKIP_DIRS = new Set([
        'node_modules', '.git', '.svn', 'dist', 'build', '.next',
        '.cache', '.turbo', '__pycache__', '.venv', 'venv',
        'coverage', '.nyc_output', '.novaclaw'
    ])

    private async walkDir(dir: string, results: string[], depth: number): Promise<void> {
        if (depth > DocumentIndexer.MAX_WALK_DEPTH) return
        try {
            const entries = await readdir(dir, {withFileTypes: true})
            for (const entry of entries) {
                if (entry.name.startsWith('.') && depth > 0) continue
                const full = join(dir, entry.name)
                if (entry.isDirectory()) {
                    if (!DocumentIndexer.SKIP_DIRS.has(entry.name)) await this.walkDir(full, results, depth + 1)
                } else if (entry.isFile()) {
                    const ext = entry.name.includes('.') ? '.' + entry.name.split('.').pop()!.toLowerCase() : ''
                    if (INDEXABLE_EXTENSIONS.has(ext)) results.push(full)
                }
            }
        } catch (err) {
            const e = err as NodeJS.ErrnoException
            if (e.code !== 'ENOENT' && e.code !== 'EACCES') {
                this.logger.warn('Failed to walk directory', {dir, error: toErrorMessage(err)})
            }
        }
    }

    private buildHeadingMap(lines: string[]): Map<number, string> {
        const map = new Map<number, string>()
        let currentHeading = ''
        for (let i = 0; i < lines.length; i++) {
            const line = lines[i]!.trim()
            const hm = HEADING_RE.exec(line)
            const fm = FUNC_RE.exec(line)
            const cm = CONV_RE.test(line)
            if (hm) currentHeading = hm[2]!
            else if (fm) currentHeading = fm[1]!
            else if (cm) currentHeading = line.slice(0, 60)
            map.set(i, currentHeading)
        }
        return map
    }

    private makeChunk(docId: string, idx: number, lines: string[], startLine: number, heading: string, sourcePath: string): Chunk {
        const text = lines.join('\n')
        return {
            chunkId: `${docId}#${idx}`,
            documentId: docId,
            text,
            startLine,
            endLine: startLine + lines.length - 1,
            tokenCount: this.estimateTokens(text),
            heading,
            sourcePath,
            index: idx,
            siblingCount: 0
        }
    }

    private computeOverlap(lines: string[]): { keptLines: string[]; keptTokens: number } {
        const kept: string[] = []
        let tokens = 0
        for (let i = lines.length - 1; i >= 0; i--) {
            const lt = this.estimateTokens(lines[i]!)
            if (tokens + lt > this.chunkOverlap) break
            kept.unshift(lines[i]!)
            tokens += lt
        }
        return {keptLines: kept, keptTokens: tokens}
    }

    private estimateTokens(text: string): number {
        const cjkCount = (text.match(/[\u4e00-\u9fff\u3400-\u4dbf]/g) || []).length
        const nonCjk = text.length - cjkCount
        return Math.ceil(nonCjk / 4 + cjkCount / 1.5)
    }

    private buildStructureTree(content: string, title: string): TreeNode {
        const lines = content.split('\n')
        const sections = this.detectSections(lines)
        if (sections.length === 0) {
            return {
                id: 'root',
                title,
                summary: `Document with ${lines.length} lines`,
                sourceRange: {start: 0, end: lines.length - 1},
                children: []
            }
        }
        return {
            id: 'root',
            title,
            summary: `Document with ${sections.length} sections`,
            sourceRange: {start: 0, end: lines.length - 1},
            children: sections.map((s, i) => ({
                id: `s${i}`,
                title: s.title,
                summary: s.preview,
                children: [],
                sourceRange: {start: s.startLine, end: s.endLine}
            }))
        }
    }

    private detectSections(lines: string[]): Array<{
        title: string;
        startLine: number;
        endLine: number;
        preview: string
    }> {
        const sections: Array<{ title: string; startLine: number; endLine: number; preview: string }> = []
        let currentStart = 0
        let currentTitle = ''
        const flush = (endLine: number) => {
            if (endLine < currentStart) return
            const block = lines.slice(currentStart, endLine + 1).join('\n').trim()
            if (block) sections.push({
                title: currentTitle || block.slice(0, 60),
                startLine: currentStart,
                endLine,
                preview: block.slice(0, 200)
            })
        }
        for (let i = 0; i < lines.length; i++) {
            const line = lines[i]!
            const headingMatch = HEADING_RE.exec(line)
            const funcMatch = FUNC_RE.exec(line.trim())
            const convMatch = CONV_RE.test(line.trim())
            if ((headingMatch || funcMatch || convMatch) && i > currentStart) {
                flush(i - 1)
                currentStart = i
                currentTitle = headingMatch?.[2] ?? funcMatch?.[1] ?? line.trim().slice(0, 60)
            }
        }
        flush(lines.length - 1)
        return sections
    }
}
