/**
 * WorkerRuntime — lightweight agent runtime for specialized worker agents.
 * Reuses AgentExecutor for the ReAct loop but with scoped tools and a
 * simplified prompt.
 */

import type { ProviderRegistry } from '../../../registries/provider-registry.ts'
import type { RuleRegistry } from '../../../registries/rule-registry.ts'
import type { ToolProviderRegistry } from '../../../registries/tool-provider-registry.ts'
import { Logger } from '../../../utils/logger.ts'
import type { NovaClawConfig, StreamChunk } from '../../apis/index.ts'
import type { SkillsEngine } from '../../skills/skills-engine.ts'
import { AgentExecutor } from '../agent-executor.ts'
import { ModelManager } from '../model/model-manager.ts'
import { toolsToOpenAISchema } from '../tool/tool-schema.ts'
import { ToolRegistry } from '../tool/tool-registry.ts'
import type { WorkerAgentConfig, WorkerExecuteParams, WorkerResult } from './types.ts'
import { WorkerPromptBuilder } from './worker-prompt.ts'

export interface WorkerRuntimeOptions {
    providerRegistry?: ProviderRegistry | null
    ruleRegistry?: RuleRegistry | null
    toolProviderRegistry?: ToolProviderRegistry | null
    skillsEngine?: SkillsEngine | null
    protocolBridge?: import('../../protocol/protocol-bridge').ProtocolBridge | null
}

export class WorkerRuntime {
    private modelManager: ModelManager
    private toolRegistry: ToolRegistry
    private promptBuilder: WorkerPromptBuilder
    private executor: AgentExecutor
    private logger: Logger
    private initialized = false

    constructor(
        private workerConfig: WorkerAgentConfig,
        novaConfig: NovaClawConfig,
        options: WorkerRuntimeOptions = {},
    ) {
        const logLevel = novaConfig.logging?.level || 'info'
        this.logger = new Logger(`Worker:${workerConfig.id}`, logLevel)

        const configOverride = workerConfig.model
            ? { ...novaConfig, models: { ...novaConfig.models, primary: workerConfig.model } }
            : novaConfig

        this.modelManager = new ModelManager(configOverride, {
            providerRegistry: options.providerRegistry ?? undefined,
        })

        this.toolRegistry = new ToolRegistry(novaConfig, {
            skillsEngine: options.skillsEngine ?? undefined,
            ruleEngine: options.ruleRegistry?.getEngine(),
            toolProviderRegistry: options.toolProviderRegistry ?? undefined,
            protocolBridge: options.protocolBridge ?? undefined,
        })

        this.promptBuilder = new WorkerPromptBuilder(workerConfig)

        this.executor = new AgentExecutor(this.toolRegistry, logLevel, {
            maxTurns: workerConfig.maxTurns,
            toolResultContextMax: novaConfig.agent?.toolResultContextMax ?? 16_000,
        })
    }

    get id(): string {
        return this.workerConfig.id
    }

    get role(): string {
        return this.workerConfig.role
    }

    get config(): WorkerAgentConfig {
        return this.workerConfig
    }

    async initialize(): Promise<void> {
        if (this.initialized) return

        this.logger.info('Initializing...')

        await Promise.all([
            this.modelManager.initialize(),
            this.toolRegistry.initializeForScope({
                builtinTools: this.workerConfig.tools,
                mcpServer: this.workerConfig.mcpServer,
                skills: (this.workerConfig.skillDomains?.length ?? 0) > 0,
            }),
        ])

        this.initialized = true
        this.logger.info('Initialized', {
            tools: this.toolRegistry.getAll().map(t => t.name),
            model: this.modelManager.getActiveModel()?.model,
        })
    }

    async execute(params: WorkerExecuteParams): Promise<WorkerResult> {
        if (!this.initialized) await this.initialize()

        const { task, context, onChunk, abortSignal } = params

        try {
            const session = this.modelManager.createSession()
            const tools = this.toolRegistry.getAll()

            const systemPrompt = this.promptBuilder.build({
                task,
                context,
                tools,
                skills: params.skillHints ? [] : undefined,
                memoryContext: params.memoryContext,
            })
            await session.updateSystemPrompt(systemPrompt)

            const toolSchemas = toolsToOpenAISchema(tools)

            const sessionContext = {
                sessionKey: context.sessionKey,
                sessionId: `worker-${this.workerConfig.id}-${Date.now()}`,
                userId: context.userId,
                channel: context.channel,
                workspaceDir: context.workspaceDir,
                startTime: Date.now(),
                lastActivity: Date.now(),
                metadata: {} as Record<string, unknown>,
                messageHistory: context.messageHistory ?? [],
            }

            const result = await this.executor.execute({
                session,
                message: task,
                tools: toolSchemas,
                executor: {
                    message: task,
                    context: sessionContext,
                    skills: [],
                    onChunk: (chunk: StreamChunk) => {
                        onChunk({ ...chunk, agentId: this.workerConfig.id })
                    },
                    abortSignal,
                },
            })

            return {
                agentId: this.workerConfig.id,
                content: result.content,
                toolCalls: result.toolCalls,
                usage: result.usage,
                aborted: result.aborted,
            }
        } catch (error) {
            const errorMsg = error instanceof Error ? error.message : String(error)
            this.logger.error('Execution failed', error)
            return {
                agentId: this.workerConfig.id,
                content: '',
                toolCalls: [],
                usage: { totalTokens: 0 },
                error: errorMsg,
            }
        }
    }

    async cleanup(): Promise<void> {
        this.logger.debug('Cleaned up')
        this.initialized = false
    }
}
