/**
 * Default rules — sensitive tool channel allowlist.
 * Framework implementation; uses only framework rule contract.
 */

import type { IRule, RuleContext, RuleVerdict } from '../apis/rule.ts'

const SENSITIVE_TOOLS = new Set(['exec'])
const DEFAULT_ALLOWED_CHANNELS = ['cli']

/**
 * Gate sensitive tools (exec, etc.) by channel.
 * Uses config `allowExecInChannels` as the single source of truth;
 * falls back to ['cli'] when the config key is absent.
 */
export function createExecChannelRule(): IRule {
    return {
        id: 'exec-channel-allowlist',
        name: 'Sensitive tool channel allowlist',
        description: 'Allow sensitive tools only on channels listed in allowExecInChannels (defaults to cli)',
        phase: 'behavior',
        priority: 10,

        evaluate(ctx: RuleContext): RuleVerdict | undefined {
            if (ctx.type !== 'tool' && !ctx.toolName) return undefined
            const toolName = ctx.toolName ?? ctx.name
            if (!toolName || !SENSITIVE_TOOLS.has(toolName)) return undefined

            const channel = ctx.channel ?? ctx.payload?.channel as string | undefined
            if (!channel) return undefined

            const allowList = ctx.payload?.allowExecInChannels as string[] | undefined
            const effectiveList = Array.isArray(allowList) ? allowList : DEFAULT_ALLOWED_CHANNELS

            if (effectiveList.includes('*') || effectiveList.includes(channel)) {
                return { action: 'allow' }
            }
            return { action: 'reject', reason: `${toolName} is not allowed on channel: ${channel}` }
        }
    }
}
