/**
 * OpenAI-compatible LLM provider — default implementation in framework.
 * Uses only framework apis and framework utils.
 */

import type { ChatStreamOptions, LLMProviderConfig, ProviderMessage, StreamingChunk } from '../apis/provider.ts'
import { BaseStreamProvider, type ParsedSSEResult } from './base-stream-provider.ts'
import { extractSystemPrompt } from './message-utils.ts'

export { LLMApiError } from './errors.ts'

export class OpenAICompatibleProvider extends BaseStreamProvider {
    readonly name = 'openai-compatible'

    constructor(providerKey: string, config: LLMProviderConfig) {
        super(providerKey, config)
    }

    // -- Hook implementations -------------------------------------------------

    protected buildStreamUrl(model: string): string {
        void model
        return `${this.config.baseUrl}/v1/chat/completions`
    }

    protected buildCompleteUrl(model: string): string {
        void model
        return `${this.config.baseUrl}/v1/chat/completions`
    }

    protected buildHeaders(): Record<string, string> {
        const headers: Record<string, string> = {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${this.config.apiKey}`,
        }
        const extra = this.config as LLMProviderConfig & { extraHeaders?: Record<string, string> }
        if (extra.extraHeaders) {
            Object.assign(headers, extra.extraHeaders)
        }
        return headers
    }

    protected buildCompleteBody(
        model: string,
        messages: ProviderMessage[],
        maxTokens: number,
    ): Record<string, unknown> {
        const { systemPrompt, nonSystemMessages } = extractSystemPrompt(messages)
        const messagesToSend = systemPrompt
            ? [{ role: 'system', content: systemPrompt }, ...nonSystemMessages]
            : nonSystemMessages
        const extra = this.config as LLMProviderConfig & { defaultTemperature?: number }
        return {
            model,
            messages: messagesToSend,
            stream: false,
            max_tokens: maxTokens,
            temperature: extra.defaultTemperature ?? 0.7,
        }
    }

    protected extractCompleteContent(json: unknown): string | null {
        const data = json as {
            choices?: Array<{ message?: { content?: string; reasoning_content?: string } }>
        }
        const msg = data.choices?.[0]?.message
        const reasoning = msg?.reasoning_content ?? ''
        const content = msg?.content?.trim() ?? ''
        if (!reasoning && !content) return null
        return reasoning ? `<think>${reasoning}</think>\n${content}` : content
    }

    protected buildStreamBody(
        model: string,
        messages: ProviderMessage[],
        options?: ChatStreamOptions,
    ): Record<string, unknown> {
        const { systemPrompt, nonSystemMessages } = extractSystemPrompt(messages)
        const messagesToSend = systemPrompt
            ? [{ role: 'system', content: systemPrompt }, ...nonSystemMessages]
            : nonSystemMessages
        const body: Record<string, unknown> = {
            model,
            messages: messagesToSend,
            stream: true,
            stream_options: { include_usage: true },
            max_tokens: options?.maxTokens ?? 4096,
            temperature: options?.temperature ?? 0.7,
            top_p: options?.topP ?? 1,
            frequency_penalty: options?.frequencyPenalty ?? 0,
            presence_penalty: options?.presencePenalty ?? 0,
        }
        if (options?.stop != null) body.stop = options.stop
        if (options?.responseFormat) body.response_format = options.responseFormat
        if (options?.enableThinking != null) body.enable_thinking = options.enableThinking
        if (options?.tools && options.tools.length > 0) {
            body.tools = options.tools
            body.tool_choice = 'auto'
        }
        return body
    }

    protected parseSSEPayload(json: Record<string, unknown>): ParsedSSEResult {
        const chunks: StreamingChunk[] = []
        const toolCalls: ParsedSSEResult['toolCalls'] = []
        let usage: ParsedSSEResult['usage']
        let finished = false

        const choices = json.choices as Array<Record<string, unknown>> | undefined
        const choice = choices?.[0]
        const delta = choice?.delta as Record<string, unknown> | undefined

        if (typeof delta?.content === 'string' && delta.content) {
            chunks.push({ type: 'content', content: delta.content })
        }

        if (typeof delta?.reasoning_content === 'string' && delta.reasoning_content) {
            chunks.push({ type: 'reasoning', content: delta.reasoning_content as string })
        }

        if (Array.isArray(delta?.tool_calls)) {
            for (const tc of delta.tool_calls as Array<Record<string, unknown>>) {
                const fn = tc.function as Record<string, unknown> | undefined
                toolCalls.push({
                    index: (tc.index as number) ?? 0,
                    id: typeof tc.id === 'string' ? tc.id : undefined,
                    name: fn?.name as string | undefined,
                    argsFragment: fn?.arguments as string | undefined,
                })
            }
        }

        if (typeof json.content === 'string') chunks.push({ type: 'content', content: json.content })
        if (typeof json.text === 'string') chunks.push({ type: 'content', content: json.text })

        const msg = json.message as Record<string, unknown> | undefined
        if (typeof msg?.content === 'string') chunks.push({ type: 'content', content: msg.content })
        if (typeof msg?.reasoning_content === 'string' && msg.reasoning_content) {
            chunks.push({ type: 'reasoning', content: msg.reasoning_content as string })
        }

        const choiceUsage = choice?.usage as Record<string, unknown> | undefined
        if (choiceUsage) {
            const input = (choiceUsage.prompt_tokens as number) ?? 0
            const output = (choiceUsage.completion_tokens as number) ?? 0
            if (input || output) usage = { input, output }
        }

        const topUsage = json.usage as Record<string, unknown> | undefined
        if (topUsage) {
            const input = (topUsage.prompt_tokens as number) ?? 0
            const output = (topUsage.completion_tokens as number) ?? 0
            if (input || output) usage = { input, output }
        }

        const fr = choice?.finish_reason
        if (typeof fr === 'string') finished = true

        return { chunks, toolCalls: toolCalls.length > 0 ? toolCalls : undefined, usage, finished }
    }
}
