/**
 * Background indexer — indexes workspace files and conversations in the
 * background after system initialization.
 *
 * Cancellable via AbortController; non-critical failures are logged as warnings.
 */

import { performance } from 'node:perf_hooks'
import { toErrorMessage } from './constants/errors.ts'
import type { IMemoryProvider, NovaClawConfig } from './framework/index.ts'
import type { Logger } from './utils/index.ts'

export class BackgroundIndexer {
    private abort: AbortController | null = null
    private promise: Promise<void> | null = null

    constructor(
        private readonly memoryEngine: IMemoryProvider,
        private readonly config: NovaClawConfig,
        private readonly logger: Logger,
        private readonly onComplete?: (result: { indexed: number; elapsed: number }) => void,
    ) {}

    start(): void {
        if (!this.memoryEngine.enabled) {
            this.logger.debug('Skipping background indexing (memory disabled)')
            return
        }

        this.logger.info('Starting background indexing...')
        this.abort = new AbortController()
        const signal = this.abort.signal
        const t0 = performance.now()

        this.promise = this.run(signal, t0)
    }

    async cancel(): Promise<void> {
        if (this.abort) {
            this.abort.abort()
            this.logger.info('Cancelled background indexing')
        }
        if (this.promise) {
            await this.promise
        }
    }

    get running(): boolean {
        return this.promise !== null
    }

    private async run(signal: AbortSignal, t0: number): Promise<void> {
        try {
            let totalIndexed = 0

            if (this.config.workspaceDir) {
                if (signal.aborted) return
                const count = await this.memoryEngine.indexWorkspace(this.config.workspaceDir)
                totalIndexed += count
                this.logger.info('Workspace indexing done', { indexed: count })
            }

            if (signal.aborted) return

            const convList = await this.memoryEngine.listConversations()
            let indexed = 0
            for (const summary of convList) {
                if (signal.aborted) {
                    this.logger.info('Background indexing cancelled')
                    return
                }
                try {
                    const conv = await this.memoryEngine.getConversation(summary.id)
                    if (conv && conv.messages.length > 0) {
                        const ok = await this.memoryEngine.indexConversation(conv)
                        if (ok) indexed++
                    }
                } catch (err) {
                    this.logger.debug('Skipping corrupt conversation', {
                        id: summary.id,
                        error: toErrorMessage(err),
                    })
                }
            }
            totalIndexed += indexed
            if (indexed > 0) {
                this.logger.info('Conversation indexing done', {
                    indexed,
                    total: convList.length,
                })
            }

            const elapsed = performance.now() - t0
            this.logger.info('Background indexing complete', this.memoryEngine.getStats())
            this.onComplete?.({ indexed: totalIndexed, elapsed })
        } catch (err) {
            if (signal.aborted) return
            this.logger.warn('Background indexing failed (non-critical)', err)
        } finally {
            this.abort = null
            this.promise = null
        }
    }
}
