/**
 * Allowlist — whitelist logic for channel access control.
 * First line of defense: determines who can interact with the bot.
 */

import type { ChannelSecurityDmPolicy } from './types/adapters.ts'

// --- AllowFromSources (from allow-from) ---

export interface AllowFromSources {
    allowFrom?: Array<string | number>
    storeAllowFrom?: Array<string | number>
    dmPolicy?: ChannelSecurityDmPolicy
}

export function mergeDmAllowFromSources(sources: AllowFromSources): Array<string | number> {
    const { allowFrom = [], storeAllowFrom = [], dmPolicy } = sources

    if (dmPolicy?.policy === 'allowlist') {
        return [...allowFrom]
    }

    const merged = new Set<string | number>()
    for (const entry of allowFrom) merged.add(entry)
    for (const entry of storeAllowFrom) merged.add(entry)
    return Array.from(merged)
}

// --- AllowlistMatch (from allowlist-match) ---

export interface AllowlistMatchParams {
    allowFrom: Array<string | number>
    senderId: string
    senderName?: string
    allowNameMatching?: boolean
}

export type AllowlistMatchResult =
    | { allowed: true; matchedBy: 'wildcard' | 'id' | 'name' }
    | { allowed: false }

export function resolveAllowlistMatch(params: AllowlistMatchParams): AllowlistMatchResult {
    const { allowFrom, senderId, senderName, allowNameMatching = false } = params

    if (allowFrom.length === 0) {
        return { allowed: true, matchedBy: 'wildcard' }
    }

    for (const entry of allowFrom) {
        const normalized = String(entry).trim()

        if (normalized === '*') {
            return { allowed: true, matchedBy: 'wildcard' }
        }

        if (normalized === senderId) {
            return { allowed: true, matchedBy: 'id' }
        }

        if (
            allowNameMatching &&
            senderName &&
            normalized.toLowerCase() === senderName.toLowerCase()
        ) {
            return { allowed: true, matchedBy: 'name' }
        }
    }

    return { allowed: false }
}

/** Thin wrapper around resolveAllowlistMatch for boolean result. */
export function isAllowedSender(params: AllowlistMatchParams): boolean {
    return resolveAllowlistMatch(params).allowed
}

// --- Formatting / normalization helpers (from allowlist-match) ---

export function formatAllowlistEntry(entry: string | number): string {
    return String(entry).trim()
}

export function normalizeAllowlist(entries: Array<string | number>): string[] {
    return entries.map(formatAllowlistEntry).filter(e => e.length > 0)
}

// --- Add/remove helpers (from allow-from) ---

export function addToAllowFrom(
    current: Array<string | number>,
    newEntry: string | number,
): Array<string | number> {
    const normalized = String(newEntry).trim()
    if (current.some(e => String(e).trim() === normalized)) return current
    return [...current, newEntry]
}

export function removeFromAllowFrom(
    current: Array<string | number>,
    entry: string | number,
): Array<string | number> {
    const normalized = String(entry).trim()
    return current.filter(e => String(e).trim() !== normalized)
}
