/**
 * AgentPool — manages lifecycle of worker agent instances.
 * Lazy instantiation with LRU eviction of idle workers.
 */

import { Logger } from '../../../utils/logger.ts'
import type { NovaClawConfig } from '../../apis/index.ts'
import type { ProviderRegistry } from '../../../registries/provider-registry.ts'
import type { RuleRegistry } from '../../../registries/rule-registry.ts'
import type { ToolProviderRegistry } from '../../../registries/tool-provider-registry.ts'
import type { ProtocolBridge } from '../../protocol/protocol-bridge.ts'
import type { SkillsEngine } from '../../skills/skills-engine.ts'
import type { AgentCatalogEntry, AgentPoolConfig, WorkerAgentConfig, WorkerOverrideConfig } from './types.ts'
import { WorkerRuntime, type WorkerRuntimeOptions } from './worker-runtime.ts'
import { WORKER_CONFIGS, mergeWorkerOverride } from './worker-configs.ts'

interface PoolEntry {
    runtime: WorkerRuntime
    lastUsedAt: number
}

const DEFAULT_POOL_CONFIG: AgentPoolConfig = {
    maxIdleTime: 300_000,
    maxConcurrent: 5,
}

export class AgentPool {
    private pool = new Map<string, PoolEntry>()
    private config: AgentPoolConfig
    private cleanupTimer: ReturnType<typeof setInterval> | null = null
    private logger: Logger
    private protocolBridge: ProtocolBridge | null = null

    constructor(
        private novaConfig: NovaClawConfig,
        private runtimeOptions: WorkerRuntimeOptions,
        poolConfig?: Partial<AgentPoolConfig>,
        private workerOverrides?: Record<string, WorkerOverrideConfig>,
    ) {
        this.config = { ...DEFAULT_POOL_CONFIG, ...poolConfig }
        this.logger = new Logger('AgentPool', novaConfig.logging?.level || 'info')
    }

    setProtocolBridge(bridge: ProtocolBridge | null): void {
        this.protocolBridge = bridge
    }

    /**
     * Get or create a worker runtime by agent ID.
     * Returns undefined if the agent ID is not recognized or disabled.
     */
    async getOrCreate(agentId: string): Promise<WorkerRuntime | undefined> {
        const existing = this.pool.get(agentId)
        if (existing) {
            existing.lastUsedAt = Date.now()
            return existing.runtime
        }

        if (this.pool.size >= this.config.maxConcurrent) {
            this.evictOldest()
        }

        const workerConfig = this.resolveWorkerConfig(agentId)
        if (!workerConfig) {
            this.logger.warn(`Unknown agent: ${agentId}`)
            return undefined
        }

        const override = this.workerOverrides?.[agentId]
        if (override?.enabled === false) {
            this.logger.debug(`Skipped disabled worker: ${agentId}`)
            return undefined
        }

        const runtime = new WorkerRuntime(workerConfig, this.novaConfig, {
            ...this.runtimeOptions,
            protocolBridge: this.protocolBridge,
        })
        await runtime.initialize()

        this.pool.set(agentId, { runtime, lastUsedAt: Date.now() })
        this.logger.info(`Worker created: ${agentId} (pool: ${this.pool.size})`)
        return runtime
    }

    /**
     * Get the catalog of available agents for the Director prompt.
     */
    getCatalog(): AgentCatalogEntry[] {
        const entries: AgentCatalogEntry[] = []

        for (const [id, config] of Object.entries(WORKER_CONFIGS)) {
            const override = this.workerOverrides?.[id]
            if (override?.enabled === false) continue

            const merged = override
                ? mergeWorkerOverride(config, override)
                : config

            entries.push({
                id: merged.id,
                role: merged.role,
                tools: merged.tools,
                description: merged.systemPromptTemplate.split('\n')[0] ?? merged.role,
            })
        }

        return entries
    }

    /**
     * Get all active worker IDs.
     */
    getActiveWorkerIds(): string[] {
        return Array.from(this.pool.keys())
    }

    /**
     * Dispose all idle workers and stop the cleanup timer.
     */
    async cleanup(): Promise<void> {
        if (this.cleanupTimer) {
            clearInterval(this.cleanupTimer)
            this.cleanupTimer = null
        }

        const cleanupPromises = Array.from(this.pool.values()).map(e => e.runtime.cleanup())
        await Promise.allSettled(cleanupPromises)
        this.pool.clear()
        this.logger.debug('Cleaned up')
    }

    /**
     * Start periodic cleanup of idle workers.
     */
    startPeriodicCleanup(): void {
        if (this.cleanupTimer) return
        const interval = Math.max(this.config.maxIdleTime / 2, 30_000)
        this.cleanupTimer = setInterval(() => this.evictIdle(), interval)
    }

    get size(): number {
        return this.pool.size
    }

    private resolveWorkerConfig(agentId: string): WorkerAgentConfig | undefined {
        const base = WORKER_CONFIGS[agentId]
        if (!base) return undefined

        const override = this.workerOverrides?.[agentId]
        if (!override) return base

        return mergeWorkerOverride(base, override)
    }

    private evictOldest(): void {
        let oldest: string | null = null
        let oldestTime = Infinity

        for (const [id, entry] of this.pool) {
            if (entry.lastUsedAt < oldestTime) {
                oldestTime = entry.lastUsedAt
                oldest = id
            }
        }

        if (oldest) {
            const entry = this.pool.get(oldest)
            entry?.runtime.cleanup().catch(() => {})
            this.pool.delete(oldest)
            this.logger.debug(`Evicted worker: ${oldest} (LRU)`)
        }
    }

    private evictIdle(): void {
        const now = Date.now()
        for (const [id, entry] of this.pool) {
            if (now - entry.lastUsedAt > this.config.maxIdleTime) {
                entry.runtime.cleanup().catch(() => {})
                this.pool.delete(id)
                this.logger.debug(`Evicted worker: ${id} (idle)`)
            }
        }
    }
}

export interface AgentPoolOptions {
    novaConfig: NovaClawConfig
    providerRegistry?: ProviderRegistry | null
    ruleRegistry?: RuleRegistry | null
    toolProviderRegistry?: ToolProviderRegistry | null
    skillsEngine?: SkillsEngine | null
    poolConfig?: Partial<AgentPoolConfig>
    workerOverrides?: Record<string, WorkerOverrideConfig>
}

export function createAgentPool(options: AgentPoolOptions): AgentPool {
    return new AgentPool(
        options.novaConfig,
        {
            providerRegistry: options.providerRegistry,
            ruleRegistry: options.ruleRegistry,
            toolProviderRegistry: options.toolProviderRegistry,
            skillsEngine: options.skillsEngine,
        },
        options.poolConfig,
        options.workerOverrides,
    )
}
