import type { SessionContext } from '../apis/common.ts'
import type { ISkillProvider, SkillDefinition } from '../apis/skill.ts'
import type { Tool, ToolExecutionResult } from '../apis/tool.ts'

function minimalContext(): SessionContext {
    return {
        sessionKey: '',
        sessionId: '',
        userId: '',
        channel: '',
        workspaceDir: process.cwd(),
        startTime: Date.now(),
        lastActivity: Date.now(),
        metadata: {},
    }
}

/** Compact skill descriptor returned by tools (avoids dumping full content in list views). */
interface SkillEntry {
    name: string
    description: string
    executable: boolean
    runScript?: string
    skillDir?: string
    childSkills?: string[]
}

function toSkillEntry(s: SkillDefinition, includeContent: true): SkillEntry & { content: string }
function toSkillEntry(s: SkillDefinition, includeContent?: false): SkillEntry
function toSkillEntry(s: SkillDefinition, includeContent = false): SkillEntry & { content?: string } {
    const entry: SkillEntry & { content?: string } = {
        name: s.id,
        description: s.description,
        executable: !!s.runScript,
    }
    if (s.runScript) entry.runScript = s.runScript
    if (s.skillDir) entry.skillDir = s.skillDir
    if (s.childSkills?.length) entry.childSkills = s.childSkills
    if (includeContent) entry.content = s.content
    return entry
}

// ── list_skills ──────────────────────────────────────────────────────────

export class ListSkillsTool implements Tool {
    readonly name = 'list_skills'
    readonly description = 'List all available skills with name, description, and whether they are executable. No parameters required.'
    readonly parameters = { type: 'object', properties: {} }

    constructor(private provider: ISkillProvider) {}

    async execute(): Promise<ToolExecutionResult> {
        const all = await this.provider.listSkills()
        return {
            success: true,
            count: all.length,
            skills: all.map(s => toSkillEntry(s)),
        }
    }
}

// ── get_skill ────────────────────────────────────────────────────────────

export class GetSkillTool implements Tool {
    readonly name = 'get_skill'
    readonly description = 'Get a skill document by name, including its full content. Parameters: name (skill name).'
    readonly parameters = {
        type: 'object',
        properties: { name: { type: 'string', description: 'Skill name to fetch' } },
        required: ['name'],
    }

    constructor(private provider: ISkillProvider) {}

    validate(args: Record<string, unknown>): string | null {
        return typeof args?.name === 'string' && args.name.trim() ? null : 'Missing parameter: name'
    }

    async execute(args: Record<string, unknown>, context?: SessionContext): Promise<ToolExecutionResult> {
        const name = (args.name as string).trim()
        if (!name) return { success: false, error: 'Missing parameter: name' }

        const all = await this.provider.listSkills()

        const exact = all.find(s => s.id === name)
        if (exact) return { success: true, ...toSkillEntry(exact, true) }

        const ctx = context ?? minimalContext()
        const results = await this.provider.resolve(name, ctx, { maxSkills: 1 })
        const hit = results[0]
        if (hit) return { success: true, ...toSkillEntry(hit.skill, true) }

        return {
            success: false,
            error: `Skill not found: ${name}`,
            available: all.slice(0, 20).map(s => s.id),
        }
    }
}

// ── search_skills ────────────────────────────────────────────────────────

export class SearchSkillsTool implements Tool {
    readonly name = 'search_skills'
    readonly description = 'Search skills by query and return relevant skill contents. Parameters: query, limit (optional, default 5).'
    readonly parameters = {
        type: 'object',
        properties: {
            query: { type: 'string', description: 'Search query for skills' },
            limit: { type: 'number', description: 'Max results (default 5)' },
        },
        required: ['query'],
    }

    constructor(private provider: ISkillProvider) {}

    validate(args: Record<string, unknown>): string | null {
        return typeof args?.query === 'string' && args.query.trim() ? null : 'Missing parameter: query'
    }

    async execute(args: Record<string, unknown>, context?: SessionContext): Promise<ToolExecutionResult> {
        const query = (args.query as string).trim()
        if (!query) return { success: false, error: 'Missing parameter: query' }

        const limit = typeof args?.limit === 'number' ? Math.min(20, Math.max(1, args.limit)) : 5
        const ctx = context ?? minimalContext()
        const results = await this.provider.resolve(query, ctx, { maxSkills: limit })
        return {
            success: true,
            count: results.length,
            skills: results.map(r => toSkillEntry(r.skill, true)),
        }
    }
}

// ── Factory ──────────────────────────────────────────────────────────────

export function createSkillTools(provider: ISkillProvider): Tool[] {
    return [new ListSkillsTool(provider), new GetSkillTool(provider), new SearchSkillsTool(provider)]
}
