import type { ILogger } from '../../utils/logger.ts'
import type { MCPCallToolResult, MCPTool } from '../apis/mcp.ts'
import { createTransport } from './transport/mcp-transport-factory.ts'
import type { CreateTransportOptions } from './transport/types.ts'
import type { MCPClientHandle, MCPConnection } from './types.ts'

export async function openConnection(
    options: CreateTransportOptions,
    logger: ILogger,
): Promise<MCPConnection> {
    const result = await createTransport(options, logger)
    return {
        endpoint: options.endpoint.trim(),
        client: result.client as MCPClientHandle,
        transport: result.transport,
        closed: false,
    }
}

export async function closeConnection(conn: MCPConnection): Promise<void> {
    if (conn.closed) return
    conn.closed = true
    await conn.client.close()
}

export async function listTools(conn: MCPConnection): Promise<MCPTool[]> {
    const result = await conn.client.listTools()
    const tools = (result as { tools?: MCPTool[] }).tools ?? []
    return tools.map(t => ({ name: t.name, description: t.description, inputSchema: t.inputSchema }))
}

/** Returns raw result — callers decide how to handle `isError`. */
export async function callTool(
    conn: MCPConnection,
    toolName: string,
    args: Record<string, unknown>,
): Promise<MCPCallToolResult> {
    const result = await conn.client.callTool({ name: toolName, arguments: args })
    const typed = result as { content?: MCPCallToolResult['content']; isError?: boolean }
    return {
        content: typed.content ?? [],
        isError: typed.isError ?? false,
    }
}
