// Reciprocal Rank Fusion algorithm

export interface RankedItem {
    id: string
    score: number
    source: string // 'bm25' | 'vector' | 'graph'
    content?: string
    metadata?: Record<string, unknown>
}

export interface FusionWeights {
    bm25: number
    vector: number
    graph: number
}

export function rrfFusion(
    resultSets: Array<{ source: string; items: RankedItem[] }>,
    weights: FusionWeights,
    k: number = 60
): RankedItem[] {
    const fused = new Map<string, { item: RankedItem; fusedScore: number }>()

    for (const { source, items } of resultSets) {
        const weightKey = source.toLowerCase() as keyof FusionWeights
        const weight = weightKey in weights ? weights[weightKey as keyof FusionWeights] : 1
        if (weight <= 0) continue

        for (let rank = 0; rank < items.length; rank++) {
            const item = items[rank]!
            const rrfContrib = weight * (1 / (k + rank + 1))
            const existing = fused.get(item.id)
            if (existing) {
                existing.fusedScore += rrfContrib
                if (item.content && !existing.item.content) {
                    existing.item = { ...existing.item, content: item.content }
                }
                if (item.metadata && Object.keys(item.metadata).length > 0) {
                    existing.item = {
                        ...existing.item,
                        metadata: { ...existing.item.metadata, ...item.metadata },
                    }
                }
            } else {
                fused.set(item.id, {
                    item: { ...item, source },
                    fusedScore: rrfContrib,
                })
            }
        }
    }

    return Array.from(fused.values())
        .map(({ item, fusedScore }) => ({ ...item, score: fusedScore }))
        .sort((a, b) => b.score - a.score)
}
