import {execa} from 'execa'
import {mkdir} from 'node:fs/promises'
import path from 'node:path'
import { toErrorMessage } from '../../../constants/errors.ts'
import type {Tool, ToolExecutionResult} from '../apis/tool.ts'
import {Logger} from '../../utils/logger.ts'
import {isCommandBlocked, resolvePathInWorkspace} from './security.ts'

export interface ExecToolOptions {
    allowedCommands: string[]
    timeoutMs: number
    useLoginShell: boolean
    dockerSandbox?: {
        enabled: boolean
        image?: string
        memoryLimit?: string
        networkDisabled?: boolean
    }
}

export class ExecTool implements Tool {
    readonly name = 'exec'
    readonly description = 'Run a shell command. Parameters: command (required), cwd (optional).'
    readonly parameters = {
        type: 'object',
        properties: {
            command: {type: 'string', description: 'Shell command to run'},
            cwd: {type: 'string', description: 'Working directory'}
        },
        required: ['command']
    }

    private logger = new Logger('ExecTool')

    constructor(
        private workspaceDir: string,
        private options: ExecToolOptions
    ) {
    }

    validate(args: Record<string, unknown>): string | null {
        const command = this.extractCommand(args)
        if (!command) return 'Missing parameter: command'
        const check = isCommandBlocked(command, this.options.allowedCommands)
        if (check.blocked) return `Command blocked: ${check.reason}`
        return null
    }

    async execute(args: Record<string, unknown>): Promise<ToolExecutionResult> {
        const command = this.extractCommand(args)
        if (!command) return {success: false, error: 'Missing parameter: command'}

        const check = isCommandBlocked(command, this.options.allowedCommands)
        if (check.blocked) {
            this.logger.warn('Blocked exec command', {command: command.slice(0, 100), reason: check.reason})
            return {success: false, error: `Command blocked: ${check.reason}`}
        }

        const rawCwd = typeof args?.cwd === 'string' ? args.cwd.trim() : undefined
        const cwd = this.validateCwd(rawCwd)
        if (cwd === false) {
            return {success: false, error: `cwd '${rawCwd}' is outside the workspace directory`}
        }
        if (this.options.dockerSandbox?.enabled) {
            return this.runInDocker(command, cwd ?? undefined)
        }
        return this.runCommand(command, cwd ?? undefined)
    }

    /**
     * Returns resolved cwd if valid, null if no cwd given, false if path escapes workspace.
     */
    private validateCwd(rawCwd: string | undefined): string | null | false {
        if (!rawCwd) return null
        if (!this.workspaceDir) return rawCwd
        const resolved = resolvePathInWorkspace(rawCwd, this.workspaceDir)
        if (!resolved) {
            this.logger.warn('cwd rejected: outside workspace', {cwd: rawCwd, workspace: this.workspaceDir})
            return false
        }
        return resolved
    }

    private static readonly COMMAND_KEYS = ['command', 'cmd', 'shell', 'script'] as const

    private extractCommand(args: Record<string, unknown>): string {
        for (const key of ExecTool.COMMAND_KEYS) {
            if (typeof args?.[key] === 'string' && (args[key] as string).trim()) {
                return (args[key] as string).trim()
            }
        }
        return ''
    }

    private async runCommand(command: string, cwd?: string): Promise<ToolExecutionResult> {
        const workDir = cwd ?? this.workspaceDir ?? process.cwd()
        try {
            await mkdir(workDir, {recursive: true})
        } catch (e) {
            if (cwd) {
                const fallbackDir = this.workspaceDir ?? process.cwd()
                this.logger.warn('Provided cwd not usable, falling back', {
                    cwd, fallbackDir, error: toErrorMessage(e)
                })
                return this.runCommand(command, fallbackDir)
            }
            throw e
        }

        const {timeoutMs, useLoginShell} = this.options
        const env = process.env

        try {
            if (useLoginShell && process.platform !== 'win32') {
                const loginShell = process.env.SHELL ?? (process.platform === 'darwin' ? '/bin/zsh' : '/bin/bash')
                const shellName = path.basename(loginShell)
                const sourceRc =
                    shellName === 'zsh'
                        ? 'source ~/.zshrc 2>/dev/null; source ~/.zprofile 2>/dev/null; '
                        : shellName === 'bash'
                            ? 'source ~/.bashrc 2>/dev/null; source ~/.bash_profile 2>/dev/null; '
                            : ''
                const result = await execa(loginShell, ['-l', '-c', `${sourceRc}${command}`], {
                    cwd: workDir, timeout: timeoutMs, env, reject: false
                })
                if (result.failed) {
                    return {
                        success: false,
                        error: result.stderr || result.message || 'Command failed',
                        stderr: result.stderr ?? ''
                    }
                }
                return {success: true, stdout: (result.stdout ?? '').trim(), stderr: (result.stderr ?? '').trim()}
            }

            const isWin = process.platform === 'win32'
            const result = isWin
                ? await execa('cmd.exe', ['/d', '/s', '/c', command], {
                    cwd: workDir,
                    timeout: timeoutMs,
                    env,
                    reject: false
                })
                : await execa('sh', ['-c', command], {cwd: workDir, timeout: timeoutMs, env, reject: false})

            if (result.failed) {
                return {
                    success: false,
                    error: result.stderr || result.message || 'Command failed',
                    stderr: result.stderr ?? ''
                }
            }
            return {success: true, stdout: (result.stdout ?? '').trim(), stderr: (result.stderr ?? '').trim()}
        } catch (err: unknown) {
            const e = err as Error & { stderr?: string }
            const stderr = typeof e.stderr === 'string' ? e.stderr : ''
            return {success: false, error: toErrorMessage(err), stderr}
        }
    }

    private async runInDocker(command: string, cwd?: string): Promise<ToolExecutionResult> {
        const sandbox = this.options.dockerSandbox!
        const image = sandbox.image ?? 'node:22-slim'
        const memLimit = sandbox.memoryLimit ?? '256m'
        const workDir = cwd ?? this.workspaceDir ?? '/workspace'
        const { timeoutMs } = this.options

        const dockerArgs = [
            'run', '--rm',
            '--memory', memLimit,
            '--cpus', '1',
            '-v', `${this.workspaceDir}:/workspace:rw`,
            '-w', workDir.startsWith(this.workspaceDir)
                ? workDir.replace(this.workspaceDir, '/workspace')
                : '/workspace',
        ]

        if (sandbox.networkDisabled) {
            dockerArgs.push('--network', 'none')
        }

        dockerArgs.push(
            '--pids-limit', '256',
            '--read-only',
            '--tmpfs', '/tmp:rw,exec,size=128m',
            image,
            'sh', '-c', command
        )

        try {
            const result = await execa('docker', dockerArgs, {
                timeout: timeoutMs,
                reject: false,
                env: process.env
            })

            if (result.failed) {
                return {
                    success: false,
                    error: result.stderr || result.message || 'Docker command failed',
                    stderr: result.stderr ?? ''
                }
            }
            return { success: true, stdout: (result.stdout ?? '').trim(), stderr: (result.stderr ?? '').trim() }
        } catch (err: unknown) {
            const e = err as Error & { stderr?: string }
            if (e.message?.includes('Cannot connect to the Docker daemon') || e.message?.includes('docker: not found')) {
                this.logger.warn('Docker not available, falling back to direct execution')
                return this.runCommand(command, cwd)
            }
            const stderr = typeof e.stderr === 'string' ? e.stderr : ''
            return { success: false, error: toErrorMessage(err), stderr }
        }
    }
}
