import type { MCPServerEntry } from './types.ts'

function isSensitiveHeaderKey(key: string): boolean {
    const lower = key.toLowerCase()
    return (
        lower === 'authorization'
        || lower === 'cookie'
        || lower.includes('x-api-key')
        || lower.includes('api-key')
        || lower === 'x-auth-token'
    )
}

function maskHeaderValue(key: string, value: string): string {
    if (isSensitiveHeaderKey(key) || /^Bearer\s+/i.test(value)) {
        return '***'
    }
    return value
}

/** Mask requestInit.headers for GET /api/config (unless showKeys). */
export function maskMcpListForResponse(
    entries: MCPServerEntry[] | undefined,
    showKeys: boolean,
): MCPServerEntry[] | undefined {
    if (entries == null || showKeys) return entries
    return entries.map((row) => {
        const ri = row.requestInit
        if (!ri?.headers || typeof ri.headers !== 'object') return row
        const headers: Record<string, string> = {}
        for (const [k, v] of Object.entries(ri.headers)) {
            headers[k] = typeof v === 'string' ? maskHeaderValue(k, v) : '***'
        }
        return {
            ...row,
            requestInit: {
                ...ri,
                headers,
            },
        }
    })
}

/**
 * Merge incoming MCP entries with existing: header values sent as `***` keep the previous value (same endpoint).
 */
export function mergeMcpIncomingWithExisting(
    incoming: MCPServerEntry[],
    existing: MCPServerEntry[] | undefined,
): MCPServerEntry[] {
    const byEndpoint = new Map(
        (existing ?? []).map((e) => [e.endpoint.trim(), e]),
    )
    return incoming.map((row) => {
        const ep = row.endpoint.trim()
        const prev = byEndpoint.get(ep)
        const ri = row.requestInit
        if (!ri?.headers || typeof ri.headers !== 'object') return row
        const prevHeaders = prev?.requestInit?.headers
        const merged: Record<string, string> = { ...ri.headers }
        for (const [hk, hv] of Object.entries(merged)) {
            if (hv === '***' && prevHeaders && typeof prevHeaders[hk] === 'string') {
                merged[hk] = prevHeaders[hk]
            }
        }
        return {
            ...row,
            requestInit: {
                ...ri,
                headers: merged,
            },
        }
    })
}
